// Auto-generated native CSL styles for offline use

export const CSL_STYLES: Record<string, string> = {
  "apa": "<?xml version=\"1.0\" encoding=\"utf-8\"?>\n<style xmlns=\"http://purl.org/net/xbiblio/csl\" class=\"in-text\" demote-non-dropping-particle=\"never\" initialize-with=\". \" names-delimiter=\", \" page-range-format=\"expanded\" version=\"1.0\">\n  <!-- This file was generated by the Style Variant Builder <https://github.com/citation-style-language/style-variant-builder>. To contribute changes, modify the template and regenerate variants. -->\n  <info>\n    <title>APA Style 7th edition</title>\n    <title-short>Publication Manual of the American Psychological Association, with Bluebook</title-short>\n    <id>http://www.zotero.org/styles/apa</id>\n    <link href=\"http://www.zotero.org/styles/apa\" rel=\"self\"/>\n    <link href=\"http://www.zotero.org/styles/apa-6th-edition\" rel=\"template\"/>\n    <link href=\"https://apastyle.apa.org/style-grammar-guidelines/references\" rel=\"documentation\"/>\n    <link href=\"https://zotero.org/groups/2205533/collections/MR2N872S\" rel=\"documentation\"/>\n    <author>\n      <name>Brenton M. Wiernik</name>\n      <email>zotero@wiernik.org</email>\n      <uri>https://orcid.org/0000-0001-9560-6336</uri>\n    </author>\n    <author>\n      <name>Andrew Dunning</name>\n      <uri>https://orcid.org/0000-0003-0464-5036</uri>\n    </author>\n    <category citation-format=\"author-date\"/>\n    <category field=\"anthropology\"/>\n    <category field=\"communications\"/>\n    <category field=\"generic-base\"/>\n    <category field=\"law\"/>\n    <category field=\"medicine\"/>\n    <category field=\"psychology\"/>\n    <category field=\"social_science\"/>\n    <category field=\"sociology\"/>\n    <summary>Author-date system of the Publication Manual of the American Psychological Association (2020)</summary>\n    <updated>2026-02-07T00:00:00+00:00</updated>\n    <rights license=\"http://creativecommons.org/licenses/by-sa/3.0/\">This work is licensed under a Creative Commons Attribution-ShareAlike 3.0 License</rights>\n  </info>\n  <locale xml:lang=\"en\">\n    <terms>\n      <term name=\"ad\"> C.E.</term>\n      <term name=\"bc\"> B.C.E.</term>\n      <term form=\"short\" name=\"circa\">ca.</term>\n      <term name=\"guest\">\n        <single>guest expert</single>\n        <multiple>guest experts</multiple>\n      </term>\n      <term form=\"short\" name=\"illustrator\">illus.</term>\n      <term form=\"short\" name=\"interviewer\">\n        <single>interviewer</single>\n        <multiple>interviewers</multiple>\n      </term>\n      <term form=\"short\" name=\"legislation\">Pub. L.</term>\n      <term name=\"manuscript\">unpublished manuscript</term>\n      <term form=\"verb\" name=\"performer\">recorded by</term>\n      <term name=\"post\">online post</term>\n      <term name=\"review-of\">review of the</term>\n      <term form=\"short\" name=\"review-of\">review of</term>\n      <term name=\"software\">computer software</term>\n      <term form=\"short\" name=\"supplement\">\n        <single>suppl.</single>\n        <multiple>suppls.</multiple>\n      </term>\n    </terms>\n  </locale>\n  <locale xml:lang=\"da\">\n    <terms>\n      <term name=\"et-al\">et al.</term>\n    </terms>\n  </locale>\n  <locale xml:lang=\"de\">\n    <terms>\n      <term name=\"et-al\">et al.</term>\n    </terms>\n  </locale>\n  <locale xml:lang=\"es\">\n    <terms>\n      <term name=\"from\">de</term>\n    </terms>\n  </locale>\n  <locale xml:lang=\"fr\">\n    <terms>\n      <term form=\"short\" name=\"editor\">\n        <single>éd.</single>\n        <multiple>éds.</multiple>\n      </term>\n    </terms>\n  </locale>\n  <locale xml:lang=\"nb\">\n    <terms>\n      <term name=\"et-al\">et al.</term>\n    </terms>\n  </locale>\n  <locale xml:lang=\"nl\">\n    <terms>\n      <term name=\"et-al\">et al.</term>\n    </terms>\n  </locale>\n  <locale xml:lang=\"nn\">\n    <terms>\n      <term name=\"et-al\">et al.</term>\n    </terms>\n  </locale>\n  <locale xml:lang=\"pl\">\n    <terms>\n      <term name=\"et-al\">i in.</term>\n    </terms>\n  </locale>\n  <locale xml:lang=\"ro\">\n    <terms>\n      <term name=\"et-al\">et al.</term>\n    </terms>\n  </locale>\n  <!-- Contents:\n\n       APA uses four main reference elements:\n\n        1. Author (APA 9.7-12)\n        2. Date (APA 9.13-17)\n        3. Title and descriptions (APA 9.18-22)\n            3.1. Title (APA 9.18)\n            3.2. Identifier (in parentheses) (APA 9.19)\n            3.3. Description [in square brackets] (APA 9.21-22)\n        4. Source (APA 9.23-37)\n            4.1. Serial sources (APA 9.25-27)\n            4.2. Monographic sources (APA 9.28)\n            4.3. Publisher sources (APA 9.29)\n            4.4. Database and archive sources (APA 9.30)\n            4.5. Works with specific locations (APA 9.31)\n            4.6. Social media and website sources (APA 9.32-33)\n            4.7. DOI or URL (APA 9.34-36)\n\n       A note on the source may follow the main reference elements:\n\n        5. Publication history (APA 9.39-41)\n\n       APA also provides parallel rules for legal references following The Bluebook: A Uniform System of Citation (chap. 11):\n\n        6. Legal references\n  -->\n  <!-- APA categorizes all sources as serial (APA 9.25-27) or monographic (APA 9.28).\n\n       Serial\n       : article-journal article-magazine article-newspaper periodical post-weblog review review-book\n\n       Serial or Monographic\n       : interview paper-conference\n\n         Monographic with any of `collection-editor compiler editor editorial-director`.\n         A serial `paper-conference` is unpublished if it lacks any of `issue page supplement-number volume`.\n\n       Monographic\n       : article book broadcast chapter classic collection dataset document entry entry-dictionary entry-encyclopedia event figure graphic manuscript map motion_picture musical_score pamphlet patent performance personal_communication post report software song speech standard thesis webpage\n\n       Legal\n       : bill hearing legal_case legislation regulation treaty\n  -->\n  <!-- Equivalencies:\n\n       `classic` == `book`\n       `document` == `report` (but give full date)\n       `standard` == `report`\n       `performance` == `speech`\n       `event` == `speech`\n  -->\n  <!-- Role equivalencies:\n\n       `compiler` == `editor`\n       `organizer`, `curator` == `chair`\n       `script-writer` == `director`\n       `producer` == `director` (but don't print both)\n       `guest`, `host` == `director`\n       `series-creator`, `executive-producer` == `editor`\n  -->\n  <!-- Reviews are detected if an item has type `review` or `review-book` or if it has any of the variables `reviewed-title`, `reviewed-author`, or `reviewed-genre`. For the latter case, reviews are commonly stored as types `article-journal`, `article-magazine`, `article-newspaper`, `post-weblog`, or `webpage`. -->\n  <!-- Indigeneous knowledge: Assume the item is stored as `document` or `speech` and that Nation/Community, treaty territory, where the Elder lives, and topic are all stored in `title`. Cf. <https://libguides.norquest.ca/c.php?g=314831&p=5188823>. If the item is stored as `interview`, assume that Nation/Community, treaty territory, and topic are stored in `title`. 'Oral teaching' or similar is stored in `archive`, and where the Elder lives is stored in `archive-place`. -->\n  <!-- Variable labels -->\n  <macro name=\"label-chapter-number\">\n    <group delimiter=\" \">\n      <choose>\n        <if is-numeric=\"chapter-number\" type=\"song\">\n          <text text-case=\"capitalize-first\" value=\"track\"/>\n        </if>\n        <else-if is-numeric=\"chapter-number\">\n          <label text-case=\"capitalize-first\" variable=\"chapter-number\"/>\n        </else-if>\n      </choose>\n      <text variable=\"chapter-number\"/>\n    </group>\n  </macro>\n  <macro name=\"label-edition\">\n    <group delimiter=\" \">\n      <choose>\n        <if is-numeric=\"edition\">\n          <number form=\"ordinal\" variable=\"edition\"/>\n          <label form=\"short\" variable=\"edition\"/>\n        </if>\n        <else>\n          <text variable=\"edition\"/>\n        </else>\n      </choose>\n    </group>\n  </macro>\n  <macro name=\"label-issue\">\n    <group delimiter=\" \">\n      <label text-case=\"capitalize-first\" variable=\"issue\"/>\n      <text variable=\"issue\"/>\n    </group>\n  </macro>\n  <macro name=\"label-locator\">\n    <!-- Abbreviate page and paragraph; leave other locator labels in long form (APA 8.13) -->\n    <group delimiter=\" \">\n      <choose>\n        <if locator=\"page\">\n          <label form=\"short\" variable=\"locator\"/>\n        </if>\n        <else-if match=\"any\" type=\"bill hearing legal_case legislation regulation treaty\">\n          <!-- Bluebook-style labels for legal types -->\n          <choose>\n            <if locator=\"chapter paragraph section\" match=\"any\">\n              <label form=\"symbol\" variable=\"locator\"/>\n            </if>\n            <else>\n              <label text-case=\"capitalize-first\" variable=\"locator\"/>\n            </else>\n          </choose>\n        </else-if>\n        <else-if locator=\"paragraph\">\n          <label form=\"short\" variable=\"locator\"/>\n        </else-if>\n        <else-if is-numeric=\"locator\">\n          <label text-case=\"capitalize-first\" variable=\"locator\"/>\n        </else-if>\n        <!-- a non-numeric canonical reference is identified by its formatting and does not need a label, similar to a timestamp -->\n        <else-if locator=\"chapter line verse\" match=\"any\"/>\n        <else>\n          <label text-case=\"capitalize-first\" variable=\"locator\"/>\n        </else>\n      </choose>\n      <text variable=\"locator\"/>\n    </group>\n  </macro>\n  <macro name=\"label-number\">\n    <group delimiter=\" \">\n      <choose>\n        <if type=\"standard\"/>\n        <else-if is-numeric=\"number\" match=\"any\" type=\"legislation patent regulation\">\n          <label form=\"short\" text-case=\"capitalize-first\" variable=\"number\"/>\n        </else-if>\n      </choose>\n      <text text-case=\"capitalize-first\" variable=\"number\"/>\n    </group>\n  </macro>\n  <macro name=\"label-number-capitalized\">\n    <!-- alias for cross-compatibility of Bluebook macros -->\n    <text macro=\"label-number\"/>\n  </macro>\n  <macro name=\"label-number-article\">\n    <!-- APA example 6: Journal article with article number or eLocator -->\n    <group delimiter=\" \">\n      <text term=\"article-locator\" text-case=\"capitalize-first\"/>\n      <text variable=\"number\"/>\n    </group>\n  </macro>\n  <macro name=\"label-number-of-volumes\">\n    <group delimiter=\" \">\n      <choose>\n        <if is-numeric=\"number-of-volumes\">\n          <label form=\"short\" text-case=\"capitalize-first\" variable=\"number-of-volumes\"/>\n          <group>\n            <text prefix=\"1\" term=\"page-range-delimiter\"/>\n            <number variable=\"number-of-volumes\"/>\n          </group>\n        </if>\n        <else>\n          <text variable=\"number-of-volumes\"/>\n        </else>\n      </choose>\n    </group>\n  </macro>\n  <macro name=\"label-page\">\n    <group delimiter=\" \">\n      <label form=\"short\" variable=\"page\"/>\n      <text variable=\"page\"/>\n    </group>\n  </macro>\n  <macro name=\"label-part-number\">\n    <group delimiter=\" \">\n      <choose>\n        <if is-numeric=\"part-number\">\n          <!-- TODO: Replace with `part-number` label when CSL provides one -->\n          <text form=\"short\" term=\"part\" text-case=\"capitalize-first\"/>\n        </if>\n      </choose>\n      <text text-case=\"capitalize-first\" variable=\"part-number\"/>\n    </group>\n  </macro>\n  <macro name=\"label-section-symbol\">\n    <group delimiter=\" \">\n      <label form=\"symbol\" variable=\"section\"/>\n      <text variable=\"section\"/>\n    </group>\n  </macro>\n  <macro name=\"label-supplement-number\">\n    <group delimiter=\" \">\n      <choose>\n        <if is-numeric=\"supplement-number\">\n          <!-- TODO: Replace with `supplement-number` label when CSL provides one -->\n          <text form=\"short\" term=\"supplement\" text-case=\"capitalize-first\"/>\n        </if>\n      </choose>\n      <text text-case=\"capitalize-first\" variable=\"supplement-number\"/>\n    </group>\n  </macro>\n  <macro name=\"label-version\">\n    <group delimiter=\" \">\n      <label text-case=\"capitalize-first\" variable=\"version\"/>\n      <text variable=\"version\"/>\n    </group>\n  </macro>\n  <macro name=\"label-volume\">\n    <group delimiter=\" \">\n      <choose>\n        <if is-numeric=\"volume\">\n          <label form=\"short\" text-case=\"capitalize-first\" variable=\"volume\"/>\n        </if>\n      </choose>\n      <text text-case=\"capitalize-first\" variable=\"volume\"/>\n    </group>\n  </macro>\n  <!-- 1. Author (APA 9.7-12) -->\n  <macro name=\"author\">\n    <!-- Substitutes for missing authors: order prioritizes primary creators (e.g., composer, author) over secondary roles (e.g., editor, curator), with title as the final fallback. -->\n    <names variable=\"composer\">\n      <name and=\"symbol\" delimiter-precedes-last=\"always\" name-as-sort-order=\"all\"/>\n      <label form=\"short\" prefix=\" (\" suffix=\")\" text-case=\"title\"/>\n      <substitute>\n        <names variable=\"author\"/>\n        <!-- `narrator` only cited in `identifier-contributors` -->\n        <names variable=\"illustrator\"/>\n        <choose>\n          <if type=\"broadcast\">\n            <names variable=\"script-writer director\">\n              <!-- Actors/performers and producers [not executive] not cited in APA style. -->\n              <name and=\"symbol\" delimiter-precedes-last=\"always\" name-as-sort-order=\"all\"/>\n              <label prefix=\" (\" suffix=\")\" text-case=\"title\"/>\n            </names>\n          </if>\n        </choose>\n        <names variable=\"director\">\n          <!-- For non-broadcast items, APA only cites directors and not writers. -->\n          <name and=\"symbol\" delimiter-precedes-last=\"always\" name-as-sort-order=\"all\"/>\n          <label prefix=\" (\" suffix=\")\" text-case=\"title\"/>\n        </names>\n        <names variable=\"guest host\">\n          <!-- TODO: Collapse variables when that becomes available. -->\n          <name and=\"symbol\" delimiter-precedes-last=\"always\" name-as-sort-order=\"all\"/>\n          <label prefix=\" (\" suffix=\")\" text-case=\"title\"/>\n        </names>\n        <names variable=\"producer\">\n          <!-- Producers not cited if there is a writer/director, but use if they are the principal creator. -->\n          <name and=\"symbol\" delimiter-precedes-last=\"always\" name-as-sort-order=\"all\"/>\n          <label prefix=\" (\" suffix=\")\" text-case=\"title\"/>\n        </names>\n        <choose>\n          <if match=\"any\" type=\"entry-dictionary entry-encyclopedia\">\n            <text variable=\"publisher\"/>\n          </if>\n        </choose>\n        <choose>\n          <if match=\"none\" variable=\"container-title\"/>\n          <else-if match=\"any\" type=\"book classic entry entry-dictionary entry-encyclopedia\">\n            <!-- Items with a monographic `container-title` substitute their title and identifier, but leave description after `container-title`. This mimics the `source-monographic` macro. -->\n            <text macro=\"author-title-substitute\"/>\n          </else-if>\n        </choose>\n        <names variable=\"executive-producer\">\n          <name and=\"symbol\" delimiter-precedes-last=\"always\" name-as-sort-order=\"all\"/>\n          <label prefix=\" (\" suffix=\")\" text-case=\"title\"/>\n        </names>\n        <names variable=\"series-creator\">\n          <name and=\"symbol\" delimiter-precedes-last=\"always\" name-as-sort-order=\"all\"/>\n          <label prefix=\" (\" suffix=\")\" text-case=\"title\"/>\n        </names>\n        <names variable=\"editor-translator\"/>\n        <!-- `translator` is not cited as a primary creator (only as Ed. & Trans.). -->\n        <names variable=\"editor\"/>\n        <names variable=\"editorial-director\"/>\n        <names variable=\"compiler\">\n          <name and=\"symbol\" delimiter-precedes-last=\"always\" name-as-sort-order=\"all\"/>\n          <label prefix=\" (\" suffix=\")\" text-case=\"title\"/>\n        </names>\n        <choose>\n          <if match=\"any\" type=\"event performance speech\">\n            <names variable=\"chair\">\n              <name and=\"symbol\" delimiter-precedes-last=\"always\" name-as-sort-order=\"all\"/>\n              <label prefix=\" (\" suffix=\")\" text-case=\"title\"/>\n            </names>\n            <names variable=\"organizer\">\n              <name and=\"symbol\" delimiter-precedes-last=\"always\" name-as-sort-order=\"all\"/>\n              <label prefix=\" (\" suffix=\")\" text-case=\"title\"/>\n            </names>\n          </if>\n        </choose>\n        <names variable=\"curator\">\n          <name and=\"symbol\" delimiter-precedes-last=\"always\" name-as-sort-order=\"all\"/>\n          <label prefix=\" (\" suffix=\")\" text-case=\"title\"/>\n        </names>\n        <names variable=\"collection-editor\"/>\n        <choose>\n          <if match=\"any\" type=\"software webpage\">\n            <!-- `software` (APA 10.10) and `webpage` (APA 10.16) can be cited under \"name of group\": likely in `publisher` if no `author` -->\n            <text variable=\"publisher\"/>\n          </if>\n          <else-if type=\"standard\">\n            <text variable=\"authority\"/>\n          </else-if>\n        </choose>\n        <text macro=\"author-title-substitute\"/>\n      </substitute>\n    </names>\n  </macro>\n  <macro name=\"author-and-contributors\">\n    <group delimiter=\" \">\n      <text macro=\"author\"/>\n      <choose>\n        <!-- add nonprimary authors equivalent to those appearing \"on a book cover\"; do not modify the in-text citation (APA 9.8) -->\n        <if match=\"none\" variable=\"author compiler composer editor editor-translator illustrator\"/>\n        <else-if match=\"any\" type=\"book musical_score pamphlet report standard\">\n          <names prefix=\"(\" suffix=\")\" variable=\"contributor\">\n            <label form=\"verb\" suffix=\" \"/>\n            <name and=\"symbol\" delimiter-precedes-last=\"always\" name-as-sort-order=\"all\"/>\n          </names>\n        </else-if>\n      </choose>\n    </group>\n  </macro>\n  <macro name=\"author-short\">\n    <choose>\n      <if match=\"any\" type=\"bill hearing legal_case legislation regulation treaty\">\n        <text macro=\"title-and-descriptions-short\"/>\n      </if>\n      <else-if match=\"any\" type=\"interview personal_communication\">\n        <choose>\n          <!-- These variables indicate that the letter is retrievable by the reader. If not, use the APA in-text-only personal communication format. -->\n          <if match=\"any\" variable=\"archive archive-place container-title DOI number publisher references URL\">\n            <names variable=\"author\">\n              <name and=\"symbol\" form=\"short\"/>\n              <substitute>\n                <text macro=\"title-and-descriptions-short\"/>\n              </substitute>\n            </names>\n          </if>\n          <else>\n            <group delimiter=\", \">\n              <names variable=\"author\">\n                <name and=\"symbol\"/>\n                <substitute>\n                  <text macro=\"title-and-descriptions-short\"/>\n                </substitute>\n              </names>\n              <text term=\"personal-communication\"/>\n            </group>\n          </else>\n        </choose>\n      </else-if>\n      <else>\n        <names variable=\"composer\">\n          <name and=\"symbol\" form=\"short\"/>\n          <substitute>\n            <names variable=\"author\"/>\n            <names variable=\"illustrator\"/>\n            <choose>\n              <if type=\"broadcast\">\n                <!-- TODO: Collapse variables when that becomes available. -->\n                <!-- Ideally combine as `script-writer director` -->\n                <names variable=\"script-writer\"/>\n              </if>\n            </choose>\n            <names variable=\"director\"/>\n            <!-- TODO: Collapse variables when that becomes available. -->\n            <names variable=\"guest host\"/>\n            <names variable=\"producer\"/>\n            <choose>\n              <if match=\"any\" type=\"entry-dictionary entry-encyclopedia\">\n                <text variable=\"publisher\"/>\n              </if>\n            </choose>\n            <choose>\n              <if match=\"none\" variable=\"container-title\"/>\n              <else-if match=\"any\" type=\"book classic entry entry-dictionary entry-encyclopedia\">\n                <text macro=\"title-and-descriptions-short\"/>\n              </else-if>\n            </choose>\n            <names variable=\"executive-producer\"/>\n            <names variable=\"series-creator\"/>\n            <names variable=\"editor\"/>\n            <names variable=\"editorial-director\"/>\n            <names variable=\"compiler\"/>\n            <choose>\n              <if match=\"any\" type=\"event performance speech\">\n                <names variable=\"chair\"/>\n                <names variable=\"organizer\"/>\n              </if>\n            </choose>\n            <names variable=\"curator\"/>\n            <names variable=\"collection-editor\"/>\n            <choose>\n              <if match=\"any\" type=\"software webpage\">\n                <!-- `software` (APA 10.10) and `webpage` (APA 10.16) can be cited under \"name of group\": likely in `publisher` if no `author` -->\n                <text form=\"short\" variable=\"publisher\"/>\n              </if>\n              <else-if type=\"standard\">\n                <text form=\"short\" variable=\"authority\"/>\n              </else-if>\n            </choose>\n            <text macro=\"title-and-descriptions-short\"/>\n          </substitute>\n        </names>\n      </else>\n    </choose>\n  </macro>\n  <macro name=\"author-sort\">\n    <choose>\n      <if match=\"any\" type=\"bill hearing legal_case legislation regulation treaty\">\n        <text macro=\"legal-title\"/>\n      </if>\n      <else>\n        <text macro=\"author\"/>\n      </else>\n    </choose>\n  </macro>\n  <!-- Author elements -->\n  <macro name=\"author-title-substitute\">\n    <choose>\n      <if match=\"any\" type=\"review review-book\" variable=\"reviewed-author reviewed-genre reviewed-title\">\n        <!-- `title` is only the review title if there is a separate `reviewed-genre` or `reviewed-title`; otherwise, it is the title of the reviewed work, printed in the description -->\n        <choose>\n          <if variable=\"reviewed-genre title\">\n            <text macro=\"title\"/>\n          </if>\n          <else-if variable=\"reviewed-title title\">\n            <text macro=\"title\"/>\n          </else-if>\n          <else>\n            <text macro=\"title-and-descriptions\"/>\n          </else>\n        </choose>\n      </if>\n      <else-if variable=\"title\">\n        <!-- If an item has a `title`, substitute missing author with title and identifier, but leave description after the date (in the title position). -->\n        <group delimiter=\" \">\n          <text macro=\"title\"/>\n          <text macro=\"identifier\"/>\n        </group>\n      </else-if>\n      <else>\n        <!-- If an item has no `title`, substitute with descriptions. -->\n        <text macro=\"title-and-descriptions\"/>\n      </else>\n    </choose>\n  </macro>\n  <!-- 2. Date (APA 9.13-17) -->\n  <macro name=\"date\">\n    <!-- Full dates included for ephemeral sources (e.g. broadcasts, interviews) to provide maximum specificity, while books use year only. -->\n    <group delimiter=\"-\" prefix=\"(\" suffix=\")\">\n      <choose>\n        <if variable=\"issued\">\n          <group delimiter=\", \">\n            <group>\n              <text macro=\"date-issued-year\"/>\n              <text variable=\"year-suffix\"/>\n            </group>\n            <choose>\n              <if match=\"any\" type=\"article-magazine article-newspaper broadcast collection document event motion_picture pamphlet performance personal_communication post post-weblog song speech webpage\">\n                <!-- Many video and audio examples in manual give full dates. Err on the side of too much information. -->\n                <text macro=\"date-issued-month-day\"/>\n              </if>\n              <!-- Only show the month and day for an unpublished `interview` or `paper-conference` -->\n              <else-if match=\"any\" variable=\"collection-editor compiler editor editorial-director issue page supplement-number volume\"/>\n              <else-if match=\"any\" type=\"interview paper-conference\">\n                <text macro=\"date-issued-month-day\"/>\n              </else-if>\n              <!-- Only year: article article-journal book chapter classic entry entry-dictionary entry-encyclopedia dataset figure graphic manuscript map musical_score paper-conference[published] patent periodical report review review-book software standard thesis -->\n            </choose>\n          </group>\n        </if>\n        <else-if variable=\"status\">\n          <!-- Print the status variable rather than use generic CSL terms (`in press`, etc.) -->\n          <text text-case=\"lowercase\" variable=\"status\"/>\n          <text variable=\"year-suffix\"/>\n        </else-if>\n        <else>\n          <text form=\"short\" term=\"no date\"/>\n          <text variable=\"year-suffix\"/>\n        </else>\n      </choose>\n    </group>\n  </macro>\n  <macro name=\"date-short\">\n    <group delimiter=\"-\">\n      <choose>\n        <if variable=\"issued\">\n          <group delimiter=\"/\">\n            <text macro=\"date-original-year\"/>\n            <group>\n              <choose>\n                <if match=\"any\" variable=\"archive archive-place container-title DOI number publisher references URL\">\n                  <text macro=\"date-issued-year\"/>\n                </if>\n                <else-if match=\"any\" type=\"interview personal_communication\">\n                  <!-- use the in-text-only format for inaccessible personal communications -->\n                  <text macro=\"date-issued-full\"/>\n                </else-if>\n                <else>\n                  <text macro=\"date-issued-year\"/>\n                </else>\n              </choose>\n              <text variable=\"year-suffix\"/>\n            </group>\n          </group>\n        </if>\n        <else-if variable=\"status\">\n          <!-- Print the status variable rather than use generic CSL terms (`in press`, etc.) -->\n          <text text-case=\"lowercase\" variable=\"status\"/>\n          <text variable=\"year-suffix\"/>\n        </else-if>\n        <else>\n          <text form=\"short\" term=\"no date\"/>\n          <text variable=\"year-suffix\"/>\n        </else>\n      </choose>\n    </group>\n  </macro>\n  <macro name=\"date-sort\">\n    <!-- Sort items by issue date as printed -->\n    <choose>\n      <if match=\"any\" type=\"article article-journal book chapter entry entry-dictionary entry-encyclopedia dataset figure graphic manuscript map musical_score patent report review review-book thesis\">\n        <date date-parts=\"year\" form=\"numeric\" variable=\"issued\"/>\n      </if>\n      <else-if type=\"paper-conference\">\n        <!-- Determine whether published and serial or monographic -->\n        <choose>\n          <if match=\"any\" variable=\"collection-editor compiler editor editorial-director issue page supplement-number volume\">\n            <date date-parts=\"year\" form=\"numeric\" variable=\"issued\"/>\n          </if>\n          <else>\n            <text macro=\"date-issued-leading-zeros\"/>\n          </else>\n        </choose>\n      </else-if>\n      <else>\n        <text macro=\"date-issued-leading-zeros\"/>\n      </else>\n    </choose>\n  </macro>\n  <macro name=\"date-sort-group\">\n    <!-- Sorts items with and without dates:\n\n          1. `no date` items (= 0)\n          2. items with dates (= 1)\n          3. items with `status` (forthcoming, in press, etc.) (= 2) -->\n    <choose>\n      <if variable=\"issued\">\n        <text value=\"1\"/>\n      </if>\n      <else-if variable=\"status\">\n        <text value=\"2\"/>\n      </else-if>\n      <else>\n        <text value=\"0\"/>\n      </else>\n    </choose>\n  </macro>\n  <!-- Date elements -->\n  <macro name=\"date-event-full\">\n    <group delimiter=\" \">\n      <choose>\n        <if is-uncertain-date=\"event-date\">\n          <text form=\"short\" term=\"circa\"/>\n        </if>\n      </choose>\n      <date form=\"text\" variable=\"event-date\"/>\n    </group>\n  </macro>\n  <macro name=\"date-issued-full\">\n    <group delimiter=\" \">\n      <choose>\n        <if is-uncertain-date=\"issued\">\n          <text form=\"short\" term=\"circa\"/>\n        </if>\n      </choose>\n      <date form=\"text\" variable=\"issued\"/>\n    </group>\n  </macro>\n  <macro name=\"date-issued-leading-zeros\">\n    <date delimiter=\"-\" variable=\"issued\">\n      <date-part name=\"year\"/>\n      <date-part form=\"numeric-leading-zeros\" name=\"month\"/>\n      <date-part form=\"numeric-leading-zeros\" name=\"day\"/>\n    </date>\n  </macro>\n  <macro name=\"date-issued-month-day\">\n    <date variable=\"issued\">\n      <date-part name=\"month\"/>\n      <date-part name=\"day\" prefix=\" \"/>\n    </date>\n  </macro>\n  <macro name=\"date-issued-year\">\n    <group delimiter=\" \">\n      <choose>\n        <if is-uncertain-date=\"issued\">\n          <text form=\"short\" term=\"circa\"/>\n        </if>\n      </choose>\n      <date date-parts=\"year\" form=\"numeric\" variable=\"issued\"/>\n    </group>\n  </macro>\n  <macro name=\"date-original-year\">\n    <group delimiter=\" \">\n      <choose>\n        <if is-uncertain-date=\"original-date\">\n          <text form=\"short\" term=\"circa\"/>\n        </if>\n      </choose>\n      <date date-parts=\"year\" form=\"numeric\" variable=\"original-date\"/>\n    </group>\n  </macro>\n  <!-- 3. Title and descriptions (APA 9.18-22) -->\n  <macro name=\"title-and-descriptions\">\n    <group delimiter=\" \">\n      <choose>\n        <if variable=\"title\">\n          <text macro=\"title\"/>\n          <text macro=\"identifier\"/>\n          <text macro=\"description\"/>\n        </if>\n        <else-if match=\"any\" type=\"bill report\">\n          <!-- Bills, resolutions, and congressional reports substitute bill number if no title. -->\n          <!-- Congressional reports are indistinguishable from other reports -->\n          <text macro=\"identifier-number\"/>\n          <text macro=\"description\"/>\n          <text macro=\"identifier\"/>\n        </else-if>\n        <else>\n          <text macro=\"description\"/>\n          <text macro=\"identifier\"/>\n        </else>\n      </choose>\n    </group>\n  </macro>\n  <macro name=\"title-and-descriptions-short\">\n    <choose>\n      <if variable=\"title\">\n        <text macro=\"title-short\"/>\n      </if>\n      <else-if match=\"any\" type=\"bill report\">\n        <!-- Bills, resolutions, and congressional reports substitute bill number if no title. -->\n        <text macro=\"legal-identifier-bill-report\"/>\n      </else-if>\n      <else>\n        <text macro=\"description-short\"/>\n      </else>\n    </choose>\n  </macro>\n  <!-- 3.1. Title (APA 9.18) -->\n  <macro name=\"title\">\n    <choose>\n      <if match=\"any\" type=\"post webpage\">\n        <!-- part number/title always at the analytic level -->\n        <text font-style=\"italic\" macro=\"title-and-part-filter-review\"/>\n      </if>\n      <!-- Other types are italicized based on presence of `container-title`. Assume that `review` and `review-book` are published either in a serial or on a webpage (APA example 69) -->\n      <else-if match=\"any\" type=\"article-journal article-magazine article-newspaper periodical post-weblog review review-book\">\n        <text macro=\"title-serial\"/>\n      </else-if>\n      <else-if match=\"any\" variable=\"collection-editor compiler editor editorial-director\">\n        <text macro=\"title-monographic\"/>\n      </else-if>\n      <else-if match=\"any\" type=\"interview paper-conference\">\n        <text macro=\"title-serial\"/>\n      </else-if>\n      <else>\n        <text macro=\"title-monographic\"/>\n      </else>\n    </choose>\n  </macro>\n  <macro name=\"title-short\">\n    <choose>\n      <if match=\"any\" type=\"review review-book\" variable=\"reviewed-author reviewed-genre reviewed-title\">\n        <!-- `title` is only the review title if there is a separate `reviewed-genre` or `reviewed-title`; otherwise, it is the title of the reviewed work, printed in the description -->\n        <choose>\n          <if variable=\"reviewed-genre title\">\n            <!-- Quotes, title case -->\n            <text form=\"short\" quotes=\"true\" text-case=\"title\" variable=\"title\"/>\n          </if>\n          <else-if variable=\"reviewed-title title\">\n            <!-- Quotes, title case -->\n            <text form=\"short\" quotes=\"true\" text-case=\"title\" variable=\"title\"/>\n          </else-if>\n          <else>\n            <text macro=\"description-short\"/>\n          </else>\n        </choose>\n      </if>\n      <else-if match=\"any\" type=\"bill legislation regulation report treaty\">\n        <!-- No italics or quotes, title case -->\n        <text form=\"short\" text-case=\"title\" variable=\"title\"/>\n      </else-if>\n      <else-if match=\"any\" type=\"legal_case post\">\n        <!-- Italicized, sentence case -->\n        <text font-style=\"italic\" form=\"short\" variable=\"title\"/>\n      </else-if>\n      <else-if match=\"any\" type=\"hearing webpage\">\n        <!-- Italicized, title case (regardless of `container-title`) -->\n        <text font-style=\"italic\" form=\"short\" text-case=\"title\" variable=\"title\"/>\n      </else-if>\n      <!-- Other types are formatted based on presence of `container-title`, as in title macro -->\n      <else-if variable=\"container-title\">\n        <!-- Quotes, title case -->\n        <text form=\"short\" quotes=\"true\" text-case=\"title\" variable=\"title\"/>\n      </else-if>\n      <else>\n        <!-- Italicized, title case (default) -->\n        <text font-style=\"italic\" form=\"short\" text-case=\"title\" variable=\"title\"/>\n      </else>\n    </choose>\n  </macro>\n  <!-- Title elements -->\n  <macro name=\"title-and-part-filter-review\">\n    <choose>\n      <if match=\"any\" type=\"review review-book\" variable=\"reviewed-author reviewed-genre reviewed-title\">\n        <!-- If a review has no `reviewed-genre` or `reviewed-title`, assume that `title` contains the title of the reviewed work; the description provides it. -->\n        <choose>\n          <if variable=\"reviewed-genre title\">\n            <text macro=\"title-and-part-title\"/>\n          </if>\n          <else-if variable=\"reviewed-title title\">\n            <text macro=\"title-and-part-title\"/>\n          </else-if>\n        </choose>\n      </if>\n      <else>\n        <text macro=\"title-and-part-title\"/>\n      </else>\n    </choose>\n  </macro>\n  <macro name=\"title-and-part-title\">\n    <group delimiter=\": \">\n      <text variable=\"title\"/>\n      <text macro=\"title-part\"/>\n    </group>\n  </macro>\n  <macro name=\"title-and-volume-title\">\n    <group delimiter=\": \">\n      <text variable=\"title\"/>\n      <text macro=\"title-volume\"/>\n    </group>\n  </macro>\n  <macro name=\"title-monographic\">\n    <!-- For monographic items, assume `part-number` and `part-title` refer to the book/volume. -->\n    <choose>\n      <if variable=\"container-title\">\n        <text variable=\"title\"/>\n      </if>\n      <else>\n        <!-- For monographic items without `container-title` and with `volume-title`, append `volume-title` to `title` (APA example 30) -->\n        <text font-style=\"italic\" macro=\"title-and-volume-title\"/>\n      </else>\n    </choose>\n  </macro>\n  <macro name=\"title-part\">\n    <choose>\n      <if variable=\"part-title\">\n        <group delimiter=\". \">\n          <text macro=\"label-part-number\"/>\n          <text text-case=\"capitalize-first\" variable=\"part-title\"/>\n        </group>\n      </if>\n      <else-if is-numeric=\"part-number\"/>\n      <else>\n        <text macro=\"label-part-number\"/>\n      </else>\n    </choose>\n  </macro>\n  <macro name=\"title-serial\">\n    <!-- For serials, assume that `part-number` and `part-title` refer to the article and append to `title` -->\n    <choose>\n      <if variable=\"container-title\">\n        <text macro=\"title-and-part-filter-review\"/>\n      </if>\n      <else>\n        <!-- for serial items without `container-title`, don't append `volume-title` to `title` -->\n        <text font-style=\"italic\" macro=\"title-and-part-filter-review\"/>\n      </else>\n    </choose>\n  </macro>\n  <macro name=\"title-volume\">\n    <group delimiter=\", \">\n      <choose>\n        <!-- Assume that `part-number` and `part-title` of monographic items refer to the source book/volume -->\n        <if variable=\"volume-title\">\n          <group delimiter=\": \">\n            <group delimiter=\". \">\n              <text macro=\"label-volume\"/>\n              <text variable=\"volume-title\"/>\n            </group>\n            <text macro=\"title-part\"/>\n          </group>\n        </if>\n        <else-if variable=\"part-title\">\n          <text macro=\"label-volume\"/>\n          <text macro=\"title-part\"/>\n        </else-if>\n        <!-- if there is no `part-title` or `volume title`, `part-number` and `volume` appear in `identifier` if numeric -->\n        <else-if is-numeric=\"part-number volume\"/>\n        <else-if is-numeric=\"part-number\" variable=\"volume\">\n          <text macro=\"label-volume\"/>\n        </else-if>\n        <else-if is-numeric=\"volume\" variable=\"part-number\">\n          <text macro=\"label-part-number\"/>\n        </else-if>\n        <else-if is-numeric=\"part-number\"/>\n        <else-if is-numeric=\"volume\"/>\n        <else>\n          <text macro=\"label-volume\"/>\n          <text macro=\"label-part-number\"/>\n        </else>\n      </choose>\n    </group>\n  </macro>\n  <!-- 3.2. Identifier (in parentheses) (APA 9.19) -->\n  <macro name=\"identifier\">\n    <!-- (Secondary contributors; Database location; Genre no. 123; Report Series 123, Version, Edition, Volume, Page) -->\n    <group delimiter=\"; \" prefix=\"(\" suffix=\")\">\n      <choose>\n        <if type=\"patent\">\n          <text macro=\"identifier-patent\"/>\n        </if>\n        <else-if match=\"any\" type=\"post webpage\">\n          <!-- print `container-title` on `post` or `webpage` in the same way as `publisher` -->\n          <text macro=\"identifier-contributors\"/>\n          <text macro=\"identifier-number\"/>\n          <text macro=\"identifier-monographic\"/>\n        </else-if>\n        <else-if type=\"report\" variable=\"container-title\">\n          <!-- If the report is a chapter in a larger report, then most identifying information is printed in the source. -->\n          <text macro=\"identifier-contributors\"/>\n        </else-if>\n        <else-if type=\"report\" variable=\"title\">\n          <text macro=\"identifier-contributors\"/>\n          <text macro=\"identifier-number\"/>\n          <text macro=\"identifier-monographic\"/>\n        </else-if>\n        <else-if type=\"report\">\n          <!-- If there is no `title`, then `genre` and `number` are already printed as the title. -->\n          <text macro=\"identifier-contributors\"/>\n          <text macro=\"identifier-monographic\"/>\n        </else-if>\n        <else-if variable=\"container-title\">\n          <choose>\n            <if match=\"none\" variable=\"genre title\">\n              <text macro=\"label-chapter-number\"/>\n            </if>\n          </choose>\n          <text macro=\"identifier-contributors\"/>\n          <choose>\n            <if match=\"any\" type=\"broadcast graphic map motion_picture\">\n              <!-- For some audiovisual media, `number` information comes after title, not `container-title` (APA example 94); but an album track number is `chapter-number` -->\n              <text macro=\"identifier-number\"/>\n            </if>\n          </choose>\n          <text macro=\"identifier-serial\"/>\n        </else-if>\n        <else>\n          <text macro=\"identifier-contributors\"/>\n          <text macro=\"identifier-number\"/>\n          <text macro=\"identifier-monographic\"/>\n          <text macro=\"identifier-serial\"/>\n        </else>\n      </choose>\n    </group>\n  </macro>\n  <!-- Identifier elements -->\n  <macro name=\"identifier-contributors\">\n    <choose>\n      <if match=\"any\" type=\"article-journal article-magazine article-newspaper periodical post-weblog review review-book\">\n        <text macro=\"identifier-contributors-serial\"/>\n      </if>\n      <else-if match=\"any\" variable=\"collection-editor compiler editor editorial-director\">\n        <text macro=\"identifier-contributors-monographic\"/>\n      </else-if>\n      <else-if match=\"any\" type=\"interview paper-conference\">\n        <text macro=\"identifier-contributors-serial\"/>\n      </else-if>\n      <else>\n        <text macro=\"identifier-contributors-monographic\"/>\n      </else>\n    </choose>\n  </macro>\n  <macro name=\"identifier-contributors-monographic\">\n    <group delimiter=\"; \">\n      <choose>\n        <if variable=\"title\">\n          <names variable=\"interviewer\">\n            <name and=\"symbol\"/>\n            <label form=\"short\" prefix=\", \" text-case=\"title\"/>\n          </names>\n        </if>\n      </choose>\n      <choose>\n        <if match=\"any\" type=\"post webpage\">\n          <!-- print `container-title` on `post` or `webpage` in the same way as `publisher` -->\n          <names variable=\"container-author\">\n            <label form=\"verb-short\" suffix=\" \" text-case=\"title\"/>\n            <name and=\"symbol\"/>\n          </names>\n          <names delimiter=\"; \" variable=\"editor translator\">\n            <name and=\"symbol\"/>\n            <label form=\"short\" prefix=\", \" text-case=\"title\"/>\n          </names>\n          <names delimiter=\"; \" variable=\"illustrator narrator\">\n            <name and=\"symbol\"/>\n            <label form=\"short\" prefix=\", \" text-case=\"title\"/>\n          </names>\n          <names delimiter=\"; \" variable=\"compiler chair organizer curator series-creator executive-producer\">\n            <name and=\"symbol\"/>\n            <label prefix=\", \" text-case=\"title\"/>\n          </names>\n        </if>\n        <else>\n          <names delimiter=\"; \" variable=\"illustrator narrator\">\n            <name and=\"symbol\"/>\n            <label form=\"short\" prefix=\", \" text-case=\"title\"/>\n          </names>\n          <choose>\n            <if variable=\"container-title editor-translator\"/>\n            <else-if variable=\"container-title\">\n              <!-- TODO: Check logic once processors start to automatically populate `editor-translator` -->\n              <names delimiter=\"; \" variable=\"translator\">\n                <name and=\"symbol\"/>\n                <label form=\"short\" prefix=\", \" text-case=\"title\"/>\n              </names>\n            </else-if>\n            <else>\n              <names variable=\"container-author\">\n                <label form=\"verb-short\" suffix=\" \" text-case=\"title\"/>\n                <name and=\"symbol\"/>\n              </names>\n              <names delimiter=\"; \" variable=\"editor translator\">\n                <name and=\"symbol\"/>\n                <label form=\"short\" prefix=\", \" text-case=\"title\"/>\n              </names>\n              <names delimiter=\"; \" variable=\"compiler chair organizer curator series-creator executive-producer\">\n                <name and=\"symbol\"/>\n                <label prefix=\", \" text-case=\"title\"/>\n              </names>\n            </else>\n          </choose>\n        </else>\n      </choose>\n    </group>\n  </macro>\n  <macro name=\"identifier-contributors-serial\">\n    <group delimiter=\"; \">\n      <choose>\n        <if variable=\"title\">\n          <names delimiter=\"; \" variable=\"interviewer\">\n            <name and=\"symbol\"/>\n            <label form=\"short\" prefix=\", \" text-case=\"title\"/>\n          </names>\n        </if>\n      </choose>\n      <names delimiter=\"; \" variable=\"translator narrator\">\n        <name and=\"symbol\"/>\n        <label form=\"short\" prefix=\", \" text-case=\"title\"/>\n      </names>\n    </group>\n  </macro>\n  <macro name=\"identifier-locators\">\n    <choose>\n      <if variable=\"page\">\n        <text macro=\"label-page\"/>\n      </if>\n      <else-if variable=\"chapter-number genre\">\n        <text macro=\"label-chapter-number\"/>\n      </else-if>\n      <else-if variable=\"chapter-number title\">\n        <text macro=\"label-chapter-number\"/>\n      </else-if>\n      <!-- `chapter-number` appears earlier in `identifier` if there is no `title` or `genre` -->\n    </choose>\n  </macro>\n  <macro name=\"identifier-monographic\">\n    <choose>\n      <!-- omit serial types -->\n      <if match=\"any\" type=\"article-journal article-magazine article-newspaper broadcast event patent performance periodical post post-weblog review review-book speech webpage\"/>\n      <else-if match=\"any\" variable=\"collection-editor compiler editor editorial-director\">\n        <!-- monographic types -->\n        <text macro=\"identifier-monographic-item\"/>\n      </else-if>\n      <!-- omit serial types -->\n      <else-if match=\"any\" type=\"interview paper-conference\"/>\n      <else>\n        <!-- monographic types -->\n        <text macro=\"identifier-monographic-item\"/>\n      </else>\n    </choose>\n  </macro>\n  <macro name=\"identifier-monographic-item\">\n    <group delimiter=\", \">\n      <text macro=\"label-version\"/>\n      <text macro=\"label-edition\"/>\n      <text macro=\"identifier-series\"/>\n      <text macro=\"label-supplement-number\"/>\n      <text macro=\"identifier-number-volume\"/>\n      <text macro=\"identifier-number-part\"/>\n      <text macro=\"label-issue\"/>\n      <text macro=\"identifier-locators\"/>\n    </group>\n  </macro>\n  <macro name=\"identifier-number\">\n    <group delimiter=\" \">\n      <choose>\n        <if type=\"thesis\" variable=\"genre\">\n          <!-- `genre` provided with thesis description (APA example 65) -->\n          <text text-case=\"capitalize-first\" value=\"publication\"/>\n        </if>\n        <else-if variable=\"number\">\n          <text text-case=\"title\" variable=\"genre\"/>\n        </else-if>\n      </choose>\n      <text macro=\"label-number\"/>\n    </group>\n  </macro>\n  <macro name=\"identifier-number-part\">\n    <choose>\n      <!-- Part number printed with part title -->\n      <if variable=\"part-title\"/>\n      <!-- Non-numeric part numbers printed as part of the title -->\n      <else-if is-numeric=\"part-number\">\n        <text macro=\"label-part-number\"/>\n      </else-if>\n    </choose>\n  </macro>\n  <macro name=\"identifier-number-volume\">\n    <choose>\n      <!-- Volume number printed with volume/part title -->\n      <if variable=\"volume volume-title\"/>\n      <else-if variable=\"part-title volume\"/>\n      <!-- Non-numeric volumes printed as part of the book title -->\n      <else-if is-numeric=\"volume\">\n        <text macro=\"label-volume\"/>\n      </else-if>\n      <else>\n        <text macro=\"label-number-of-volumes\"/>\n      </else>\n    </choose>\n  </macro>\n  <macro name=\"identifier-patent\">\n    <!-- `authority`: U.S. ; `genre`: patent ; `number`: 123,445 -->\n    <group delimiter=\" \">\n      <text form=\"short\" variable=\"authority\"/>\n      <choose>\n        <if variable=\"genre\">\n          <text text-case=\"capitalize-first\" variable=\"genre\"/>\n        </if>\n        <else>\n          <text term=\"patent\" text-case=\"capitalize-first\"/>\n        </else>\n      </choose>\n      <text macro=\"label-number\"/>\n    </group>\n  </macro>\n  <macro name=\"identifier-serial\">\n    <choose>\n      <if match=\"any\" type=\"article-journal article-magazine article-newspaper periodical post-weblog review review-book\">\n        <!-- serial types -->\n        <text macro=\"identifier-number-part\"/>\n      </if>\n      <!-- omit monographic types -->\n      <else-if match=\"any\" variable=\"collection-editor compiler editor editorial-director\"/>\n      <else-if match=\"any\" type=\"interview paper-conference\">\n        <!-- serial types -->\n        <text macro=\"identifier-number-part\"/>\n      </else-if>\n    </choose>\n  </macro>\n  <macro name=\"identifier-series\">\n    <!-- Series given only for report-like types (APA example 52) -->\n    <choose>\n      <if match=\"any\" type=\"document report standard\">\n        <group delimiter=\" \">\n          <text text-case=\"title\" variable=\"collection-title\"/>\n          <text variable=\"collection-number\"/>\n        </group>\n      </if>\n    </choose>\n  </macro>\n  <!-- 3.3. Description [in square brackets] (APA 9.21) -->\n  <macro name=\"description\">\n    <group prefix=\"[\" suffix=\"]\">\n      <choose>\n        <if match=\"any\" type=\"interview\" variable=\"interviewer\">\n          <text macro=\"description-interview\"/>\n        </if>\n        <else-if match=\"any\" type=\"review review-book\" variable=\"reviewed-author reviewed-genre reviewed-title\">\n          <text macro=\"description-review\"/>\n        </else-if>\n        <else-if type=\"personal_communication\">\n          <text macro=\"description-letter\"/>\n        </else-if>\n        <else-if type=\"song\" variable=\"composer\">\n          <text macro=\"description-song\"/>\n        </else-if>\n        <else-if type=\"thesis\">\n          <text macro=\"description-thesis\"/>\n        </else-if>\n        <else-if match=\"any\" type=\"article-journal article-magazine article-newspaper periodical post-weblog review review-book\">\n          <text macro=\"description-serial\"/>\n        </else-if>\n        <else-if match=\"none\" variable=\"container-title\">\n          <!-- Other description -->\n          <text macro=\"description-format\"/>\n        </else-if>\n        <!-- For unpublished conference presentations/performances/events, chapters in reports/standards/generic documents, software, place description within the source element -->\n        <else-if match=\"any\" type=\"document report software standard\"/>\n        <else-if match=\"any\" type=\"event paper-conference performance speech\">\n          <choose>\n            <if match=\"any\" variable=\"collection-editor compiler editor editorial-director issue page supplement-number volume\">\n              <text macro=\"description-format\"/>\n            </if>\n          </choose>\n        </else-if>\n        <else>\n          <text macro=\"description-format\"/>\n        </else>\n      </choose>\n    </group>\n  </macro>\n  <macro name=\"description-short\">\n    <group prefix=\"[\" suffix=\"]\">\n      <choose>\n        <if match=\"any\" type=\"interview\" variable=\"interviewer\">\n          <text macro=\"description-interview-short\"/>\n        </if>\n        <else-if match=\"any\" type=\"review review-book\" variable=\"reviewed-author reviewed-genre reviewed-title\">\n          <text macro=\"description-review-short\"/>\n        </else-if>\n        <else-if type=\"personal_communication\">\n          <text macro=\"description-letter-short\"/>\n        </else-if>\n        <else-if match=\"any\" type=\"article-journal article-magazine article-newspaper periodical post-weblog review review-book\">\n          <!-- serial types -->\n          <text macro=\"description-serial-short\"/>\n        </else-if>\n        <else-if match=\"any\" variable=\"collection-editor compiler editor editorial-director\">\n          <!-- monographic types -->\n          <text macro=\"description-format-short\"/>\n        </else-if>\n        <else-if match=\"any\" type=\"interview paper-conference\">\n          <!-- serial types -->\n          <text macro=\"description-serial-short\"/>\n        </else-if>\n        <else>\n          <!-- monographic types -->\n          <text macro=\"description-format-short\"/>\n        </else>\n      </choose>\n    </group>\n  </macro>\n  <!-- Description elements -->\n  <macro name=\"description-format\">\n    <choose>\n      <if match=\"any\" variable=\"genre medium\">\n        <group delimiter=\"; \">\n          <choose>\n            <if match=\"none\" variable=\"number\">\n              <text text-case=\"capitalize-first\" variable=\"genre\"/>\n            </if>\n          </choose>\n          <text text-case=\"capitalize-first\" variable=\"medium\"/>\n        </group>\n      </if>\n      <else>\n        <text macro=\"description-format-term-generic\"/>\n      </else>\n    </choose>\n  </macro>\n  <macro name=\"description-format-short\">\n    <choose>\n      <if variable=\"genre\">\n        <text form=\"short\" text-case=\"capitalize-first\" variable=\"genre\"/>\n      </if>\n      <else-if variable=\"medium\">\n        <text form=\"short\" text-case=\"capitalize-first\" variable=\"medium\"/>\n      </else-if>\n      <else>\n        <text macro=\"description-format-term-generic\"/>\n      </else>\n    </choose>\n  </macro>\n  <macro name=\"description-format-term-generic\">\n    <!-- Generic labels for specific types -->\n    <choose>\n      <if type=\"broadcast\">\n        <text term=\"broadcast\" text-case=\"capitalize-first\"/>\n      </if>\n      <else-if type=\"collection\">\n        <text term=\"collection\" text-case=\"capitalize-first\"/>\n      </else-if>\n      <else-if type=\"dataset\">\n        <text term=\"dataset\" text-case=\"capitalize-first\"/>\n      </else-if>\n      <else-if type=\"figure\">\n        <text term=\"figure\" text-case=\"capitalize-first\"/>\n      </else-if>\n      <else-if type=\"graphic\">\n        <text term=\"graphic\" text-case=\"capitalize-first\"/>\n      </else-if>\n      <else-if match=\"any\" type=\"interview personal_communication\">\n        <choose>\n          <if match=\"none\" variable=\"archive archive-place container-title DOI number publisher references URL\">\n            <text term=\"personal-communication\" text-case=\"capitalize-first\"/>\n          </if>\n          <else-if type=\"interview\">\n            <text term=\"interview\" text-case=\"capitalize-first\"/>\n          </else-if>\n          <else-if type=\"personal_communication\">\n            <text term=\"letter\" text-case=\"capitalize-first\"/>\n          </else-if>\n        </choose>\n      </else-if>\n      <else-if type=\"manuscript\">\n        <choose>\n          <if match=\"none\" variable=\"archive archive-place container-title DOI number publisher references URL\">\n            <text term=\"manuscript\" text-case=\"capitalize-first\"/>\n          </if>\n        </choose>\n      </else-if>\n      <else-if type=\"map\">\n        <text term=\"map\" text-case=\"capitalize-first\"/>\n      </else-if>\n      <else-if type=\"motion_picture\">\n        <text term=\"motion_picture\" text-case=\"capitalize-first\"/>\n      </else-if>\n      <else-if type=\"periodical\" variable=\"container-title supplement-number\">\n        <text term=\"supplement\" text-case=\"capitalize-first\"/>\n      </else-if>\n      <else-if type=\"periodical\" variable=\"container-title title\">\n        <text term=\"special-issue\" text-case=\"capitalize-first\"/>\n      </else-if>\n      <else-if type=\"song\">\n        <text term=\"song\" text-case=\"capitalize-first\"/>\n      </else-if>\n      <else-if type=\"software\">\n        <text term=\"software\" text-case=\"capitalize-first\"/>\n      </else-if>\n      <else-if type=\"post\">\n        <text term=\"post\" text-case=\"capitalize-first\"/>\n      </else-if>\n      <else-if type=\"review\">\n        <text term=\"review\" text-case=\"capitalize-first\"/>\n      </else-if>\n      <else-if type=\"review-book\">\n        <text term=\"review-book\" text-case=\"capitalize-first\"/>\n      </else-if>\n    </choose>\n  </macro>\n  <macro name=\"description-interview\">\n    <group delimiter=\"; \">\n      <choose>\n        <if variable=\"interviewer title\">\n          <!-- Avoid repeating 'interview' -->\n          <choose>\n            <if match=\"none\" variable=\"number\">\n              <text text-case=\"capitalize-first\" variable=\"genre\"/>\n            </if>\n          </choose>\n          <text text-case=\"capitalize-first\" variable=\"medium\"/>\n        </if>\n        <else-if variable=\"title\">\n          <text macro=\"description-format\"/>\n        </else-if>\n        <else-if variable=\"genre\">\n          <group delimiter=\" \">\n            <text text-case=\"capitalize-first\" variable=\"genre\"/>\n            <choose>\n              <if variable=\"interviewer\">\n                <text form=\"verb\" term=\"container-author\"/>\n                <names variable=\"interviewer\">\n                  <name and=\"symbol\"/>\n                </names>\n              </if>\n            </choose>\n          </group>\n        </else-if>\n        <else-if variable=\"interviewer\">\n          <names variable=\"interviewer\">\n            <label form=\"verb\" suffix=\" \" text-case=\"capitalize-first\"/>\n            <name and=\"symbol\"/>\n          </names>\n          <text text-case=\"capitalize-first\" variable=\"medium\"/>\n        </else-if>\n        <else>\n          <text macro=\"description-format\"/>\n        </else>\n      </choose>\n    </group>\n  </macro>\n  <macro name=\"description-interview-short\">\n    <names variable=\"interviewer\">\n      <label form=\"verb\" suffix=\" \" text-case=\"capitalize-first\"/>\n      <name and=\"symbol\" form=\"short\"/>\n      <substitute>\n        <text macro=\"description-format-short\"/>\n      </substitute>\n    </names>\n  </macro>\n  <macro name=\"description-letter\">\n    <choose>\n      <if variable=\"recipient\">\n        <group delimiter=\"; \">\n          <group delimiter=\" \">\n            <text macro=\"description-format\"/>\n            <names variable=\"recipient\">\n              <label form=\"verb\" suffix=\" \"/>\n              <name and=\"symbol\" initialize=\"false\"/>\n            </names>\n          </group>\n          <text macro=\"description-medium\"/>\n        </group>\n      </if>\n      <else>\n        <text macro=\"description-format\"/>\n      </else>\n    </choose>\n  </macro>\n  <macro name=\"description-letter-short\">\n    <choose>\n      <if variable=\"recipient\">\n        <group delimiter=\" \">\n          <text macro=\"description-format-short\"/>\n          <names variable=\"recipient\">\n            <label form=\"verb\" suffix=\" \"/>\n            <name and=\"symbol\" form=\"short\"/>\n          </names>\n        </group>\n      </if>\n      <else>\n        <text macro=\"description-format-short\"/>\n      </else>\n    </choose>\n  </macro>\n  <macro name=\"description-medium\">\n    <choose>\n      <if variable=\"number\"/>\n      <else-if variable=\"genre\">\n        <text text-case=\"capitalize-first\" variable=\"medium\"/>\n      </else-if>\n    </choose>\n  </macro>\n  <macro name=\"description-review\">\n    <group delimiter=\"; \">\n      <group delimiter=\", \">\n        <group delimiter=\" \">\n          <choose>\n            <if variable=\"reviewed-genre\">\n              <text term=\"review-of\" text-case=\"capitalize-first\"/>\n              <text variable=\"reviewed-genre\"/>\n            </if>\n            <else-if variable=\"number\">\n              <!-- Genre printed with `number` -->\n              <text form=\"short\" term=\"review-of\" text-case=\"capitalize-first\"/>\n            </else-if>\n            <!-- If no `reviewed-genre`, assume that `genre` or `medium` is entered as 'Review of the book' or similar -->\n            <else-if variable=\"genre\">\n              <text text-case=\"capitalize-first\" variable=\"genre\"/>\n            </else-if>\n            <else-if variable=\"medium\">\n              <text text-case=\"capitalize-first\" variable=\"medium\"/>\n            </else-if>\n            <else-if type=\"review-book\">\n              <text term=\"review-of\" text-case=\"capitalize-first\"/>\n              <text term=\"book\" text-case=\"lowercase\"/>\n            </else-if>\n            <else>\n              <text form=\"short\" term=\"review-of\" text-case=\"capitalize-first\"/>\n            </else>\n          </choose>\n          <text macro=\"description-review-title\"/>\n        </group>\n        <names variable=\"reviewed-author\">\n          <label form=\"verb-short\" suffix=\" \"/>\n          <name and=\"symbol\"/>\n        </names>\n      </group>\n      <text macro=\"description-medium\"/>\n    </group>\n  </macro>\n  <macro name=\"description-review-short\">\n    <group delimiter=\" \">\n      <text form=\"short\" term=\"review-of\" text-case=\"capitalize-first\"/>\n      <text macro=\"description-review-title-short\"/>\n    </group>\n  </macro>\n  <macro name=\"description-review-title\">\n    <choose>\n      <if match=\"any\" variable=\"reviewed-genre reviewed-title\">\n        <!-- Not possible to distinguish TV series episode from other reviewed works without a reviewed source title (APA example 69) -->\n        <!-- TODO: Adapt for `reviewed-container-title` or similar if it becomes available -->\n        <text font-style=\"italic\" variable=\"reviewed-title\"/>\n      </if>\n      <else>\n        <!-- Assume `title` is the title of the reviewed work -->\n        <text font-style=\"italic\" variable=\"title\"/>\n      </else>\n    </choose>\n  </macro>\n  <macro name=\"description-review-title-short\">\n    <choose>\n      <if match=\"any\" variable=\"reviewed-genre reviewed-title\">\n        <!-- Not possible to distinguish TV series episode from other reviewed works without a reviewed source title (APA example 69) -->\n        <!-- TODO: Adapt for `reviewed-container-title` or similar if it becomes available -->\n        <text font-style=\"italic\" form=\"short\" text-case=\"title\" variable=\"reviewed-title\"/>\n      </if>\n      <else>\n        <!-- Assume `title` is the title of the reviewed work -->\n        <text font-style=\"italic\" form=\"short\" text-case=\"title\" variable=\"title\"/>\n      </else>\n    </choose>\n  </macro>\n  <macro name=\"description-serial\">\n    <group delimiter=\"; \">\n      <text macro=\"description-format\"/>\n      <choose>\n        <if match=\"none\" variable=\"title\">\n          <text variable=\"section\"/>\n        </if>\n      </choose>\n    </group>\n  </macro>\n  <macro name=\"description-serial-short\">\n    <choose>\n      <if variable=\"title\"/>\n      <else-if variable=\"section\">\n        <text form=\"short\" text-case=\"capitalize-first\" variable=\"section\"/>\n      </else-if>\n      <else>\n        <text macro=\"description-format-short\"/>\n      </else>\n    </choose>\n  </macro>\n  <macro name=\"description-song\">\n    <!-- Performer of classical music works -->\n    <group delimiter=\"; \">\n      <group delimiter=\" \">\n        <!-- Based on `description-format` macro -->\n        <choose>\n          <if match=\"any\" variable=\"genre medium\">\n            <choose>\n              <if match=\"none\" variable=\"number\">\n                <text text-case=\"capitalize-first\" variable=\"genre\"/>\n              </if>\n            </choose>\n            <text text-case=\"capitalize-first\" variable=\"medium\"/>\n            <text form=\"verb\" term=\"performer\"/>\n          </if>\n          <else>\n            <text form=\"verb\" term=\"performer\" text-case=\"capitalize-first\"/>\n          </else>\n        </choose>\n        <names variable=\"author\">\n          <name and=\"symbol\"/>\n          <substitute>\n            <names variable=\"performer\"/>\n          </substitute>\n        </names>\n      </group>\n      <text macro=\"description-medium\"/>\n    </group>\n  </macro>\n  <macro name=\"description-thesis\">\n    <group delimiter=\"; \">\n      <group delimiter=\", \">\n        <text text-case=\"capitalize-first\" variable=\"genre\"/>\n        <choose>\n          <if match=\"any\" variable=\"archive DOI URL\">\n            <!-- Include the university in description if thesis is published -->\n            <text variable=\"publisher\"/>\n          </if>\n        </choose>\n      </group>\n      <text text-case=\"capitalize-first\" variable=\"medium\"/>\n    </group>\n  </macro>\n  <!-- 4. Source (APA 9.23-37) -->\n  <macro name=\"source\">\n    <group delimiter=\". \">\n      <choose>\n        <if match=\"any\" type=\"post webpage\"/>\n        <else-if match=\"any\" type=\"article-journal article-magazine article-newspaper periodical post-weblog review review-book\">\n          <text macro=\"source-serial\"/>\n        </else-if>\n        <else-if match=\"any\" variable=\"collection-editor compiler editor editorial-director\">\n          <text macro=\"source-monographic\"/>\n        </else-if>\n        <else-if match=\"any\" type=\"interview paper-conference\">\n          <text macro=\"source-serial\"/>\n        </else-if>\n        <else>\n          <text macro=\"source-monographic\"/>\n        </else>\n      </choose>\n      <text macro=\"source-publisher\"/>\n      <text macro=\"source-archive\"/>\n      <text macro=\"source-location\"/>\n      <text macro=\"source-website\"/>\n    </group>\n  </macro>\n  <!-- 4.1. Serial sources (APA 9.25-27) -->\n  <macro name=\"source-serial\">\n    <group delimiter=\". \">\n      <group delimiter=\", \">\n        <group delimiter=\", \" font-style=\"italic\">\n          <text text-case=\"title\" variable=\"container-title\"/>\n          <!-- `collection-title` is for any serial with multiple series (e.g. 'second series') -->\n          <text text-case=\"title\" variable=\"collection-title\"/>\n        </group>\n        <group>\n          <text font-style=\"italic\" variable=\"volume\"/>\n          <group delimiter=\", \" prefix=\"(\" suffix=\")\">\n            <text variable=\"issue\"/>\n            <text macro=\"label-supplement-number\"/>\n          </group>\n        </group>\n        <choose>\n          <if variable=\"number\">\n            <text macro=\"label-number-article\"/>\n          </if>\n          <else>\n            <text variable=\"page\"/>\n          </else>\n        </choose>\n      </group>\n      <choose>\n        <if match=\"any\" variable=\"collection-title issue number page supplement-number volume\"/>\n        <else-if variable=\"issued status\">\n          <!-- Print the status variable rather than use generic CSL terms (`in press`, etc.) -->\n          <text text-case=\"capitalize-first\" variable=\"status\"/>\n        </else-if>\n      </choose>\n    </group>\n  </macro>\n  <!-- 4.2. Monographic sources (APA 9.28) -->\n  <macro name=\"source-monographic\">\n    <!-- Monographic sources repeat main reference elements -->\n    <choose>\n      <if variable=\"container-title\">\n        <group delimiter=\" \">\n          <choose>\n            <if type=\"song\">\n              <text term=\"on\" text-case=\"capitalize-first\"/>\n            </if>\n            <else>\n              <text term=\"in\" text-case=\"capitalize-first\"/>\n            </else>\n          </choose>\n          <group delimiter=\", \">\n            <text macro=\"source-monographic-author\"/>\n            <text macro=\"source-monographic-title\"/>\n          </group>\n          <text macro=\"source-monographic-identifier\"/>\n          <text macro=\"source-monographic-description\"/>\n        </group>\n      </if>\n    </choose>\n  </macro>\n  <!-- Monographic source author -->\n  <macro name=\"source-monographic-author\">\n    <names variable=\"container-author\">\n      <name and=\"symbol\"/>\n      <label prefix=\" (\" suffix=\")\" text-case=\"title\"/>\n      <substitute>\n        <names variable=\"executive-producer\"/>\n        <names variable=\"series-creator\"/>\n        <names variable=\"editor-translator\">\n          <name and=\"symbol\"/>\n          <label form=\"short\" prefix=\" (\" suffix=\")\" text-case=\"title\"/>\n        </names>\n        <!-- TODO: Translator omitted on the assumption that editor-translators are uncommon for chapter citations. If needed, direct entry or automatic population of `editor-translator` can produce combined labels. -->\n        <names delimiter=\"; \" variable=\"editor\">\n          <name and=\"symbol\"/>\n          <label form=\"short\" prefix=\" (\" suffix=\")\" text-case=\"title\"/>\n        </names>\n        <names variable=\"editorial-director\">\n          <name and=\"symbol\"/>\n          <label form=\"short\" prefix=\" (\" suffix=\")\" text-case=\"title\"/>\n        </names>\n        <names variable=\"compiler\"/>\n        <choose>\n          <if match=\"any\" type=\"event performance speech\">\n            <names variable=\"chair\"/>\n            <names variable=\"organizer\"/>\n          </if>\n        </choose>\n        <names variable=\"curator\"/>\n        <names variable=\"collection-editor\">\n          <name and=\"symbol\"/>\n          <label form=\"short\" prefix=\" (\" suffix=\")\" text-case=\"title\"/>\n        </names>\n      </substitute>\n    </names>\n  </macro>\n  <!-- Monographic source title -->\n  <macro name=\"source-monographic-title\">\n    <group delimiter=\": \" font-style=\"italic\">\n      <text variable=\"container-title\"/>\n      <text macro=\"title-volume\"/>\n    </group>\n  </macro>\n  <!-- Monographic source identifier -->\n  <macro name=\"source-monographic-identifier\">\n    <choose>\n      <if variable=\"container-title\">\n        <group delimiter=\"; \" prefix=\"(\" suffix=\")\">\n          <choose>\n            <if match=\"none\" type=\"broadcast graphic map motion_picture\">\n              <!-- For some audiovisual media, number information comes after `title`, not `container-title` (APA example 94); but an album track number is `chapter-number` -->\n              <text macro=\"identifier-number\"/>\n            </if>\n          </choose>\n          <text macro=\"identifier-monographic\"/>\n        </group>\n      </if>\n    </choose>\n  </macro>\n  <!-- Monographic source description -->\n  <macro name=\"source-monographic-description\">\n    <group prefix=\"[\" suffix=\"]\">\n      <choose>\n        <if match=\"any\" type=\"document report software standard\">\n          <!-- place description after `container-title` -->\n          <text macro=\"description-format\"/>\n        </if>\n        <else-if match=\"any\" variable=\"collection-editor compiler editor editorial-director issue page supplement-number volume\"/>\n        <else-if match=\"any\" type=\"event paper-conference performance speech\">\n          <!-- unpublished conference presentations should describe the session -->\n          <text macro=\"description-format\"/>\n        </else-if>\n      </choose>\n    </group>\n  </macro>\n  <!-- 4.3. Publisher sources (APA 9.29) -->\n  <macro name=\"source-publisher\">\n    <choose>\n      <if type=\"thesis\">\n        <choose>\n          <if match=\"none\" variable=\"archive DOI URL\">\n            <!-- Provide university in `publisher` if unpublished -->\n            <text variable=\"publisher\"/>\n          </if>\n        </choose>\n      </if>\n      <!-- omit serial types -->\n      <else-if match=\"any\" type=\"article-journal article-magazine article-newspaper periodical post-weblog review review-book\"/>\n      <else-if match=\"any\" variable=\"collection-editor compiler editor editorial-director\">\n        <!-- monographic types -->\n        <text variable=\"publisher\"/>\n      </else-if>\n      <else-if type=\"interview\">\n        <!-- give publisher for a broadcast `interview` handled as a serial type -->\n        <text variable=\"publisher\"/>\n      </else-if>\n      <!-- omit serial `paper-conference` -->\n      <else-if type=\"paper-conference\"/>\n      <else>\n        <text variable=\"publisher\"/>\n      </else>\n    </choose>\n  </macro>\n  <!-- 4.4. Database and archive sources (APA 9.30) -->\n  <macro name=\"source-archive\">\n    <group delimiter=\", \">\n      <choose>\n        <if variable=\"archive_collection\">\n          <!-- With collection: `archive_collection` (`archive_location`), `archive`, `archive-place` -->\n          <group delimiter=\" \">\n            <text variable=\"archive_collection\"/>\n            <text prefix=\"(\" suffix=\")\" variable=\"archive_location\"/>\n          </group>\n          <text variable=\"archive\"/>\n          <text variable=\"archive-place\"/>\n        </if>\n        <else>\n          <!-- No collection: `archive` (`archive_location`), `archive-place` -->\n          <group delimiter=\" \">\n            <text variable=\"archive\"/>\n            <text prefix=\"(\" suffix=\")\" variable=\"archive_location\"/>\n          </group>\n          <text variable=\"archive-place\"/>\n        </else>\n      </choose>\n      <!-- a database identifier/number is stored in `number` and appears in `identifier-number` -->\n    </group>\n  </macro>\n  <!-- 4.5. Works with specific locations (APA 9.31) -->\n  <macro name=\"source-location\">\n    <choose>\n      <if match=\"any\" variable=\"event event-title\">\n        <!-- TODO: To prevent Zotero from printing `event-place`, due to its double-mapping of `publisher-place` and `event-place`. Remove this when that is changed. -->\n        <choose>\n          <if type=\"paper-conference\">\n            <choose>\n              <if match=\"none\" variable=\"collection-editor compiler editor editorial-director issue page supplement-number volume\">\n                <!-- Don't print event info for conference papers published in a proceedings -->\n                <text macro=\"source-location-title-place-date\"/>\n              </if>\n            </choose>\n          </if>\n          <else>\n            <!-- For other item types, print event info even if published (e.g. collection catalogs, performance programs). These items aren't given explicit examples in the APA manual, so err on the side of providing too much information. -->\n            <text macro=\"source-location-title-place-date\"/>\n          </else>\n        </choose>\n      </if>\n    </choose>\n  </macro>\n  <macro name=\"source-location-title-place-date\">\n    <group delimiter=\", \">\n      <choose>\n        <!-- TODO: We expect `event-title` to be used, but processors and applications may not be updated yet. This macro ensures that either `event` or `event-title` can be accepted. Remove if processor logic and application adoption can handle this. -->\n        <if variable=\"event-title\">\n          <text text-case=\"capitalize-first\" variable=\"event-title\"/>\n        </if>\n        <else>\n          <text text-case=\"capitalize-first\" variable=\"event\"/>\n        </else>\n      </choose>\n      <text variable=\"event-place\"/>\n      <text macro=\"date-event-full\"/>\n    </group>\n  </macro>\n  <!-- 4.6. Social media and website sources (APA 9.32-33) -->\n  <macro name=\"source-website\">\n    <choose>\n      <if match=\"any\" type=\"post webpage\">\n        <text text-case=\"title\" variable=\"container-title\"/>\n      </if>\n    </choose>\n  </macro>\n  <!-- 4.7. DOI or URL (APA 9.34-36) -->\n  <macro name=\"source-DOI-URL\">\n    <choose>\n      <if variable=\"DOI\">\n        <text prefix=\"https://doi.org/\" variable=\"DOI\"/>\n      </if>\n      <else-if variable=\"URL\">\n        <group delimiter=\" \">\n          <choose>\n            <if match=\"none\" variable=\"issued status\">\n              <text term=\"retrieved\" text-case=\"capitalize-first\"/>\n              <group delimiter=\", \">\n                <date form=\"text\" variable=\"accessed\"/>\n                <text term=\"from\"/>\n              </group>\n            </if>\n          </choose>\n          <text variable=\"URL\"/>\n        </group>\n      </else-if>\n    </choose>\n  </macro>\n  <!-- 5. Publication history (APA 9.39-41) -->\n  <macro name=\"publication-history\">\n    <!-- Notes on source element: original publication, reprint info, retraction info -->\n    <group delimiter=\"; \" prefix=\"(\" suffix=\")\">\n      <choose>\n        <if type=\"patent\">\n          <text variable=\"references\"/>\n        </if>\n        <else>\n          <!-- Print `status` here for \"retracted\" etc. if it's not printed elsewhere. -->\n          <choose>\n            <if match=\"none\" variable=\"issued\"/>\n            <else-if match=\"any\" variable=\"collection-title issue number page supplement-number volume\">\n              <text text-case=\"capitalize-first\" variable=\"status\"/>\n            </else-if>\n          </choose>\n          <choose>\n            <if variable=\"references\">\n              <!-- Provide the option for more elaborate description of publication history, such as full \"reprinted\" references (APA examples 11, 43, 44) -->\n              <text variable=\"references\"/>\n            </if>\n            <else>\n              <!-- Format publication history using CSL variables -->\n              <group delimiter=\" \">\n                <text term=\"original-work-published\" text-case=\"capitalize-first\"/>\n                <group delimiter=\", \">\n                  <group delimiter=\" \">\n                    <text value=\"as\"/>\n                    <text font-style=\"italic\" variable=\"original-title\"/>\n                  </group>\n                  <text macro=\"date-original-year\"/>\n                  <text variable=\"original-publisher\"/>\n                </group>\n              </group>\n            </else>\n          </choose>\n        </else>\n      </choose>\n    </group>\n  </macro>\n  <!-- 6. Legal references: Bluebook style (shared with Chicago) -->\n  <!-- Where APA or Chicago diverge from Bluebook, the official manual is followed -->\n  <macro name=\"legal-reference\">\n    <!-- Type usage:\n\n         `bill`\n         : bills, resolutions, federal reports\n\n         `legal_case`\n         : all legal and court cases\n\n         `hearing`\n         : hearings and testimony\n\n         `legislation`\n         : statutes, constitutional items, and charters\n\n         `regulation`\n         : codified regulations, uncodified regulations, executive orders\n\n         `treaty`\n         : treaties\n    -->\n    <group delimiter=\", \">\n      <choose>\n        <if type=\"treaty\">\n          <text macro=\"legal-title\"/>\n          <names variable=\"author\">\n            <!-- Treaty parties should be included at least for bilateral treaties (Bluebook 21.4.2) -->\n            <name delimiter=\"-\" et-al-min=\"100\" et-al-use-first=\"99\" form=\"short\" initialize=\"false\"/>\n          </names>\n          <text macro=\"legal-date\"/>\n          <!-- treaty source/report in addition to URL (Bluebook 21.4.5) -->\n          <text macro=\"legal-source\"/>\n        </if>\n        <else>\n          <group delimiter=\" \">\n            <group delimiter=\", \">\n              <text macro=\"legal-title\"/>\n              <text macro=\"legal-source\"/>\n            </group>\n            <text macro=\"legal-date\"/>\n            <text macro=\"legal-identifier\"/>\n          </group>\n        </else>\n      </choose>\n      <group delimiter=\" \">\n        <!-- locator for use in notes -->\n        <choose>\n          <if locator=\"page\" variable=\"page\">\n            <text term=\"at\"/>\n          </if>\n        </choose>\n        <text macro=\"label-locator\"/>\n      </group>\n    </group>\n  </macro>\n  <!-- 6.1. Legal date -->\n  <macro name=\"legal-date\">\n    <choose>\n      <if type=\"treaty\">\n        <text macro=\"date-issued-full\"/>\n      </if>\n      <else-if type=\"legal_case\">\n        <text macro=\"legal-date-case\"/>\n      </else-if>\n      <else-if match=\"any\" type=\"bill hearing legislation regulation\">\n        <group delimiter=\" \" prefix=\"(\" suffix=\")\">\n          <group delimiter=\" \">\n            <text macro=\"date-original-year\"/>\n            <text form=\"symbol\" term=\"and\"/>\n          </group>\n          <choose>\n            <if variable=\"issued\">\n              <text macro=\"date-issued-year\"/>\n            </if>\n            <else>\n              <!-- Show proposal date for uncodified regulations. Assume date is entered literally ala \"proposed May 23, 2016\". -->\n              <!-- TODO: Add `proposed` date here if that becomes available -->\n              <date form=\"text\" variable=\"submitted\"/>\n            </else>\n          </choose>\n        </group>\n      </else-if>\n    </choose>\n  </macro>\n  <macro name=\"legal-date-case\">\n    <group delimiter=\" \" prefix=\"(\" suffix=\")\">\n      <text variable=\"authority\"/>\n      <choose>\n        <if variable=\"container-title\">\n          <!-- Print only year for cases published in reporters-->\n          <text macro=\"date-issued-year\"/>\n        </if>\n        <else>\n          <text macro=\"date-issued-full\"/>\n        </else>\n      </choose>\n    </group>\n  </macro>\n  <!-- 6.2.1. Legal title -->\n  <macro name=\"legal-title\">\n    <choose>\n      <if match=\"any\" type=\"bill legal_case legislation regulation treaty\">\n        <text text-case=\"title\" variable=\"title\"/>\n      </if>\n      <else-if type=\"hearing\">\n        <!-- use standard format (Bluebook 13.3) -->\n        <group delimiter=\": \" font-style=\"italic\">\n          <text text-case=\"capitalize-first\" variable=\"title\"/>\n          <group delimiter=\" \">\n            <text term=\"hearing\" text-case=\"capitalize-first\"/>\n            <group delimiter=\" \">\n              <text term=\"on\"/>\n              <text variable=\"number\"/>\n            </group>\n            <group delimiter=\" \">\n              <text value=\"before the\"/>\n              <text variable=\"section\"/>\n            </group>\n          </group>\n        </group>\n      </else-if>\n    </choose>\n  </macro>\n  <!-- 6.2.2. Legal identifier -->\n  <macro name=\"legal-identifier\">\n    <group delimiter=\" \" prefix=\"(\" suffix=\")\">\n      <choose>\n        <if type=\"hearing\">\n          <!-- Use the 'verb' form of the hearing term to hold 'testimony of' -->\n          <text form=\"verb\" term=\"hearing\"/>\n          <names variable=\"author\">\n            <name and=\"symbol\" initialize=\"false\"/>\n          </names>\n        </if>\n        <else-if match=\"any\" type=\"bill legislation regulation\">\n          <!-- For uncodified regulations, assume future code section is in `status`. -->\n          <text variable=\"status\"/>\n        </else-if>\n      </choose>\n    </group>\n  </macro>\n  <macro name=\"legal-identifier-bill-report\">\n    <group delimiter=\" \">\n      <text variable=\"genre\"/>\n      <choose>\n        <if match=\"any\" variable=\"authority chapter-number container-title\">\n          <text variable=\"number\"/>\n        </if>\n        <else>\n          <!-- If there is no legislative body, session number, or code/record title, assume the item is a congressional report and include 'No.' label. -->\n          <text macro=\"label-number-capitalized\"/>\n        </else>\n      </choose>\n    </group>\n  </macro>\n  <!-- 6.3. Legal source -->\n  <macro name=\"legal-source\">\n    <!-- Expect legal item `container-title` to be stored in short form -->\n    <choose>\n      <if type=\"bill\">\n        <text macro=\"legal-source-bill\"/>\n      </if>\n      <else-if type=\"hearing\">\n        <text macro=\"legal-source-hearing\"/>\n      </else-if>\n      <else-if type=\"legal_case\">\n        <text macro=\"legal-source-case\"/>\n      </else-if>\n      <else-if type=\"legislation\">\n        <text macro=\"legal-source-legislation\"/>\n      </else-if>\n      <else-if type=\"regulation\">\n        <text macro=\"legal-source-regulation\"/>\n      </else-if>\n      <else-if type=\"treaty\">\n        <text macro=\"legal-source-treaty\"/>\n      </else-if>\n    </choose>\n  </macro>\n  <!-- Legal source types -->\n  <macro name=\"legal-source-bill\">\n    <group delimiter=\", \">\n      <text macro=\"legal-identifier-bill-report\"/>\n      <group delimiter=\" \">\n        <text variable=\"authority\"/>\n        <!-- `chapter-number` is a session number -->\n        <text variable=\"chapter-number\"/>\n      </group>\n      <group delimiter=\" \">\n        <text variable=\"volume\"/>\n        <text variable=\"container-title\"/>\n        <text variable=\"page-first\"/>\n      </group>\n    </group>\n  </macro>\n  <macro name=\"legal-source-case\">\n    <group delimiter=\" \">\n      <choose>\n        <if variable=\"container-title\">\n          <text variable=\"volume\"/>\n          <text variable=\"container-title\"/>\n          <text macro=\"label-section-symbol\"/>\n          <choose>\n            <if match=\"any\" variable=\"page page-first\">\n              <text variable=\"page-first\"/>\n            </if>\n            <else>\n              <text value=\"___\"/>\n            </else>\n          </choose>\n        </if>\n        <else>\n          <text macro=\"label-number-capitalized\"/>\n        </else>\n      </choose>\n    </group>\n  </macro>\n  <macro name=\"legal-source-hearing\">\n    <group delimiter=\" \">\n      <text variable=\"authority\"/>\n      <!-- `chapter-number` is a session number -->\n      <text variable=\"chapter-number\"/>\n    </group>\n  </macro>\n  <macro name=\"legal-source-legislation\">\n    <choose>\n      <if variable=\"number\">\n        <!-- `number` is a public law number -->\n        <group delimiter=\", \">\n          <group delimiter=\" \">\n            <choose>\n              <if variable=\"genre\">\n                <text text-case=\"capitalize-first\" variable=\"genre\"/>\n              </if>\n              <else>\n                <text form=\"short\" term=\"legislation\" text-case=\"capitalize-first\"/>\n              </else>\n            </choose>\n            <text macro=\"label-number-capitalized\"/>\n          </group>\n          <group delimiter=\" \">\n            <text variable=\"volume\"/>\n            <text variable=\"container-title\"/>\n            <text variable=\"page-first\"/>\n          </group>\n        </group>\n      </if>\n      <else>\n        <group delimiter=\" \">\n          <text variable=\"volume\"/>\n          <text variable=\"container-title\"/>\n          <choose>\n            <if variable=\"section\">\n              <text macro=\"label-section-symbol\"/>\n            </if>\n            <else>\n              <text variable=\"page-first\"/>\n            </else>\n          </choose>\n        </group>\n      </else>\n    </choose>\n  </macro>\n  <macro name=\"legal-source-regulation\">\n    <group delimiter=\", \">\n      <group delimiter=\" \">\n        <text variable=\"genre\"/>\n        <text macro=\"label-number-capitalized\"/>\n      </group>\n      <group delimiter=\" \">\n        <text variable=\"volume\"/>\n        <text variable=\"container-title\"/>\n        <choose>\n          <if variable=\"section\">\n            <text macro=\"label-section-symbol\"/>\n          </if>\n          <else>\n            <text variable=\"page-first\"/>\n          </else>\n        </choose>\n      </group>\n    </group>\n  </macro>\n  <macro name=\"legal-source-treaty\">\n    <group delimiter=\" \">\n      <number variable=\"volume\"/>\n      <text variable=\"container-title\"/>\n      <choose>\n        <if match=\"any\" variable=\"page page-first\">\n          <text variable=\"page-first\"/>\n        </if>\n        <else>\n          <text macro=\"label-number-capitalized\"/>\n        </else>\n      </choose>\n    </group>\n  </macro>\n  <!-- Citation -->\n  <citation collapse=\"year\" disambiguate-add-givenname=\"true\" disambiguate-add-names=\"true\" disambiguate-add-year-suffix=\"true\" et-al-min=\"3\" et-al-use-first=\"1\" givenname-disambiguation-rule=\"primary-name-with-initials\">\n    <sort>\n      <key macro=\"author-sort\" names-min=\"3\" names-use-first=\"1\"/>\n      <key macro=\"date-sort-group\"/>\n      <key macro=\"date-sort\"/>\n      <key variable=\"status\"/>\n    </sort>\n    <layout delimiter=\"; \" prefix=\"(\" suffix=\")\">\n      <group delimiter=\", \">\n        <text macro=\"author-short\"/>\n        <text macro=\"date-short\"/>\n        <text macro=\"label-locator\"/>\n      </group>\n    </layout>\n  </citation>\n  <!-- Bibliography -->\n  <macro name=\"bibliography\">\n    <group delimiter=\" \">\n      <choose>\n        <if match=\"any\" type=\"bill hearing legal_case legislation regulation treaty\">\n          <!-- Legal items have different orders and delimiters -->\n          <text macro=\"legal-reference\" suffix=\".\"/>\n          <text macro=\"source-DOI-URL\"/>\n          <text variable=\"references\"/>\n        </if>\n        <else>\n          <group delimiter=\". \" suffix=\".\">\n            <text macro=\"author-and-contributors\"/>\n            <text macro=\"date\"/>\n            <text macro=\"title-and-descriptions\"/>\n            <text macro=\"source\"/>\n          </group>\n          <text macro=\"source-DOI-URL\"/>\n          <text macro=\"publication-history\"/>\n        </else>\n      </choose>\n    </group>\n  </macro>\n  <bibliography entry-spacing=\"0\" et-al-min=\"21\" et-al-use-first=\"19\" et-al-use-last=\"true\" hanging-indent=\"true\" line-spacing=\"2\">\n    <sort>\n      <key macro=\"author-sort\"/>\n      <key macro=\"date-sort-group\"/>\n      <key macro=\"date-sort\"/>\n      <key variable=\"status\"/>\n      <key macro=\"title\"/>\n      <key variable=\"volume\"/>\n      <key variable=\"part-number\"/>\n      <key variable=\"event-date\"/>\n      <key variable=\"original-date\"/>\n      <key macro=\"source-archive\"/>\n    </sort>\n    <layout>\n      <choose>\n        <if match=\"any\" variable=\"archive archive-place container-title DOI number publisher references URL\">\n          <text macro=\"bibliography\"/>\n        </if>\n        <!-- an inaccessible `interview` or `personal_communication` is cited in-text only (APA 8.9) -->\n        <else-if match=\"any\" type=\"interview personal_communication\"/>\n        <else>\n          <text macro=\"bibliography\"/>\n        </else>\n      </choose>\n    </layout>\n  </bibliography>\n</style>\n",
  "mla": "<?xml version=\"1.0\" encoding=\"utf-8\"?>\n<style xmlns=\"http://purl.org/net/xbiblio/csl\" and=\"text\" class=\"in-text\" demote-non-dropping-particle=\"never\" initialize-with=\". \" page-range-format=\"minimal-two\" version=\"1.0\">\n  <!-- This file was generated by the Style Variant Builder <https://github.com/citation-style-language/style-variant-builder>. To contribute changes, modify the template and regenerate variants. -->\n  <info>\n    <title>MLA Handbook 9th edition (in-text citations)</title>\n    <title-short>Modern Language Association (in-text citations)</title-short>\n    <id>http://www.zotero.org/styles/modern-language-association</id>\n    <link href=\"http://www.zotero.org/styles/modern-language-association\" rel=\"self\"/>\n    <link href=\"https://style.mla.org/\" rel=\"documentation\"/>\n    <link href=\"https://zotero.org/groups/2205533/collections/L96HMJXY\" rel=\"documentation\"/>\n    <author>\n      <name>Sebastian Karcher</name>\n      <uri>https://orcid.org/0000-0001-8249-7388</uri>\n    </author>\n    <author>\n      <name>Andrew Dunning</name>\n      <uri>https://orcid.org/0000-0003-0464-5036</uri>\n    </author>\n    <contributor>\n      <name>Patrick O'Brien</name>\n    </contributor>\n    <category citation-format=\"author\"/>\n    <category field=\"generic-base\"/>\n    <category field=\"humanities\"/>\n    <category field=\"literature\"/>\n    <summary>MLA source citations, in-text citations system (chapter 6)</summary>\n    <updated>2026-02-03T00:00:00+00:00</updated>\n    <rights license=\"http://creativecommons.org/licenses/by-sa/3.0/\">This work is licensed under a Creative Commons Attribution-ShareAlike 3.0 License</rights>\n  </info>\n  <locale xml:lang=\"en\">\n    <date form=\"text\">\n      <date-part name=\"day\" suffix=\" \"/>\n      <date-part form=\"short\" name=\"month\" suffix=\" \"/>\n      <date-part name=\"year\"/>\n    </date>\n    <terms>\n      <!-- MLA Appendix 1 -->\n      <term form=\"short\" name=\"chapter\">\n        <single>ch.</single>\n        <multiple>chs.</multiple>\n      </term>\n      <term name=\"collection-editor\">\n        <single>general editor</single>\n        <multiple>general editors</multiple>\n      </term>\n      <term name=\"editor-translator\">\n        <single>editor and translator</single>\n        <multiple>editors and translators</multiple>\n      </term>\n      <term name=\"editortranslator\">\n        <single>editor and translator</single>\n        <multiple>editors and translators</multiple>\n      </term>\n      <term form=\"verb\" name=\"editor-translator\">edited and translated by</term>\n      <term form=\"verb\" name=\"editortranslator\">edited and translated by</term>\n      <term name=\"original-work-published\">originally published</term>\n      <term form=\"short\" name=\"paragraph\">\n        <single>par.</single>\n        <multiple>pars.</multiple>\n      </term>\n      <term form=\"short\" name=\"version\">vers.</term>\n    </terms>\n  </locale>\n  <!-- Contents:\n\n       MLA provides the following series of elements for citations:\n\n       1. Author (MLA 5.3-22)\n       2. Title of Source (MLA 5.23-30)\n       3. Supplemental Element after Title of Source (MLA 5.106-109)\n          3.1. Contributor (MLA 5.107)\n          3.2. Original publication date (MLA 5.108)\n          3.3. Section of a work labeled generically (MLA 5.109)\n       4. Container 1\n          4.1. Title of Container (MLA 5.31-37)\n          4.2. Contributor (MLA 5.38-47)\n          4.3. Version (MLA 5.48-50)\n          4.4. Number (MLA 5.51-53)\n          4.5. Publisher (MLA 5.54-67)\n          4.6. Publication Date (MLA 5.68-83)\n          4.7. Location (MLA 5.84-99)\n       5. Supplemental Element Between Containers (MLA 5.119)\n       6. Container 2 (MLA 5.102)\n       7. Supplemental Element at End of Entry (MLA 5.110-118)\n          7.1. Date of access (MLA 5.111)\n          7.2. Medium of publication (MLA 5.112)\n          7.3. Dissertations and theses (MLA 5.113)\n          7.4. Publication history (MLA 5.114)\n          7.5. Book series (MLA 5.115)\n          7.6. Columns, sections, and other recurring titled features (MLA 5.116)\n          7.7. Multivolume works (MLA 5.117)\n  -->\n  <!-- Categories of CSL item types:\n\n       Serial\n       : article-journal article-magazine article-newspaper periodical post-weblog review review-book\n\n       Serial or Monographic\n       : interview paper-conference\n\n         Monographic with any of `collection-editor compiler editor editorial-director`.\n         A serial `paper-conference` is unpublished if it lacks any of `issue page supplement-number volume`.\n\n       Monographic\n       : article book broadcast chapter classic collection dataset document\n         entry entry-dictionary entry-encyclopedia event figure\n         graphic manuscript map motion_picture musical_score\n         pamphlet patent performance personal_communication post report\n         software song speech standard thesis webpage\n\n       Legal\n       : bill hearing legal_case legislation regulation treaty\n  -->\n  <!-- Variable labels -->\n  <macro name=\"label-edition-capitalized\">\n    <group delimiter=\" \">\n      <choose>\n        <if is-numeric=\"edition\">\n          <number form=\"ordinal\" variable=\"edition\"/>\n          <label form=\"short\" variable=\"edition\"/>\n        </if>\n        <else>\n          <text text-case=\"capitalize-first\" variable=\"edition\"/>\n        </else>\n      </choose>\n    </group>\n  </macro>\n  <macro name=\"label-issue\">\n    <group delimiter=\" \">\n      <label form=\"short\" variable=\"issue\"/>\n      <text variable=\"issue\"/>\n    </group>\n  </macro>\n  <macro name=\"label-locator\">\n    <group delimiter=\" \">\n      <label form=\"short\" variable=\"locator\"/>\n      <text variable=\"locator\"/>\n    </group>\n  </macro>\n  <macro name=\"label-number\">\n    <group delimiter=\" \">\n      <choose>\n        <if type=\"standard\"/>\n        <else-if is-numeric=\"number\">\n          <label form=\"short\" variable=\"number\"/>\n        </else-if>\n      </choose>\n      <text variable=\"number\"/>\n    </group>\n  </macro>\n  <macro name=\"label-number-of-volumes\">\n    <group delimiter=\" \">\n      <text variable=\"number-of-volumes\"/>\n      <choose>\n        <if is-numeric=\"number-of-volumes\">\n          <label form=\"short\" variable=\"number-of-volumes\"/>\n        </if>\n      </choose>\n    </group>\n  </macro>\n  <macro name=\"label-page\">\n    <group delimiter=\" \">\n      <label form=\"short\" variable=\"page\"/>\n      <text variable=\"page\"/>\n    </group>\n  </macro>\n  <macro name=\"label-part-number\">\n    <group delimiter=\" \">\n      <choose>\n        <if is-numeric=\"part-number\">\n          <!-- TODO: Replace with `part-number` label when CSL provides one -->\n          <text form=\"short\" term=\"part\"/>\n        </if>\n      </choose>\n      <text variable=\"part-number\"/>\n    </group>\n  </macro>\n  <macro name=\"label-part-number-capitalized\">\n    <group delimiter=\" \">\n      <choose>\n        <if is-numeric=\"part-number\">\n          <!-- TODO: Replace with `part-number` label when CSL provides one -->\n          <text form=\"short\" term=\"part\" text-case=\"capitalize-first\"/>\n        </if>\n      </choose>\n      <text text-case=\"capitalize-first\" variable=\"part-number\"/>\n    </group>\n  </macro>\n  <macro name=\"label-supplement-number\">\n    <group delimiter=\" \">\n      <choose>\n        <!-- TODO: Replace with `supplement-number` label when CSL provides one -->\n        <if is-numeric=\"supplement-number\">\n          <text form=\"short\" term=\"supplement\"/>\n        </if>\n      </choose>\n      <text variable=\"supplement-number\"/>\n    </group>\n  </macro>\n  <macro name=\"label-version\">\n    <group delimiter=\" \">\n      <label variable=\"version\"/>\n      <text variable=\"version\"/>\n    </group>\n  </macro>\n  <macro name=\"label-version-capitalized\">\n    <group delimiter=\" \">\n      <label text-case=\"capitalize-first\" variable=\"version\"/>\n      <text variable=\"version\"/>\n    </group>\n  </macro>\n  <macro name=\"label-volume\">\n    <group delimiter=\" \">\n      <choose>\n        <if is-numeric=\"volume\">\n          <label form=\"short\" variable=\"volume\"/>\n        </if>\n      </choose>\n      <text variable=\"volume\"/>\n    </group>\n  </macro>\n  <macro name=\"label-volume-capitalized\">\n    <group delimiter=\" \">\n      <choose>\n        <if is-numeric=\"volume\">\n          <label form=\"short\" text-case=\"capitalize-first\" variable=\"volume\"/>\n        </if>\n      </choose>\n      <text text-case=\"capitalize-first\" variable=\"volume\"/>\n    </group>\n  </macro>\n  <!-- 1. Author (MLA 5.3-22) -->\n  <macro name=\"author\">\n    <names variable=\"composer\">\n      <name delimiter-precedes-et-al=\"always\" delimiter-precedes-last=\"always\" initialize=\"false\" name-as-sort-order=\"first\"/>\n      <label prefix=\", \"/>\n      <substitute>\n        <names variable=\"author\"/>\n        <names variable=\"guest\">\n          <name delimiter-precedes-et-al=\"always\" delimiter-precedes-last=\"always\" initialize=\"false\" name-as-sort-order=\"first\"/>\n          <!-- `guest` has no label (see MLA 'Interview by podcast host') -->\n        </names>\n        <names variable=\"editor-translator\"/>\n        <names variable=\"editor\"/>\n        <names variable=\"translator\"/>\n        <choose>\n          <if type=\"standard\">\n            <text variable=\"authority\"/>\n          </if>\n        </choose>\n        <text macro=\"title\"/>\n      </substitute>\n    </names>\n  </macro>\n  <macro name=\"author-short\">\n    <group delimiter=\", \">\n      <names variable=\"composer\">\n        <name form=\"short\" initialize=\"true\"/>\n        <substitute>\n          <names variable=\"author\"/>\n          <names variable=\"guest\"/>\n          <names variable=\"editor-translator\"/>\n          <names variable=\"editor\"/>\n          <names variable=\"translator\"/>\n          <choose>\n            <if type=\"standard\">\n              <text variable=\"authority\"/>\n            </if>\n          </choose>\n          <text macro=\"title-short\"/>\n        </substitute>\n      </names>\n      <choose>\n        <if disambiguate=\"true\">\n          <text macro=\"title-short\"/>\n        </if>\n      </choose>\n    </group>\n  </macro>\n  <!-- 2. Title of Source (MLA 5.23-30) -->\n  <macro name=\"title\">\n    <choose>\n      <if match=\"any\" type=\"post webpage\">\n        <!-- print `container-title` on `post` or `webpage` in the same way as `publisher` -->\n        <text macro=\"title-and-part-filter-review\"/>\n      </if>\n      <else-if match=\"any\" type=\"article-journal article-magazine article-newspaper periodical post-weblog review review-book\">\n        <!-- serial types -->\n        <text macro=\"title-and-part-filter-review\"/>\n      </else-if>\n      <else-if match=\"any\" variable=\"collection-editor compiler editor editorial-director\">\n        <text macro=\"title-monographic\"/>\n      </else-if>\n      <else-if match=\"any\" type=\"interview paper-conference\">\n        <!-- serial types -->\n        <text macro=\"title-and-part-filter-review\"/>\n      </else-if>\n      <else>\n        <text macro=\"title-monographic\"/>\n      </else>\n    </choose>\n  </macro>\n  <macro name=\"title-short\">\n    <choose>\n      <if match=\"any\" type=\"review review-book\" variable=\"reviewed-author reviewed-genre reviewed-title\">\n        <!-- If a review has no `reviewed-title`, assume that `title` contains the title of the reviewed work; the description provides it. -->\n        <choose>\n          <if variable=\"reviewed-genre title\">\n            <!-- Quotes, title case -->\n            <text form=\"short\" quotes=\"true\" text-case=\"title\" variable=\"title\"/>\n          </if>\n          <else-if variable=\"reviewed-genre reviewed-title title\">\n            <!-- Quotes, title case -->\n            <text form=\"short\" quotes=\"true\" text-case=\"title\" variable=\"title\"/>\n          </else-if>\n          <else>\n            <text macro=\"supplemental-generic-label-short\"/>\n          </else>\n        </choose>\n      </if>\n      <else-if variable=\"title\">\n        <text macro=\"title-primary-short\"/>\n      </else-if>\n      <else>\n        <text macro=\"supplemental-generic-label-short\"/>\n      </else>\n    </choose>\n  </macro>\n  <!-- Title elements -->\n  <macro name=\"title-and-part-filter-review\">\n    <choose>\n      <if match=\"any\" type=\"review review-book\" variable=\"reviewed-author reviewed-genre reviewed-title\">\n        <!-- `title` is only the review title if there is a separate `reviewed-genre` or `reviewed-title`; otherwise, it is the title of the reviewed work, printed in the description -->\n        <choose>\n          <if match=\"any\" variable=\"reviewed-genre reviewed-title\">\n            <text macro=\"title-and-part-title\"/>\n          </if>\n        </choose>\n      </if>\n      <else>\n        <text macro=\"title-and-part-title\"/>\n      </else>\n    </choose>\n  </macro>\n  <macro name=\"title-and-part-title\">\n    <group delimiter=\", \">\n      <text macro=\"title-primary\"/>\n      <text macro=\"label-part-number\"/>\n      <text macro=\"title-part\"/>\n    </group>\n  </macro>\n  <macro name=\"title-monographic\">\n    <!-- For monographic items, assume `part-number` and `part-title` refer to the book/volume. -->\n    <choose>\n      <if variable=\"container-title\">\n        <text macro=\"title-primary\"/>\n      </if>\n      <!-- For monographic items without `container-title`, bibliography entries list `part-title` or `volume-title` first if available -->\n      <else-if variable=\"part-title\">\n        <text font-style=\"italic\" text-case=\"title\" variable=\"part-title\"/>\n      </else-if>\n      <else-if variable=\"volume-title\">\n        <text font-style=\"italic\" text-case=\"title\" variable=\"volume-title\"/>\n      </else-if>\n      <else>\n        <text macro=\"title-primary\"/>\n      </else>\n    </choose>\n  </macro>\n  <macro name=\"title-part\">\n    <choose>\n      <if match=\"any\" type=\"article-journal article-magazine article-newspaper periodical post-weblog review review-book\">\n        <text quotes=\"true\" text-case=\"title\" variable=\"part-title\"/>\n      </if>\n      <else-if match=\"any\" variable=\"collection-editor compiler editor editorial-director\">\n        <!-- monographic types -->\n        <text font-style=\"italic\" text-case=\"title\" variable=\"part-title\"/>\n      </else-if>\n      <else-if match=\"any\" type=\"interview paper-conference\">\n        <!-- serial types -->\n        <text quotes=\"true\" text-case=\"title\" variable=\"part-title\"/>\n      </else-if>\n      <else>\n        <!-- monographic types -->\n        <text font-style=\"italic\" text-case=\"title\" variable=\"part-title\"/>\n      </else>\n    </choose>\n  </macro>\n  <macro name=\"title-primary\">\n    <choose>\n      <if match=\"any\" type=\"bill collection legislation regulation treaty\">\n        <!-- No italics or quotes, title case -->\n        <text text-case=\"title\" variable=\"title\"/>\n      </if>\n      <else-if type=\"legal_case\">\n        <!-- Italicized, sentence case -->\n        <text font-style=\"italic\" variable=\"title\"/>\n      </else-if>\n      <else-if match=\"any\" type=\"book classic graphic hearing map periodical\">\n        <!-- Italicized, title case (regardless of `container-title`) -->\n        <text font-style=\"italic\" text-case=\"title\" variable=\"title\"/>\n      </else-if>\n      <else-if type=\"post\">\n        <!-- Quotes, sentence case -->\n        <text quotes=\"true\" variable=\"title\"/>\n      </else-if>\n      <!-- Other types are formatted based on presence of `container-title` -->\n      <else-if variable=\"container-title\">\n        <!-- Quotes, title case -->\n        <text quotes=\"true\" text-case=\"title\" variable=\"title\"/>\n      </else-if>\n      <else-if match=\"any\" type=\"article dataset document interview manuscript paper-conference personal_communication speech\">\n        <!-- Container-like but not necessarily with `container-title` -->\n        <!-- Quotes, title case -->\n        <text quotes=\"true\" text-case=\"title\" variable=\"title\"/>\n      </else-if>\n      <else>\n        <!-- Italicized, title case (default) -->\n        <text font-style=\"italic\" text-case=\"title\" variable=\"title\"/>\n      </else>\n    </choose>\n  </macro>\n  <macro name=\"title-primary-short\">\n    <choose>\n      <if match=\"any\" type=\"bill collection legislation regulation treaty\">\n        <!-- No italics or quotes, title case -->\n        <text form=\"short\" text-case=\"title\" variable=\"title\"/>\n      </if>\n      <else-if type=\"legal_case\">\n        <!-- Italicized, sentence case -->\n        <text font-style=\"italic\" form=\"short\" variable=\"title\"/>\n      </else-if>\n      <else-if match=\"any\" type=\"book classic graphic hearing map periodical\">\n        <!-- Italicized, title case (regardless of `container-title`) -->\n        <text font-style=\"italic\" form=\"short\" text-case=\"title\" variable=\"title\"/>\n      </else-if>\n      <else-if type=\"post\">\n        <!-- Quotes, sentence case -->\n        <text form=\"short\" quotes=\"true\" variable=\"title\"/>\n      </else-if>\n      <!-- Other types are formatted based on presence of `container-title` -->\n      <else-if variable=\"container-title\">\n        <!-- Quotes, title case -->\n        <text form=\"short\" quotes=\"true\" text-case=\"title\" variable=\"title\"/>\n      </else-if>\n      <else-if match=\"any\" type=\"article dataset document interview manuscript paper-conference personal_communication speech\">\n        <!-- Container-like but not necessarily with `container-title` -->\n        <!-- Quotes, title case -->\n        <text form=\"short\" quotes=\"true\" text-case=\"title\" variable=\"title\"/>\n      </else-if>\n      <else>\n        <!-- Italicized, title case (default) -->\n        <text font-style=\"italic\" form=\"short\" text-case=\"title\" variable=\"title\"/>\n      </else>\n    </choose>\n  </macro>\n  <!-- 3. Supplemental Element after Title of Source (MLA 5.106-109) -->\n  <macro name=\"supplemental-element-after-title\">\n    <group delimiter=\", \">\n      <text macro=\"supplemental-contributor\"/>\n      <text macro=\"supplemental-original-date\"/>\n      <text macro=\"supplemental-generic-label\"/>\n    </group>\n  </macro>\n  <!-- 3.1. Contributor (MLA 5.107) -->\n  <macro name=\"supplemental-contributor\">\n    <names delimiter=\", \" variable=\"interviewer\">\n      <label form=\"verb\" suffix=\" \" text-case=\"capitalize-first\"/>\n      <name initialize=\"false\"/>\n    </names>\n  </macro>\n  <!-- 3.2. Original publication date (MLA 5.108) -->\n  <macro name=\"supplemental-original-date\">\n    <choose>\n      <if type=\"personal_communication\">\n        <!-- date and place of composition for letters -->\n        <text macro=\"container1-location-event\"/>\n      </if>\n      <else-if match=\"any\" variable=\"original-publisher original-publisher-place\"/>\n      <else-if is-uncertain-date=\"original-date\">\n        <date form=\"text\" prefix=\"[\" suffix=\"?]\" variable=\"original-date\"/>\n      </else-if>\n      <else>\n        <date form=\"text\" variable=\"original-date\"/>\n      </else>\n    </choose>\n  </macro>\n  <!-- 3.3. Section of a work labeled generically (MLA 5.109) -->\n  <macro name=\"supplemental-generic-label\">\n    <choose>\n      <if match=\"any\" type=\"review review-book\" variable=\"reviewed-author reviewed-genre reviewed-title\">\n        <text macro=\"supplemental-generic-label-review\"/>\n      </if>\n      <else-if type=\"thesis\"/>\n      <else-if variable=\"number\"/>\n      <else>\n        <text text-case=\"capitalize-first\" variable=\"genre\"/>\n      </else>\n    </choose>\n  </macro>\n  <macro name=\"supplemental-generic-label-short\">\n    <choose>\n      <if match=\"any\" type=\"review review-book\" variable=\"reviewed-author reviewed-genre reviewed-title\">\n        <text macro=\"supplemental-generic-label-review-short\"/>\n      </if>\n      <else>\n        <text form=\"short\" text-case=\"capitalize-first\" variable=\"genre\"/>\n      </else>\n    </choose>\n  </macro>\n  <!-- Generic label elements -->\n  <macro name=\"supplemental-generic-label-review\">\n    <group delimiter=\" \">\n      <choose>\n        <if variable=\"reviewed-genre\">\n          <text term=\"review-of\" text-case=\"capitalize-first\"/>\n          <text variable=\"reviewed-genre\"/>\n          <choose>\n            <if match=\"none\" variable=\"reviewed-title\">\n              <names variable=\"reviewed-author\">\n                <label form=\"verb\" suffix=\" \"/>\n                <name initialize=\"false\"/>\n              </names>\n            </if>\n          </choose>\n        </if>\n        <else-if variable=\"number\">\n          <text term=\"review-of\" text-case=\"capitalize-first\"/>\n        </else-if>\n        <!-- If no `reviewed-genre`, assume that `genre` is entered as 'Review of the book' or similar -->\n        <else-if variable=\"genre\">\n          <text text-case=\"capitalize-first\" variable=\"genre\"/>\n        </else-if>\n        <else>\n          <text term=\"review-of\" text-case=\"capitalize-first\"/>\n        </else>\n      </choose>\n      <choose>\n        <if match=\"any\" variable=\"reviewed-genre reviewed-title\">\n          <!-- Not possible to distinguish TV series episode from other reviewed works without a reviewed source title -->\n          <!-- Adapt for `reviewed-container-title` or similar if it becomes available -->\n          <text font-style=\"italic\" text-case=\"title\" variable=\"reviewed-title\"/>\n        </if>\n        <else>\n          <!-- Assume title is title of reviewed work -->\n          <text font-style=\"italic\" text-case=\"title\" variable=\"title\"/>\n        </else>\n      </choose>\n    </group>\n    <choose>\n      <if variable=\"reviewed-genre reviewed-title title\">\n        <names variable=\"reviewed-author\">\n          <label form=\"verb\" suffix=\" \"/>\n          <name initialize=\"false\"/>\n        </names>\n      </if>\n      <else-if variable=\"reviewed-genre\"/>\n      <else>\n        <names variable=\"reviewed-author\">\n          <label form=\"verb\" suffix=\" \"/>\n          <name initialize=\"false\"/>\n        </names>\n      </else>\n    </choose>\n  </macro>\n  <macro name=\"supplemental-generic-label-review-short\">\n    <group delimiter=\" \">\n      <text term=\"review-of\"/>\n      <choose>\n        <if match=\"any\" variable=\"reviewed-genre reviewed-title\">\n          <!-- Not possible to distinguish TV series episode from other reviewed works without a reviewed source title -->\n          <!-- Adapt for `reviewed-container-title` or similar if it becomes available -->\n          <text font-style=\"italic\" form=\"short\" text-case=\"title\" variable=\"reviewed-title\"/>\n        </if>\n        <else>\n          <!-- Assume title is title of reviewed work -->\n          <text font-style=\"italic\" form=\"short\" text-case=\"title\" variable=\"title\"/>\n        </else>\n      </choose>\n    </group>\n  </macro>\n  <!-- 4. Container 1 -->\n  <macro name=\"container1\">\n    <group delimiter=\", \">\n      <text macro=\"container1-title\"/>\n      <text macro=\"container1-contributor\"/>\n      <text macro=\"container1-version\"/>\n      <text macro=\"container1-number\"/>\n      <text macro=\"container1-publisher\"/>\n      <text macro=\"container1-publication-date\"/>\n      <text macro=\"container1-location\"/>\n    </group>\n  </macro>\n  <!-- 4.1. Title of Container (MLA 5.31-37) -->\n  <macro name=\"container1-title\">\n    <choose>\n      <if match=\"any\" type=\"article-journal article-magazine article-newspaper periodical post-weblog review review-book\">\n        <!-- serial types -->\n        <text macro=\"container1-title-serial\"/>\n      </if>\n      <else-if match=\"any\" variable=\"collection-editor compiler editor editorial-director\">\n        <!-- monographic types -->\n        <text macro=\"container1-title-monographic\"/>\n      </else-if>\n      <else-if match=\"any\" type=\"interview paper-conference\">\n        <!-- serial types -->\n        <text macro=\"container1-title-serial\"/>\n      </else-if>\n      <else>\n        <!-- monographic types -->\n        <text macro=\"container1-title-monographic\"/>\n      </else>\n    </choose>\n  </macro>\n  <macro name=\"container1-title-serial\">\n    <group delimiter=\", \">\n      <text font-style=\"italic\" text-case=\"title\" variable=\"volume-title\"/>\n      <group delimiter=\" \">\n        <choose>\n          <!-- Journal special issues and supplements (MLA 7.4) -->\n          <if match=\"none\" variable=\"container-title\"/>\n          <else-if variable=\"supplement-number volume-title\">\n            <text term=\"supplement\"/>\n            <text value=\"to\"/>\n          </else-if>\n          <else-if type=\"periodical\" variable=\"supplement-number title\">\n            <text term=\"supplement\" text-case=\"capitalize-first\"/>\n            <text value=\"to\"/>\n          </else-if>\n          <else-if type=\"periodical\" variable=\"volume-title\">\n            <text term=\"special-issue\" text-case=\"capitalize-first\"/>\n            <text value=\"of\"/>\n          </else-if>\n          <else-if type=\"periodical\" variable=\"title\">\n            <text term=\"special-issue\" text-case=\"capitalize-first\"/>\n            <text value=\"of\"/>\n          </else-if>\n          <else-if variable=\"volume-title\">\n            <text term=\"special-issue\"/>\n            <text value=\"of\"/>\n          </else-if>\n        </choose>\n        <text font-style=\"italic\" text-case=\"title\" variable=\"container-title\"/>\n        <text prefix=\"[\" suffix=\"]\" variable=\"publisher-place\"/>\n      </group>\n    </group>\n  </macro>\n  <macro name=\"container1-title-monographic\">\n    <choose>\n      <if variable=\"container-title part-title\">\n        <text font-style=\"italic\" text-case=\"title\" variable=\"part-title\"/>\n      </if>\n      <else-if variable=\"container-title volume-title\">\n        <text font-style=\"italic\" text-case=\"title\" variable=\"volume-title\"/>\n      </else-if>\n      <else>\n        <text font-style=\"italic\" text-case=\"title\" variable=\"container-title\"/>\n      </else>\n    </choose>\n  </macro>\n  <!-- 4.2. Contributor (MLA 5.38-47) -->\n  <macro name=\"container1-contributor\">\n    <group delimiter=\", \">\n      <names delimiter=\", \" variable=\"container-author\">\n        <label form=\"verb\" suffix=\" \"/>\n        <name initialize=\"false\"/>\n      </names>\n      <choose>\n        <if variable=\"container-title\">\n          <names delimiter=\", \" variable=\"editor-translator\">\n            <label form=\"verb\" suffix=\" \"/>\n            <name initialize=\"false\"/>\n          </names>\n          <names delimiter=\", \" variable=\"editor translator\">\n            <label form=\"verb\" suffix=\" \"/>\n            <name initialize=\"false\"/>\n          </names>\n          <names delimiter=\", \" variable=\"director series-creator illustrator host narrator contributor\">\n            <label form=\"verb\" suffix=\" \"/>\n            <name initialize=\"false\"/>\n          </names>\n        </if>\n        <else>\n          <names delimiter=\", \" variable=\"editor-translator\">\n            <label form=\"verb\" suffix=\" \" text-case=\"capitalize-first\"/>\n            <name initialize=\"false\"/>\n          </names>\n          <names delimiter=\", \" variable=\"editor translator\">\n            <label form=\"verb\" suffix=\" \" text-case=\"capitalize-first\"/>\n            <name initialize=\"false\"/>\n          </names>\n          <names delimiter=\", \" variable=\"director series-creator illustrator host narrator contributor\">\n            <label form=\"verb\" suffix=\" \" text-case=\"capitalize-first\"/>\n            <name initialize=\"false\"/>\n          </names>\n        </else>\n      </choose>\n    </group>\n  </macro>\n  <!-- 4.3. Version (MLA 5.48-50) -->\n  <macro name=\"container1-version\">\n    <group delimiter=\", \">\n      <text macro=\"label-edition-capitalized\"/>\n      <choose>\n        <if variable=\"edition\">\n          <text macro=\"label-version\"/>\n        </if>\n        <else>\n          <text macro=\"label-version-capitalized\"/>\n        </else>\n      </choose>\n    </group>\n  </macro>\n  <!-- 4.4. Number (MLA 5.51-53) -->\n  <macro name=\"container1-number\">\n    <group delimiter=\", \">\n      <choose>\n        <!-- `collection-title` is for any serial with multiple series (e.g. 'second series') -->\n        <if match=\"any\" type=\"article-journal article-magazine article-newspaper periodical post-weblog review review-book\">\n          <!-- serial types -->\n          <text variable=\"collection-title\"/>\n          <text macro=\"label-volume\"/>\n        </if>\n        <else-if match=\"any\" variable=\"collection-editor compiler editor editorial-director\">\n          <!-- monographic types -->\n          <text macro=\"label-volume\"/>\n        </else-if>\n        <else-if match=\"any\" type=\"interview paper-conference\">\n          <!-- serial types -->\n          <text variable=\"collection-title\"/>\n          <text macro=\"label-volume\"/>\n        </else-if>\n        <!-- in monographic types, lowercase with a preceding element -->\n        <else-if match=\"any\" variable=\"part-title volume-title\">\n          <!-- monographic types -->\n          <text macro=\"label-volume\"/>\n        </else-if>\n        <else-if match=\"any\" variable=\"edition container-title\">\n          <text macro=\"label-volume\"/>\n        </else-if>\n        <!--other contributors preceding the volume-->\n        <else-if variable=\"author\">\n          <choose>\n            <if match=\"any\" variable=\"container-author contributor director editor editor-translator illustrator interviewer translator\">\n              <text macro=\"label-volume\"/>\n            </if>\n          </choose>\n        </else-if>\n        <else>\n          <text macro=\"label-volume-capitalized\"/>\n        </else>\n      </choose>\n      <text macro=\"label-issue\"/>\n      <text macro=\"label-supplement-number\"/>\n      <group delimiter=\" \">\n        <choose>\n          <if is-numeric=\"number\" type=\"broadcast\" variable=\"genre\">\n            <text variable=\"genre\"/>\n            <text variable=\"number\"/>\n          </if>\n          <else-if is-numeric=\"number\" type=\"broadcast\">\n            <text value=\"episode\"/>\n            <text variable=\"number\"/>\n          </else-if>\n          <else-if variable=\"number\">\n            <text variable=\"genre\"/>\n            <text macro=\"label-number\"/>\n          </else-if>\n        </choose>\n      </group>\n    </group>\n  </macro>\n  <!-- 4.5. Publisher (MLA 5.54-67) -->\n  <macro name=\"container1-publisher\">\n    <choose>\n      <if type=\"thesis\"/>\n      <!-- omit serial types -->\n      <else-if match=\"any\" type=\"article-journal article-magazine article-newspaper periodical post-weblog review review-book\"/>\n      <else-if match=\"any\" variable=\"collection-editor compiler editor editorial-director\">\n        <!-- monographic types -->\n        <text macro=\"container1-publisher-or-place\"/>\n      </else-if>\n      <!-- omit serial types -->\n      <else-if match=\"any\" type=\"interview paper-conference\"/>\n      <else>\n        <!-- monographic types -->\n        <text macro=\"container1-publisher-or-place\"/>\n      </else>\n    </choose>\n  </macro>\n  <macro name=\"container1-publisher-or-place\">\n    <choose>\n      <if variable=\"publisher\">\n        <text variable=\"publisher\"/>\n      </if>\n      <else>\n        <!-- use place of publication as fallback (cf. MLA 5.67) -->\n        <text variable=\"publisher-place\"/>\n      </else>\n    </choose>\n  </macro>\n  <!-- 4.6. Publication Date (MLA 5.68-83) -->\n  <macro name=\"container1-publication-date\">\n    <choose>\n      <if match=\"any\" type=\"book chapter motion_picture paper-conference thesis\">\n        <choose>\n          <if is-uncertain-date=\"issued\">\n            <date date-parts=\"year\" form=\"numeric\" prefix=\"[\" suffix=\"?]\" variable=\"issued\"/>\n          </if>\n          <else>\n            <date date-parts=\"year\" form=\"numeric\" variable=\"issued\"/>\n          </else>\n        </choose>\n      </if>\n      <else-if type=\"article-journal\">\n        <choose>\n          <if is-uncertain-date=\"issued\">\n            <date date-parts=\"year-month\" form=\"text\" prefix=\"[\" suffix=\"?]\" variable=\"issued\"/>\n          </if>\n          <else>\n            <date date-parts=\"year-month\" form=\"text\" variable=\"issued\"/>\n          </else>\n        </choose>\n      </else-if>\n      <else-if type=\"speech\"/>\n      <else>\n        <choose>\n          <if is-uncertain-date=\"issued\">\n            <group delimiter=\" \">\n              <text term=\"circa\" text-case=\"capitalize-first\"/>\n              <date form=\"text\" variable=\"issued\"/>\n            </group>\n          </if>\n          <else>\n            <date form=\"text\" variable=\"issued\"/>\n          </else>\n        </choose>\n      </else>\n    </choose>\n  </macro>\n  <!-- 4.7. Location (MLA 5.84-99) -->\n  <macro name=\"container1-location\">\n    <!-- location of a physical object or event (MLA 5.99) -->\n    <group delimiter=\", \">\n      <choose>\n        <!-- serials cannot be part of an event -->\n        <if match=\"any\" type=\"article-journal article-magazine article-newspaper periodical post-weblog review review-book\"/>\n        <!-- `event-date` supplies date of composition for letters, handled in `supplemental-original-date` -->\n        <else-if type=\"personal_communication\"/>\n        <else-if type=\"paper-conference\">\n          <choose>\n            <if match=\"none\" variable=\"collection-editor compiler editor editorial-director issue page supplement-number volume\">\n              <!-- Don't print event info for conference papers published in a proceedings volume -->\n              <text macro=\"container1-location-event\"/>\n            </if>\n          </choose>\n        </else-if>\n        <else>\n          <!-- For other item types, print event info even if published (e.g. collection catalogs, performance programs). -->\n          <text macro=\"container1-location-event\"/>\n        </else>\n      </choose>\n      <text variable=\"archive\"/>\n      <text variable=\"archive-place\"/>\n      <text variable=\"archive_collection\"/>\n      <text variable=\"archive_location\"/>\n      <text macro=\"label-page\"/>\n      <choose>\n        <if match=\"none\" variable=\"source\">\n          <text macro=\"container1-location-URI\"/>\n        </if>\n      </choose>\n    </group>\n  </macro>\n  <macro name=\"container1-location-event\">\n    <group delimiter=\", \">\n      <choose>\n        <if match=\"any\" variable=\"event event-date event-title\">\n          <!-- TODO: We expect `event-title` to be used, but processors and applications may not be updated yet. This macro ensures that either `event` or `event-title` can be accepted. Remove if processor logic and application adoption can handle this. -->\n          <choose>\n            <if variable=\"event-title\">\n              <text text-case=\"capitalize-first\" variable=\"event-title\"/>\n            </if>\n            <else>\n              <text text-case=\"capitalize-first\" variable=\"event\"/>\n            </else>\n          </choose>\n          <choose>\n            <if is-uncertain-date=\"event-date\">\n              <date form=\"text\" prefix=\"[\" suffix=\"?]\" variable=\"event-date\"/>\n            </if>\n            <else>\n              <date form=\"text\" variable=\"event-date\"/>\n            </else>\n          </choose>\n          <text variable=\"event-place\"/>\n        </if>\n      </choose>\n    </group>\n  </macro>\n  <macro name=\"container1-location-URI\">\n    <choose>\n      <if variable=\"DOI\">\n        <text prefix=\"https://doi.org/\" variable=\"DOI\"/>\n      </if>\n      <else>\n        <text variable=\"URL\"/>\n      </else>\n    </choose>\n  </macro>\n  <!-- 5. Supplemental Element Between Containers (MLA 5.119) -->\n  <macro name=\"supplemental-element-between\">\n    <choose>\n      <if variable=\"source\">\n        <text macro=\"supplemental-element-movable\"/>\n      </if>\n    </choose>\n  </macro>\n  <!-- 6. Container 2 (MLA 5.102) -->\n  <macro name=\"container2\">\n    <group delimiter=\", \">\n      <choose>\n        <if match=\"none\" variable=\"source\"/>\n        <else-if match=\"any\" variable=\"DOI URL\">\n          <!-- Title of Container -->\n          <text font-style=\"italic\" variable=\"source\"/>\n          <!-- Location -->\n          <text macro=\"container1-location-URI\"/>\n        </else-if>\n      </choose>\n    </group>\n  </macro>\n  <!-- 7. Supplemental Element at End of Entry (MLA 5.110-118) -->\n  <macro name=\"supplemental-element-end\">\n    <group delimiter=\", \">\n      <text macro=\"supplemental-date-access\"/>\n      <text macro=\"supplemental-medium\"/>\n      <choose>\n        <if variable=\"source\"/>\n        <else>\n          <text macro=\"supplemental-element-movable\"/>\n        </else>\n      </choose>\n    </group>\n  </macro>\n  <macro name=\"supplemental-element-movable\">\n    <!-- information relevant only to one container appears either in `supplemental-element-between` or `supplemental-element-end` depending on the presence of `source` -->\n    <group delimiter=\", \">\n      <choose>\n        <if match=\"any\" type=\"article-journal article-magazine article-newspaper periodical post-weblog review review-book\">\n          <!-- serial types -->\n          <text macro=\"supplemental-columns-sections\"/>\n        </if>\n        <else-if match=\"any\" type=\"interview paper-conference\">\n          <choose>\n            <if match=\"any\" variable=\"collection-editor compiler editor editorial-director\">\n              <!-- monographic types -->\n              <text macro=\"supplemental-dissertations-theses\"/>\n              <text macro=\"supplemental-publication-history\"/>\n              <text macro=\"supplemental-book-series\"/>\n              <text macro=\"supplemental-multivolume-works\"/>\n            </if>\n            <else>\n              <!-- serial types -->\n              <text macro=\"supplemental-columns-sections\"/>\n            </else>\n          </choose>\n        </else-if>\n        <else>\n          <!-- monographic types -->\n          <text macro=\"supplemental-dissertations-theses\"/>\n          <text macro=\"supplemental-publication-history\"/>\n          <text macro=\"supplemental-book-series\"/>\n          <text macro=\"supplemental-multivolume-works\"/>\n        </else>\n      </choose>\n    </group>\n  </macro>\n  <!-- 7.1. Date of access (MLA 5.111) -->\n  <macro name=\"supplemental-date-access\">\n    <choose>\n      <if match=\"none\" variable=\"issued\">\n        <group delimiter=\" \">\n          <text term=\"accessed\" text-case=\"capitalize-first\"/>\n          <date form=\"text\" variable=\"accessed\"/>\n        </group>\n      </if>\n    </choose>\n  </macro>\n  <!-- 7.2. Medium of publication (MLA 5.112) -->\n  <macro name=\"supplemental-medium\">\n    <text text-case=\"capitalize-first\" variable=\"medium\"/>\n  </macro>\n  <!-- 7.3. Dissertations and theses (MLA 5.113) -->\n  <macro name=\"supplemental-dissertations-theses\">\n    <choose>\n      <if type=\"thesis\">\n        <group delimiter=\", \">\n          <text variable=\"publisher\"/>\n          <text variable=\"genre\"/>\n        </group>\n      </if>\n    </choose>\n  </macro>\n  <!-- 7.4. Publication history (MLA 5.114) -->\n  <macro name=\"supplemental-publication-history\">\n    <group delimiter=\" \">\n      <choose>\n        <if match=\"any\" variable=\"original-publisher original-publisher-place original-title\">\n          <text term=\"original-work-published\" text-case=\"capitalize-first\"/>\n        </if>\n      </choose>\n      <group delimiter=\", \">\n        <group delimiter=\" \">\n          <text value=\"as\"/>\n          <text font-style=\"italic\" text-case=\"title\" variable=\"original-title\"/>\n        </group>\n        <choose>\n          <if match=\"any\" variable=\"original-publisher original-publisher-place\">\n            <choose>\n              <if variable=\"original-publisher\">\n                <group delimiter=\" \">\n                  <choose>\n                    <if match=\"none\" variable=\"original-title\">\n                      <text term=\"by\"/>\n                    </if>\n                  </choose>\n                  <text variable=\"original-publisher\"/>\n                </group>\n              </if>\n              <else>\n                <text variable=\"original-publisher-place\"/>\n              </else>\n            </choose>\n            <choose>\n              <if is-uncertain-date=\"original-date\">\n                <date date-parts=\"year\" form=\"numeric\" prefix=\"[\" suffix=\"?]\" variable=\"original-date\"/>\n              </if>\n              <else>\n                <date date-parts=\"year\" form=\"numeric\" variable=\"original-date\"/>\n              </else>\n            </choose>\n          </if>\n        </choose>\n      </group>\n    </group>\n  </macro>\n  <!-- 7.5. Book series (MLA 5.115) -->\n  <macro name=\"supplemental-book-series\">\n    <group delimiter=\", \">\n      <choose>\n        <if is-numeric=\"collection-number\" variable=\"collection-title\">\n          <group delimiter=\" \">\n            <text text-case=\"title\" variable=\"collection-title\"/>\n            <text variable=\"collection-number\"/>\n          </group>\n        </if>\n        <else-if variable=\"collection-title\">\n          <text text-case=\"title\" variable=\"collection-title\"/>\n          <text variable=\"collection-number\"/>\n        </else-if>\n      </choose>\n    </group>\n  </macro>\n  <!-- 7.6. Columns, sections, and other recurring titled features (MLA 5.116) -->\n  <macro name=\"supplemental-columns-sections\">\n    <text text-case=\"title\" variable=\"section\"/>\n  </macro>\n  <!-- 7.7. Multivolume works (MLA 5.117) -->\n  <macro name=\"supplemental-multivolume-works\">\n    <group delimiter=\", \">\n      <choose>\n        <if variable=\"part-number part-title volume volume-title\">\n          <!-- part and title with individual titles -->\n          <group delimiter=\" \">\n            <text macro=\"label-part-number-capitalized\"/>\n            <text value=\"of\"/>\n            <text font-style=\"italic\" text-case=\"title\" variable=\"volume-title\"/>\n          </group>\n          <group delimiter=\" \">\n            <text macro=\"label-volume\"/>\n            <text value=\"of\"/>\n            <group delimiter=\", \">\n              <choose>\n                <if variable=\"container-title\">\n                  <text font-style=\"italic\" text-case=\"title\" variable=\"container-title\"/>\n                </if>\n                <else>\n                  <text macro=\"title-primary\"/>\n                </else>\n              </choose>\n              <names variable=\"collection-editor\">\n                <name initialize=\"false\"/>\n                <label prefix=\", \"/>\n              </names>\n            </group>\n          </group>\n        </if>\n        <else-if match=\"any\" variable=\"part-title volume-title\">\n          <group delimiter=\" \">\n            <choose>\n              <if variable=\"part-number volume\">\n                <group delimiter=\", \">\n                  <text macro=\"label-volume-capitalized\"/>\n                  <text macro=\"label-part-number\"/>\n                  <text value=\"of\"/>\n                </group>\n              </if>\n              <else-if variable=\"part-number\">\n                <text macro=\"label-part-number-capitalized\"/>\n                <text value=\"of\"/>\n              </else-if>\n              <else-if variable=\"volume\">\n                <text macro=\"label-volume-capitalized\"/>\n                <text value=\"of\"/>\n              </else-if>\n            </choose>\n            <group delimiter=\", \">\n              <choose>\n                <if variable=\"container-title\">\n                  <text font-style=\"italic\" text-case=\"title\" variable=\"container-title\"/>\n                </if>\n                <else>\n                  <text macro=\"title-primary\"/>\n                </else>\n              </choose>\n              <names variable=\"collection-editor\">\n                <name initialize=\"false\"/>\n                <label prefix=\", \"/>\n              </names>\n            </group>\n          </group>\n        </else-if>\n        <!-- numbers without a volume title appear in `container1-number` -->\n      </choose>\n      <choose>\n        <if match=\"none\" variable=\"volume\">\n          <text macro=\"label-number-of-volumes\"/>\n        </if>\n      </choose>\n      <!-- TODO: provide container date here when available -->\n    </group>\n  </macro>\n  <citation disambiguate-add-givenname=\"true\" disambiguate-add-names=\"true\" et-al-min=\"3\" et-al-use-first=\"1\">\n    <layout delimiter=\"; \" prefix=\"(\" suffix=\")\">\n      <choose>\n        <if locator=\"line page timestamp\" match=\"any\">\n          <group delimiter=\" \">\n            <text macro=\"author-short\"/>\n            <text variable=\"locator\"/>\n          </group>\n        </if>\n        <else>\n          <group delimiter=\", \">\n            <text macro=\"author-short\"/>\n            <text macro=\"label-locator\"/>\n          </group>\n        </else>\n      </choose>\n    </layout>\n  </citation>\n  <bibliography entry-spacing=\"0\" et-al-min=\"3\" et-al-use-first=\"1\" hanging-indent=\"true\" line-spacing=\"2\" subsequent-author-substitute=\"&#8212;&#8212;&#8212;\">\n    <sort>\n      <key macro=\"author\"/>\n      <key macro=\"title\"/>\n      <key macro=\"supplemental-element-after-title\"/>\n      <key macro=\"container1\"/>\n      <key macro=\"supplemental-element-between\"/>\n      <key macro=\"container2\"/>\n      <key macro=\"supplemental-element-end\"/>\n    </sort>\n    <layout suffix=\".\">\n      <group delimiter=\". \">\n        <text macro=\"author\"/>\n        <text macro=\"title\"/>\n        <text macro=\"supplemental-element-after-title\"/>\n        <text macro=\"container1\"/>\n        <text macro=\"supplemental-element-between\"/>\n        <text macro=\"container2\"/>\n        <text macro=\"supplemental-element-end\"/>\n      </group>\n    </layout>\n  </bibliography>\n</style>\n",
  "chicago": "<?xml version=\"1.0\" encoding=\"utf-8\"?>\n<style xmlns=\"http://purl.org/net/xbiblio/csl\" class=\"in-text\" demote-non-dropping-particle=\"display-and-sort\" initialize-with=\". \" page-range-format=\"chicago-16\" version=\"1.0\">\n  <!-- This file was generated by the Style Variant Builder <https://github.com/citation-style-language/style-variant-builder>. To contribute changes, modify the template and regenerate variants. -->\n  <info>\n    <title>Chicago Manual of Style 18th edition (author-date)</title>\n    <title-short>CMOS/CMS with Bluebook (author-date/AD [13.102])</title-short>\n    <id>http://www.zotero.org/styles/chicago-author-date</id>\n    <link href=\"http://www.zotero.org/styles/chicago-author-date\" rel=\"self\"/>\n    <link href=\"http://www.zotero.org/styles/chicago-notes-bibliography\" rel=\"template\"/>\n    <link href=\"https://www.chicagomanualofstyle.org/\" rel=\"documentation\"/>\n    <link href=\"https://zotero.org/groups/2205533/collections/5V67EPX3\" rel=\"documentation\"/>\n    <author>\n      <name>Andrew Dunning</name>\n      <uri>https://orcid.org/0000-0003-0464-5036</uri>\n    </author>\n    <category citation-format=\"author-date\"/>\n    <category field=\"anthropology\"/>\n    <category field=\"communications\"/>\n    <category field=\"generic-base\"/>\n    <category field=\"geography\"/>\n    <category field=\"history\"/>\n    <category field=\"humanities\"/>\n    <category field=\"law\"/>\n    <category field=\"linguistics\"/>\n    <category field=\"literature\"/>\n    <category field=\"philosophy\"/>\n    <category field=\"political_science\"/>\n    <category field=\"science\"/>\n    <category field=\"social_science\"/>\n    <category field=\"sociology\"/>\n    <category field=\"theology\"/>\n    <summary>Chicago-style source citations (with Bluebook for legal citations), author-date system</summary>\n    <updated>2025-02-09T00:00:00+00:00</updated>\n    <rights license=\"http://creativecommons.org/licenses/by-sa/3.0/\">This work is licensed under a Creative Commons Attribution-ShareAlike 3.0 License</rights>\n  </info>\n  <locale xml:lang=\"en\">\n    <terms>\n      <!-- Chicago omits 'by' from `verb-short` forms; it abbreviates only the most common roles -->\n      <term name=\"advance-online-publication\">ahead of print</term>\n      <term name=\"anonymous\">unsigned</term>\n      <term form=\"verb-short\" name=\"collection-editor\">ed.</term>\n      <term form=\"short\" name=\"collection-number\">\n        <single>vol.</single>\n        <multiple>vols.</multiple>\n      </term>\n      <term form=\"verb-short\" name=\"compiler\">comp.</term>\n      <term form=\"verb-short\" name=\"editor\">ed.</term>\n      <term form=\"short\" name=\"editor-translator\">\n        <single>ed. and trans.</single>\n        <multiple>eds. and trans.</multiple>\n      </term>\n      <term form=\"short\" name=\"editortranslator\">\n        <single>ed. and trans.</single>\n        <multiple>eds. and trans.</multiple>\n      </term>\n      <term form=\"verb\" name=\"editor-translator\">edited and translated by</term>\n      <term form=\"verb\" name=\"editortranslator\">edited and translated by</term>\n      <term form=\"verb-short\" name=\"editor-translator\">ed. and trans.</term>\n      <term form=\"verb-short\" name=\"editortranslator\">ed. and trans.</term>\n      <term form=\"verb-short\" name=\"illustrator\">ill.</term>\n      <term form=\"short\" name=\"legislation\">Pub. L.</term>\n      <term name=\"manuscript\">unpublished manuscript</term>\n      <term name=\"original-work-published\">originally published as</term>\n      <term form=\"short\" name=\"paper-conference\">paper</term>\n      <!-- 'under' replaces 's.v.' from CMOS17 and earlier (CMOS18 14.130) -->\n      <term name=\"sub-verbo\">under</term>\n      <term form=\"short\" name=\"sub-verbo\">under</term>\n      <term name=\"timestamp\">at</term>\n      <term form=\"verb-short\" name=\"translator\">trans.</term>\n    </terms>\n  </locale>\n  <locale xml:lang=\"en-GB\">\n    <terms>\n      <!-- the Bibliography of Additional Resources recommends the New Oxford Style Manual as a British English guide, which the `en-GB` locale follows -->\n      <term form=\"short\" name=\"collection-number\">\n        <single>vol.</single>\n        <multiple>vols</multiple>\n      </term>\n      <term form=\"short\" name=\"editor-translator\">\n        <single>ed. and trans.</single>\n        <multiple>eds and trans.</multiple>\n      </term>\n      <term form=\"short\" name=\"editortranslator\">\n        <single>ed. and trans.</single>\n        <multiple>eds and trans.</multiple>\n      </term>\n      <term form=\"verb-short\" name=\"illustrator\">illus.</term>\n    </terms>\n  </locale>\n  <!-- Contents:\n    \n       This file interprets Chicago using APA's four basic reference elements\n       (cf. CMOS18 14.2, 14.64, 14.161):\n\n        1. Author (CMOS18 13.74-86)\n        2. Date (author-date system only, CMOS18 13.102)\n        3. Title and descriptions (CMOS18 13.87-101)\n            3.1. Title\n            3.2. Description\n            3.3. Identifiers (edition, contributors, volume)\n        4. Source\n            4.1. Serial sources\n            4.2. Monographic sources\n            4.3. Series\n            4.4. Event\n            4.5. Publisher\n            4.6. Date\n            4.7. Locator (including page references)\n            4.8. Medium\n            4.9. Archival location\n            4.10. URL or persistent identifier\n      \n       Freeform annotations to bibliography entries: \n        \n        5. Notes\n       \n       Chicago also provides parallel rules for legal references following\n       The Bluebook: A Uniform System of Citation (code shared with APA):\n\n        6. Legal references\n  -->\n  <!-- In this file, macros suffixed `-bib` and `-note` are parallel versions\n       of the same features for the bibliography and notes, and all changes\n       must be applied to both. They should only contain differences of\n       punctuation (periods in bibliography, commas in notes) and capitalization,\n       except where the comments indicate structural changes. -->\n  <!-- Categories of CSL item types:\n\n       Serial\n       : article-journal article-magazine article-newspaper periodical post-weblog review review-book\n\n       Serial or Monographic\n       : interview paper-conference\n\n         Monographic with any of `collection-editor compiler editor editorial-director`.\n         A serial `paper-conference` is unpublished if it lacks any of `issue page supplement-number volume`.\n\n       Monographic\n       : article book broadcast chapter classic collection dataset document\n         entry entry-dictionary entry-encyclopedia event figure\n         graphic manuscript map motion_picture musical_score\n         pamphlet patent performance personal_communication post report\n         software song speech standard thesis webpage\n\n       Legal\n       : bill hearing legal_case legislation regulation treaty\n  -->\n  <!-- Variable labels -->\n  <macro name=\"label-chapter-number\">\n    <group delimiter=\" \">\n      <choose>\n        <if is-numeric=\"chapter-number\" type=\"song\">\n          <text value=\"track\"/>\n        </if>\n        <else-if is-numeric=\"chapter-number\">\n          <label form=\"short\" variable=\"chapter-number\"/>\n        </else-if>\n      </choose>\n      <text variable=\"chapter-number\"/>\n    </group>\n  </macro>\n  <macro name=\"label-chapter-number-capitalized\">\n    <group delimiter=\" \">\n      <choose>\n        <if is-numeric=\"chapter-number\" type=\"song\">\n          <text text-case=\"capitalize-first\" value=\"track\"/>\n        </if>\n        <else-if is-numeric=\"chapter-number\">\n          <label form=\"short\" text-case=\"capitalize-first\" variable=\"chapter-number\"/>\n        </else-if>\n      </choose>\n      <text text-case=\"capitalize-first\" variable=\"chapter-number\"/>\n    </group>\n  </macro>\n  <macro name=\"label-collection-number\">\n    <group delimiter=\" \">\n      <choose>\n        <if is-numeric=\"collection-number\">\n          <label form=\"short\" variable=\"collection-number\"/>\n        </if>\n      </choose>\n      <text variable=\"collection-number\"/>\n    </group>\n  </macro>\n  <macro name=\"label-edition\">\n    <group delimiter=\" \">\n      <choose>\n        <if is-numeric=\"edition\">\n          <number form=\"ordinal\" variable=\"edition\"/>\n          <label form=\"short\" variable=\"edition\"/>\n        </if>\n        <else-if match=\"any\" type=\"article-journal article-magazine article-newspaper periodical post-weblog review review-book\">\n          <!-- serial types: full label (CMOS18 14.89) -->\n          <text variable=\"edition\"/>\n          <label variable=\"edition\"/>\n        </else-if>\n        <else-if match=\"any\" variable=\"collection-editor compiler editor editorial-director\">\n          <!-- monographic types -->\n          <text variable=\"edition\"/>\n        </else-if>\n        <else-if match=\"any\" type=\"interview paper-conference\">\n          <!-- serial types -->\n          <text variable=\"edition\"/>\n          <label variable=\"edition\"/>\n        </else-if>\n        <else>\n          <!-- monographic types -->\n          <text variable=\"edition\"/>\n        </else>\n      </choose>\n    </group>\n  </macro>\n  <macro name=\"label-edition-capitalized\">\n    <group delimiter=\" \">\n      <choose>\n        <if is-numeric=\"edition\">\n          <number form=\"ordinal\" variable=\"edition\"/>\n          <label form=\"short\" variable=\"edition\"/>\n        </if>\n        <else-if match=\"any\" type=\"article-journal article-magazine article-newspaper periodical post-weblog review review-book\">\n          <!-- serial types: full label (CMOS18 14.89) -->\n          <text text-case=\"title\" variable=\"edition\"/>\n          <label text-case=\"capitalize-first\" variable=\"edition\"/>\n        </else-if>\n        <else-if match=\"any\" variable=\"collection-editor compiler editor editorial-director\">\n          <!-- monographic types -->\n          <text text-case=\"capitalize-first\" variable=\"edition\"/>\n        </else-if>\n        <else-if match=\"any\" type=\"interview paper-conference\">\n          <!-- serial types -->\n          <text text-case=\"title\" variable=\"edition\"/>\n          <label text-case=\"capitalize-first\" variable=\"edition\"/>\n        </else-if>\n        <else>\n          <!-- monographic types -->\n          <text text-case=\"capitalize-first\" variable=\"edition\"/>\n        </else>\n      </choose>\n    </group>\n  </macro>\n  <macro name=\"label-issue\">\n    <group delimiter=\" \">\n      <label form=\"short\" variable=\"issue\"/>\n      <text variable=\"issue\"/>\n    </group>\n  </macro>\n  <macro name=\"label-locator\">\n    <group delimiter=\" \">\n      <choose>\n        <if locator=\"page\"/>\n        <else-if match=\"any\" type=\"bill hearing legal_case legislation regulation treaty\">\n          <!-- Bluebook-style labels for legal types (CMOS18 14.174) -->\n          <choose>\n            <if locator=\"chapter paragraph section\" match=\"any\">\n              <label form=\"symbol\" variable=\"locator\"/>\n            </if>\n            <else>\n              <label form=\"short\" variable=\"locator\"/>\n            </else>\n          </choose>\n        </else-if>\n        <else-if is-numeric=\"locator\" locator=\"line\">\n          <label variable=\"locator\"/>\n        </else-if>\n        <else-if is-numeric=\"locator\">\n          <label form=\"short\" variable=\"locator\"/>\n        </else-if>\n        <else-if locator=\"chapter line verse\" match=\"any\"/>\n        <!-- a non-numeric canonical reference is identified by its formatting and does not need a label (CMOS18 14.143-54) -->\n        <else>\n          <label form=\"short\" variable=\"locator\"/>\n        </else>\n      </choose>\n      <text variable=\"locator\"/>\n    </group>\n  </macro>\n  <macro name=\"label-locator-all\">\n    <group delimiter=\" \">\n      <label form=\"short\" variable=\"locator\"/>\n      <text variable=\"locator\"/>\n    </group>\n  </macro>\n  <macro name=\"label-number-capitalized\">\n    <group delimiter=\" \">\n      <choose>\n        <if type=\"standard\"/>\n        <else-if is-numeric=\"number\" match=\"any\" type=\"legislation regulation\">\n          <label form=\"short\" text-case=\"capitalize-first\" variable=\"number\"/>\n        </else-if>\n      </choose>\n      <text text-case=\"capitalize-first\" variable=\"number\"/>\n    </group>\n  </macro>\n  <macro name=\"label-number-of-volumes\">\n    <group delimiter=\" \">\n      <text variable=\"number-of-volumes\"/>\n      <choose>\n        <if is-numeric=\"number-of-volumes\">\n          <label form=\"short\" variable=\"number-of-volumes\"/>\n        </if>\n      </choose>\n    </group>\n  </macro>\n  <macro name=\"label-page\">\n    <group delimiter=\" \">\n      <label form=\"short\" variable=\"page\"/>\n      <text variable=\"page\"/>\n    </group>\n  </macro>\n  <macro name=\"label-part-number\">\n    <group delimiter=\" \">\n      <choose>\n        <if is-numeric=\"part-number\">\n          <!-- TODO: Replace with `part-number` label when CSL provides one -->\n          <text form=\"short\" term=\"part\"/>\n        </if>\n      </choose>\n      <text variable=\"part-number\"/>\n    </group>\n  </macro>\n  <macro name=\"label-part-number-capitalized\">\n    <group delimiter=\" \">\n      <choose>\n        <if is-numeric=\"part-number\">\n          <!-- TODO: Replace with `part-number` label when CSL provides one -->\n          <text form=\"short\" term=\"part\" text-case=\"capitalize-first\"/>\n        </if>\n      </choose>\n      <text text-case=\"capitalize-first\" variable=\"part-number\"/>\n    </group>\n  </macro>\n  <macro name=\"label-section-capitalized\">\n    <group delimiter=\" \">\n      <choose>\n        <if is-numeric=\"section\">\n          <label form=\"short\" text-case=\"capitalize-first\" variable=\"section\"/>\n        </if>\n      </choose>\n      <text text-case=\"title\" variable=\"section\"/>\n    </group>\n  </macro>\n  <macro name=\"label-section-symbol\">\n    <group delimiter=\" \">\n      <label form=\"symbol\" variable=\"section\"/>\n      <text variable=\"section\"/>\n    </group>\n  </macro>\n  <macro name=\"label-supplement-number\">\n    <group delimiter=\" \">\n      <choose>\n        <!-- TODO: Replace with `supplement-number` label when CSL provides one -->\n        <if variable=\"issue supplement-number\">\n          <!-- if there is both an issue and supplement number, do not label both as 'no.' -->\n          <text form=\"short\" term=\"supplement\"/>\n        </if>\n        <else-if is-numeric=\"supplement-number\" variable=\"volume-title\">\n          <!-- if there is a volume title, it is already described as a supplement -->\n          <text form=\"short\" term=\"issue\"/>\n        </else-if>\n        <else-if is-numeric=\"supplement-number\" type=\"periodical\" variable=\"title\">\n          <text form=\"short\" term=\"issue\"/>\n        </else-if>\n        <else-if is-numeric=\"supplement-number\">\n          <text form=\"short\" term=\"supplement\"/>\n        </else-if>\n      </choose>\n      <text variable=\"supplement-number\"/>\n    </group>\n  </macro>\n  <macro name=\"label-version\">\n    <group delimiter=\" \">\n      <choose>\n        <if type=\"software\">\n          <!-- short version label for software (CMOS18 14.169) -->\n          <label form=\"short\" variable=\"version\"/>\n        </if>\n        <else>\n          <label variable=\"version\"/>\n        </else>\n      </choose>\n      <text variable=\"version\"/>\n    </group>\n  </macro>\n  <macro name=\"label-version-capitalized\">\n    <group delimiter=\" \">\n      <choose>\n        <if type=\"software\">\n          <!-- short version label for software (CMOS18 14.169) -->\n          <label form=\"short\" text-case=\"capitalize-first\" variable=\"version\"/>\n        </if>\n        <else>\n          <label text-case=\"capitalize-first\" variable=\"version\"/>\n        </else>\n      </choose>\n      <text variable=\"version\"/>\n    </group>\n  </macro>\n  <macro name=\"label-volume\">\n    <group delimiter=\" \">\n      <choose>\n        <if is-numeric=\"volume\">\n          <label form=\"short\" variable=\"volume\"/>\n        </if>\n      </choose>\n      <text variable=\"volume\"/>\n      <!-- always display number of volumes in notes without bibliography (CMOS18 14.20): -->\n      <!-- <choose><if is-numeric=\"number-of-volumes\" variable=\"volume\"><text value=\"of\"/><text variable=\"number-of-volumes\"/></if></choose>-->\n    </group>\n  </macro>\n  <macro name=\"label-volume-capitalized\">\n    <group delimiter=\" \">\n      <choose>\n        <if is-numeric=\"volume\">\n          <label form=\"short\" text-case=\"capitalize-first\" variable=\"volume\"/>\n        </if>\n      </choose>\n      <text text-case=\"capitalize-first\" variable=\"volume\"/>\n    </group>\n  </macro>\n  <!-- 1. Author (CMOS18 13.74-86) -->\n  <macro name=\"author-bib\">\n    <names variable=\"composer\">\n      <name and=\"text\" delimiter-precedes-last=\"always\" initialize=\"false\" name-as-sort-order=\"first\"/>\n      <label form=\"short\" prefix=\", \"/>\n      <substitute>\n        <names variable=\"author\"/>\n        <!-- cf. `interview` model (CMOS18 14.110); if it is desired to prioritize `host` over `guest`, the latter could be encoded as a `contributor` -->\n        <names variable=\"guest\"/>\n        <names variable=\"host\"/>\n        <choose>\n          <if type=\"song\">\n            <names variable=\"performer\"/>\n          </if>\n        </choose>\n        <choose>\n          <if type=\"classic\">\n            <!-- contributors fall after the title of `classic` (CMOS18 14.147) -->\n            <text macro=\"author-title-substitute-bib\"/>\n          </if>\n          <else-if type=\"entry-dictionary\" variable=\"container-title\">\n            <!-- contributors fall after the title of unsigned reference entries (CMOS18 14.130) -->\n            <text macro=\"author-title-substitute-container\"/>\n          </else-if>\n          <else-if type=\"entry-encyclopedia\" variable=\"container-title\">\n            <text macro=\"author-title-substitute-container\"/>\n          </else-if>\n        </choose>\n        <names variable=\"illustrator\"/>\n        <choose>\n          <if match=\"none\" type=\"standard\">\n            <names variable=\"editor-translator\"/>\n            <names variable=\"editor\"/>\n            <names variable=\"translator\"/>\n            <names variable=\"collection-editor\"/>\n          </if>\n        </choose>\n        <names variable=\"director\"/>\n        <choose>\n          <!-- serial `broadcast` prioritizes title (CMOS18 14.165, 14.168) -->\n          <if type=\"broadcast\" variable=\"container-title number title\"/>\n          <else>\n            <names variable=\"producer\"/>\n            <names variable=\"executive-producer\"/>\n            <names variable=\"series-creator\"/>\n            <choose>\n              <if type=\"broadcast\">\n                <names variable=\"contributor\"/>\n              </if>\n            </choose>\n          </else>\n        </choose>\n        <names variable=\"editorial-director\"/>\n        <names variable=\"compiler\"/>\n        <choose>\n          <if match=\"any\" type=\"event performance speech\">\n            <names variable=\"chair\"/>\n            <names variable=\"organizer\"/>\n          </if>\n        </choose>\n        <names variable=\"curator\"/>\n        <choose>\n          <if match=\"any\" type=\"software webpage\">\n            <!-- `software` listed under the name of the publisher or developer (CMOS18 14.169); `webpage` listed under a site owner or sponsor (CMOS18 14.104) -->\n            <text variable=\"publisher\"/>\n          </if>\n          <else-if type=\"standard\">\n            <!-- `standard` listed in bibliography under organization, but note omits this (CMOS18 14.159) -->\n            <text variable=\"authority\"/>\n          </else-if>\n        </choose>\n        <text macro=\"author-title-substitute-container\"/>\n        <text macro=\"author-title-substitute-bib\"/>\n        <choose>\n          <if match=\"any\" variable=\"container-title event-date event-place event-title genre title publisher publisher-place\"/>\n          <else-if type=\"manuscript\">\n            <text macro=\"source-archive-bib\"/>\n          </else-if>\n        </choose>\n      </substitute>\n    </names>\n  </macro>\n  <macro name=\"author-inline\">\n    <choose>\n      <if match=\"any\" type=\"bill hearing legal_case legislation regulation treaty\">\n        <text macro=\"title-and-descriptions-short\"/>\n      </if>\n      <else-if match=\"any\" type=\"interview personal_communication\">\n        <text macro=\"author-inline-and-recipient\"/>\n      </else-if>\n      <else>\n        <names variable=\"composer\">\n          <name and=\"text\" form=\"short\" initialize=\"true\"/>\n          <substitute>\n            <names variable=\"author\"/>\n            <names variable=\"guest\"/>\n            <names variable=\"host\"/>\n            <choose>\n              <if type=\"song\">\n                <names variable=\"performer\"/>\n              </if>\n            </choose>\n            <choose>\n              <if match=\"any\" type=\"classic performance\">\n                <!-- contributors fall after the title of `classic` (CMOS18 14.147), `performance` (CMOS18 14.166) -->\n                <text macro=\"author-title-substitute-short\"/>\n              </if>\n              <else-if match=\"any\" type=\"entry entry-dictionary entry-encyclopedia\">\n                <!-- contributors fall after the title of unsigned reference entries (CMOS18 14.130) -->\n                <text macro=\"author-title-substitute-container\"/>\n              </else-if>\n            </choose>\n            <names variable=\"illustrator\"/>\n            <choose>\n              <if match=\"none\" type=\"standard\">\n                <names variable=\"editor-translator\"/>\n                <names variable=\"editor\"/>\n                <names variable=\"translator\"/>\n                <names variable=\"collection-editor\"/>\n              </if>\n            </choose>\n            <choose>\n              <if type=\"broadcast\" variable=\"container-title number title\"/>\n              <else>\n                <names variable=\"director\"/>\n                <names variable=\"producer\"/>\n                <names variable=\"executive-producer\"/>\n                <names variable=\"series-creator\"/>\n                <choose>\n                  <if type=\"broadcast\">\n                    <names variable=\"contributor\"/>\n                  </if>\n                </choose>\n              </else>\n            </choose>\n            <names variable=\"editorial-director\"/>\n            <names variable=\"compiler\"/>\n            <choose>\n              <if match=\"any\" type=\"event performance speech\">\n                <names variable=\"chair\"/>\n                <names variable=\"organizer\"/>\n              </if>\n            </choose>\n            <names variable=\"curator\"/>\n            <choose>\n              <if match=\"any\" type=\"software webpage\">\n                <!-- `software` listed under the name of the publisher or developer (CMOS18 14.169); `webpage` listed under a site owner or sponsor (CMOS18 14.104) -->\n                <text form=\"short\" variable=\"publisher\"/>\n              </if>\n              <else-if type=\"standard\">\n                <!-- `standard` listed in bibliography under organization, but note omits this (CMOS18 14.159) -->\n                <text form=\"short\" variable=\"authority\"/>\n              </else-if>\n            </choose>\n            <text macro=\"author-title-substitute-container-short\"/>\n            <text macro=\"author-title-substitute-short\"/>\n            <choose>\n              <if match=\"any\" variable=\"container-title event-date event-place event-title genre title publisher publisher-place\"/>\n              <else-if type=\"manuscript\">\n                <text macro=\"source-archive-note\"/>\n              </else-if>\n            </choose>\n          </substitute>\n        </names>\n      </else>\n    </choose>\n  </macro>\n  <macro name=\"author-sort\">\n    <choose>\n      <if match=\"any\" type=\"bill hearing legal_case legislation regulation treaty\">\n        <text macro=\"legal-title\"/>\n      </if>\n      <else>\n        <text macro=\"author-bib\"/>\n      </else>\n    </choose>\n  </macro>\n  <!-- Author elements -->\n  <macro name=\"author-inline-and-recipient\">\n    <!-- identical to `author-short-and-recipient` but with initialization -->\n    <group delimiter=\" \">\n      <choose>\n        <!-- inaccessible `interview` or `personal_commmunication`: in-text citation (CMOS18 14.111) -->\n        <if match=\"none\" variable=\"archive archive-place container-title DOI number publisher references URL\">\n          <choose>\n            <if position=\"first\">\n              <!-- do not shorten at first reference as there is no bibliography entry -->\n              <names variable=\"author\">\n                <name and=\"text\" initialize=\"false\"/>\n                <!-- never initialize -->\n                <substitute>\n                  <text macro=\"title-and-descriptions-short\"/>\n                </substitute>\n              </names>\n            </if>\n            <else>\n              <names variable=\"author\">\n                <name and=\"text\" form=\"short\" initialize=\"true\"/>\n                <substitute>\n                  <text macro=\"title-and-descriptions-short\"/>\n                </substitute>\n              </names>\n            </else>\n          </choose>\n          <choose>\n            <if variable=\"genre\"/>\n            <!-- recipient appears in the description if there is a `genre`; otherwise after `author` -->\n            <else-if position=\"first\">\n              <names variable=\"recipient\">\n                <label form=\"verb\" suffix=\" \"/>\n                <name and=\"text\" initialize=\"false\"/>\n              </names>\n            </else-if>\n            <else>\n              <names variable=\"recipient\">\n                <label form=\"verb\" suffix=\" \"/>\n                <name and=\"text\" form=\"short\" initialize=\"true\"/>\n              </names>\n            </else>\n          </choose>\n        </if>\n        <!-- accessible `interview` or `personal_communication`: standard citation -->\n        <else-if variable=\"author recipient\">\n          <names variable=\"author\">\n            <name and=\"text\" form=\"short\" initialize=\"true\"/>\n          </names>\n          <choose>\n            <if match=\"none\" variable=\"genre\">\n              <names variable=\"recipient\">\n                <label form=\"verb\" suffix=\" \"/>\n                <name and=\"text\" form=\"short\" initialize=\"true\"/>\n              </names>\n            </if>\n          </choose>\n        </else-if>\n        <else>\n          <names variable=\"author\">\n            <name and=\"text\" form=\"short\" initialize=\"true\"/>\n            <substitute>\n              <text macro=\"title-and-descriptions-short\"/>\n            </substitute>\n          </names>\n        </else>\n      </choose>\n    </group>\n  </macro>\n  <macro name=\"author-title-substitute-bib\">\n    <choose>\n      <if match=\"any\" type=\"review review-book\" variable=\"reviewed-author reviewed-genre reviewed-title\">\n        <!-- If a review has no `reviewed-genre` or `reviewed-title`, assume that `title` contains the title of the reviewed work; the description provides it. -->\n        <choose>\n          <if variable=\"reviewed-genre title\">\n            <text macro=\"title-bib\"/>\n          </if>\n          <else-if variable=\"reviewed-genre reviewed-title title\">\n            <text macro=\"title-bib\"/>\n          </else-if>\n          <else>\n            <text macro=\"title-and-descriptions-bib\"/>\n          </else>\n        </choose>\n      </if>\n      <else-if variable=\"title\">\n        <text macro=\"title-bib\"/>\n      </else-if>\n      <else>\n        <!-- If an item has no `title`, substitute with descriptions. -->\n        <text macro=\"title-and-descriptions-bib\"/>\n      </else>\n    </choose>\n  </macro>\n  <macro name=\"author-title-substitute-short\">\n    <choose>\n      <if match=\"any\" type=\"review review-book\" variable=\"reviewed-author reviewed-genre reviewed-title\">\n        <!-- If a review has no `reviewed-genre` or `reviewed-title`, assume that `title` contains the title of the reviewed work; the description provides it. -->\n        <choose>\n          <if variable=\"reviewed-genre title\">\n            <text macro=\"title-short\"/>\n          </if>\n          <else-if variable=\"reviewed-genre reviewed-title title\">\n            <text macro=\"title-short\"/>\n          </else-if>\n          <else>\n            <text macro=\"title-and-descriptions-short\"/>\n          </else>\n        </choose>\n      </if>\n      <else-if variable=\"title\">\n        <text macro=\"title-short\"/>\n      </else-if>\n      <else>\n        <!-- If an item has no `title`, substitute with descriptions and capitalize -->\n        <text macro=\"title-and-descriptions-bib\"/>\n      </else>\n    </choose>\n  </macro>\n  <macro name=\"author-title-substitute-container\">\n    <choose>\n      <!-- no Chicago model for citing an anonymous article with an issue title in `volume-title` -->\n      <if variable=\"volume-title\"/>\n      <else-if match=\"any\" type=\"article-magazine article-newspaper\">\n        <!-- Anonymous magazine and newspaper articles substitute name of publication (CMOS18 14.87, 14.97) -->\n        <text macro=\"source-serial-name\"/>\n      </else-if>\n      <else-if match=\"any\" type=\"review review-book\" variable=\"reviewed-author reviewed-genre reviewed-title\">\n        <!-- Publication name also substituted for unsigned reviews (CMOS18 14.102) -->\n        <text macro=\"source-serial-name\"/>\n      </else-if>\n      <else-if match=\"any\" type=\"entry entry-dictionary entry-encyclopedia\">\n        <!-- Anonymous entries in reference works (CMOS18 14.130) -->\n        <text font-style=\"italic\" text-case=\"title\" variable=\"container-title\"/>\n      </else-if>\n      <else-if type=\"broadcast\">\n        <!-- TV broadcasts and podcasts (CMOS18 14.165, 14.168) -->\n        <text font-style=\"italic\" text-case=\"title\" variable=\"container-title\"/>\n      </else-if>\n      <else-if type=\"webpage\">\n        <!-- list a webpage under the website title if there is no owner or sponsor (CMOS18 14.104) -->\n        <text text-case=\"title\" variable=\"container-title\"/>\n      </else-if>\n    </choose>\n  </macro>\n  <macro name=\"author-title-substitute-container-short\">\n    <choose>\n      <if match=\"any\" type=\"article-magazine article-newspaper\">\n        <!-- Anonymous magazine/newspaper articles substitute name of publication (CMOS18 14.87, 14.97) -->\n        <text font-style=\"italic\" text-case=\"title\" variable=\"container-title\"/>\n      </if>\n      <else-if match=\"any\" type=\"review review-book\" variable=\"reviewed-author reviewed-genre reviewed-title\">\n        <!-- Publication name also substituted for unsigned reviews (CMOS18 14.102) -->\n        <text font-style=\"italic\" text-case=\"title\" variable=\"container-title\"/>\n      </else-if>\n      <else-if match=\"any\" type=\"entry entry-dictionary entry-encyclopedia\">\n        <!-- Anonymous entries in reference works (CMOS18 14.130) -->\n        <text font-style=\"italic\" form=\"short\" text-case=\"title\" variable=\"container-title\"/>\n      </else-if>\n      <else-if type=\"broadcast\">\n        <!-- TV broadcasts and podcasts (CMOS18 14.165, 14.168) -->\n        <text font-style=\"italic\" form=\"short\" text-case=\"title\" variable=\"container-title\"/>\n      </else-if>\n      <else-if type=\"webpage\">\n        <!-- list a webpage under the website title if there is no owner or sponsor (CMOS18 14.104) -->\n        <text form=\"short\" text-case=\"title\" variable=\"container-title\"/>\n      </else-if>\n    </choose>\n  </macro>\n  <!-- 2. Date (CMOS18 13.102) -->\n  <macro name=\"date\">\n    <group delimiter=\"-\">\n      <choose>\n        <if variable=\"issued\">\n          <group delimiter=\" \">\n            <!-- reprints and earlier editions may give original year in brackets (CMOS18 14.16) -->\n            <text macro=\"date-original-year\" prefix=\"(\" suffix=\")\"/>\n            <group>\n              <text macro=\"date-issued-year\"/>\n              <text variable=\"year-suffix\"/>\n            </group>\n          </group>\n        </if>\n        <else-if variable=\"event-date\">\n          <text macro=\"date-event-year\"/>\n        </else-if>\n        <else-if variable=\"available-date\">\n          <date date-parts=\"year\" form=\"numeric\" variable=\"available-date\"/>\n        </else-if>\n        <else-if variable=\"status\">\n          <!-- Print the status variable rather than use generic CSL terms (`in press`, etc.) -->\n          <text text-case=\"capitalize-first\" variable=\"status\"/>\n          <text variable=\"year-suffix\"/>\n        </else-if>\n        <else-if type=\"collection\">\n          <!-- do not give n.d. for archival collections (CMOS18 14.128) -->\n          <text variable=\"year-suffix\"/>\n        </else-if>\n        <else-if type=\"manuscript\">\n          <!-- do not give n.d. with a bare shelfmark -->\n          <choose>\n            <if match=\"any\" variable=\"container-title event-date event-place event-title genre title publisher publisher-place\">\n              <text form=\"short\" term=\"no date\"/>\n              <text variable=\"year-suffix\"/>\n            </if>\n          </choose>\n        </else-if>\n        <else>\n          <text form=\"short\" term=\"no date\"/>\n          <text variable=\"year-suffix\"/>\n        </else>\n      </choose>\n    </group>\n  </macro>\n  <macro name=\"date-short\">\n    <group delimiter=\"-\">\n      <choose>\n        <if variable=\"issued\">\n          <group delimiter=\" \">\n            <choose>\n              <if is-uncertain-date=\"original-date\">\n                <!-- Uncertain date already has square brackets -->\n                <text macro=\"date-original-year\"/>\n              </if>\n              <else>\n                <text macro=\"date-original-year\" prefix=\"[\" suffix=\"]\"/>\n              </else>\n            </choose>\n            <group>\n              <choose>\n                <if match=\"none\" type=\"interview personal_communication\">\n                  <text macro=\"date-issued-year\"/>\n                </if>\n                <!-- accessible `interview` or `personal_communication` items appear in the bibliography; inaccessible items are in-text only -->\n                <else-if match=\"any\" variable=\"archive archive-place container-title DOI number publisher references URL\">\n                  <text macro=\"date-issued-year\"/>\n                </else-if>\n                <else>\n                  <text macro=\"date-issued-full\"/>\n                </else>\n              </choose>\n              <text variable=\"year-suffix\"/>\n            </group>\n          </group>\n        </if>\n        <else-if variable=\"event-date\">\n          <text macro=\"date-event-year\"/>\n        </else-if>\n        <else-if variable=\"available-date\">\n          <date date-parts=\"year\" form=\"numeric\" variable=\"available-date\"/>\n        </else-if>\n        <else-if variable=\"status\">\n          <!-- Print the status variable rather than use generic CSL terms (`in press`, etc.) -->\n          <text text-case=\"lowercase\" variable=\"status\"/>\n          <text variable=\"year-suffix\"/>\n        </else-if>\n        <else-if match=\"any\" type=\"interview personal_communication\">\n          <choose>\n            <if match=\"any\" variable=\"archive archive-place container-title DOI number publisher references URL\">\n              <!-- only give n.d. for accessible personal communication (CMOS18 14.111)-->\n              <text form=\"short\" term=\"no date\"/>\n              <text variable=\"year-suffix\"/>\n            </if>\n          </choose>\n        </else-if>\n        <else-if match=\"any\" type=\"classic collection entry entry-dictionary entry-encyclopedia\">\n          <!-- do not give n.d. for archival collections (CMOS18 14.128), `classic` (CMOS18 14.143), or reference entries (CMOS18 14.131) -->\n          <text variable=\"year-suffix\"/>\n        </else-if>\n        <else-if type=\"manuscript\">\n          <!-- do not give n.d. with a bare shelfmark -->\n          <choose>\n            <if match=\"any\" variable=\"container-title event-date event-place event-title genre title publisher publisher-place\">\n              <text form=\"short\" term=\"no date\"/>\n              <text variable=\"year-suffix\"/>\n            </if>\n          </choose>\n        </else-if>\n        <else>\n          <text form=\"short\" term=\"no date\"/>\n          <text variable=\"year-suffix\"/>\n        </else>\n      </choose>\n    </group>\n  </macro>\n  <macro name=\"date-sort-group\">\n    <!-- Sort items with and without dates (CMOS18 14.44):\n\n          1. items with dates (= 0)\n          2. `no date` items (= 1)\n          3. items with `status` (forthcoming, in press, etc.) (= 2) -->\n    <choose>\n      <if variable=\"issued\">\n        <text value=\"0\"/>\n      </if>\n      <else-if variable=\"status\">\n        <text value=\"2\"/>\n      </else-if>\n      <else>\n        <!-- n.d. -->\n        <text value=\"1\"/>\n      </else>\n    </choose>\n  </macro>\n  <macro name=\"date-sort-year\">\n    <!-- while reference lists are to be sorted chronologically (CMOS18 13.112), it appears that only the year is to be taken into account (CMOS18 13.114) -->\n    <choose>\n      <if type=\"personal_communication\" variable=\"event-date issued\">\n        <date date-parts=\"year\" form=\"numeric\" variable=\"event-date\"/>\n      </if>\n      <else>\n        <text macro=\"date-issued-year\"/>\n      </else>\n    </choose>\n  </macro>\n  <!-- Date elements -->\n  <macro name=\"date-event-full\">\n    <choose>\n      <if is-uncertain-date=\"issued\">\n        <!-- guessed-at date (CMOS18 14.44) -->\n        <date form=\"text\" prefix=\"[\" suffix=\"?]\" variable=\"event-date\"/>\n      </if>\n      <else>\n        <date form=\"text\" variable=\"event-date\"/>\n      </else>\n    </choose>\n  </macro>\n  <macro name=\"date-event-year\">\n    <choose>\n      <if is-uncertain-date=\"issued\">\n        <!-- guessed-at date (CMOS18 14.44) -->\n        <date date-parts=\"year\" form=\"numeric\" prefix=\"[\" suffix=\"?]\" variable=\"event-date\"/>\n      </if>\n      <else>\n        <date date-parts=\"year\" form=\"numeric\" variable=\"event-date\"/>\n      </else>\n    </choose>\n  </macro>\n  <macro name=\"date-issued-full\">\n    <choose>\n      <if is-uncertain-date=\"issued\">\n        <!-- guessed-at date (CMOS18 14.44) -->\n        <date form=\"text\" prefix=\"[\" suffix=\"?]\" variable=\"issued\"/>\n      </if>\n      <else>\n        <date form=\"text\" variable=\"issued\"/>\n      </else>\n    </choose>\n  </macro>\n  <macro name=\"date-issued-month\">\n    <date variable=\"issued\">\n      <date-part name=\"month\"/>\n    </date>\n  </macro>\n  <macro name=\"date-issued-month-day\">\n    <date variable=\"issued\">\n      <date-part name=\"month\"/>\n      <date-part name=\"day\" prefix=\" \"/>\n    </date>\n  </macro>\n  <macro name=\"date-issued-year\">\n    <choose>\n      <if is-uncertain-date=\"issued\">\n        <!-- guessed-at date (CMOS18 14.44) -->\n        <date date-parts=\"year\" form=\"numeric\" prefix=\"[\" suffix=\"?]\" variable=\"issued\"/>\n      </if>\n      <else>\n        <date date-parts=\"year\" form=\"numeric\" variable=\"issued\"/>\n      </else>\n    </choose>\n  </macro>\n  <macro name=\"date-original-month\">\n    <date variable=\"original-date\">\n      <date-part name=\"month\"/>\n    </date>\n  </macro>\n  <macro name=\"date-original-month-day\">\n    <date variable=\"original-date\">\n      <date-part name=\"month\"/>\n      <date-part name=\"day\" prefix=\" \"/>\n    </date>\n  </macro>\n  <macro name=\"date-original-year\">\n    <choose>\n      <if is-uncertain-date=\"original-date\">\n        <date date-parts=\"year\" form=\"numeric\" prefix=\"[\" suffix=\"?]\" variable=\"original-date\"/>\n      </if>\n      <else>\n        <date date-parts=\"year\" form=\"numeric\" variable=\"original-date\"/>\n      </else>\n    </choose>\n  </macro>\n  <!-- 3. Title and descriptions (CMOS18 13.87-101) -->\n  <macro name=\"title-and-descriptions-bib\">\n    <group delimiter=\". \">\n      <choose>\n        <if variable=\"title\">\n          <text macro=\"title-bib\"/>\n          <text macro=\"description-bib\"/>\n          <text macro=\"identifier-bib\"/>\n        </if>\n        <else-if match=\"any\" type=\"bill report\">\n          <!-- Bills, resolutions, and congressional reports substitute bill number if no title -->\n          <!-- Congressional reports are indistinguishable from other reports -->\n          <text macro=\"identifier-number-bib\"/>\n          <text macro=\"identifier-bib\"/>\n          <text macro=\"description-bib\"/>\n        </else-if>\n        <else>\n          <text macro=\"description-bib\"/>\n          <text macro=\"identifier-bib\"/>\n        </else>\n      </choose>\n    </group>\n  </macro>\n  <macro name=\"title-and-descriptions-short\">\n    <choose>\n      <if variable=\"title\">\n        <text macro=\"title-short\"/>\n      </if>\n      <else-if match=\"any\" type=\"bill report\">\n        <!-- Bills, resolutions, and congressional reports substitute bill number if no title -->\n        <text macro=\"legal-identifier-bill-report\"/>\n      </else-if>\n      <else>\n        <text macro=\"description-short\"/>\n      </else>\n    </choose>\n  </macro>\n  <macro name=\"title-and-source-bib\">\n    <group delimiter=\". \">\n      <choose>\n        <if type=\"broadcast\" variable=\"container-title number title\">\n          <!-- Bespoke `broadcast` format (CMOS18 14.165, 14.168) -->\n          <text macro=\"source-monographic-title-specific-title-first\"/>\n          <group delimiter=\", \">\n            <text macro=\"identifier-number-bib\"/>\n            <text macro=\"title-bib\"/>\n            <text macro=\"description-bib\"/>\n            <text macro=\"source-monographic-identifier-contributors-bib\"/>\n          </group>\n          <text macro=\"source-monographic-identifier-contributors-bib-container-author\"/>\n          <text macro=\"source-series-bib\"/>\n          <choose>\n            <!-- show event information here only if not collapsed with `issued` (CMOS18 14.167) -->\n            <if match=\"any\" variable=\"event-date original-date original-publisher original-publisher-place publisher status\">\n              <text macro=\"source-event-bib\"/>\n            </if>\n          </choose>\n        </if>\n        <else-if type=\"chapter\" variable=\"container-title genre\">\n          <!-- 'introduction to', 'online appendix to' (CMOS18 14.12, 14.14) -->\n          <group delimiter=\" \">\n            <text macro=\"title-and-descriptions-bib\"/>\n            <text macro=\"source-bib\"/>\n          </group>\n        </else-if>\n        <else-if type=\"article-journal\" variable=\"container-title genre volume-title\">\n          <!-- introduction to a special issue or supplement -->\n          <group delimiter=\" \">\n            <text macro=\"title-and-descriptions-bib\"/>\n            <text macro=\"source-bib\"/>\n          </group>\n        </else-if>\n        <else>\n          <text macro=\"title-and-descriptions-bib\"/>\n          <text macro=\"source-bib\"/>\n        </else>\n      </choose>\n      <group delimiter=\", \">\n        <choose>\n          <!-- show event information here only if collapsed with `issued` (CMOS18 14.167) -->\n          <if match=\"any\" variable=\"event-date original-date original-publisher original-publisher-place publisher status\"/>\n          <!-- omit serial types -->\n          <else-if match=\"any\" type=\"article-journal article-magazine article-newspaper periodical post-weblog review review-book\"/>\n          <else-if match=\"any\" variable=\"collection-editor compiler editor editorial-director\">\n            <!-- monographic types -->\n            <text macro=\"source-event-bib\"/>\n          </else-if>\n          <!-- omit serial types -->\n          <else-if match=\"any\" type=\"interview paper-conference\"/>\n          <else>\n            <!-- monographic types -->\n            <text macro=\"source-event-bib\"/>\n          </else>\n        </choose>\n        <text macro=\"source-monographic-publication-bib\"/>\n      </group>\n      <text macro=\"source-medium-bib\"/>\n      <text macro=\"source-archive-bib\"/>\n      <text macro=\"source-date-accessed-DOI-URL-bib\"/>\n    </group>\n  </macro>\n  <!-- 3.1. Title -->\n  <macro name=\"title-bib\">\n    <choose>\n      <if match=\"any\" type=\"post webpage\">\n        <!-- part number/title always at the analytic level -->\n        <text macro=\"title-and-part-filter-review-bib\"/>\n      </if>\n      <else-if match=\"any\" type=\"article-journal article-magazine article-newspaper periodical post-weblog review review-book\">\n        <!-- serial types -->\n        <text macro=\"title-and-part-filter-review-bib\"/>\n      </else-if>\n      <else-if match=\"any\" variable=\"collection-editor compiler editor editorial-director\">\n        <!-- monographic types -->\n        <text macro=\"title-monographic-bib-specific-title-first\"/>\n      </else-if>\n      <else-if match=\"any\" type=\"interview paper-conference\">\n        <!-- serial types -->\n        <text macro=\"title-and-part-filter-review-bib\"/>\n      </else-if>\n      <else>\n        <text macro=\"title-monographic-bib-specific-title-first\"/>\n      </else>\n    </choose>\n  </macro>\n  <macro name=\"title-short\">\n    <choose>\n      <if match=\"any\" type=\"review review-book\" variable=\"reviewed-author reviewed-genre reviewed-title\">\n        <!-- If a review has no `reviewed-title`, assume that `title` contains the title of the reviewed work; the description provides it. -->\n        <choose>\n          <if variable=\"reviewed-genre title\">\n            <!-- Quotes, title case -->\n            <text form=\"short\" quotes=\"true\" text-case=\"title\" variable=\"title\"/>\n          </if>\n          <else-if variable=\"reviewed-genre reviewed-title title\">\n            <!-- Quotes, title case -->\n            <text form=\"short\" quotes=\"true\" text-case=\"title\" variable=\"title\"/>\n          </else-if>\n          <else>\n            <text macro=\"description-short\"/>\n          </else>\n        </choose>\n      </if>\n      <else>\n        <text macro=\"title-primary-short\"/>\n      </else>\n    </choose>\n  </macro>\n  <!-- Title elements -->\n  <macro name=\"title-and-part-filter-review-bib\">\n    <choose>\n      <if match=\"any\" type=\"review review-book\" variable=\"reviewed-author reviewed-genre reviewed-title\">\n        <!-- `title` is only the review title if there is a separate `reviewed-genre` or `reviewed-title`; otherwise, it is the title of the reviewed work, printed in the description -->\n        <choose>\n          <if match=\"any\" variable=\"reviewed-genre reviewed-title\">\n            <text macro=\"title-and-part-title-bib\"/>\n          </if>\n        </choose>\n      </if>\n      <else>\n        <text macro=\"title-and-part-title-bib\"/>\n      </else>\n    </choose>\n  </macro>\n  <macro name=\"title-and-part-title-bib\">\n    <group delimiter=\". \">\n      <text macro=\"title-primary\"/>\n      <group delimiter=\", \">\n        <text macro=\"label-part-number-capitalized\"/>\n        <text macro=\"title-part\"/>\n      </group>\n    </group>\n  </macro>\n  <macro name=\"title-monographic-bib-specific-title-first\">\n    <!-- Use with author-date or notes and bibliography leading with volume title (CMOS18 14.21). -->\n    <!-- For monographic items, assume `part-number` and `part-title` refer to the book/volume. -->\n    <choose>\n      <if variable=\"container-title\">\n        <text macro=\"title-primary\"/>\n      </if>\n      <!-- For monographic items without `container-title`, bibliography entries list `part-title` or `volume-title` first if available -->\n      <else-if variable=\"part-title\">\n        <text macro=\"title-part\"/>\n      </else-if>\n      <else-if variable=\"volume-title\">\n        <text macro=\"title-volume\"/>\n      </else-if>\n      <else>\n        <text macro=\"title-primary\"/>\n      </else>\n    </choose>\n  </macro>\n  <macro name=\"title-part\">\n    <choose>\n      <if type=\"patent\">\n        <!-- No italics or quotes, sentence case -->\n        <text form=\"short\" text-case=\"capitalize-first\" variable=\"part-title\"/>\n      </if>\n      <else-if match=\"any\" type=\"bill collection legislation regulation treaty\">\n        <!-- No italics or quotes, title case -->\n        <text text-case=\"title\" variable=\"part-title\"/>\n      </else-if>\n      <else-if type=\"legal_case\">\n        <!-- Italicized, sentence case -->\n        <text font-style=\"italic\" variable=\"part-title\"/>\n      </else-if>\n      <else-if match=\"any\" type=\"book classic graphic hearing map\">\n        <!-- Italicized, title case (regardless of `container-title`) -->\n        <text font-style=\"italic\" text-case=\"title\" variable=\"part-title\"/>\n      </else-if>\n      <else-if type=\"entry-encyclopedia\" variable=\"author container-title\">\n        <!-- Signed encyclopedia entry in quotes, title case (CMOS18 14.132) -->\n        <text quotes=\"true\" text-case=\"title\" variable=\"part-title\"/>\n      </else-if>\n      <else-if type=\"entry-dictionary\" variable=\"container-title\">\n        <!-- Quotes, sentence case -->\n        <text quotes=\"true\" variable=\"part-title\"/>\n      </else-if>\n      <else-if type=\"entry-encyclopedia\" variable=\"container-title\">\n        <!-- Quotes, sentence case -->\n        <text quotes=\"true\" variable=\"part-title\"/>\n      </else-if>\n      <else-if type=\"post\">\n        <!-- Quotes, sentence case -->\n        <text quotes=\"true\" variable=\"part-title\"/>\n      </else-if>\n      <else-if type=\"webpage\">\n        <!-- Quotes, title case -->\n        <text quotes=\"true\" text-case=\"title\" variable=\"part-title\"/>\n      </else-if>\n      <!-- Other types are formatted based on presence of `container-title` -->\n      <else-if variable=\"container-title\">\n        <choose>\n          <if match=\"any\" type=\"article-journal article-magazine article-newspaper periodical post-weblog review review-book\">\n            <!-- serial types -->\n            <!-- Quotes, title case -->\n            <text quotes=\"true\" text-case=\"title\" variable=\"part-title\"/>\n          </if>\n          <else-if match=\"any\" variable=\"collection-editor compiler editor editorial-director\">\n            <!-- monographic types -->\n            <!-- Italics, title case -->\n            <text font-style=\"italic\" text-case=\"title\" variable=\"part-title\"/>\n          </else-if>\n          <else-if match=\"any\" type=\"interview paper-conference\">\n            <!-- serial types -->\n            <!-- Quotes, title case -->\n            <text quotes=\"true\" text-case=\"title\" variable=\"part-title\"/>\n          </else-if>\n          <else>\n            <!-- monographic types -->\n            <!-- Italics, title case -->\n            <text font-style=\"italic\" text-case=\"title\" variable=\"part-title\"/>\n          </else>\n        </choose>\n      </else-if>\n      <else-if match=\"any\" type=\"article dataset document interview manuscript paper-conference personal_communication speech thesis webpage\">\n        <!-- Container-like but not necessarily with `container-title` -->\n        <!-- Quotes, title case -->\n        <text quotes=\"true\" text-case=\"title\" variable=\"part-title\"/>\n      </else-if>\n      <else>\n        <!-- Italicized, title case (default) -->\n        <text font-style=\"italic\" text-case=\"title\" variable=\"part-title\"/>\n      </else>\n    </choose>\n  </macro>\n  <macro name=\"title-primary\">\n    <choose>\n      <if type=\"patent\">\n        <!-- No italics or quotes, sentence case -->\n        <text form=\"short\" text-case=\"capitalize-first\" variable=\"title\"/>\n      </if>\n      <else-if match=\"any\" type=\"bill collection legislation regulation treaty\">\n        <!-- No italics or quotes, title case -->\n        <text text-case=\"title\" variable=\"title\"/>\n      </else-if>\n      <else-if type=\"legal_case\">\n        <!-- Italicized, sentence case -->\n        <text font-style=\"italic\" variable=\"title\"/>\n      </else-if>\n      <else-if match=\"any\" type=\"book classic graphic hearing map\">\n        <!-- Italicized, title case (regardless of `container-title`) -->\n        <text font-style=\"italic\" text-case=\"title\" variable=\"title\"/>\n      </else-if>\n      <else-if type=\"entry-encyclopedia\" variable=\"author container-title\">\n        <!-- Signed encyclopedia entry in quotes, title case (CMOS18 14.132) -->\n        <text quotes=\"true\" text-case=\"title\" variable=\"title\"/>\n      </else-if>\n      <else-if type=\"entry-dictionary\" variable=\"container-title\">\n        <!-- Quotes, sentence case -->\n        <text quotes=\"true\" variable=\"title\"/>\n      </else-if>\n      <else-if type=\"entry-encyclopedia\" variable=\"container-title\">\n        <!-- Quotes, sentence case -->\n        <text quotes=\"true\" variable=\"title\"/>\n      </else-if>\n      <else-if type=\"post\">\n        <!-- Quotes, sentence case -->\n        <text quotes=\"true\" variable=\"title\"/>\n      </else-if>\n      <!-- Other types are formatted based on presence of `container-title` -->\n      <else-if variable=\"container-title\">\n        <!-- Quotes, title case -->\n        <text quotes=\"true\" text-case=\"title\" variable=\"title\"/>\n      </else-if>\n      <else-if match=\"any\" type=\"article dataset document interview manuscript paper-conference personal_communication speech thesis webpage\">\n        <!-- Container-like but not necessarily with `container-title` -->\n        <!-- Quotes, title case -->\n        <text quotes=\"true\" text-case=\"title\" variable=\"title\"/>\n      </else-if>\n      <else>\n        <!-- Italicized, title case (default) -->\n        <text font-style=\"italic\" text-case=\"title\" variable=\"title\"/>\n      </else>\n    </choose>\n  </macro>\n  <macro name=\"title-primary-short\">\n    <choose>\n      <if type=\"patent\">\n        <!-- No italics or quotes, sentence case -->\n        <text form=\"short\" text-case=\"capitalize-first\" variable=\"title\"/>\n      </if>\n      <else-if match=\"any\" type=\"bill collection legislation regulation treaty\">\n        <!-- No italics or quotes, title case -->\n        <text form=\"short\" text-case=\"title\" variable=\"title\"/>\n      </else-if>\n      <else-if type=\"legal_case\">\n        <!-- Italicized, sentence case -->\n        <text font-style=\"italic\" form=\"short\" variable=\"title\"/>\n      </else-if>\n      <else-if match=\"any\" type=\"book classic graphic hearing map\">\n        <!-- Italicized, title case (regardless of `container-title`) -->\n        <text font-style=\"italic\" form=\"short\" text-case=\"title\" variable=\"title\"/>\n      </else-if>\n      <else-if type=\"entry-encyclopedia\" variable=\"author container-title\">\n        <!-- Signed encyclopedia entry in quotes, title case (CMOS18 14.132) -->\n        <text form=\"short\" quotes=\"true\" text-case=\"title\" variable=\"title\"/>\n      </else-if>\n      <else-if type=\"entry-dictionary\" variable=\"container-title\">\n        <!-- Quotes, sentence case -->\n        <text form=\"short\" quotes=\"true\" variable=\"title\"/>\n      </else-if>\n      <else-if type=\"entry-encyclopedia\" variable=\"container-title\">\n        <!-- Quotes, sentence case -->\n        <text form=\"short\" quotes=\"true\" variable=\"title\"/>\n      </else-if>\n      <else-if type=\"post\">\n        <!-- Quotes, sentence case -->\n        <text form=\"short\" quotes=\"true\" variable=\"title\"/>\n      </else-if>\n      <!-- Other types are formatted based on presence of `container-title` -->\n      <else-if variable=\"container-title\">\n        <!-- Quotes, title case -->\n        <text form=\"short\" quotes=\"true\" text-case=\"title\" variable=\"title\"/>\n      </else-if>\n      <else-if match=\"any\" type=\"article dataset document interview manuscript paper-conference personal_communication speech thesis webpage\">\n        <!-- Container-like but not necessarily with `container-title` -->\n        <!-- Quotes, title case -->\n        <text form=\"short\" quotes=\"true\" text-case=\"title\" variable=\"title\"/>\n      </else-if>\n      <else>\n        <!-- Italicized, title case (default) -->\n        <text font-style=\"italic\" form=\"short\" text-case=\"title\" variable=\"title\"/>\n      </else>\n    </choose>\n  </macro>\n  <macro name=\"title-volume\">\n    <choose>\n      <if type=\"manuscript\">\n        <!-- Quotes, title case -->\n        <text quotes=\"true\" text-case=\"title\" variable=\"volume-title\"/>\n      </if>\n      <else-if match=\"any\" type=\"article-journal article-magazine article-newspaper periodical post-weblog review review-book\">\n        <!-- serial types -->\n        <!-- Quotes, title case -->\n        <text quotes=\"true\" text-case=\"title\" variable=\"volume-title\"/>\n      </else-if>\n      <else-if match=\"any\" variable=\"collection-editor compiler editor editorial-director\">\n        <!-- monographic types -->\n        <!-- Italics, title case -->\n        <text font-style=\"italic\" text-case=\"title\" variable=\"volume-title\"/>\n      </else-if>\n      <else-if match=\"any\" type=\"interview paper-conference\">\n        <!-- serial types -->\n        <!-- Quotes, title case -->\n        <text quotes=\"true\" text-case=\"title\" variable=\"volume-title\"/>\n      </else-if>\n      <else>\n        <!-- monographic types -->\n        <!-- Italics, title case -->\n        <text font-style=\"italic\" text-case=\"title\" variable=\"volume-title\"/>\n      </else>\n    </choose>\n  </macro>\n  <!-- 3.2. Description -->\n  <macro name=\"description-bib\">\n    <choose>\n      <if match=\"any\" type=\"interview\" variable=\"interviewer\">\n        <text macro=\"description-interview-bib\"/>\n      </if>\n      <else-if match=\"any\" type=\"review review-book\" variable=\"reviewed-author reviewed-genre reviewed-title\">\n        <text macro=\"description-review-bib\"/>\n      </else-if>\n      <else-if type=\"personal_communication\">\n        <text macro=\"description-letter-bib\"/>\n      </else-if>\n      <else-if type=\"song\" variable=\"composer\">\n        <text macro=\"description-song-bib\"/>\n      </else-if>\n      <!-- thesis type appears with university name (CMOS18 14.113) -->\n      <else-if type=\"thesis\"/>\n      <else-if match=\"any\" type=\"article-journal article-magazine article-newspaper periodical post-weblog review review-book\">\n        <!-- serial types -->\n        <text macro=\"description-serial-bib\"/>\n      </else-if>\n      <else-if type=\"paper-conference\">\n        <text macro=\"description-paper-conference-bib\"/>\n      </else-if>\n      <else-if match=\"none\" variable=\"container-title\">\n        <text macro=\"description-format-bib\"/>\n      </else-if>\n      <!-- For conference presentations/performances/events, chapters in reports/standards/generic documents, software, place description within the source element -->\n      <else-if match=\"any\" type=\"document report software standard\"/>\n      <else-if match=\"any\" type=\"event paper-conference performance speech\">\n        <choose>\n          <if match=\"any\" variable=\"collection-editor compiler editor editorial-director issue page supplement-number volume\">\n            <text macro=\"description-format-bib\"/>\n          </if>\n        </choose>\n      </else-if>\n      <else>\n        <text macro=\"description-format-bib\"/>\n      </else>\n    </choose>\n  </macro>\n  <macro name=\"description-short\">\n    <choose>\n      <if match=\"any\" type=\"interview\" variable=\"interviewer\">\n        <choose>\n          <if match=\"any\" variable=\"archive archive-place container-title DOI number publisher references URL\">\n            <text macro=\"description-interview-short\"/>\n          </if>\n          <else>\n            <!-- for an inaccessible `interview`, give a full in-text description at the first citation -->\n            <choose>\n              <if position=\"first\">\n                <text macro=\"description-interview-note\"/>\n              </if>\n              <else>\n                <text macro=\"description-interview-short\"/>\n              </else>\n            </choose>\n          </else>\n        </choose>\n      </if>\n      <else-if match=\"any\" type=\"review review-book\" variable=\"reviewed-author reviewed-genre reviewed-title\">\n        <text macro=\"description-review-short\"/>\n      </else-if>\n      <else-if type=\"personal_communication\">\n        <text macro=\"description-letter-short\"/>\n      </else-if>\n      <else-if match=\"any\" type=\"article-journal article-magazine article-newspaper periodical post-weblog review review-book\">\n        <!-- serial types -->\n        <text macro=\"description-serial-short\"/>\n      </else-if>\n      <else-if match=\"any\" variable=\"collection-editor compiler editor editorial-director\">\n        <!-- monographic types -->\n        <text macro=\"description-format-short\"/>\n      </else-if>\n      <else-if type=\"paper-conference\">\n        <!-- serial `paper-conference` -->\n        <text macro=\"description-serial-short\"/>\n      </else-if>\n      <else>\n        <!-- monographic types -->\n        <text macro=\"description-format-short\"/>\n      </else>\n    </choose>\n  </macro>\n  <!-- Description elements -->\n  <macro name=\"description-format-bib\">\n    <choose>\n      <if variable=\"genre number\"/>\n      <else-if variable=\"genre\">\n        <text text-case=\"capitalize-first\" variable=\"genre\"/>\n      </else-if>\n      <!-- generic labels if unpublished -->\n      <else-if match=\"any\" variable=\"archive archive-place container-title DOI number publisher references URL\"/>\n      <else-if type=\"manuscript\">\n        <!-- 'unpublished manuscript' if no `genre` (CMOS18 14.114) -->\n        <text term=\"manuscript\" text-case=\"capitalize-first\"/>\n      </else-if>\n      <else-if type=\"personal_communication\">\n        <!-- 'personal communication' if no `genre` (CMOS18 14.111) -->\n        <text term=\"personal-communication\" text-case=\"capitalize-first\"/>\n      </else-if>\n    </choose>\n  </macro>\n  <macro name=\"description-format-note\">\n    <choose>\n      <if variable=\"genre number\"/>\n      <else-if variable=\"genre\">\n        <text variable=\"genre\"/>\n      </else-if>\n      <!-- generic labels if unpublished -->\n      <else-if match=\"any\" variable=\"archive archive-place container-title DOI number publisher references URL\"/>\n      <else-if type=\"manuscript\">\n        <!-- 'unpublished manuscript' if no `genre` (CMOS18 14.114) -->\n        <text term=\"manuscript\"/>\n      </else-if>\n      <else-if type=\"personal_communication\">\n        <!-- 'personal communication' if no `genre` (CMOS18 14.111) -->\n        <text term=\"personal-communication\"/>\n      </else-if>\n    </choose>\n  </macro>\n  <macro name=\"description-format-short\">\n    <group delimiter=\" \">\n      <choose>\n        <if type=\"chapter\" variable=\"container-title genre\">\n          <!-- untitled introductions: cf. review model, which includes a title (CMOS18 14.101) -->\n          <text form=\"short\" variable=\"genre\"/>\n          <choose>\n            <if match=\"none\" position=\"ibid ibid-with-locator\">\n              <!-- CMOS team suggests leaving out title in repeated references -->\n              <text macro=\"source-monographic-preposition-note\"/>\n              <text font-style=\"italic\" form=\"short\" text-case=\"title\" variable=\"container-title\"/>\n            </if>\n          </choose>\n        </if>\n        <else-if type=\"article-journal\" variable=\"container-title genre volume-title\">\n          <!-- untitled introduction to a special issue or supplement -->\n          <text form=\"short\" variable=\"genre\"/>\n          <choose>\n            <if match=\"none\" position=\"ibid ibid-with-locator\">\n              <text macro=\"source-monographic-preposition-note\"/>\n              <text form=\"short\" quotes=\"true\" text-case=\"title\" variable=\"volume-title\"/>\n            </if>\n          </choose>\n        </else-if>\n        <else-if variable=\"genre\">\n          <text form=\"short\" variable=\"genre\"/>\n        </else-if>\n        <else-if variable=\"medium\">\n          <text form=\"short\" variable=\"medium\"/>\n        </else-if>\n        <else-if variable=\"chapter-number container-title\">\n          <text macro=\"source-monographic-preposition-note\"/>\n          <text font-style=\"italic\" form=\"short\" text-case=\"title\" variable=\"container-title\"/>\n        </else-if>\n        <else-if variable=\"chapter-number\">\n          <text macro=\"label-chapter-number\"/>\n        </else-if>\n        <!-- generic labels if unpublished -->\n        <else-if match=\"any\" variable=\"archive archive-place container-title DOI number publisher references URL\"/>\n        <else-if type=\"manuscript\">\n          <!-- 'unpublished manuscript' if no `genre` (CMOS18 14.114) -->\n          <text term=\"manuscript\"/>\n        </else-if>\n        <else-if type=\"personal_communication\">\n          <!-- 'pers. comm.' if no `genre` (CMOS18 14.111) -->\n          <text form=\"short\" term=\"personal-communication\"/>\n        </else-if>\n      </choose>\n    </group>\n  </macro>\n  <macro name=\"description-interview-bib\">\n    <group delimiter=\", \">\n      <choose>\n        <if variable=\"genre number\">\n          <!-- `genre` printed with `number` -->\n          <names variable=\"interviewer\">\n            <label form=\"verb\" suffix=\" \" text-case=\"capitalize-first\"/>\n            <name and=\"text\" initialize=\"false\"/>\n          </names>\n        </if>\n        <else-if variable=\"genre\">\n          <group delimiter=\" \">\n            <text text-case=\"capitalize-first\" variable=\"genre\"/>\n            <group delimiter=\" \">\n              <text form=\"verb\" term=\"container-author\"/>\n              <names variable=\"interviewer\">\n                <name and=\"text\" initialize=\"false\"/>\n              </names>\n            </group>\n          </group>\n        </else-if>\n        <else-if variable=\"interviewer\">\n          <names variable=\"interviewer\">\n            <label form=\"verb\" suffix=\" \" text-case=\"capitalize-first\"/>\n            <name and=\"text\" initialize=\"false\"/>\n          </names>\n        </else-if>\n        <else>\n          <text macro=\"description-format-bib\"/>\n        </else>\n      </choose>\n      <text macro=\"source-event-place-first\"/>\n    </group>\n  </macro>\n  <macro name=\"description-interview-note\">\n    <group delimiter=\", \">\n      <choose>\n        <if variable=\"genre number\">\n          <!-- `genre` printed with `number` -->\n          <names variable=\"interviewer\">\n            <label form=\"verb\" suffix=\" \"/>\n            <name and=\"text\" initialize=\"false\"/>\n          </names>\n        </if>\n        <else-if variable=\"genre\">\n          <group delimiter=\" \">\n            <text variable=\"genre\"/>\n            <group delimiter=\" \">\n              <text form=\"verb\" term=\"container-author\"/>\n              <names variable=\"interviewer\">\n                <name and=\"text\" initialize=\"false\"/>\n              </names>\n            </group>\n          </group>\n        </else-if>\n        <else-if variable=\"interviewer\">\n          <names variable=\"interviewer\">\n            <label form=\"verb\" suffix=\" \"/>\n            <name and=\"text\" initialize=\"false\"/>\n          </names>\n        </else-if>\n        <else>\n          <text macro=\"description-format-note\"/>\n        </else>\n      </choose>\n      <text macro=\"source-event-place-first\"/>\n    </group>\n  </macro>\n  <macro name=\"description-interview-short\">\n    <choose>\n      <if disambiguate=\"true\">\n        <names variable=\"interviewer\">\n          <label form=\"verb\" suffix=\" \"/>\n          <name and=\"text\" form=\"short\" initialize=\"true\"/>\n          <substitute>\n            <text macro=\"description-format-short\"/>\n          </substitute>\n        </names>\n      </if>\n      <else-if match=\"any\" variable=\"genre medium\">\n        <choose>\n          <if match=\"any\" variable=\"author chair collection-editor compiler composer curator director editor editor-translator editorial-director executive-producer guest host illustrator organizer producer series-creator translator\">\n            <text macro=\"description-format-short\"/>\n          </if>\n          <else>\n            <!-- capitalize if no author or title -->\n            <text macro=\"description-format-bib\"/>\n          </else>\n        </choose>\n      </else-if>\n      <else>\n        <!-- generic description for an unpublished interview (CMOS18 14.108) -->\n        <text term=\"interview\"/>\n      </else>\n    </choose>\n  </macro>\n  <macro name=\"description-letter-bib\">\n    <choose>\n      <if variable=\"recipient\">\n        <group delimiter=\", \">\n          <choose>\n            <if variable=\"genre number\">\n              <!-- `genre` appears with `number` -->\n              <names variable=\"recipient\">\n                <label form=\"verb\" suffix=\" \" text-case=\"capitalize-first\"/>\n                <name and=\"text\" initialize=\"false\"/>\n              </names>\n            </if>\n            <else-if variable=\"genre\">\n              <group delimiter=\" \">\n                <text macro=\"description-format-bib\"/>\n                <names variable=\"recipient\">\n                  <label form=\"verb\" suffix=\" \"/>\n                  <name and=\"text\" initialize=\"false\"/>\n                </names>\n              </group>\n            </else-if>\n            <else>\n              <names variable=\"recipient\">\n                <label form=\"verb\" suffix=\" \" text-case=\"capitalize-first\"/>\n                <name and=\"text\" initialize=\"false\"/>\n              </names>\n            </else>\n          </choose>\n          <text variable=\"event-place\"/>\n          <text macro=\"date-event-full\"/>\n        </group>\n      </if>\n      <else>\n        <text macro=\"description-format-bib\"/>\n      </else>\n    </choose>\n  </macro>\n  <macro name=\"description-letter-short\">\n    <!-- shortened notes ideally give author, recipient, place, and date (CMOS18 14.13) -->\n    <group delimiter=\", \">\n      <choose>\n        <if variable=\"genre recipient\">\n          <group delimiter=\" \">\n            <text macro=\"description-format-short\"/>\n            <names variable=\"recipient\">\n              <label form=\"verb\" suffix=\" \"/>\n              <name and=\"text\" form=\"short\" initialize=\"true\"/>\n            </names>\n          </group>\n        </if>\n        <else>\n          <text macro=\"description-format-short\"/>\n        </else>\n      </choose>\n      <text variable=\"event-place\"/>\n      <choose>\n        <if variable=\"event-date\">\n          <text macro=\"date-event-full\"/>\n        </if>\n        <else>\n          <text macro=\"date-issued-full\"/>\n        </else>\n      </choose>\n    </group>\n  </macro>\n  <macro name=\"description-paper-conference-bib\">\n    <choose>\n      <if match=\"any\" variable=\"collection-editor compiler editor editorial-director\">\n        <!-- monographic types -->\n        <text macro=\"description-format-bib\"/>\n      </if>\n      <else>\n        <!-- serial types -->\n        <group delimiter=\". \">\n          <text macro=\"description-serial-bib\"/>\n          <text macro=\"source-event-bib\"/>\n        </group>\n      </else>\n    </choose>\n  </macro>\n  <macro name=\"description-review-bib\">\n    <!-- Reviewed item -->\n    <group delimiter=\". \">\n      <group delimiter=\", \">\n        <group delimiter=\" \">\n          <text macro=\"description-review-genre-bib\"/>\n          <text macro=\"description-review-title\"/>\n        </group>\n        <choose>\n          <if variable=\"reviewed-genre reviewed-title title\">\n            <names variable=\"reviewed-author\">\n              <label form=\"verb\" suffix=\" \"/>\n              <name and=\"text\" initialize=\"false\"/>\n            </names>\n          </if>\n          <else-if variable=\"reviewed-genre\"/>\n          <else>\n            <names variable=\"reviewed-author\">\n              <label form=\"verb\" suffix=\" \"/>\n              <name and=\"text\" initialize=\"false\"/>\n            </names>\n          </else>\n        </choose>\n        <text macro=\"source-event-place-first\"/>\n      </group>\n      <text macro=\"label-section-capitalized\"/>\n    </group>\n  </macro>\n  <macro name=\"description-review-genre-bib\">\n    <choose>\n      <if variable=\"reviewed-genre\">\n        <group delimiter=\" \">\n          <text macro=\"description-review-term-unsigned-bib\"/>\n          <text variable=\"reviewed-genre\"/>\n          <choose>\n            <if match=\"none\" variable=\"reviewed-title\">\n              <names variable=\"reviewed-author\">\n                <label form=\"verb\" suffix=\" \"/>\n                <name and=\"text\" initialize=\"false\"/>\n              </names>\n            </if>\n          </choose>\n        </group>\n      </if>\n      <else-if variable=\"number\">\n        <text macro=\"description-review-term-unsigned-bib\"/>\n      </else-if>\n      <!-- If no `reviewed-genre`, assume that `genre` is entered as 'Review of the book' or similar -->\n      <else-if variable=\"genre\">\n        <text text-case=\"capitalize-first\" variable=\"genre\"/>\n      </else-if>\n      <else>\n        <text macro=\"description-review-term-unsigned-bib\"/>\n      </else>\n    </choose>\n  </macro>\n  <macro name=\"description-review-short\">\n    <choose>\n      <if match=\"any\" position=\"ibid ibid-with-locator\">\n        <text term=\"review\"/>\n      </if>\n      <else>\n        <group delimiter=\" \">\n          <text term=\"review-of\"/>\n          <text macro=\"description-review-title-short\"/>\n        </group>\n      </else>\n    </choose>\n  </macro>\n  <macro name=\"description-review-term-unsigned-bib\">\n    <!-- Anonymous reviews appear as 'unsigned' (CMOS18 14.102) -->\n    <choose>\n      <if match=\"any\" variable=\"author chair collection-editor compiler composer curator director editor editor-translator editorial-director executive-producer guest host illustrator organizer producer series-creator translator\">\n        <text term=\"review-of\" text-case=\"capitalize-first\"/>\n      </if>\n      <else>\n        <group delimiter=\" \">\n          <text term=\"anonymous\" text-case=\"capitalize-first\"/>\n          <text term=\"review-of\"/>\n        </group>\n      </else>\n    </choose>\n  </macro>\n  <macro name=\"description-review-title\">\n    <choose>\n      <if match=\"any\" variable=\"reviewed-genre reviewed-title\">\n        <!-- Not possible to distinguish TV series episode from other reviewed works without a reviewed source title -->\n        <!-- Adapt for `reviewed-container-title` or similar if it becomes available -->\n        <text font-style=\"italic\" text-case=\"title\" variable=\"reviewed-title\"/>\n      </if>\n      <else>\n        <!-- Assume title is title of reviewed work -->\n        <text font-style=\"italic\" text-case=\"title\" variable=\"title\"/>\n      </else>\n    </choose>\n  </macro>\n  <macro name=\"description-review-title-short\">\n    <choose>\n      <if match=\"any\" variable=\"reviewed-genre reviewed-title\">\n        <!-- Not possible to distinguish TV series episode from other reviewed works without a reviewed source title -->\n        <!-- Adapt for `reviewed-container-title` or similar if it becomes available -->\n        <text font-style=\"italic\" form=\"short\" text-case=\"title\" variable=\"reviewed-title\"/>\n      </if>\n      <else>\n        <!-- Assume title is title of reviewed work -->\n        <text font-style=\"italic\" form=\"short\" text-case=\"title\" variable=\"title\"/>\n      </else>\n    </choose>\n  </macro>\n  <macro name=\"description-serial-bib\">\n    <group delimiter=\". \">\n      <text macro=\"description-format-bib\"/>\n      <!-- `section` provides magazine departments (CMOS18 14.88) and newspaper column names (CMOS18 14.93) -->\n      <text macro=\"label-section-capitalized\"/>\n    </group>\n  </macro>\n  <macro name=\"description-serial-short\">\n    <choose>\n      <if variable=\"title\"/>\n      <else-if variable=\"genre\">\n        <text macro=\"description-format-short\"/>\n      </else-if>\n      <else>\n        <text form=\"short\" text-case=\"title\" variable=\"section\"/>\n      </else>\n    </choose>\n  </macro>\n  <macro name=\"description-song-bib\">\n    <!-- Performer of classical music works -->\n    <!-- TODO: remove when Zotero fixes mapping of performer to `author` -->\n    <group delimiter=\" \">\n      <!-- Based on `description-format` macro -->\n      <choose>\n        <if variable=\"genre\">\n          <text text-case=\"capitalize-first\" variable=\"genre\"/>\n          <text form=\"verb\" term=\"performer\"/>\n        </if>\n        <!-- providing 'performed by' label for recorded readings (CMOS18 14.164), but it should be omitted for classical music (CMOS18 14.163) -->\n        <else>\n          <text form=\"verb\" term=\"performer\" text-case=\"capitalize-first\"/>\n        </else>\n      </choose>\n      <names variable=\"author\">\n        <name and=\"text\" initialize=\"false\"/>\n        <substitute>\n          <names variable=\"performer\"/>\n        </substitute>\n      </names>\n    </group>\n  </macro>\n  <!-- 3.3. Identifier (edition, contributors, volume) -->\n  <macro name=\"identifier-bib\">\n    <group delimiter=\". \">\n      <choose>\n        <if type=\"patent\">\n          <text macro=\"identifier-patent\"/>\n        </if>\n        <else-if type=\"report\">\n          <text macro=\"identifier-report-bib\"/>\n        </else-if>\n        <else-if match=\"any\" type=\"post webpage\">\n          <!-- print `container-title` on `post` or `webpage` in the same way as `publisher` (CMOS18 14.104-106) -->\n          <text macro=\"identifier-number-bib\"/>\n          <text macro=\"label-version-capitalized\"/>\n          <text macro=\"identifier-edition-bib\"/>\n          <text macro=\"identifier-contributors-bib\"/>\n        </else-if>\n        <else-if variable=\"container-title\">\n          <choose>\n            <if match=\"any\" type=\"broadcast graphic map motion_picture\">\n              <!-- For audiovisual media, number information comes after `title`, not `container-title`; `song` places album catalogue `number` with `publisher` (CMOS18 14.163-164) -->\n              <text macro=\"identifier-number-bib\"/>\n            </if>\n          </choose>\n          <text macro=\"identifier-contributors-bib\"/>\n        </else-if>\n        <else>\n          <choose>\n            <if match=\"none\" type=\"song\">\n              <text macro=\"identifier-number-bib\"/>\n            </if>\n          </choose>\n          <text macro=\"label-version-capitalized\"/>\n          <text macro=\"identifier-edition-bib\"/>\n          <text macro=\"identifier-contributors-and-volume-bib\"/>\n        </else>\n      </choose>\n    </group>\n  </macro>\n  <!-- Identifier elements -->\n  <macro name=\"identifier-contributors-bib\">\n    <choose>\n      <if match=\"any\" type=\"article-journal article-magazine article-newspaper periodical post-weblog review review-book\">\n        <text macro=\"identifier-contributors-serial-bib\"/>\n      </if>\n      <else-if match=\"any\" variable=\"collection-editor compiler editor editorial-director\">\n        <text macro=\"identifier-contributors-monographic-bib\"/>\n      </else-if>\n      <else-if match=\"any\" type=\"interview paper-conference\">\n        <text macro=\"identifier-contributors-serial-bib\"/>\n      </else-if>\n      <else>\n        <text macro=\"identifier-contributors-monographic-bib\"/>\n      </else>\n    </choose>\n  </macro>\n  <macro name=\"identifier-contributors-monographic-bib\">\n    <group delimiter=\". \">\n      <choose>\n        <if match=\"any\" type=\"post webpage\">\n          <names variable=\"container-author\">\n            <label form=\"verb\" suffix=\" \" text-case=\"capitalize-first\"/>\n            <name and=\"text\" initialize=\"false\"/>\n          </names>\n          <names variable=\"editor-translator\">\n            <label form=\"verb\" suffix=\" \" text-case=\"capitalize-first\"/>\n            <name and=\"text\" initialize=\"false\"/>\n          </names>\n          <names delimiter=\". \" variable=\"editor translator\">\n            <label form=\"verb\" suffix=\" \" text-case=\"capitalize-first\"/>\n            <name and=\"text\" initialize=\"false\"/>\n          </names>\n          <names variable=\"editorial-director\">\n            <label form=\"verb\" suffix=\" \" text-case=\"capitalize-first\"/>\n            <name and=\"text\" initialize=\"false\"/>\n          </names>\n          <names variable=\"guest\">\n            <label form=\"verb\" suffix=\" \" text-case=\"capitalize-first\"/>\n            <name and=\"text\" initialize=\"false\"/>\n          </names>\n          <names variable=\"host\">\n            <label form=\"verb\" suffix=\" \" text-case=\"capitalize-first\"/>\n            <name and=\"text\" initialize=\"false\"/>\n          </names>\n          <names variable=\"illustrator\">\n            <label form=\"verb\" suffix=\" \" text-case=\"capitalize-first\"/>\n            <name and=\"text\" initialize=\"false\"/>\n          </names>\n          <names variable=\"narrator\">\n            <label form=\"verb\" suffix=\" \" text-case=\"capitalize-first\"/>\n            <name and=\"text\" initialize=\"false\"/>\n          </names>\n          <names delimiter=\". \" variable=\"compiler chair organizer curator\">\n            <label form=\"verb\" suffix=\" \" text-case=\"capitalize-first\"/>\n            <name and=\"text\" initialize=\"false\"/>\n          </names>\n          <names delimiter=\". \" variable=\"series-creator executive-producer\">\n            <label form=\"verb\" suffix=\" \" text-case=\"capitalize-first\"/>\n            <name and=\"text\" initialize=\"false\"/>\n          </names>\n          <names variable=\"producer\">\n            <label form=\"verb\" suffix=\" \" text-case=\"capitalize-first\"/>\n            <name and=\"text\" initialize=\"false\"/>\n          </names>\n          <names variable=\"director\">\n            <label form=\"verb\" suffix=\" \" text-case=\"capitalize-first\"/>\n            <name and=\"text\" initialize=\"false\"/>\n          </names>\n          <choose>\n            <if match=\"any\" type=\"broadcast performance\">\n              <names variable=\"script-writer\">\n                <label form=\"verb\" suffix=\" \" text-case=\"capitalize-first\"/>\n                <name and=\"text\" initialize=\"false\"/>\n              </names>\n            </if>\n          </choose>\n          <names variable=\"performer\">\n            <label form=\"verb\" suffix=\" \" text-case=\"capitalize-first\"/>\n            <name and=\"text\" initialize=\"false\"/>\n          </names>\n          <choose>\n            <if match=\"none\" type=\"thesis\">\n              <names variable=\"contributor\">\n                <label form=\"verb\" suffix=\" \" text-case=\"capitalize-first\"/>\n                <name and=\"text\" initialize=\"false\"/>\n              </names>\n            </if>\n          </choose>\n        </if>\n        <else>\n          <!-- print `container-title` on `post` or `webpage` in the same way as `publisher` (CMOS18 14.104-106) -->\n          <choose>\n            <if match=\"none\" variable=\"container-title\">\n              <names variable=\"container-author\">\n                <label form=\"verb\" suffix=\" \" text-case=\"capitalize-first\"/>\n                <name and=\"text\" initialize=\"false\"/>\n              </names>\n              <names variable=\"editor-translator\">\n                <label form=\"verb\" suffix=\" \" text-case=\"capitalize-first\"/>\n                <name and=\"text\" initialize=\"false\"/>\n              </names>\n              <names delimiter=\". \" variable=\"editor translator\">\n                <label form=\"verb\" suffix=\" \" text-case=\"capitalize-first\"/>\n                <name and=\"text\" initialize=\"false\"/>\n              </names>\n              <names variable=\"editorial-director\">\n                <label form=\"verb\" suffix=\" \" text-case=\"capitalize-first\"/>\n                <name and=\"text\" initialize=\"false\"/>\n              </names>\n              <names variable=\"guest\">\n                <label form=\"verb\" suffix=\" \" text-case=\"capitalize-first\"/>\n                <name and=\"text\" initialize=\"false\"/>\n              </names>\n              <names variable=\"host\">\n                <label form=\"verb\" suffix=\" \" text-case=\"capitalize-first\"/>\n                <name and=\"text\" initialize=\"false\"/>\n              </names>\n            </if>\n          </choose>\n          <names variable=\"illustrator\">\n            <label form=\"verb\" suffix=\" \" text-case=\"capitalize-first\"/>\n            <name and=\"text\" initialize=\"false\"/>\n          </names>\n          <names variable=\"narrator\">\n            <label form=\"verb\" suffix=\" \" text-case=\"capitalize-first\"/>\n            <name and=\"text\" initialize=\"false\"/>\n          </names>\n          <choose>\n            <if match=\"none\" variable=\"container-title\">\n              <names delimiter=\". \" variable=\"compiler chair organizer curator\">\n                <label form=\"verb\" suffix=\" \" text-case=\"capitalize-first\"/>\n                <name and=\"text\" initialize=\"false\"/>\n              </names>\n              <names delimiter=\". \" variable=\"series-creator executive-producer\">\n                <label form=\"verb\" suffix=\" \" text-case=\"capitalize-first\"/>\n                <name and=\"text\" initialize=\"false\"/>\n              </names>\n              <names variable=\"producer\">\n                <label form=\"verb\" suffix=\" \" text-case=\"capitalize-first\"/>\n                <name and=\"text\" initialize=\"false\"/>\n              </names>\n              <names variable=\"director\">\n                <label form=\"verb\" suffix=\" \" text-case=\"capitalize-first\"/>\n                <name and=\"text\" initialize=\"false\"/>\n              </names>\n              <choose>\n                <if match=\"any\" type=\"broadcast performance\">\n                  <names variable=\"script-writer\">\n                    <label form=\"verb\" suffix=\" \" text-case=\"capitalize-first\"/>\n                    <name and=\"text\" initialize=\"false\"/>\n                  </names>\n                </if>\n              </choose>\n              <names variable=\"performer\">\n                <label form=\"verb\" suffix=\" \" text-case=\"capitalize-first\"/>\n                <name and=\"text\" initialize=\"false\"/>\n              </names>\n              <choose>\n                <if match=\"none\" type=\"song thesis\">\n                  <names variable=\"contributor\">\n                    <label form=\"verb\" suffix=\" \" text-case=\"capitalize-first\"/>\n                    <name and=\"text\" initialize=\"false\"/>\n                  </names>\n                </if>\n              </choose>\n            </if>\n          </choose>\n          <choose>\n            <if type=\"song\">\n              <!-- Song contributors attached to album (CMOS18 14.163) -->\n              <names variable=\"contributor\">\n                <label form=\"verb\" suffix=\" \" text-case=\"capitalize-first\"/>\n                <name and=\"text\" initialize=\"false\"/>\n              </names>\n            </if>\n          </choose>\n        </else>\n      </choose>\n    </group>\n  </macro>\n  <macro name=\"identifier-contributors-serial-bib\">\n    <group delimiter=\". \">\n      <names delimiter=\". \" variable=\"translator narrator\">\n        <label form=\"verb\" suffix=\" \" text-case=\"capitalize-first\"/>\n        <name and=\"text\" initialize=\"false\"/>\n      </names>\n      <names delimiter=\". \" variable=\"compiler chair organizer curator\">\n        <label form=\"verb\" suffix=\" \" text-case=\"capitalize-first\"/>\n        <name and=\"text\" initialize=\"false\"/>\n      </names>\n      <names delimiter=\". \" variable=\"series-creator executive-producer\">\n        <label form=\"verb\" suffix=\" \" text-case=\"capitalize-first\"/>\n        <name and=\"text\" initialize=\"false\"/>\n      </names>\n      <names variable=\"producer\">\n        <label form=\"verb\" suffix=\" \" text-case=\"capitalize-first\"/>\n        <name and=\"text\" initialize=\"false\"/>\n      </names>\n      <names variable=\"director\">\n        <label form=\"verb\" suffix=\" \" text-case=\"capitalize-first\"/>\n        <name and=\"text\" initialize=\"false\"/>\n      </names>\n      <names variable=\"script-writer\">\n        <label form=\"verb\" suffix=\" \" text-case=\"capitalize-first\"/>\n        <name and=\"text\" initialize=\"false\"/>\n      </names>\n      <names variable=\"performer\">\n        <label form=\"verb\" suffix=\" \" text-case=\"capitalize-first\"/>\n        <name and=\"text\" initialize=\"false\"/>\n      </names>\n    </group>\n  </macro>\n  <macro name=\"identifier-contributors-and-volume-bib\">\n    <choose>\n      <if match=\"any\" type=\"article-journal article-magazine article-newspaper periodical post-weblog review review-book\">\n        <!-- serial types -->\n        <text macro=\"identifier-contributors-serial-bib\"/>\n      </if>\n      <else-if match=\"any\" variable=\"collection-editor compiler editor editorial-director\">\n        <!-- monographic types -->\n        <text macro=\"identifier-contributors-and-volume-monographic-bib-specific-title-first\"/>\n      </else-if>\n      <else-if match=\"any\" type=\"interview paper-conference\">\n        <!-- serial types -->\n        <text macro=\"identifier-contributors-serial-bib\"/>\n      </else-if>\n      <else>\n        <!-- monographic types -->\n        <text macro=\"identifier-contributors-and-volume-monographic-bib-specific-title-first\"/>\n      </else>\n    </choose>\n  </macro>\n  <macro name=\"identifier-contributors-and-volume-monographic-bib-specific-title-first\">\n    <group delimiter=\". \">\n      <text macro=\"identifier-contributors-monographic-bib\"/>\n      <group delimiter=\", \">\n        <text macro=\"identifier-volume-bib-specific-title-first\"/>\n        <choose>\n          <if match=\"any\" variable=\"number-of-volumes part-number part-title volume volume-title\">\n            <!-- cite multivolume `collection-editor`; otherwise it belongs with `collection-title` -->\n            <names variable=\"collection-editor\">\n              <label form=\"verb\" suffix=\" \"/>\n              <name and=\"text\" initialize=\"false\"/>\n            </names>\n          </if>\n        </choose>\n      </group>\n      <choose>\n        <if match=\"none\" variable=\"part-number part-title volume volume-title\">\n          <text macro=\"label-number-of-volumes\"/>\n        </if>\n      </choose>\n    </group>\n  </macro>\n  <macro name=\"identifier-edition-bib\">\n    <choose>\n      <!-- ensure `source-publication-history-bib` does not duplicate edition -->\n      <if variable=\"original-title\">\n        <text macro=\"label-edition-capitalized\"/>\n      </if>\n      <else-if variable=\"issued original-date\"/>\n      <else>\n        <text macro=\"label-edition-capitalized\"/>\n      </else>\n    </choose>\n  </macro>\n  <macro name=\"identifier-edition-note\">\n    <choose>\n      <!-- ensure `source-publication-history-note` does not duplicate edition -->\n      <if variable=\"original-title\">\n        <text macro=\"label-edition\"/>\n      </if>\n      <else-if variable=\"issued original-date\"/>\n      <else>\n        <text macro=\"label-edition\"/>\n      </else>\n    </choose>\n  </macro>\n  <macro name=\"identifier-number-bib\">\n    <group delimiter=\" \">\n      <choose>\n        <if type=\"thesis\"/>\n        <else-if is-numeric=\"number\" type=\"broadcast\" variable=\"genre\">\n          <text text-case=\"capitalize-first\" variable=\"genre\"/>\n          <text variable=\"number\"/>\n        </else-if>\n        <else-if is-numeric=\"number\" type=\"broadcast\">\n          <text text-case=\"capitalize-first\" value=\"episode\"/>\n          <text variable=\"number\"/>\n        </else-if>\n        <else-if variable=\"number\">\n          <text text-case=\"title\" variable=\"genre\"/>\n          <text macro=\"label-number-capitalized\"/>\n        </else-if>\n      </choose>\n    </group>\n  </macro>\n  <macro name=\"identifier-patent\">\n    <group delimiter=\", \">\n      <group delimiter=\" \">\n        <!-- `authority`: US ; `genre`: patent ; `number`: 123,445 -->\n        <text form=\"short\" variable=\"authority\"/>\n        <!-- 'US Patent' capitalized in both bibliography and note forms -->\n        <choose>\n          <if variable=\"genre\">\n            <text text-case=\"capitalize-first\" variable=\"genre\"/>\n          </if>\n          <else>\n            <text term=\"patent\" text-case=\"capitalize-first\"/>\n          </else>\n        </choose>\n        <text variable=\"number\"/>\n      </group>\n      <group delimiter=\" \">\n        <text value=\"filed\"/>\n        <date form=\"text\" variable=\"submitted\"/>\n      </group>\n      <group delimiter=\" \">\n        <choose>\n          <if variable=\"issued submitted\">\n            <text term=\"and\"/>\n          </if>\n        </choose>\n        <text value=\"issued\"/>\n        <!-- Always give full issue date, even in author-date (CMOS18 14.158) -->\n        <text macro=\"date-issued-full\"/>\n      </group>\n    </group>\n  </macro>\n  <macro name=\"identifier-report-bib\">\n    <group delimiter=\". \">\n      <choose>\n        <if variable=\"container-title\">\n          <!-- If the report is a chapter in a larger report, then most identifying information is printed in the source. -->\n          <text macro=\"identifier-contributors-bib\"/>\n        </if>\n        <else-if variable=\"title\">\n          <text macro=\"identifier-number-bib\"/>\n          <text macro=\"label-version-capitalized\"/>\n          <text macro=\"identifier-edition-bib\"/>\n          <text macro=\"identifier-contributors-and-volume-bib\"/>\n        </else-if>\n        <else>\n          <!-- If there is no `title`, then `genre` and `number` are already printed as the title. -->\n          <text macro=\"label-version-capitalized\"/>\n          <text macro=\"identifier-edition-bib\"/>\n          <text macro=\"identifier-contributors-and-volume-bib\"/>\n        </else>\n      </choose>\n    </group>\n  </macro>\n  <macro name=\"identifier-volume-bib-specific-title-first\">\n    <!-- In author-date, bibliography must be listed under the individual volume title rather than the general title of the multivolume set; this is also allowable in notes styles (CMOS18 14.21) -->\n    <group delimiter=\", \">\n      <choose>\n        <if variable=\"part-number part-title volume volume-title\">\n          <!-- part and title with individual titles -->\n          <group delimiter=\" \">\n            <text macro=\"label-part-number-capitalized\"/>\n            <text value=\"of\"/>\n            <text macro=\"title-volume\"/>\n          </group>\n          <group delimiter=\" \">\n            <text macro=\"label-volume\"/>\n            <text value=\"of\"/>\n            <text macro=\"title-primary\"/>\n          </group>\n        </if>\n        <else-if match=\"any\" variable=\"part-title volume-title\">\n          <group delimiter=\" \">\n            <choose>\n              <if variable=\"part-number volume\">\n                <group delimiter=\", \">\n                  <text macro=\"label-volume-capitalized\"/>\n                  <text macro=\"label-part-number\"/>\n                  <text value=\"of\"/>\n                </group>\n              </if>\n              <else-if variable=\"part-number\">\n                <text macro=\"label-part-number-capitalized\"/>\n                <text value=\"of\"/>\n              </else-if>\n              <else-if variable=\"volume\">\n                <text macro=\"label-volume-capitalized\"/>\n                <text value=\"of\"/>\n              </else-if>\n            </choose>\n            <text macro=\"title-primary\"/>\n          </group>\n        </else-if>\n        <else-if variable=\"part-number volume\">\n          <text macro=\"label-volume-capitalized\"/>\n          <text macro=\"label-part-number\"/>\n        </else-if>\n        <else-if variable=\"part-number\">\n          <text macro=\"label-part-number-capitalized\"/>\n        </else-if>\n        <else-if variable=\"volume\">\n          <text macro=\"label-volume-capitalized\"/>\n        </else-if>\n      </choose>\n    </group>\n  </macro>\n  <!-- 4. Source -->\n  <macro name=\"source-bib\">\n    <choose>\n      <if match=\"any\" type=\"patent post webpage\"/>\n      <else-if match=\"any\" type=\"article-journal article-magazine article-newspaper periodical post-weblog review review-book\">\n        <text macro=\"source-serial-bib\"/>\n      </else-if>\n      <else-if match=\"any\" variable=\"collection-editor compiler editor editorial-director\">\n        <text macro=\"source-monographic-bib\"/>\n      </else-if>\n      <else-if match=\"any\" type=\"interview paper-conference\">\n        <text macro=\"source-serial-bib\"/>\n      </else-if>\n      <else>\n        <text macro=\"source-monographic-bib\"/>\n      </else>\n    </choose>\n  </macro>\n  <!-- 4.1. Serial sources -->\n  <macro name=\"source-serial-bib\">\n    <group delimiter=\". \">\n      <text macro=\"source-serial-title-volume-bib\"/>\n      <choose>\n        <if match=\"any\" type=\"article-magazine article-newspaper\">\n          <!-- magazines and newspapers provide the full date in place of volume/issue numbers (CMOS18 14.87, 14.89) -->\n          <group delimiter=\", \">\n            <text macro=\"source-serial-title-bib\"/>\n            <text macro=\"source-serial-identifier-bib\"/>\n          </group>\n        </if>\n        <else-if variable=\"collection-title volume\">\n          <group delimiter=\", \">\n            <text macro=\"source-serial-title-bib\"/>\n            <text macro=\"source-serial-identifier-bib\"/>\n          </group>\n        </else-if>\n        <else-if variable=\"volume\">\n          <group delimiter=\" \">\n            <text macro=\"source-serial-title-bib\"/>\n            <text macro=\"source-serial-identifier-bib\"/>\n          </group>\n        </else-if>\n        <else>\n          <group delimiter=\", \">\n            <text macro=\"source-serial-title-bib\"/>\n            <text macro=\"source-serial-identifier-bib\"/>\n          </group>\n        </else>\n      </choose>\n    </group>\n  </macro>\n  <!-- Serial source title -->\n  <macro name=\"source-serial-name\">\n    <group delimiter=\" \">\n      <text font-style=\"italic\" text-case=\"title\" variable=\"container-title\"/>\n      <choose>\n        <!-- TODO: remove conditional when Zotero stops double-mapping `event-place` and `publisher-place` -->\n        <if match=\"none\" variable=\"event-date event-title\">\n          <text prefix=\"(\" suffix=\")\" variable=\"publisher-place\"/>\n        </if>\n      </choose>\n    </group>\n  </macro>\n  <macro name=\"source-serial-title-bib\">\n    <group delimiter=\", \">\n      <choose>\n        <!-- Journal special issues (CMOS18 14.77) and supplements (CMOS18 14.78) -->\n        <if match=\"none\" variable=\"container-title\"/>\n        <else-if match=\"none\" type=\"periodical\" variable=\"supplement-number volume-title\"/>\n        <!-- TODO: use `container-genre` here once available to allow a custom description of the journal volume -->\n        <else-if variable=\"supplement-number volume-title\">\n          <text term=\"supplement\" text-case=\"capitalize-first\"/>\n        </else-if>\n        <else-if type=\"periodical\" variable=\"supplement-number title\">\n          <text term=\"supplement\" text-case=\"capitalize-first\"/>\n        </else-if>\n        <else-if variable=\"volume-title\">\n          <text term=\"special-issue\" text-case=\"capitalize-first\"/>\n        </else-if>\n        <else-if type=\"periodical\" variable=\"title\">\n          <text term=\"special-issue\" text-case=\"capitalize-first\"/>\n        </else-if>\n      </choose>\n      <text macro=\"source-serial-name\"/>\n      <choose>\n        <!-- 'ahead of print' is placed akin to a series (CMOS18 14.75) -->\n        <if match=\"any\" variable=\"available-date collection-title issue number page status supplement-number volume volume-title\"/>\n        <else-if type=\"article-journal\" variable=\"DOI issued\">\n          <text term=\"advance-online-publication\"/>\n        </else-if>\n      </choose>\n    </group>\n  </macro>\n  <macro name=\"source-serial-title-volume-bib\">\n    <choose>\n      <if variable=\"volume-title\">\n        <!-- Journal special issues (CMOS18 14.77) and supplements (CMOS18 14.78) -->\n        <group delimiter=\", \">\n          <group delimiter=\" \">\n            <text macro=\"source-monographic-preposition-bib\"/>\n            <text macro=\"title-volume\"/>\n          </group>\n          <text macro=\"source-monographic-identifier-contributors-bib\"/>\n        </group>\n      </if>\n    </choose>\n  </macro>\n  <!-- Serial source identifier -->\n  <macro name=\"source-serial-identifier-bib\">\n    <group delimiter=\", \">\n      <choose>\n        <if match=\"any\" type=\"article-magazine article-newspaper\">\n          <group delimiter=\". \">\n            <text macro=\"source-serial-identifier-volume-author-date\"/>\n            <!-- newspaper edition always capitalized (CMOS18 14.89) -->\n            <text macro=\"label-edition-capitalized\"/>\n          </group>\n          <text macro=\"source-serial-locator\"/>\n        </if>\n        <else-if match=\"any\" variable=\"issue supplement-number volume\">\n          <group delimiter=\": \">\n            <text macro=\"source-serial-identifier-volume-author-date\"/>\n            <text macro=\"source-serial-locator\"/>\n          </group>\n        </else-if>\n        <else>\n          <text macro=\"source-serial-identifier-volume-author-date\"/>\n          <text macro=\"source-serial-locator\"/>\n        </else>\n        <!-- TODO: If CSL adds `date-part` detection, add two further conditions to address CMOS18 14.74: delimiting with \":\" if there is a `volume` and no month or `issue` or `supplement number`; delimiting with \", \" or there is an `issue` or `supplement number` and no month -->\n      </choose>\n    </group>\n  </macro>\n  <macro name=\"source-serial-identifier-volume-author-date\">\n    <group delimiter=\", \">\n      <choose>\n        <if match=\"any\" type=\"article-magazine article-newspaper\">\n          <!-- magazines and newspapers provide the full date in place of volume/issue numbers (CMOS18 14.87, 14.89) -->\n          <text variable=\"collection-title\"/>\n          <text macro=\"source-serial-volume-status-bib\"/>\n        </if>\n        <else-if match=\"any\" variable=\"issue supplement-number volume\">\n          <choose>\n            <if match=\"any\" variable=\"author chair collection-editor compiler composer curator director editor editor-translator editorial-director executive-producer guest host illustrator organizer producer series-creator translator\"/>\n            <else-if match=\"any\" type=\"review review-book\" variable=\"reviewed-author reviewed-genre reviewed-title\">\n              <!-- date appears first if the review `container-title` has been substituted for a missing author (CMOS18 14.87, 14.102) -->\n              <choose>\n                <!-- extra date details only appear with a lone volume or issue -->\n                <if variable=\"issue volume\"/>\n                <else-if variable=\"supplement-number\"/>\n                <else-if match=\"any\" variable=\"issue volume\">\n                  <text macro=\"source-date-specific-title-first\"/>\n                </else-if>\n              </choose>\n            </else-if>\n          </choose>\n          <!-- `collection-title` is for any serial with multiple series (e.g. '4th ser.') -->\n          <text variable=\"collection-title\"/>\n          <group delimiter=\" \">\n            <choose>\n              <if variable=\"volume\">\n                <choose>\n                  <if variable=\"collection-title\">\n                    <text macro=\"label-volume\"/>\n                  </if>\n                  <else-if match=\"any\" type=\"review review-book\" variable=\"reviewed-author reviewed-genre reviewed-title\">\n                    <!-- provide label if a review `container-title` has been substituted for a missing author (CMOS18 14.87, 14.102) -->\n                    <choose>\n                      <if match=\"any\" variable=\"author chair collection-editor compiler composer curator director editor editor-translator editorial-director executive-producer guest host illustrator organizer producer series-creator translator\">\n                        <text variable=\"volume\"/>\n                      </if>\n                      <!-- TODO: when CSL provides date part detection, volume should be lowercase if there is a month, but otherwise capitalized -->\n                      <else>\n                        <text macro=\"label-volume-capitalized\"/>\n                      </else>\n                    </choose>\n                  </else-if>\n                  <else>\n                    <text variable=\"volume\"/>\n                  </else>\n                </choose>\n                <group delimiter=\", \" prefix=\"(\" suffix=\")\">\n                  <choose>\n                    <if match=\"any\" variable=\"issue supplement-number\">\n                      <text variable=\"issue\"/>\n                      <text macro=\"label-supplement-number\"/>\n                    </if>\n                    <else-if match=\"any\" type=\"review review-book\" variable=\"reviewed-author reviewed-genre reviewed-title\">\n                      <!-- date for unsigned reviews only appears here if it did not earlier (CMOS18 14.102) -->\n                      <choose>\n                        <if match=\"any\" variable=\"author chair collection-editor compiler composer curator director editor editor-translator editorial-director executive-producer guest host illustrator organizer producer series-creator translator\">\n                          <text macro=\"source-date-specific-title-first\"/>\n                        </if>\n                      </choose>\n                    </else-if>\n                    <else>\n                      <text macro=\"source-date-specific-title-first\"/>\n                    </else>\n                  </choose>\n                </group>\n              </if>\n              <else-if match=\"any\" variable=\"issue supplement-number\">\n                <group delimiter=\" \">\n                  <group delimiter=\", \">\n                    <text macro=\"label-issue\"/>\n                    <text macro=\"label-supplement-number\"/>\n                  </group>\n                  <choose>\n                    <if match=\"any\" variable=\"author chair collection-editor compiler composer curator director editor editor-translator editorial-director executive-producer guest host illustrator organizer producer series-creator translator\">\n                      <text macro=\"source-date-specific-title-first\" prefix=\"(\" suffix=\")\"/>\n                    </if>\n                  </choose>\n                </group>\n              </else-if>\n            </choose>\n          </group>\n        </else-if>\n        <else>\n          <text variable=\"collection-title\"/>\n          <choose>\n            <if match=\"any\" type=\"interview post-weblog\">\n              <!-- publisher possible with broadcast `interview` (CMOS18 14.110) or `post-weblog` (CMOS18 14.105) -->\n              <text variable=\"publisher\"/>\n            </if>\n          </choose>\n          <text macro=\"source-serial-volume-status-bib\"/>\n        </else>\n      </choose>\n    </group>\n  </macro>\n  <macro name=\"source-serial-volume-status-bib\">\n    <group delimiter=\", \">\n      <choose>\n        <if match=\"none\" variable=\"collection-title issue number page supplement-number volume\">\n          <group delimiter=\" \">\n            <!-- article accepted for publication and available on publisher website (CMOS18 14.75) -->\n            <!-- TODO: use CSL term for `available-date` when available -->\n            <text value=\"accepted\"/>\n            <date form=\"text\" variable=\"available-date\"/>\n          </group>\n        </if>\n      </choose>\n      <group delimiter=\" \">\n        <text macro=\"source-date-status-bib\"/>\n        <text macro=\"source-date-specific-title-first\"/>\n      </group>\n    </group>\n  </macro>\n  <!-- Serial source locator -->\n  <macro name=\"source-serial-locator\">\n    <choose>\n      <if match=\"any\" variable=\"locator number\">\n        <group delimiter=\", \">\n          <text macro=\"label-locator\"/>\n          <!-- an article ID appears alongside locators in notes (CMOS18 14.71) -->\n          <choose>\n            <!-- if there is an `archive` with no other reference, `number` appears in `source-archive-database-number` -->\n            <if match=\"any\" variable=\"archive_collection archive_location archive-place\">\n              <text variable=\"number\"/>\n            </if>\n            <else-if variable=\"archive\"/>\n            <else>\n              <text variable=\"number\"/>\n            </else>\n          </choose>\n        </group>\n      </if>\n      <!-- do not give pages for magazines or newspapers (CMOS18 14.87, 14.89) -->\n      <else-if match=\"any\" type=\"article-magazine article-newspaper\"/>\n      <else>\n        <text variable=\"page\"/>\n      </else>\n    </choose>\n  </macro>\n  <!-- 4.2. Monographic sources -->\n  <macro name=\"source-monographic-bib\">\n    <group delimiter=\". \">\n      <!-- Monographic sources repeat main reference elements -->\n      <choose>\n        <if variable=\"container-title\">\n          <group delimiter=\", \">\n            <group delimiter=\" \">\n              <text macro=\"source-monographic-preposition-bib\"/>\n              <text macro=\"source-monographic-title-specific-title-first\"/>\n            </group>\n            <text macro=\"source-monographic-description\"/>\n            <text macro=\"source-monographic-identifier-bib\"/>\n            <text macro=\"source-monographic-locator\"/>\n          </group>\n        </if>\n      </choose>\n      <text macro=\"source-monographic-identifier-contributors-bib-container-author\"/>\n      <text macro=\"source-series-bib\"/>\n      <choose>\n        <!-- show event information here only if not collapsed with `issued` (CMOS18 14.167) -->\n        <if match=\"any\" variable=\"event-date original-date original-publisher original-publisher-place publisher status\">\n          <text macro=\"source-event-bib\"/>\n        </if>\n      </choose>\n    </group>\n  </macro>\n  <!-- Monographic source title -->\n  <macro name=\"source-monographic-preposition-bib\">\n    <choose>\n      <if match=\"any\" type=\"broadcast motion_picture\"/>\n      <else-if type=\"chapter\" variable=\"container-title genre\">\n        <text value=\"to\"/>\n      </else-if>\n      <else-if type=\"article-journal\" variable=\"container-title genre volume-title\">\n        <text value=\"to\"/>\n      </else-if>\n      <else-if match=\"any\" type=\"entry entry-dictionary entry-encyclopedia\">\n        <choose>\n          <if match=\"any\" variable=\"author composer\">\n            <!-- Give preposition only for signed entries; otherwise, title is substituted -->\n            <text term=\"in\" text-case=\"capitalize-first\"/>\n          </if>\n        </choose>\n      </else-if>\n      <!-- if printing chapter page numbers (CMOS17/classic):\n      <else-if variable=\"chapter-number page title\"><text term=\"in\" text-case=\"capitalize-first\"/></else-if>\n      -->\n      <else-if variable=\"chapter-number\">\n        <group delimiter=\" \">\n          <text macro=\"label-chapter-number-capitalized\"/>\n          <choose>\n            <if type=\"song\">\n              <text term=\"on\"/>\n            </if>\n            <else>\n              <text term=\"in\"/>\n            </else>\n          </choose>\n        </group>\n      </else-if>\n      <else>\n        <text term=\"in\" text-case=\"capitalize-first\"/>\n      </else>\n    </choose>\n  </macro>\n  <macro name=\"source-monographic-preposition-note\">\n    <choose>\n      <if match=\"any\" type=\"broadcast motion_picture\"/>\n      <else-if type=\"chapter\" variable=\"container-title genre\">\n        <text value=\"to\"/>\n      </else-if>\n      <else-if type=\"article-journal\" variable=\"container-title genre volume-title\">\n        <text value=\"to\"/>\n      </else-if>\n      <else-if match=\"any\" type=\"entry entry-dictionary entry-encyclopedia\">\n        <choose>\n          <if match=\"any\" variable=\"author composer\">\n            <!-- Give preposition only for signed entries; otherwise, title is substituted -->\n            <text term=\"in\"/>\n          </if>\n        </choose>\n      </else-if>\n      <!-- if printing chapter page numbers (CMOS17/classic):\n      <else-if variable=\"chapter-number page title\"><text term=\"in\"/></else-if>\n      -->\n      <else-if variable=\"chapter-number\">\n        <group delimiter=\" \">\n          <text macro=\"label-chapter-number\"/>\n          <choose>\n            <if type=\"song\">\n              <text term=\"on\"/>\n            </if>\n            <else>\n              <text term=\"in\"/>\n            </else>\n          </choose>\n        </group>\n      </else-if>\n      <else>\n        <text term=\"in\"/>\n      </else>\n    </choose>\n  </macro>\n  <macro name=\"source-monographic-title-specific-title-first\">\n    <choose>\n      <if variable=\"part-title\">\n        <text macro=\"title-part\"/>\n      </if>\n      <else-if variable=\"volume-title\">\n        <text macro=\"title-volume\"/>\n      </else-if>\n      <else>\n        <text font-style=\"italic\" text-case=\"title\" variable=\"container-title\"/>\n      </else>\n    </choose>\n  </macro>\n  <!-- Monographic source description -->\n  <macro name=\"source-monographic-description\">\n    <choose>\n      <if match=\"any\" type=\"document report software standard\">\n        <!-- place description after `container-title` -->\n        <text macro=\"description-format-note\"/>\n      </if>\n      <else-if match=\"any\" variable=\"collection-editor compiler editor editorial-director issue page supplement-number volume\"/>\n      <else-if match=\"any\" type=\"event paper-conference performance speech\">\n        <!-- unpublished conference presentations should describe the session -->\n        <text macro=\"description-format-note\"/>\n      </else-if>\n    </choose>\n  </macro>\n  <!-- Monographic source identifier -->\n  <macro name=\"source-monographic-identifier-bib\">\n    <!-- Based on `identifier-bib` -->\n    <choose>\n      <if variable=\"container-title\">\n        <group delimiter=\", \">\n          <choose>\n            <if match=\"none\" type=\"broadcast graphic map motion_picture song\">\n              <!-- For audiovisual media, number information comes after `title`, not `container-title`; `song` places album catalogue `number` with `publisher` (CMOS18 14.163-164) -->\n              <text macro=\"identifier-number-bib\"/>\n            </if>\n          </choose>\n          <text macro=\"label-version\"/>\n          <!-- use note form as `edition` is not capitalized here -->\n          <text macro=\"identifier-edition-note\"/>\n          <text macro=\"source-monographic-identifier-contributors-and-volume-bib-specific-title-first\"/>\n        </group>\n      </if>\n    </choose>\n  </macro>\n  <macro name=\"source-monographic-identifier-contributors-bib\">\n    <choose>\n      <if variable=\"container-author container-title\">\n        <!-- set off `container-author` from other contributors in the bibliography (CMOS18 14.12; for page location, CMOS17 14.110) -->\n        <names variable=\"container-author\">\n          <label form=\"verb\" suffix=\" \"/>\n          <name and=\"text\" initialize=\"false\"/>\n        </names>\n        <!-- other contributors shift to `source-monographic-identifier-contributors-bib-container-author` -->\n      </if>\n      <else>\n        <group delimiter=\", \">\n          <names variable=\"editor-translator\">\n            <label form=\"verb\" suffix=\" \"/>\n            <name and=\"text\" initialize=\"false\"/>\n          </names>\n          <names delimiter=\", \" variable=\"editor translator\">\n            <label form=\"verb\" suffix=\" \"/>\n            <name and=\"text\" initialize=\"false\"/>\n          </names>\n          <names variable=\"guest\">\n            <label form=\"verb\" suffix=\" \"/>\n            <name and=\"text\" initialize=\"false\"/>\n          </names>\n          <names variable=\"host\">\n            <label form=\"verb\" suffix=\" \"/>\n            <name and=\"text\" initialize=\"false\"/>\n          </names>\n          <names delimiter=\", \" variable=\"chair organizer\">\n            <label form=\"verb\" suffix=\" \"/>\n            <name and=\"text\" initialize=\"false\"/>\n          </names>\n          <names delimiter=\", \" variable=\"illustrator narrator compiler curator\">\n            <label form=\"verb\" suffix=\" \"/>\n            <name and=\"text\" initialize=\"false\"/>\n          </names>\n          <names delimiter=\", \" variable=\"series-creator executive-producer\">\n            <label form=\"verb\" suffix=\" \"/>\n            <name and=\"text\" initialize=\"false\"/>\n          </names>\n          <names variable=\"producer\">\n            <label form=\"verb\" suffix=\" \"/>\n            <name and=\"text\" initialize=\"false\"/>\n          </names>\n          <names variable=\"editorial-director\">\n            <label form=\"verb\" suffix=\" \"/>\n            <name and=\"text\" initialize=\"false\"/>\n          </names>\n          <choose>\n            <if match=\"any\" type=\"broadcast performance\">\n              <names variable=\"script-writer\">\n                <label form=\"verb\" suffix=\" \"/>\n                <name and=\"text\" initialize=\"false\"/>\n              </names>\n            </if>\n          </choose>\n          <names variable=\"director\">\n            <label form=\"verb\" suffix=\" \"/>\n            <name and=\"text\" initialize=\"false\"/>\n          </names>\n          <names variable=\"performer\">\n            <label form=\"verb\" suffix=\" \"/>\n            <name and=\"text\" initialize=\"false\"/>\n          </names>\n          <choose>\n            <if match=\"none\" type=\"song thesis\">\n              <!-- Song contributors attached to album (CMOS18 14.163) -->\n              <names variable=\"contributor\">\n                <label form=\"verb\" suffix=\" \"/>\n                <name and=\"text\" initialize=\"false\"/>\n              </names>\n            </if>\n          </choose>\n        </group>\n      </else>\n    </choose>\n  </macro>\n  <macro name=\"source-monographic-identifier-contributors-bib-container-author\">\n    <!-- set off `container-author` from other contributors in the bibliography (CMOS18 14.12; for page location, CMOS17 14.110) -->\n    <choose>\n      <if variable=\"container-author container-title\">\n        <group delimiter=\". \">\n          <names variable=\"editor-translator\">\n            <label form=\"verb\" suffix=\" \" text-case=\"capitalize-first\"/>\n            <name and=\"text\" initialize=\"false\"/>\n          </names>\n          <names delimiter=\". \" variable=\"editor translator\">\n            <label form=\"verb\" suffix=\" \" text-case=\"capitalize-first\"/>\n            <name and=\"text\" initialize=\"false\"/>\n          </names>\n          <names variable=\"guest\">\n            <label form=\"verb\" suffix=\" \" text-case=\"capitalize-first\"/>\n            <name and=\"text\" initialize=\"false\"/>\n          </names>\n          <names variable=\"host\">\n            <label form=\"verb\" suffix=\" \" text-case=\"capitalize-first\"/>\n            <name and=\"text\" initialize=\"false\"/>\n          </names>\n          <names delimiter=\". \" variable=\"chair organizer\">\n            <label form=\"verb\" suffix=\" \" text-case=\"capitalize-first\"/>\n            <name and=\"text\" initialize=\"false\"/>\n          </names>\n          <names delimiter=\". \" variable=\"illustrator narrator compiler curator\">\n            <label form=\"verb\" suffix=\" \" text-case=\"capitalize-first\"/>\n            <name and=\"text\" initialize=\"false\"/>\n          </names>\n          <names delimiter=\". \" variable=\"series-creator executive-producer\">\n            <label form=\"verb\" suffix=\" \" text-case=\"capitalize-first\"/>\n            <name and=\"text\" initialize=\"false\"/>\n          </names>\n          <names variable=\"producer\">\n            <label form=\"verb\" suffix=\" \" text-case=\"capitalize-first\"/>\n            <name and=\"text\" initialize=\"false\"/>\n          </names>\n          <names variable=\"editorial-director\">\n            <label form=\"verb\" suffix=\" \" text-case=\"capitalize-first\"/>\n            <name and=\"text\" initialize=\"false\"/>\n          </names>\n          <choose>\n            <if match=\"any\" type=\"broadcast performance\">\n              <names variable=\"script-writer\">\n                <label form=\"verb\" suffix=\" \" text-case=\"capitalize-first\"/>\n                <name and=\"text\" initialize=\"false\"/>\n              </names>\n            </if>\n          </choose>\n          <names variable=\"director\">\n            <label form=\"verb\" suffix=\" \" text-case=\"capitalize-first\"/>\n            <name and=\"text\" initialize=\"false\"/>\n          </names>\n          <names variable=\"performer\">\n            <label form=\"verb\" suffix=\" \" text-case=\"capitalize-first\"/>\n            <name and=\"text\" initialize=\"false\"/>\n          </names>\n          <choose>\n            <if match=\"none\" type=\"song thesis\">\n              <!-- Song contributors attached to album (CMOS18 14.163) -->\n              <names variable=\"contributor\">\n                <label form=\"verb\" suffix=\" \" text-case=\"capitalize-first\"/>\n                <name and=\"text\" initialize=\"false\"/>\n              </names>\n            </if>\n          </choose>\n        </group>\n      </if>\n    </choose>\n  </macro>\n  <macro name=\"source-monographic-identifier-contributors-and-volume-bib-specific-title-first\">\n    <group delimiter=\", \">\n      <text macro=\"source-monographic-identifier-contributors-bib\"/>\n      <text macro=\"source-monographic-identifier-volume-bib-specific-title-first\"/>\n      <choose>\n        <if match=\"any\" variable=\"number-of-volumes part-number part-title volume volume-title\">\n          <!-- cite multivolume `collection-editor`; otherwise it belongs with `collection-title` -->\n          <names variable=\"collection-editor\">\n            <label form=\"verb\" suffix=\" \"/>\n            <name and=\"text\" initialize=\"false\"/>\n          </names>\n        </if>\n      </choose>\n      <choose>\n        <if match=\"any\" variable=\"part-number part-title volume volume-title\"/>\n        <else-if variable=\"page\"/>\n        <else>\n          <text macro=\"label-number-of-volumes\"/>\n        </else>\n      </choose>\n    </group>\n  </macro>\n  <macro name=\"source-monographic-identifier-volume-bib-specific-title-first\">\n    <!-- based on `identifier-volume-bib-specific-title-first` without capitalization; giving `container-title` rather than `title-primary`; and ensuring volume number -->\n    <group delimiter=\", \">\n      <choose>\n        <if variable=\"part-number part-title volume volume-title\">\n          <!-- part and title with individual titles -->\n          <group delimiter=\" \">\n            <text macro=\"label-part-number\"/>\n            <text value=\"of\"/>\n            <text macro=\"title-volume\"/>\n          </group>\n          <group delimiter=\" \">\n            <text macro=\"label-volume\"/>\n            <text value=\"of\"/>\n            <text font-style=\"italic\" text-case=\"title\" variable=\"container-title\"/>\n          </group>\n        </if>\n        <else-if match=\"any\" variable=\"part-title volume-title\">\n          <group delimiter=\" \">\n            <choose>\n              <if variable=\"part-number volume\">\n                <group delimiter=\", \">\n                  <text macro=\"label-volume\"/>\n                  <text macro=\"label-part-number\"/>\n                  <text value=\"of\"/>\n                </group>\n              </if>\n              <else-if variable=\"part-number\">\n                <text macro=\"label-part-number\"/>\n                <text value=\"of\"/>\n              </else-if>\n              <else-if variable=\"volume\">\n                <text macro=\"label-volume\"/>\n                <text value=\"of\"/>\n              </else-if>\n            </choose>\n            <text font-style=\"italic\" text-case=\"title\" variable=\"container-title\"/>\n          </group>\n        </else-if>\n        <else-if variable=\"part-number\">\n          <text macro=\"label-volume\"/>\n          <text macro=\"label-part-number\"/>\n        </else-if>\n        <else-if is-numeric=\"volume\" match=\"none\">\n          <text macro=\"label-volume\"/>\n        </else-if>\n        <else-if variable=\"container-title\">\n          <!-- remove condition in styles that print chapter page numbers (CMOS17/classic) -->\n          <text macro=\"label-volume\"/>\n        </else-if>\n        <else-if is-numeric=\"volume\" variable=\"page\">\n          <choose>\n            <!-- check for variables that might come between the volume and page number -->\n            <if variable=\"collection-editor\">\n              <text macro=\"label-volume\"/>\n            </if>\n          </choose>\n        </else-if>\n        <else>\n          <text macro=\"label-volume\"/>\n        </else>\n      </choose>\n    </group>\n  </macro>\n  <!-- Monographic source locator -->\n  <macro name=\"source-monographic-locator\">\n    <choose>\n      <!-- archival locators appear after the shelfmark (CMOS18 14.127) -->\n      <if locator=\"column\" variable=\"archive archive_location\"/>\n      <else-if locator=\"folio\" variable=\"archive archive_location\"/>\n      <else-if locator=\"page\" variable=\"archive archive_location\"/>\n      <else-if is-numeric=\"volume\" locator=\"page\">\n        <!-- separate a volume and page number with a colon (CMOS18 14.18) -->\n        <group delimiter=\":\">\n          <choose>\n            <if match=\"any\" variable=\"part-number part-title volume-title\"/>\n            <else-if variable=\"collection-editor\"/>\n            <else>\n              <text variable=\"volume\"/>\n            </else>\n          </choose>\n          <text variable=\"locator\"/>\n        </group>\n      </else-if>\n      <else-if variable=\"locator\">\n        <text macro=\"label-locator\"/>\n      </else-if>\n      <!-- remove `container-title` condition in styles that print chapter page numbers (CMOS17/classic) -->\n      <else-if variable=\"container-title\"/>\n      <else-if is-numeric=\"volume\" variable=\"page\">\n        <!-- collapse the volume and page number if adjacent (CMOS18 14.18) -->\n        <group delimiter=\":\">\n          <choose>\n            <!-- check for variables that might come between the volume and page number -->\n            <if match=\"any\" variable=\"part-number part-title volume-title\"/>\n            <else-if variable=\"collection-editor\"/>\n            <else>\n              <text variable=\"volume\"/>\n            </else>\n          </choose>\n          <text variable=\"page\"/>\n        </group>\n      </else-if>\n      <!-- archival locators appear after the shelfmark (CMOS18 14.127) -->\n      <else-if variable=\"archive archive_location page\"/>\n      <else>\n        <text variable=\"page\"/>\n      </else>\n    </choose>\n  </macro>\n  <!-- 4.3. Series -->\n  <macro name=\"source-series-bib\">\n    <group delimiter=\", \">\n      <choose>\n        <if match=\"any\" variable=\"number-of-volumes part-number part-title volume volume-title\">\n          <text macro=\"source-series-title\"/>\n        </if>\n        <else-if variable=\"collection-editor collection-title\">\n          <!-- `collection-editor` belongs with `collection-title` if the item is not multivolume -->\n          <text text-case=\"title\" variable=\"collection-title\"/>\n          <names variable=\"collection-editor\">\n            <label form=\"verb\" suffix=\" \"/>\n            <name and=\"text\" initialize=\"false\"/>\n          </names>\n          <text macro=\"label-collection-number\"/>\n          <text macro=\"label-issue\"/>\n        </else-if>\n        <else>\n          <text macro=\"source-series-title\"/>\n        </else>\n      </choose>\n    </group>\n  </macro>\n  <macro name=\"source-series-title\">\n    <group delimiter=\", \">\n      <choose>\n        <if variable=\"issue\">\n          <text text-case=\"title\" variable=\"collection-title\"/>\n          <text macro=\"label-collection-number\"/>\n          <text macro=\"label-issue\"/>\n        </if>\n        <else-if is-numeric=\"collection-number\" variable=\"collection-title\">\n          <group delimiter=\" \">\n            <text text-case=\"title\" variable=\"collection-title\"/>\n            <text variable=\"collection-number\"/>\n          </group>\n        </else-if>\n        <else-if variable=\"collection-title\">\n          <text text-case=\"title\" variable=\"collection-title\"/>\n          <text variable=\"collection-number\"/>\n        </else-if>\n      </choose>\n    </group>\n  </macro>\n  <!-- 4.4. Event -->\n  <macro name=\"source-event-bib\">\n    <group delimiter=\" \">\n      <choose>\n        <!-- omit types that provide event information in description  -->\n        <if match=\"any\" type=\"interview\" variable=\"interviewer\"/>\n        <else-if type=\"personal_communication\" variable=\"recipient\"/>\n        <else-if match=\"any\" type=\"review review-book\" variable=\"reviewed-author reviewed-genre reviewed-title\"/>\n        <else-if match=\"any\" variable=\"event event-date event-title\">\n          <!-- TODO: To prevent Zotero from printing `event-place`, due to its double-mapping of `publisher-place` and `event-place`. Remove this when that is changed. -->\n          <choose>\n            <if type=\"paper-conference\">\n              <choose>\n                <if match=\"none\" variable=\"collection-editor compiler editor editorial-director issue page supplement-number volume\">\n                  <!-- Don't print event info for conference papers published in proceedings -->\n                  <text macro=\"source-event-status-bib\"/>\n                  <text macro=\"source-event-description-bib\"/>\n                </if>\n              </choose>\n            </if>\n            <else>\n              <!-- For other item types, print event info even if published (e.g. collection catalogs, performance programs). -->\n              <text macro=\"source-event-status-bib\"/>\n              <text macro=\"source-event-description-bib\"/>\n            </else>\n          </choose>\n        </else-if>\n      </choose>\n    </group>\n  </macro>\n  <macro name=\"source-event-place-first\">\n    <!-- for descriptive elements for interviews, reviews, letters -->\n    <choose>\n      <if match=\"any\" variable=\"event event-date event-title\">\n        <group delimiter=\", \">\n          <text variable=\"event-title\"/>\n          <text variable=\"event-place\"/>\n          <text macro=\"date-event-full\"/>\n        </group>\n      </if>\n    </choose>\n  </macro>\n  <macro name=\"source-event-status-bib\">\n    <group delimiter=\" \">\n      <choose>\n        <if type=\"broadcast\" variable=\"status\">\n          <!-- 'aired', 'performed', etc. (CMOS18 14.165) -->\n          <text text-case=\"capitalize-first\" variable=\"status\"/>\n        </if>\n        <else-if type=\"paper-conference\">\n          <choose>\n            <if variable=\"genre\">\n              <text text-case=\"capitalize-first\" value=\"presented\"/>\n            </if>\n            <else>\n              <text form=\"short\" term=\"paper-conference\" text-case=\"capitalize-first\"/>\n              <text value=\"presented\"/>\n            </else>\n          </choose>\n          <choose>\n            <if variable=\"event-title\">\n              <text term=\"at\"/>\n            </if>\n          </choose>\n        </else-if>\n        <else-if type=\"song\">\n          <text text-case=\"capitalize-first\" value=\"recorded\"/>\n          <choose>\n            <if variable=\"event-title\">\n              <text term=\"at\"/>\n            </if>\n          </choose>\n        </else-if>\n        <else-if variable=\"event-date issued\"/>\n        <else-if variable=\"issued\"/>\n        <else>\n          <text text-case=\"capitalize-first\" variable=\"status\"/>\n        </else>\n      </choose>\n    </group>\n  </macro>\n  <macro name=\"source-event-title\">\n    <choose>\n      <!-- TODO: We expect `event-title` to be used, but processors and applications may not be updated yet. This macro ensures that either `event` or `event-title` can be accepted. Remove if processor logic and application adoption can handle this. -->\n      <if variable=\"event-title\">\n        <text variable=\"event-title\"/>\n      </if>\n      <else>\n        <text variable=\"event\"/>\n      </else>\n    </choose>\n  </macro>\n  <macro name=\"source-event-title-capitalized\">\n    <choose>\n      <!-- TODO: We expect `event-title` to be used, but processors and applications may not be updated yet. This macro ensures that either `event` or `event-title` can be accepted. Remove if processor logic and application adoption can handle this. -->\n      <if variable=\"event-title\">\n        <text text-case=\"capitalize-first\" variable=\"event-title\"/>\n      </if>\n      <else>\n        <text text-case=\"capitalize-first\" variable=\"event\"/>\n      </else>\n    </choose>\n  </macro>\n  <macro name=\"source-event-description-bib\">\n    <group delimiter=\", \">\n      <choose>\n        <if type=\"song\">\n          <text macro=\"source-event-title\"/>\n        </if>\n        <else-if type=\"paper-conference\" variable=\"genre\">\n          <text macro=\"source-event-title-capitalized\"/>\n        </else-if>\n        <else-if type=\"paper-conference\">\n          <text macro=\"source-event-title\"/>\n        </else-if>\n        <else>\n          <text macro=\"source-event-title-capitalized\"/>\n        </else>\n      </choose>\n      <text macro=\"date-event-full\"/>\n      <text variable=\"event-place\"/>\n    </group>\n  </macro>\n  <!-- 4.5. Facts of publication -->\n  <macro name=\"source-monographic-publication-bib\">\n    <group delimiter=\". \">\n      <choose>\n        <!-- `patent` date in identification (CMOS18 14.158) -->\n        <if type=\"patent\"/>\n        <!-- omit serial types -->\n        <else-if match=\"any\" type=\"article-journal article-magazine article-newspaper periodical post-weblog review review-book\"/>\n        <else-if match=\"any\" variable=\"collection-editor compiler editor editorial-director\">\n          <!-- monographic types -->\n          <text macro=\"source-publication-and-date-bib\"/>\n        </else-if>\n        <!-- omit serial types -->\n        <else-if match=\"any\" type=\"interview paper-conference\"/>\n        <else>\n          <!-- monographic types -->\n          <text macro=\"source-publication-and-date-bib\"/>\n        </else>\n      </choose>\n      <text macro=\"source-publication-original-title-bib\"/>\n    </group>\n  </macro>\n  <macro name=\"source-publication-and-date-bib\">\n    <group delimiter=\", \">\n      <choose>\n        <if match=\"any\" type=\"post webpage\">\n          <!-- print `container-title` on `post` or `webpage` in the same way as `publisher` (CMOS18 14.104-106) -->\n          <text text-case=\"title\" variable=\"container-title\"/>\n        </if>\n      </choose>\n      <choose>\n        <if type=\"broadcast\" variable=\"DOI\">\n          <!-- a podcast publisher appears before the date, whereas the network of an aired show appears after (CMOS18 14.165); unfortunately CSL stores both in `publisher` -->\n          <!-- TODO: `DOI` or `URL` detection is the only way to distinguish radio/TV from podcasts, but it is obviously imprecise; modify if CSL provides a `podcast` type -->\n          <text macro=\"source-publication-history-bib\"/>\n        </if>\n        <else-if type=\"broadcast\" variable=\"URL\">\n          <text macro=\"source-publication-history-bib\"/>\n        </else-if>\n        <else-if type=\"broadcast\"/>\n        <else>\n          <text macro=\"source-publication-history-bib\"/>\n        </else>\n      </choose>\n      <group delimiter=\" \">\n        <text macro=\"source-date-status-bib\"/>\n        <text macro=\"source-date-specific-title-first\"/>\n      </group>\n      <choose>\n        <if type=\"broadcast\" variable=\"URL\"/>\n        <else-if type=\"broadcast\">\n          <group delimiter=\" \">\n            <text term=\"on\"/>\n            <text macro=\"source-publication-history-bib\"/>\n          </group>\n        </else-if>\n      </choose>\n    </group>\n  </macro>\n  <!-- Facts of publication elements -->\n  <macro name=\"source-publication-description-bib\">\n    <choose>\n      <if type=\"article\" variable=\"genre\"/>\n      <else-if type=\"article\">\n        <!-- `preprint` term attached to repository name, but specific working paper descriptors appear in description (CMOS18 14.76, 14.116) -->\n        <text term=\"preprint\" text-case=\"capitalize-first\"/>\n      </else-if>\n      <else-if type=\"thesis\">\n        <!-- thesis type appears with university name (CMOS18 14.113) -->\n        <text text-case=\"capitalize-first\" variable=\"genre\"/>\n      </else-if>\n      <else-if match=\"any\" variable=\"original-publisher original-publisher-place\">\n        <choose>\n          <!-- `edition` provides an alternative label to `reprint` (CMOS18 14.16) -->\n          <if match=\"any\" variable=\"edition original-title\"/>\n          <else-if match=\"none\" type=\"book chapter classic entry entry-dictionary entry-encyclopedia interview musical_score pamphlet paper-conference report thesis\"/>\n          <else-if variable=\"issued original-date\">\n            <text text-case=\"capitalize-first\" value=\"reprint\"/>\n          </else-if>\n        </choose>\n      </else-if>\n    </choose>\n  </macro>\n  <macro name=\"source-publication-history-bib\">\n    <choose>\n      <if variable=\"original-title\">\n        <!-- `original-title` is covered in `source-publication-original-title-bib` -->\n        <group delimiter=\", \">\n          <text macro=\"source-publication-description-bib\"/>\n          <text macro=\"source-publication-publisher-bib\"/>\n        </group>\n      </if>\n      <else-if match=\"any\" variable=\"edition original-publisher original-publisher-place\">\n        <group delimiter=\". \">\n          <!-- full stop to separate original date if `original-publisher` (CMOS18 14.16) -->\n          <group delimiter=\", \">\n            <text macro=\"source-publication-publisher-original-bib\"/>\n            <text macro=\"source-date-original\"/>\n          </group>\n          <group delimiter=\". \">\n            <choose>\n              <if variable=\"issued original-date\">\n                <text macro=\"label-edition-capitalized\"/>\n              </if>\n            </choose>\n            <group delimiter=\", \">\n              <text macro=\"source-publication-description-bib\"/>\n              <text macro=\"source-publication-publisher-bib\"/>\n            </group>\n          </group>\n        </group>\n      </else-if>\n      <else>\n        <group delimiter=\"; \">\n          <!-- semicolon to separate original date if no publisher (CMOS18 14.165) -->\n          <text macro=\"source-date-original\"/>\n          <group delimiter=\", \">\n            <text macro=\"source-publication-description-bib\"/>\n            <text macro=\"source-publication-publisher-bib\"/>\n          </group>\n        </group>\n      </else>\n    </choose>\n  </macro>\n  <macro name=\"source-publication-original-title-bib\">\n    <!-- Work originally published under a different title (CMOS18 13.101) -->\n    <choose>\n      <if variable=\"original-title\">\n        <group delimiter=\" \">\n          <text term=\"original-work-published\" text-case=\"capitalize-first\"/>\n          <group delimiter=\", \">\n            <names variable=\"original-author\">\n              <name and=\"text\" initialize=\"false\"/>\n            </names>\n            <text font-style=\"italic\" text-case=\"title\" variable=\"original-title\"/>\n          </group>\n          <group delimiter=\", \" prefix=\"(\" suffix=\")\">\n            <text macro=\"source-publication-publisher-original-bib\"/>\n            <text macro=\"source-date-original\"/>\n          </group>\n        </group>\n      </if>\n    </choose>\n  </macro>\n  <macro name=\"source-publication-publisher-bib\">\n    <group delimiter=\" \">\n      <choose>\n        <if type=\"thesis\" variable=\"publisher\">\n          <text text-case=\"capitalize-first\" variable=\"publisher\"/>\n        </if>\n        <else-if variable=\"publisher\">\n          <group delimiter=\": \">\n            <!-- <text text-case=\"capitalize-first\" variable=\"publisher-place\"/> -->\n            <text text-case=\"capitalize-first\" variable=\"publisher\"/>\n          </group>\n        </else-if>\n        <!-- TODO: remove conditional when Zotero fixes double-mapping of `event-place` -->\n        <else-if match=\"any\" variable=\"event-date event-title\"/>\n        <else>\n          <text text-case=\"capitalize-first\" variable=\"publisher-place\"/>\n        </else>\n      </choose>\n      <choose>\n        <if type=\"song\">\n          <!-- Album catalogue number follows label name (CMOS18 14.163-164) -->\n          <text variable=\"number\"/>\n        </if>\n      </choose>\n    </group>\n  </macro>\n  <macro name=\"source-publication-publisher-original-bib\">\n    <choose>\n      <if variable=\"original-publisher\">\n        <group delimiter=\": \">\n          <!-- <text text-case=\"capitalize-first\" variable=\"original-publisher-place\"/> -->\n          <text text-case=\"capitalize-first\" variable=\"original-publisher\"/>\n        </group>\n      </if>\n      <else>\n        <text text-case=\"capitalize-first\" variable=\"original-publisher-place\"/>\n      </else>\n    </choose>\n  </macro>\n  <!-- 4.6. Date -->\n  <macro name=\"source-date-specific-title-first\">\n    <!-- date for the last-mentioned title, for author-date or notes and bibliography leading with volume title (CMOS18 14.21) -->\n    <choose>\n      <if variable=\"available-date volume-title\">\n        <!-- TODO: Is there a better CSL variable for a date of a multivolume work (CMOS18 14.21)? -->\n        <date date-parts=\"year\" form=\"numeric\" variable=\"available-date\"/>\n      </if>\n      <else-if variable=\"available-date part-title\">\n        <date date-parts=\"year\" form=\"numeric\" variable=\"available-date\"/>\n      </else-if>\n      <else-if match=\"any\" type=\"article-journal article-magazine article-newspaper periodical post-weblog review review-book\">\n        <!-- serial types -->\n        <text macro=\"source-date-issued-month-day\"/>\n        <!-- for CMOS17 author-date: -->\n        <!-- <text macro=\"source-date-issued-full-serial\"/> -->\n        <!-- for notes and bibliography leading with volume title (CMOS18 14.21): -->\n        <!-- <text macro=\"source-date-issued-or-status\"/> -->\n      </else-if>\n      <else-if match=\"any\" variable=\"collection-editor compiler editor editorial-director\">\n        <!-- monographic types -->\n        <text macro=\"source-date-issued-month-day\"/>\n        <!-- for notes and bibliography leading with volume title (CMOS18 14.21): -->\n        <!-- <text macro=\"source-date-issued-or-status\"/> -->\n      </else-if>\n      <else-if match=\"any\" type=\"interview paper-conference\">\n        <!-- serial types -->\n        <text macro=\"source-date-issued-month-day\"/>\n        <!-- for CMOS17 author-date: -->\n        <!-- <text macro=\"source-date-issued-full-serial\"/> -->\n        <!-- for notes and bibliography leading with volume title (CMOS18 14.21): -->\n        <!-- <text macro=\"source-date-issued-or-status\"/> -->\n      </else-if>\n      <else>\n        <!-- monographic types -->\n        <text macro=\"source-date-issued-month-day\"/>\n        <!-- for notes and bibliography leading with volume title (CMOS18 14.21): -->\n        <!-- <text macro=\"source-date-issued-or-status\"/> -->\n      </else>\n    </choose>\n  </macro>\n  <!-- Date elements -->\n  <macro name=\"source-date-issued-month-day\">\n    <!-- Use with author-date -->\n    <!-- Give full date for more ephemeral types -->\n    <!-- NB: any changes must also be applied to `source-date-original-month-day` -->\n    <choose>\n      <if type=\"personal_communication\" variable=\"event-date issued\">\n        <!-- Provide issue date for letters listed under event-date -->\n        <text macro=\"date-issued-year\"/>\n      </if>\n      <else-if match=\"any\" type=\"entry entry-dictionary entry-encyclopedia\">\n        <choose>\n          <if match=\"any\" variable=\"DOI URL\">\n            <!-- Online reference works use full dates (CMOS18 14.131) -->\n            <text macro=\"date-issued-month-day\"/>\n          </if>\n        </choose>\n      </else-if>\n      <else-if match=\"any\" type=\"article broadcast collection dataset document event graphic manuscript map patent performance personal_communication post software song speech standard webpage\">\n        <text macro=\"date-issued-month-day\"/>\n      </else-if>\n      <else-if match=\"any\" type=\"article-journal article-magazine article-newspaper periodical post-weblog review review-book\">\n        <text macro=\"source-date-issued-month-day-serial\"/>\n      </else-if>\n      <!-- omit monographic types -->\n      <else-if match=\"any\" variable=\"collection-editor compiler editor editorial-director\"/>\n      <else-if match=\"any\" type=\"interview paper-conference\">\n        <!-- serial types -->\n        <text macro=\"source-date-issued-month-day-serial\"/>\n      </else-if>\n    </choose>\n  </macro>\n  <macro name=\"source-date-issued-month-day-serial\">\n    <choose>\n      <if match=\"any\" type=\"article-magazine article-newspaper\">\n        <!-- magazines and newspapers provide the full date in place of volume/issue numbers (CMOS18 14.87, 14.89) -->\n        <text macro=\"date-issued-month-day\"/>\n      </if>\n      <else-if match=\"any\" variable=\"issue supplement-number volume\">\n        <text macro=\"date-issued-month\"/>\n      </else-if>\n      <else>\n        <text macro=\"date-issued-month-day\"/>\n      </else>\n    </choose>\n  </macro>\n  <macro name=\"source-date-original\">\n    <text macro=\"source-date-original-month-day\"/>\n  </macro>\n  <macro name=\"source-date-original-month-day\">\n    <!-- Give full date for more ephemeral types -->\n    <!-- Macro derived from `source-date-issued-month-day` -->\n    <choose>\n      <if type=\"personal_communication\" variable=\"event-date original-date\">\n        <!-- Provide original date for letters listed under event-date -->\n        <text macro=\"date-original-year\"/>\n      </if>\n      <else-if match=\"any\" type=\"entry entry-dictionary entry-encyclopedia\">\n        <choose>\n          <if match=\"any\" variable=\"DOI URL\">\n            <!-- Online reference works use full dates (CMOS18 14.131) -->\n            <text macro=\"date-original-month-day\"/>\n          </if>\n        </choose>\n      </else-if>\n      <else-if match=\"any\" type=\"article broadcast collection dataset document event graphic manuscript map patent performance personal_communication post software song speech standard webpage\">\n        <text macro=\"date-original-month-day\"/>\n      </else-if>\n      <else-if match=\"any\" type=\"article-journal article-magazine article-newspaper periodical post-weblog review review-book\">\n        <choose>\n          <if match=\"any\" variable=\"issue supplement-number volume\">\n            <text macro=\"date-original-month\"/>\n          </if>\n          <else>\n            <text macro=\"date-original-month-day\"/>\n          </else>\n        </choose>\n      </else-if>\n      <else-if match=\"any\" type=\"interview paper-conference\">\n        <choose>\n          <if match=\"any\" variable=\"collection-editor compiler editor editorial-director\"/>\n          <else-if match=\"any\" variable=\"issue supplement-number volume\">\n            <text macro=\"date-original-month\"/>\n          </else-if>\n          <else>\n            <text macro=\"date-original-month-day\"/>\n          </else>\n        </choose>\n      </else-if>\n    </choose>\n  </macro>\n  <macro name=\"source-date-status-bib\">\n    <choose>\n      <if type=\"broadcast\" variable=\"event-title issued status\"/>\n      <!-- on a `broadcast`, if there is an `event-title`, `status` appears with `event-date` as part of `source-event` (CMOS18 14.165) -->\n      <else-if variable=\"issued status\">\n        <!-- `status` specifies date type, e.g. 'effective', 'last modified', 'approved' (CMOS18 14.104 for `webpage`; CMOS18 14.159 for `standard`) -->\n        <choose>\n          <if type=\"webpage\" variable=\"container-title\">\n            <text variable=\"status\"/>\n          </if>\n          <else-if type=\"webpage\" variable=\"author publisher\">\n            <text variable=\"status\"/>\n          </else-if>\n          <else-if type=\"webpage\" variable=\"translator publisher\">\n            <text variable=\"status\"/>\n          </else-if>\n          <else-if type=\"webpage\">\n            <!-- capitalize `status` if there is nothing else after the `title` (either no website title or substituted publisher) -->\n            <text text-case=\"capitalize-first\" variable=\"status\"/>\n          </else-if>\n          <else-if match=\"any\" variable=\"original-date original-publisher original-publisher-place original-title publisher\">\n            <text variable=\"status\"/>\n          </else-if>\n          <else>\n            <text text-case=\"capitalize-first\" variable=\"status\"/>\n          </else>\n        </choose>\n      </else-if>\n      <else-if type=\"broadcast\" variable=\"issued URL\"/>\n      <else-if type=\"broadcast\" variable=\"issued\">\n        <!-- `status` of a radio or TV broadcast is 'aired' if unspecified (CMOS18 14.165) -->\n        <text text-case=\"capitalize-first\" value=\"aired\"/>\n      </else-if>\n      <else-if type=\"software\" variable=\"issued publisher\">\n        <!-- `status` of software is 'released' if unspecified (CMOS18 14.169) -->\n        <choose>\n          <if match=\"any\" variable=\"author chair collection-editor compiler composer contributor curator director editor editor-translator editorial-director executive-producer guest host illustrator organizer producer series-creator translator\">\n            <!-- lowercase if `publisher` is adjacent -->\n            <text value=\"released\"/>\n          </if>\n          <else>\n            <text text-case=\"capitalize-first\" value=\"released\"/>\n          </else>\n        </choose>\n      </else-if>\n      <else-if type=\"software\" variable=\"original-date\">\n        <!-- lowercase if `original-date` is adjacent -->\n        <text value=\"released\"/>\n      </else-if>\n      <else-if type=\"software\" variable=\"issued\">\n        <!-- capitalize if `publisher` is not present -->\n        <text text-case=\"capitalize-first\" value=\"released\"/>\n      </else-if>\n    </choose>\n  </macro>\n  <!-- 4.7. Locator (including page references) -->\n  <macro name=\"source-locator-author-date\">\n    <choose>\n      <if match=\"any\" type=\"entry entry-dictionary entry-encyclopedia\">\n        <choose>\n          <if match=\"any\" variable=\"author locator\">\n            <text macro=\"label-locator\"/>\n          </if>\n          <else-if variable=\"container-title title\">\n            <!-- unsigned reference entry title appears in the locator (CMOS18 13.130) -->\n            <group delimiter=\" \">\n              <choose>\n                <if match=\"none\" variable=\"DOI URL\">\n                  <!-- Only print reference entries use `sub-verbo` (CMOS18 14.131) -->\n                  <text form=\"short\" term=\"sub-verbo\"/>\n                </if>\n              </choose>\n              <text form=\"short\" quotes=\"true\" variable=\"title\"/>\n            </group>\n          </else-if>\n        </choose>\n      </if>\n      <else>\n        <text macro=\"label-locator\"/>\n      </else>\n    </choose>\n  </macro>\n  <!-- 4.8. Medium -->\n  <macro name=\"source-medium-bib\">\n    <group delimiter=\", \">\n      <text text-case=\"capitalize-first\" variable=\"medium\"/>\n      <text variable=\"scale\"/>\n      <text variable=\"dimensions\"/>\n    </group>\n  </macro>\n  <macro name=\"source-medium-note\">\n    <group delimiter=\", \">\n      <text variable=\"medium\"/>\n      <text variable=\"scale\"/>\n      <text variable=\"dimensions\"/>\n    </group>\n  </macro>\n  <!-- 4.9. Archival location -->\n  <macro name=\"source-archive-bib\">\n    <group delimiter=\" \">\n      <choose>\n        <if type=\"graphic\">\n          <text macro=\"source-archive-reference-institution-first\"/>\n        </if>\n        <else>\n          <text macro=\"source-archive-reference-location-first-bib\"/>\n        </else>\n      </choose>\n      <text macro=\"source-archive-database-number\" prefix=\"(\" suffix=\")\"/>\n    </group>\n  </macro>\n  <macro name=\"source-archive-note\">\n    <group delimiter=\" \">\n      <choose>\n        <if type=\"graphic\">\n          <text macro=\"source-archive-reference-institution-first\"/>\n        </if>\n        <else>\n          <text macro=\"source-archive-reference-location-first-note\"/>\n        </else>\n      </choose>\n      <text macro=\"source-archive-database-number\" prefix=\"(\" suffix=\")\"/>\n    </group>\n  </macro>\n  <!-- Archival elements -->\n  <macro name=\"source-archive-database-number\">\n    <!-- database identifier, if not included elsewhere (CMOS18 14.113) -->\n    <choose>\n      <if match=\"any\" variable=\"archive_collection archive_location archive-place\"/>\n      <!-- `number` never shown elsewhere with a thesis -->\n      <else-if type=\"thesis\">\n        <text variable=\"number\"/>\n      </else-if>\n      <!-- `number` shown with `genre` -->\n      <else-if match=\"any\" type=\"dataset entry song\" variable=\"genre\"/>\n      <else-if variable=\"archive\">\n        <text variable=\"number\"/>\n      </else-if>\n    </choose>\n  </macro>\n  <macro name=\"source-archive-locator\">\n    <choose>\n      <!-- physical locators with archival references appear after the shelfmark (CMOS18 14.127) -->\n      <if locator=\"column\" variable=\"archive archive_location\">\n        <!-- archival locators must always be labelled to avoid confusion with `archive_location` (CMOS18 14.123) -->\n        <text macro=\"label-locator-all\"/>\n      </if>\n      <else-if locator=\"folio\" variable=\"archive archive_location\">\n        <text macro=\"label-locator-all\"/>\n      </else-if>\n      <else-if locator=\"page\" variable=\"archive archive_location\">\n        <text macro=\"label-locator-all\"/>\n      </else-if>\n      <else-if variable=\"archive archive_location page\">\n        <choose>\n          <if is-numeric=\"page\">\n            <!-- TODO: remove this conditional when `page` parsing is fixed for different locator types -->\n            <text macro=\"label-page\"/>\n          </if>\n          <else>\n            <text variable=\"page\"/>\n          </else>\n        </choose>\n      </else-if>\n    </choose>\n  </macro>\n  <macro name=\"source-archive-reference-institution-first\">\n    <!-- Archive (gallery) name first for art (CMOS18 14.133) -->\n    <group delimiter=\", \">\n      <text variable=\"archive\"/>\n      <text variable=\"archive-place\"/>\n      <text variable=\"archive_collection\"/>\n      <text variable=\"archive_location\"/>\n      <text macro=\"source-archive-locator\"/>\n    </group>\n  </macro>\n  <macro name=\"source-archive-reference-location-first-bib\">\n    <!-- Order of elements begins with the most specific (CMOS18 14.128) -->\n    <group delimiter=\". \">\n      <group delimiter=\", \">\n        <text text-case=\"capitalize-first\" variable=\"archive_location\"/>\n        <text macro=\"source-archive-locator\"/>\n      </group>\n      <text variable=\"archive_collection\"/>\n      <group delimiter=\", \">\n        <text variable=\"archive\"/>\n        <text variable=\"archive-place\"/>\n      </group>\n    </group>\n  </macro>\n  <macro name=\"source-archive-reference-location-first-note\">\n    <!-- Order of elements begins with the most specific (CMOS18 14.127) -->\n    <group delimiter=\", \">\n      <text variable=\"archive_location\"/>\n      <text macro=\"source-archive-locator\"/>\n      <text variable=\"archive_collection\"/>\n      <text variable=\"archive\"/>\n      <text variable=\"archive-place\"/>\n    </group>\n  </macro>\n  <!-- 4.10. URL or persistent identifier -->\n  <macro name=\"source-date-accessed-DOI-URL-bib\">\n    <group delimiter=\". \">\n      <choose>\n        <if variable=\"DOI\"/>\n        <else-if match=\"any\" variable=\"available-date event-date issued status\"/>\n        <else-if variable=\"accessed URL\">\n          <group delimiter=\" \">\n            <text term=\"accessed\" text-case=\"capitalize-first\"/>\n            <date form=\"text\" variable=\"accessed\"/>\n          </group>\n        </else-if>\n      </choose>\n      <text macro=\"source-DOI-URL\"/>\n    </group>\n  </macro>\n  <macro name=\"source-DOI-URL\">\n    <choose>\n      <if variable=\"DOI\">\n        <text prefix=\"https://doi.org/\" variable=\"DOI\"/>\n      </if>\n      <else-if variable=\"URL\">\n        <text variable=\"URL\"/>\n      </else-if>\n    </choose>\n  </macro>\n  <!-- 5. Notes -->\n  <!-- TODO: add variables for distributor and exhibitions if available in CSL -->\n  <!-- 6. Legal references: Bluebook style (shared with APA) -->\n  <!-- Where APA or Chicago diverge from Bluebook, the official manual is followed -->\n  <macro name=\"legal-reference\">\n    <!-- Type usage:\n\n         `bill`\n         : bills, resolutions, federal reports\n\n         `legal_case`\n         : all legal and court cases\n\n         `hearing`\n         : hearings and testimony\n\n         `legislation`\n         : statutes, constitutional items, and charters\n\n         `regulation`\n         : codified regulations, uncodified regulations, executive orders\n\n         `treaty`\n         : treaties\n    -->\n    <group delimiter=\", \">\n      <choose>\n        <if type=\"treaty\">\n          <text macro=\"legal-title\"/>\n          <names variable=\"author\">\n            <!-- Treaty parties should be included at least for bilateral treaties (Bluebook 21.4.2) -->\n            <name delimiter=\"-\" et-al-min=\"100\" et-al-use-first=\"99\" form=\"short\" initialize=\"false\"/>\n          </names>\n          <text macro=\"legal-date\"/>\n          <!-- treaty source/report in addition to URL (Bluebook 21.4.5) -->\n          <text macro=\"legal-source\"/>\n        </if>\n        <else>\n          <group delimiter=\" \">\n            <group delimiter=\", \">\n              <text macro=\"legal-title\"/>\n              <text macro=\"legal-source\"/>\n            </group>\n            <text macro=\"legal-date\"/>\n            <text macro=\"legal-identifier\"/>\n          </group>\n        </else>\n      </choose>\n      <group delimiter=\" \">\n        <!-- locator for use in notes -->\n        <choose>\n          <if locator=\"page\" variable=\"page\">\n            <text term=\"at\"/>\n          </if>\n        </choose>\n        <text macro=\"label-locator\"/>\n      </group>\n    </group>\n  </macro>\n  <!-- 6.1. Legal date -->\n  <macro name=\"legal-date\">\n    <choose>\n      <if type=\"treaty\">\n        <text macro=\"date-issued-full\"/>\n      </if>\n      <else-if type=\"legal_case\">\n        <text macro=\"legal-date-case\"/>\n      </else-if>\n      <else-if match=\"any\" type=\"bill hearing legislation regulation\">\n        <group delimiter=\" \" prefix=\"(\" suffix=\")\">\n          <group delimiter=\" \">\n            <text macro=\"date-original-year\"/>\n            <text form=\"symbol\" term=\"and\"/>\n          </group>\n          <choose>\n            <if variable=\"issued\">\n              <text macro=\"date-issued-year\"/>\n            </if>\n            <else>\n              <!-- Show proposal date for uncodified regulations. Assume date is entered literally ala \"proposed May 23, 2016\". -->\n              <!-- TODO: Add `proposed` date here if that becomes available -->\n              <date form=\"text\" variable=\"submitted\"/>\n            </else>\n          </choose>\n        </group>\n      </else-if>\n    </choose>\n  </macro>\n  <macro name=\"legal-date-case\">\n    <group delimiter=\" \" prefix=\"(\" suffix=\")\">\n      <text variable=\"authority\"/>\n      <choose>\n        <if variable=\"container-title\">\n          <!-- Print only year for cases published in reporters-->\n          <text macro=\"date-issued-year\"/>\n        </if>\n        <else>\n          <text macro=\"date-issued-full\"/>\n        </else>\n      </choose>\n    </group>\n  </macro>\n  <!-- 6.2.1. Legal title -->\n  <macro name=\"legal-title\">\n    <choose>\n      <if match=\"any\" type=\"bill legal_case legislation regulation treaty\">\n        <text text-case=\"title\" variable=\"title\"/>\n      </if>\n      <else-if type=\"hearing\">\n        <!-- use standard format (Bluebook 13.3) -->\n        <group delimiter=\": \" font-style=\"italic\">\n          <text text-case=\"capitalize-first\" variable=\"title\"/>\n          <group delimiter=\" \">\n            <text term=\"hearing\" text-case=\"capitalize-first\"/>\n            <group delimiter=\" \">\n              <text term=\"on\"/>\n              <text variable=\"number\"/>\n            </group>\n            <group delimiter=\" \">\n              <text value=\"before the\"/>\n              <text variable=\"section\"/>\n            </group>\n          </group>\n        </group>\n      </else-if>\n    </choose>\n  </macro>\n  <!-- 6.2.2. Legal identifier -->\n  <macro name=\"legal-identifier\">\n    <group delimiter=\" \" prefix=\"(\" suffix=\")\">\n      <choose>\n        <if type=\"hearing\">\n          <!-- Use the 'verb' form of the hearing term to hold 'testimony of' -->\n          <text form=\"verb\" term=\"hearing\"/>\n          <names variable=\"author\">\n            <name and=\"symbol\" initialize=\"false\"/>\n          </names>\n        </if>\n        <else-if match=\"any\" type=\"bill legislation regulation\">\n          <!-- For uncodified regulations, assume future code section is in `status`. -->\n          <text variable=\"status\"/>\n        </else-if>\n      </choose>\n    </group>\n  </macro>\n  <macro name=\"legal-identifier-bill-report\">\n    <group delimiter=\" \">\n      <text variable=\"genre\"/>\n      <choose>\n        <if match=\"any\" variable=\"authority chapter-number container-title\">\n          <text variable=\"number\"/>\n        </if>\n        <else>\n          <!-- If there is no legislative body, session number, or code/record title, assume the item is a congressional report and include 'No.' label. -->\n          <text macro=\"label-number-capitalized\"/>\n        </else>\n      </choose>\n    </group>\n  </macro>\n  <!-- 6.3. Legal source -->\n  <macro name=\"legal-source\">\n    <!-- Expect legal item `container-title` to be stored in short form -->\n    <choose>\n      <if type=\"bill\">\n        <text macro=\"legal-source-bill\"/>\n      </if>\n      <else-if type=\"hearing\">\n        <text macro=\"legal-source-hearing\"/>\n      </else-if>\n      <else-if type=\"legal_case\">\n        <text macro=\"legal-source-case\"/>\n      </else-if>\n      <else-if type=\"legislation\">\n        <text macro=\"legal-source-legislation\"/>\n      </else-if>\n      <else-if type=\"regulation\">\n        <text macro=\"legal-source-regulation\"/>\n      </else-if>\n      <else-if type=\"treaty\">\n        <text macro=\"legal-source-treaty\"/>\n      </else-if>\n    </choose>\n  </macro>\n  <!-- Legal source types -->\n  <macro name=\"legal-source-bill\">\n    <group delimiter=\", \">\n      <text macro=\"legal-identifier-bill-report\"/>\n      <group delimiter=\" \">\n        <text variable=\"authority\"/>\n        <!-- `chapter-number` is a session number -->\n        <text variable=\"chapter-number\"/>\n      </group>\n      <group delimiter=\" \">\n        <text variable=\"volume\"/>\n        <text variable=\"container-title\"/>\n        <text variable=\"page-first\"/>\n      </group>\n    </group>\n  </macro>\n  <macro name=\"legal-source-case\">\n    <group delimiter=\" \">\n      <choose>\n        <if variable=\"container-title\">\n          <text variable=\"volume\"/>\n          <text variable=\"container-title\"/>\n          <text macro=\"label-section-symbol\"/>\n          <choose>\n            <if match=\"any\" variable=\"page page-first\">\n              <text variable=\"page-first\"/>\n            </if>\n            <else>\n              <text value=\"___\"/>\n            </else>\n          </choose>\n        </if>\n        <else>\n          <text macro=\"label-number-capitalized\"/>\n        </else>\n      </choose>\n    </group>\n  </macro>\n  <macro name=\"legal-source-hearing\">\n    <group delimiter=\" \">\n      <text variable=\"authority\"/>\n      <!-- `chapter-number` is a session number -->\n      <text variable=\"chapter-number\"/>\n    </group>\n  </macro>\n  <macro name=\"legal-source-legislation\">\n    <choose>\n      <if variable=\"number\">\n        <!-- `number` is a public law number -->\n        <group delimiter=\", \">\n          <group delimiter=\" \">\n            <choose>\n              <if variable=\"genre\">\n                <text text-case=\"capitalize-first\" variable=\"genre\"/>\n              </if>\n              <else>\n                <text form=\"short\" term=\"legislation\" text-case=\"capitalize-first\"/>\n              </else>\n            </choose>\n            <text macro=\"label-number-capitalized\"/>\n          </group>\n          <group delimiter=\" \">\n            <text variable=\"volume\"/>\n            <text variable=\"container-title\"/>\n            <text variable=\"page-first\"/>\n          </group>\n        </group>\n      </if>\n      <else>\n        <group delimiter=\" \">\n          <text variable=\"volume\"/>\n          <text variable=\"container-title\"/>\n          <choose>\n            <if variable=\"section\">\n              <text macro=\"label-section-symbol\"/>\n            </if>\n            <else>\n              <text variable=\"page-first\"/>\n            </else>\n          </choose>\n        </group>\n      </else>\n    </choose>\n  </macro>\n  <macro name=\"legal-source-regulation\">\n    <group delimiter=\", \">\n      <group delimiter=\" \">\n        <text variable=\"genre\"/>\n        <text macro=\"label-number-capitalized\"/>\n      </group>\n      <group delimiter=\" \">\n        <text variable=\"volume\"/>\n        <text variable=\"container-title\"/>\n        <choose>\n          <if variable=\"section\">\n            <text macro=\"label-section-symbol\"/>\n          </if>\n          <else>\n            <text variable=\"page-first\"/>\n          </else>\n        </choose>\n      </group>\n    </group>\n  </macro>\n  <macro name=\"legal-source-treaty\">\n    <group delimiter=\" \">\n      <number variable=\"volume\"/>\n      <text variable=\"container-title\"/>\n      <choose>\n        <if match=\"any\" variable=\"page page-first\">\n          <text variable=\"page-first\"/>\n        </if>\n        <else>\n          <text macro=\"label-number-capitalized\"/>\n        </else>\n      </choose>\n    </group>\n  </macro>\n  <!-- Citation -->\n  <macro name=\"citation-author-date-item\">\n    <group delimiter=\", \">\n      <choose>\n        <if type=\"classic\">\n          <text macro=\"author-inline\"/>\n          <choose>\n            <if variable=\"author\">\n              <text macro=\"title-and-descriptions-short\"/>\n            </if>\n          </choose>\n        </if>\n        <else-if match=\"any\" type=\"interview personal_communication\">\n          <choose>\n            <if match=\"any\" variable=\"archive archive-place container-title DOI number publisher references URL\">\n              <!-- accessible `interview` or `personal_communication` uses standard format -->\n              <choose>\n                <if match=\"any\" variable=\"event-date issued\">\n                  <group delimiter=\" \">\n                    <text macro=\"author-inline\"/>\n                    <text macro=\"date-short\"/>\n                  </group>\n                </if>\n                <else>\n                  <text macro=\"author-inline\"/>\n                  <text macro=\"date-short\"/>\n                </else>\n              </choose>\n            </if>\n            <else>\n              <!-- inaccessible `interview` or `personal_communication` uses in-text format (CMOS18 14.111) -->\n              <text macro=\"author-inline\"/>\n              <text macro=\"title-and-descriptions-short\"/>\n              <choose>\n                <if position=\"first\">\n                  <choose>\n                    <if type=\"interview\">\n                      <text macro=\"date-short\"/>\n                    </if>\n                  </choose>\n                  <text macro=\"source-medium-note\"/>\n                </if>\n              </choose>\n            </else>\n          </choose>\n        </else-if>\n        <else-if match=\"any\" variable=\"event-date issued\">\n          <group delimiter=\" \">\n            <text macro=\"author-inline\"/>\n            <text macro=\"date-short\"/>\n          </group>\n        </else-if>\n        <else>\n          <!--- comma with forthcoming or n.d. -->\n          <text macro=\"author-inline\"/>\n          <text macro=\"date-short\"/>\n        </else>\n      </choose>\n    </group>\n  </macro>\n  <citation collapse=\"year\" disambiguate-add-givenname=\"true\" disambiguate-add-names=\"true\" disambiguate-add-year-suffix=\"true\" et-al-min=\"3\" et-al-use-first=\"1\" givenname-disambiguation-rule=\"primary-name\">\n    <layout delimiter=\"; \" prefix=\"(\" suffix=\")\">\n      <group delimiter=\", \">\n        <choose>\n          <if match=\"none\" type=\"classic\">\n            <text macro=\"citation-author-date-item\"/>\n            <text macro=\"source-locator-author-date\"/>\n          </if>\n          <!-- with `classic`, a non-numeric canonical reference or identifying number is separated by a space rather than a comma (CMOS18 14.145) -->\n          <else-if is-numeric=\"locator\">\n            <text macro=\"citation-author-date-item\"/>\n            <text macro=\"source-locator-author-date\"/>\n          </else-if>\n          <else-if locator=\"chapter line verse\" match=\"any\">\n            <group delimiter=\" \">\n              <text macro=\"citation-author-date-item\"/>\n              <text macro=\"source-locator-author-date\"/>\n            </group>\n          </else-if>\n          <else>\n            <text macro=\"citation-author-date-item\"/>\n            <text macro=\"source-locator-author-date\"/>\n          </else>\n        </choose>\n      </group>\n    </layout>\n  </citation>\n  <!-- Bibliography -->\n  <macro name=\"bibliography-author-date\">\n    <group delimiter=\". \">\n      <choose>\n        <if match=\"any\" type=\"bill hearing legal_case legislation regulation treaty\">\n          <!-- Legal items have different orders and delimiters -->\n          <text macro=\"legal-reference\"/>\n          <text macro=\"source-date-accessed-DOI-URL-bib\"/>\n          <text variable=\"references\"/>\n        </if>\n        <else>\n          <text macro=\"author-bib\"/>\n          <text macro=\"date\"/>\n          <text macro=\"title-and-source-bib\"/>\n          <text variable=\"references\"/>\n        </else>\n      </choose>\n    </group>\n  </macro>\n  <bibliography et-al-min=\"7\" et-al-use-first=\"3\" hanging-indent=\"true\">\n    <sort>\n      <key macro=\"author-sort\"/>\n      <key macro=\"date-sort-group\"/>\n      <key macro=\"date-sort-year\"/>\n      <key macro=\"date\"/>\n      <key macro=\"title-and-descriptions-bib\"/>\n      <key macro=\"source-bib\"/>\n      <key variable=\"volume\"/>\n      <key variable=\"part-number\"/>\n      <key variable=\"event-date\"/>\n      <key variable=\"issued\"/>\n      <key macro=\"source-archive-bib\"/>\n    </sort>\n    <layout suffix=\".\">\n      <choose>\n        <if type=\"classic\">\n          <choose>\n            <if match=\"any\" variable=\"archive editor translator publisher\">\n              <text macro=\"bibliography-author-date\"/>\n            </if>\n          </choose>\n        </if>\n        <else-if match=\"any\" type=\"entry entry-dictionary entry-encyclopedia\">\n          <choose>\n            <if variable=\"author\">\n              <!-- Signed reference entries appear in the bibliography (CMOS18 14.132) -->\n              <text macro=\"bibliography-author-date\"/>\n            </if>\n            <else-if match=\"any\" variable=\"DOI URL\">\n              <!-- Provide a bibliography if necessary identifying information is not in text -->\n              <text macro=\"bibliography-author-date\"/>\n            </else-if>\n          </choose>\n        </else-if>\n        <!-- Personal communications only appear in the bibliography if the reader can retrieve them (CMOS18 14.13, 14.111) -->\n        <else-if match=\"any\" variable=\"archive archive-place container-title DOI number publisher references URL\">\n          <text macro=\"bibliography-author-date\"/>\n        </else-if>\n        <else-if match=\"any\" type=\"interview personal_communication\"/>\n        <else>\n          <text macro=\"bibliography-author-date\"/>\n        </else>\n      </choose>\n    </layout>\n  </bibliography>\n</style>\n",
  "vancouver": "404: Not Found",
  "ieee": "<?xml version=\"1.0\" encoding=\"utf-8\"?>\n<style xmlns=\"http://purl.org/net/xbiblio/csl\" class=\"in-text\" version=\"1.0\" demote-non-dropping-particle=\"sort-only\">\n  <info>\n    <title>IEEE Reference Guide version 11.29.2023</title>\n    <title-short>Institute of Electrical and Electronics Engineers</title-short>\n    <id>http://www.zotero.org/styles/ieee</id>\n    <link href=\"http://www.zotero.org/styles/ieee\" rel=\"self\"/>\n    <link href=\"https://journals.ieeeauthorcenter.ieee.org/your-role-in-article-production/ieee-editorial-style-manual/\" rel=\"documentation\"/>\n    <author>\n      <name>Michael Berkowitz</name>\n      <email>mberkowi@gmu.edu</email>\n    </author>\n    <contributor>\n      <name>Julian Onions</name>\n      <email>julian.onions@gmail.com</email>\n    </contributor>\n    <contributor>\n      <name>Rintze Zelle</name>\n      <uri>http://twitter.com/rintzezelle</uri>\n    </contributor>\n    <contributor>\n      <name>Stephen Frank</name>\n      <uri>http://www.zotero.org/sfrank</uri>\n    </contributor>\n    <contributor>\n      <name>Sebastian Karcher</name>\n    </contributor>\n    <contributor>\n      <name>Giuseppe Silano</name>\n      <email>g.silano89@gmail.com</email>\n      <uri>http://giuseppesilano.net</uri>\n    </contributor>\n    <contributor>\n      <name>Patrick O'Brien</name>\n    </contributor>\n    <contributor>\n      <name>Brenton M. Wiernik</name>\n    </contributor>\n    <contributor>\n      <name>Oliver Couch</name>\n      <email>oliver.couch@gmail.com</email>\n    </contributor>\n    <contributor>\n      <name>Andrew Dunning</name>\n      <uri>https://orcid.org/0000-0003-0464-5036</uri>\n    </contributor>\n    <category citation-format=\"numeric\"/>\n    <category field=\"engineering\"/>\n    <category field=\"generic-base\"/>\n    <summary>IEEE style as per the 2023 guidelines.</summary>\n    <updated>2024-03-27T11:41:27+00:00</updated>\n    <rights license=\"http://creativecommons.org/licenses/by-sa/3.0/\">This work is licensed under a Creative Commons Attribution-ShareAlike 3.0 License</rights>\n  </info>\n  <locale xml:lang=\"en\">\n    <date form=\"text\">\n      <date-part name=\"month\" form=\"short\" suffix=\" \"/>\n      <date-part name=\"day\" form=\"numeric-leading-zeros\" suffix=\", \"/>\n      <date-part name=\"year\"/>\n    </date>\n    <terms>\n      <term name=\"chapter\" form=\"short\">ch.</term>\n      <term name=\"chapter-number\" form=\"short\">ch.</term>\n      <term name=\"presented at\">presented at the</term>\n      <term name=\"available at\">available</term>\n      <!-- always use three-letter abbreviations for months -->\n      <term name=\"month-06\" form=\"short\">Jun.</term>\n      <term name=\"month-07\" form=\"short\">Jul.</term>\n      <term name=\"month-09\" form=\"short\">Sep.</term>\n    </terms>\n  </locale>\n  <!-- Macros -->\n  <macro name=\"status\">\n    <choose>\n      <if variable=\"page issue volume\" match=\"none\">\n        <text variable=\"status\" text-case=\"capitalize-first\" suffix=\"\" font-weight=\"bold\"/>\n      </if>\n    </choose>\n  </macro>\n  <macro name=\"edition\">\n    <choose>\n      <if type=\"bill book chapter graphic legal_case legislation motion_picture paper-conference report song\" match=\"any\">\n        <choose>\n          <if is-numeric=\"edition\">\n            <group delimiter=\" \">\n              <number variable=\"edition\" form=\"ordinal\"/>\n              <text term=\"edition\" form=\"short\"/>\n            </group>\n          </if>\n          <else>\n            <text variable=\"edition\" text-case=\"capitalize-first\" suffix=\".\"/>\n          </else>\n        </choose>\n      </if>\n    </choose>\n  </macro>\n  <macro name=\"issued\">\n    <choose>\n      <if type=\"article-journal report\" match=\"any\">\n        <date variable=\"issued\">\n          <date-part name=\"month\" form=\"short\" suffix=\" \"/>\n          <date-part name=\"year\" form=\"long\"/>\n        </date>\n      </if>\n      <else-if type=\"bill book chapter graphic legal_case legislation song thesis\" match=\"any\">\n        <date variable=\"issued\">\n          <date-part name=\"year\" form=\"long\"/>\n        </date>\n      </else-if>\n      <else-if type=\"paper-conference\" match=\"any\">\n        <date variable=\"issued\">\n          <date-part name=\"month\" form=\"short\"/>\n          <date-part name=\"year\" prefix=\" \"/>\n        </date>\n      </else-if>\n      <else-if type=\"motion_picture\" match=\"any\">\n        <date variable=\"issued\" form=\"text\" prefix=\"(\" suffix=\")\"/>\n      </else-if>\n      <else>\n        <date variable=\"issued\" form=\"text\"/>\n      </else>\n    </choose>\n  </macro>\n  <macro name=\"author\">\n    <names variable=\"author\">\n      <name and=\"text\" et-al-min=\"7\" et-al-use-first=\"1\" initialize-with=\". \"/>\n      <label form=\"short\" prefix=\", \" text-case=\"capitalize-first\"/>\n      <et-al font-style=\"italic\"/>\n      <substitute>\n        <names variable=\"editor\"/>\n        <names variable=\"translator\"/>\n        <text macro=\"director\"/>\n      </substitute>\n    </names>\n  </macro>\n  <macro name=\"editor\">\n    <names variable=\"editor\">\n      <name initialize-with=\". \" delimiter=\", \" and=\"text\"/>\n      <label form=\"short\" prefix=\", \" text-case=\"capitalize-first\"/>\n    </names>\n  </macro>\n  <macro name=\"director\">\n    <names variable=\"director\">\n      <name and=\"text\" et-al-min=\"7\" et-al-use-first=\"1\" initialize-with=\". \"/>\n      <et-al font-style=\"italic\"/>\n    </names>\n  </macro>\n  <macro name=\"locators\">\n    <group delimiter=\", \">\n      <text macro=\"edition\"/>\n      <group delimiter=\" \">\n        <text term=\"volume\" form=\"short\"/>\n        <number variable=\"volume\" form=\"numeric\"/>\n      </group>\n      <group delimiter=\" \">\n        <number variable=\"number-of-volumes\" form=\"numeric\"/>\n        <text term=\"volume\" form=\"short\" plural=\"true\"/>\n      </group>\n      <group delimiter=\" \">\n        <text term=\"issue\" form=\"short\"/>\n        <number variable=\"issue\" form=\"numeric\"/>\n      </group>\n    </group>\n  </macro>\n  <macro name=\"title\">\n    <choose>\n      <if type=\"bill book graphic legal_case legislation motion_picture song standard software\" match=\"any\">\n        <text variable=\"title\" font-style=\"italic\"/>\n      </if>\n      <else>\n        <text variable=\"title\" quotes=\"true\"/>\n      </else>\n    </choose>\n  </macro>\n  <macro name=\"publisher\">\n    <choose>\n      <if type=\"bill book chapter graphic legal_case legislation motion_picture paper-conference song\" match=\"any\">\n        <group delimiter=\": \">\n          <text variable=\"publisher-place\"/>\n          <text variable=\"publisher\"/>\n        </group>\n      </if>\n      <else>\n        <group delimiter=\", \">\n          <text variable=\"publisher\"/>\n          <text variable=\"publisher-place\"/>\n        </group>\n      </else>\n    </choose>\n  </macro>\n  <macro name=\"event\">\n    <choose>\n      <!-- Published Conference Paper -->\n      <if type=\"paper-conference speech\" match=\"any\">\n        <choose>\n          <if variable=\"container-title\" match=\"any\">\n            <group delimiter=\" \">\n              <text term=\"in\"/>\n              <text variable=\"container-title\" font-style=\"italic\"/>\n            </group>\n          </if>\n          <!-- Unpublished Conference Paper -->\n          <else>\n            <group delimiter=\" \">\n              <text term=\"presented at\"/>\n              <text variable=\"event\"/>\n            </group>\n          </else>\n        </choose>\n      </if>\n    </choose>\n  </macro>\n  <macro name=\"access\">\n    <choose>\n      <if type=\"webpage post post-weblog\" match=\"any\">\n        <!-- https://url.com/ (accessed Mon. DD, YYYY). -->\n        <choose>\n          <if variable=\"URL\">\n            <group delimiter=\". \" prefix=\" \">\n              <group delimiter=\": \">\n                <text term=\"accessed\" text-case=\"capitalize-first\"/>\n                <date variable=\"accessed\" form=\"text\"/>\n              </group>\n              <text term=\"online\" prefix=\"[\" suffix=\"]\" text-case=\"capitalize-first\"/>\n              <group delimiter=\": \">\n                <text term=\"available at\" text-case=\"capitalize-first\"/>\n                <text variable=\"URL\"/>\n              </group>\n            </group>\n          </if>\n        </choose>\n      </if>\n      <else-if match=\"any\" variable=\"DOI\">\n        <!-- doi: 10.1000/xyz123. -->\n        <text variable=\"DOI\" prefix=\" doi: \" suffix=\".\"/>\n      </else-if>\n      <else-if variable=\"URL\">\n        <!-- Accessed: Mon. DD, YYYY. [Medium]. Available: https://URL.com/ -->\n        <group delimiter=\". \" prefix=\" \" suffix=\". \">\n          <!-- Accessed: Mon. DD, YYYY. -->\n          <group delimiter=\": \">\n            <text term=\"accessed\" text-case=\"capitalize-first\"/>\n            <date variable=\"accessed\" form=\"text\"/>\n          </group>\n          <!-- [Online Video]. -->\n          <group prefix=\"[\" suffix=\"]\" delimiter=\" \">\n            <choose>\n              <if variable=\"medium\" match=\"any\">\n                <text variable=\"medium\" text-case=\"capitalize-first\"/>\n              </if>\n              <else>\n                <text term=\"online\" text-case=\"capitalize-first\"/>\n                <choose>\n                  <if type=\"motion_picture\">\n                    <text term=\"video\" text-case=\"capitalize-first\"/>\n                  </if>\n                </choose>\n              </else>\n            </choose>\n          </group>\n        </group>\n        <!-- Available: https://URL.com/ -->\n        <group delimiter=\": \" prefix=\" \">\n          <text term=\"available at\" text-case=\"capitalize-first\"/>\n          <text variable=\"URL\"/>\n        </group>\n      </else-if>\n    </choose>\n  </macro>\n  <macro name=\"page\">\n    <choose>\n      <if type=\"article-journal\" variable=\"number\" match=\"all\">\n        <group delimiter=\" \">\n          <text value=\"Art.\"/>\n          <text term=\"issue\" form=\"short\"/>\n          <text variable=\"number\"/>\n        </group>\n      </if>\n      <else>\n        <group delimiter=\" \">\n          <label variable=\"page\" form=\"short\"/>\n          <text variable=\"page\"/>\n        </group>\n      </else>\n    </choose>\n  </macro>\n  <macro name=\"citation-locator\">\n    <group delimiter=\" \">\n      <choose>\n        <if locator=\"page\">\n          <label variable=\"locator\" form=\"short\"/>\n        </if>\n        <else>\n          <label variable=\"locator\" form=\"short\" text-case=\"capitalize-first\"/>\n        </else>\n      </choose>\n      <text variable=\"locator\"/>\n    </group>\n  </macro>\n  <macro name=\"geographic-location\">\n    <group delimiter=\", \" suffix=\".\">\n      <choose>\n        <if variable=\"publisher-place\">\n          <text variable=\"publisher-place\" text-case=\"title\"/>\n        </if>\n        <else-if variable=\"event-place\">\n          <text variable=\"event-place\" text-case=\"title\"/>\n        </else-if>\n      </choose>\n    </group>\n  </macro>\n  <!-- Series -->\n  <macro name=\"collection\">\n    <choose>\n      <if variable=\"collection-title\" match=\"any\">\n        <text term=\"in\" suffix=\" \"/>\n        <group delimiter=\", \" suffix=\". \">\n          <text variable=\"collection-title\"/>\n          <text variable=\"collection-number\" prefix=\"no. \"/>\n          <text variable=\"volume\" prefix=\"vol. \"/>\n        </group>\n      </if>\n    </choose>\n  </macro>\n  <!-- Citation -->\n  <citation>\n    <sort>\n      <key variable=\"citation-number\"/>\n    </sort>\n    <layout delimiter=\", \">\n      <group prefix=\"[\" suffix=\"]\" delimiter=\", \">\n        <text variable=\"citation-number\"/>\n        <text macro=\"citation-locator\"/>\n      </group>\n    </layout>\n  </citation>\n  <!-- Bibliography -->\n  <bibliography entry-spacing=\"0\" second-field-align=\"flush\">\n    <layout>\n      <!-- Citation Number -->\n      <text variable=\"citation-number\" prefix=\"[\" suffix=\"]\"/>\n      <!-- Author(s) -->\n      <text macro=\"author\" suffix=\", \"/>\n      <!-- Rest of Citation -->\n      <choose>\n        <!-- Specific Formats -->\n        <if type=\"article-journal\">\n          <group delimiter=\", \">\n            <text macro=\"title\"/>\n            <text variable=\"container-title\" font-style=\"italic\" form=\"short\"/>\n            <text macro=\"locators\"/>\n            <text macro=\"page\"/>\n            <text macro=\"issued\"/>\n            <text macro=\"status\"/>\n          </group>\n          <choose>\n            <if variable=\"URL DOI\" match=\"none\">\n              <text value=\".\"/>\n            </if>\n            <else>\n              <text value=\",\"/>\n            </else>\n          </choose>\n          <text macro=\"access\"/>\n        </if>\n        <else-if type=\"paper-conference speech\" match=\"any\">\n          <group delimiter=\", \" suffix=\", \">\n            <text macro=\"title\"/>\n            <text macro=\"event\"/>\n            <text macro=\"editor\"/>\n          </group>\n          <text macro=\"collection\"/>\n          <group delimiter=\", \" suffix=\".\">\n            <text macro=\"publisher\"/>\n            <text macro=\"issued\"/>\n            <text macro=\"page\"/>\n            <text macro=\"status\"/>\n          </group>\n          <text macro=\"access\"/>\n        </else-if>\n        <else-if type=\"chapter\">\n          <group delimiter=\", \" suffix=\".\">\n            <text macro=\"title\"/>\n            <group delimiter=\" \">\n              <text term=\"in\" suffix=\" \"/>\n              <text variable=\"container-title\" font-style=\"italic\"/>\n            </group>\n            <text macro=\"locators\"/>\n            <text macro=\"editor\"/>\n            <text macro=\"collection\"/>\n            <text macro=\"publisher\"/>\n            <text macro=\"issued\"/>\n            <group delimiter=\" \">\n              <label variable=\"chapter-number\" form=\"short\"/>\n              <text variable=\"chapter-number\"/>\n            </group>\n            <text macro=\"page\"/>\n          </group>\n          <text macro=\"access\"/>\n        </else-if>\n        <else-if type=\"report\">\n          <group delimiter=\", \" suffix=\".\">\n            <text macro=\"title\"/>\n            <text macro=\"publisher\"/>\n            <group delimiter=\" \">\n              <text variable=\"genre\"/>\n              <text variable=\"number\"/>\n            </group>\n            <text macro=\"issued\"/>\n          </group>\n          <text macro=\"access\"/>\n        </else-if>\n        <else-if type=\"thesis\">\n          <group delimiter=\", \" suffix=\".\">\n            <text macro=\"title\"/>\n            <text variable=\"genre\"/>\n            <text macro=\"publisher\"/>\n            <text macro=\"issued\"/>\n          </group>\n          <text macro=\"access\"/>\n        </else-if>\n        <else-if type=\"software\">\n          <group delimiter=\". \" suffix=\".\">\n            <text macro=\"title\"/>\n            <text macro=\"issued\" prefix=\"(\" suffix=\")\"/>\n            <text variable=\"genre\"/>\n            <text macro=\"publisher\"/>\n          </group>\n          <text macro=\"access\"/>\n        </else-if>\n        <else-if type=\"article\">\n          <group delimiter=\", \" suffix=\".\">\n            <text macro=\"title\"/>\n            <text macro=\"issued\"/>\n            <group delimiter=\": \">\n              <text macro=\"publisher\" font-style=\"italic\"/>\n              <text variable=\"number\"/>\n            </group>\n          </group>\n          <text macro=\"access\"/>\n        </else-if>\n        <else-if type=\"webpage post-weblog post\" match=\"any\">\n          <group delimiter=\", \" suffix=\".\">\n            <text macro=\"title\"/>\n            <text variable=\"container-title\"/>\n          </group>\n          <text macro=\"access\"/>\n        </else-if>\n        <else-if type=\"patent\">\n          <group delimiter=\", \">\n            <text macro=\"title\"/>\n            <text variable=\"number\"/>\n            <text macro=\"issued\"/>\n          </group>\n          <text macro=\"access\"/>\n        </else-if>\n        <!-- Online Video -->\n        <else-if type=\"motion_picture\">\n          <text macro=\"geographic-location\" suffix=\". \"/>\n          <group delimiter=\", \" suffix=\".\">\n            <text macro=\"title\"/>\n            <text macro=\"issued\"/>\n          </group>\n          <text macro=\"access\"/>\n        </else-if>\n        <else-if type=\"standard\">\n          <group delimiter=\", \" suffix=\".\">\n            <text macro=\"title\"/>\n            <group delimiter=\" \">\n              <text variable=\"genre\"/>\n              <text variable=\"number\"/>\n            </group>\n            <text macro=\"geographic-location\"/>\n            <text macro=\"issued\"/>\n          </group>\n          <text macro=\"access\"/>\n        </else-if>\n        <!-- Generic/Fallback Formats -->\n        <else-if type=\"bill book graphic legal_case legislation report song\" match=\"any\">\n          <group delimiter=\", \" suffix=\". \">\n            <text macro=\"title\"/>\n            <text macro=\"locators\"/>\n          </group>\n          <text macro=\"collection\"/>\n          <group delimiter=\", \" suffix=\".\">\n            <text macro=\"publisher\"/>\n            <text macro=\"issued\"/>\n            <text macro=\"page\"/>\n          </group>\n          <text macro=\"access\"/>\n        </else-if>\n        <else-if type=\"article-magazine article-newspaper broadcast interview manuscript map patent personal_communication song speech thesis webpage\" match=\"any\">\n          <group delimiter=\", \" suffix=\".\">\n            <text macro=\"title\"/>\n            <text variable=\"container-title\" font-style=\"italic\"/>\n            <text macro=\"locators\"/>\n            <text macro=\"publisher\"/>\n            <text macro=\"page\"/>\n            <text macro=\"issued\"/>\n          </group>\n          <text macro=\"access\"/>\n        </else-if>\n        <else>\n          <group delimiter=\", \" suffix=\". \">\n            <text macro=\"title\"/>\n            <text variable=\"container-title\" font-style=\"italic\"/>\n            <text macro=\"locators\"/>\n          </group>\n          <text macro=\"collection\"/>\n          <group delimiter=\", \" suffix=\".\">\n            <text macro=\"publisher\"/>\n            <text macro=\"page\"/>\n            <text macro=\"issued\"/>\n          </group>\n          <text macro=\"access\"/>\n        </else>\n      </choose>\n    </layout>\n  </bibliography>\n</style>\n",
  "harvard": "<?xml version=\"1.0\" encoding=\"utf-8\"?>\n<style xmlns=\"http://purl.org/net/xbiblio/csl\" class=\"in-text\" version=\"1.0\" demote-non-dropping-particle=\"sort-only\">\n  <info>\n    <title>Cite Them Right 12th edition (author-date/Harvard)</title>\n    <id>http://www.zotero.org/styles/harvard-cite-them-right</id>\n    <link href=\"http://www.zotero.org/styles/harvard-cite-them-right\" rel=\"self\"/>\n    <link href=\"http://www.zotero.org/styles/harvard-cite-them-right-11th-edition\" rel=\"template\"/>\n    <link href=\"http://www.citethemrightonline.com/\" rel=\"documentation\"/>\n    <author>\n      <name>Patrick O'Brien</name>\n    </author>\n    <category citation-format=\"author-date\"/>\n    <category field=\"generic-base\"/>\n    <summary>Harvard according to Cite Them Right, 11th edition.</summary>\n    <updated>2026-02-12T10:08:06+00:00</updated>\n    <rights license=\"http://creativecommons.org/licenses/by-sa/3.0/\">This work is licensed under a Creative Commons Attribution-ShareAlike 3.0 License</rights>\n  </info>\n  <locale xml:lang=\"en-GB\">\n    <terms>\n      <term name=\"editor\" form=\"short\">\n        <single>ed.</single>\n        <multiple>eds</multiple>\n      </term>\n      <term name=\"editortranslator\" form=\"verb\">edited and translated by</term>\n      <term name=\"edition\" form=\"short\">edn.</term>\n    </terms>\n  </locale>\n  <macro name=\"editor\">\n    <choose>\n      <if type=\"chapter paper-conference\" match=\"any\">\n        <group delimiter=\" \">\n          <text term=\"in\"/>\n          <names variable=\"container-author\" delimiter=\", \" suffix=\", \">\n            <name and=\"text\" initialize-with=\". \"/>\n          </names>\n          <choose>\n            <if variable=\"container-author\" match=\"none\">\n              <names variable=\"editor translator\" delimiter=\", \">\n                <name and=\"text\" initialize-with=\".\"/>\n                <label form=\"short\" prefix=\" (\" suffix=\")\"/>\n              </names>\n            </if>\n          </choose>\n        </group>\n      </if>\n    </choose>\n  </macro>\n  <macro name=\"secondary-contributors\">\n    <choose>\n      <if type=\"chapter paper-conference\" match=\"none\">\n        <names variable=\"editor translator\" delimiter=\". \">\n          <label form=\"verb\" text-case=\"capitalize-first\" suffix=\" \"/>\n          <name and=\"text\" initialize-with=\".\"/>\n        </names>\n      </if>\n      <else-if variable=\"container-author\" match=\"any\">\n        <names variable=\"editor translator\" delimiter=\". \">\n          <label form=\"verb\" text-case=\"capitalize-first\" suffix=\" \"/>\n          <name and=\"text\" initialize-with=\". \" delimiter=\", \"/>\n        </names>\n      </else-if>\n    </choose>\n  </macro>\n  <macro name=\"author\">\n    <names variable=\"author\">\n      <name and=\"text\" delimiter-precedes-last=\"never\" initialize-with=\".\" name-as-sort-order=\"all\"/>\n      <label form=\"short\" prefix=\" (\" suffix=\")\"/>\n      <et-al font-style=\"italic\"/>\n      <substitute>\n        <names variable=\"editor\"/>\n        <names variable=\"translator\"/>\n        <choose>\n          <if type=\"article-newspaper article-magazine article-journal\" match=\"any\">\n            <text variable=\"container-title\" text-case=\"title\" font-style=\"italic\"/>\n          </if>\n          <else>\n            <text macro=\"title\"/>\n          </else>\n        </choose>\n      </substitute>\n    </names>\n  </macro>\n  <macro name=\"author-short\">\n    <names variable=\"author\">\n      <name form=\"short\" and=\"text\" delimiter=\", \" delimiter-precedes-last=\"never\" initialize-with=\". \"/>\n      <et-al font-style=\"italic\"/>\n      <substitute>\n        <names variable=\"editor\"/>\n        <names variable=\"translator\"/>\n        <choose>\n          <if type=\"article-newspaper article-magazine article-journal\" match=\"any\">\n            <text variable=\"container-title\" text-case=\"title\" font-style=\"italic\"/>\n          </if>\n          <else>\n            <text macro=\"title\"/>\n          </else>\n        </choose>\n      </substitute>\n    </names>\n  </macro>\n  <macro name=\"access\">\n    <choose>\n      <if variable=\"DOI\">\n        <group delimiter=\": \">\n          <text term=\"available at\" text-case=\"capitalize-first\"/>\n          <text variable=\"DOI\" prefix=\"https://doi.org/\"/>\n        </group>\n      </if>\n      <else-if variable=\"URL\">\n        <text term=\"available at\" suffix=\": \" text-case=\"capitalize-first\"/>\n        <text variable=\"URL\"/>\n        <group prefix=\" (\" delimiter=\": \" suffix=\")\">\n          <text term=\"accessed\" text-case=\"capitalize-first\"/>\n          <date form=\"text\" variable=\"accessed\">\n            <date-part name=\"day\"/>\n            <date-part name=\"month\"/>\n            <date-part name=\"year\"/>\n          </date>\n        </group>\n      </else-if>\n    </choose>\n  </macro>\n  <macro name=\"number-volumes\">\n    <choose>\n      <if variable=\"volume\" match=\"none\">\n        <group delimiter=\" \" prefix=\"(\" suffix=\")\">\n          <text variable=\"number-of-volumes\"/>\n          <label variable=\"volume\" form=\"short\" strip-periods=\"true\"/>\n        </group>\n      </if>\n    </choose>\n  </macro>\n  <macro name=\"title\">\n    <choose>\n      <if type=\"bill book legal_case legislation motion_picture report song thesis webpage graphic\" match=\"any\">\n        <group delimiter=\". \">\n          <group delimiter=\" \">\n            <group delimiter=\" \">\n              <text variable=\"title\" font-style=\"italic\"/>\n              <text variable=\"medium\" prefix=\"[\" suffix=\"]\"/>\n            </group>\n            <text macro=\"number-volumes\"/>\n          </group>\n          <text macro=\"edition\"/>\n        </group>\n      </if>\n      <else>\n        <text variable=\"title\" form=\"long\" quotes=\"true\"/>\n      </else>\n    </choose>\n  </macro>\n  <macro name=\"publisher\">\n    <choose>\n      <if type=\"thesis\">\n        <group delimiter=\". \">\n          <text variable=\"genre\"/>\n          <text variable=\"publisher\"/>\n        </group>\n      </if>\n      <else-if type=\"report\">\n        <group delimiter=\". \">\n          <group delimiter=\" \">\n            <text variable=\"genre\"/>\n            <text variable=\"number\"/>\n          </group>\n          <group delimiter=\": \">\n            <text variable=\"publisher-place\"/>\n            <text variable=\"publisher\"/>\n          </group>\n        </group>\n      </else-if>\n      <else-if type=\"article-journal article-newspaper article-magazine\" match=\"none\">\n        <group delimiter=\" \">\n          <group delimiter=\", \">\n            <choose>\n              <if type=\"speech\" variable=\"event\" match=\"any\">\n                <text variable=\"event\" font-style=\"italic\"/>\n              </if>\n            </choose>\n            <group delimiter=\": \">\n              <text variable=\"publisher-place\"/>\n              <text variable=\"publisher\"/>\n            </group>\n          </group>\n          <group prefix=\"(\" suffix=\")\" delimiter=\", \">\n            <text variable=\"collection-title\"/>\n            <text variable=\"collection-number\"/>\n          </group>\n        </group>\n      </else-if>\n    </choose>\n  </macro>\n  <macro name=\"year-date\">\n    <choose>\n      <if variable=\"issued\">\n        <date variable=\"issued\">\n          <date-part name=\"year\"/>\n        </date>\n        <text variable=\"year-suffix\"/>\n      </if>\n      <else>\n        <text term=\"no date\"/>\n        <text variable=\"year-suffix\" prefix=\" \"/>\n      </else>\n    </choose>\n  </macro>\n  <macro name=\"locator\">\n    <choose>\n      <if type=\"article-journal\">\n        <text variable=\"volume\"/>\n        <text variable=\"issue\" prefix=\"(\" suffix=\")\"/>\n      </if>\n    </choose>\n  </macro>\n  <macro name=\"published-date\">\n    <choose>\n      <if type=\"article-newspaper article-magazine post-weblog speech\" match=\"any\">\n        <date variable=\"issued\">\n          <date-part name=\"day\" suffix=\" \"/>\n          <date-part name=\"month\" form=\"long\"/>\n        </date>\n      </if>\n    </choose>\n  </macro>\n  <macro name=\"pages\">\n    <choose>\n      <if type=\"chapter paper-conference article-journal article article-magazine article-newspaper book review review-book report\" match=\"any\">\n        <group delimiter=\" \">\n          <label variable=\"page\" form=\"short\"/>\n          <text variable=\"page\"/>\n        </group>\n      </if>\n    </choose>\n  </macro>\n  <macro name=\"container-title\">\n    <choose>\n      <if variable=\"container-title\">\n        <group delimiter=\". \">\n          <group delimiter=\" \">\n            <text variable=\"container-title\" font-style=\"italic\"/>\n            <choose>\n              <if type=\"article article-journal\" match=\"any\">\n                <choose>\n                  <if match=\"none\" variable=\"page volume\">\n                    <text value=\"Preprint\" prefix=\"[\" suffix=\"]\"/>\n                  </if>\n                </choose>\n              </if>\n            </choose>\n          </group>\n          <text macro=\"edition\"/>\n        </group>\n      </if>\n    </choose>\n  </macro>\n  <macro name=\"edition\">\n    <choose>\n      <if is-numeric=\"edition\">\n        <group delimiter=\" \">\n          <number variable=\"edition\" form=\"ordinal\"/>\n          <text term=\"edition\" form=\"short\" strip-periods=\"true\"/>\n        </group>\n      </if>\n      <else>\n        <text variable=\"edition\"/>\n      </else>\n    </choose>\n  </macro>\n  <citation et-al-min=\"4\" et-al-use-first=\"1\" disambiguate-add-year-suffix=\"true\" disambiguate-add-names=\"true\" disambiguate-add-givenname=\"true\" collapse=\"year\">\n    <sort>\n      <key macro=\"year-date\"/>\n    </sort>\n    <layout prefix=\"(\" suffix=\")\" delimiter=\"; \">\n      <group delimiter=\", \">\n        <group delimiter=\", \">\n          <text macro=\"author-short\"/>\n          <text macro=\"year-date\"/>\n        </group>\n        <group>\n          <label variable=\"locator\" form=\"short\" suffix=\" \"/>\n          <text variable=\"locator\"/>\n        </group>\n      </group>\n    </layout>\n  </citation>\n  <bibliography and=\"text\" et-al-min=\"4\" et-al-use-first=\"1\">\n    <sort>\n      <key macro=\"author\"/>\n      <key macro=\"year-date\"/>\n      <key variable=\"title\"/>\n    </sort>\n    <layout suffix=\".\">\n      <group delimiter=\". \">\n        <group delimiter=\" \">\n          <text macro=\"author\"/>\n          <text macro=\"year-date\" prefix=\"(\" suffix=\")\"/>\n          <group delimiter=\", \">\n            <text macro=\"title\"/>\n            <group delimiter=\" \">\n              <text macro=\"editor\"/>\n              <text macro=\"container-title\"/>\n            </group>\n          </group>\n        </group>\n        <text macro=\"secondary-contributors\"/>\n        <text macro=\"publisher\"/>\n      </group>\n      <group delimiter=\", \" prefix=\", \">\n        <text macro=\"locator\"/>\n        <text macro=\"published-date\"/>\n        <text macro=\"pages\"/>\n      </group>\n      <text macro=\"access\" prefix=\". \"/>\n    </layout>\n  </bibliography>\n</style>\n",
  "nature": "<?xml version=\"1.0\" encoding=\"utf-8\"?>\n<style xmlns=\"http://purl.org/net/xbiblio/csl\" class=\"in-text\" version=\"1.0\" demote-non-dropping-particle=\"sort-only\" default-locale=\"en-GB\">\n  <info>\n    <title>Nature</title>\n    <id>http://www.zotero.org/styles/nature</id>\n    <link href=\"http://www.zotero.org/styles/nature\" rel=\"self\"/>\n    <link href=\"https://www.nature.com/nature/for-authors/formatting-guide\" rel=\"documentation\"/>\n    <author>\n      <name>Michael Berkowitz</name>\n      <email>mberkowi@gmu.edu</email>\n    </author>\n    <contributor>\n      <name>Patrick O'Brien</name>\n      <email>citationstyler@gmail.com</email>\n    </contributor>\n    <category citation-format=\"numeric\"/>\n    <category field=\"science\"/>\n    <category field=\"generic-base\"/>\n    <issn>0028-0836</issn>\n    <eissn>1476-4687</eissn>\n    <updated>2025-09-10T18:26:21+00:00</updated>\n    <rights license=\"http://creativecommons.org/licenses/by-sa/3.0/\">This work is licensed under a Creative Commons Attribution-ShareAlike 3.0 License</rights>\n  </info>\n  <macro name=\"title\">\n    <choose>\n      <if type=\"bill book graphic legal_case legislation motion_picture report song\" match=\"any\">\n        <text variable=\"title\" font-style=\"italic\" text-case=\"title\"/>\n      </if>\n      <else>\n        <text variable=\"title\"/>\n      </else>\n    </choose>\n  </macro>\n  <macro name=\"author\">\n    <names variable=\"author\">\n      <name sort-separator=\", \" delimiter=\", \" and=\"symbol\" initialize-with=\". \" delimiter-precedes-last=\"never\" name-as-sort-order=\"all\"/>\n      <label form=\"short\" prefix=\", \"/>\n      <et-al font-style=\"italic\"/>\n    </names>\n  </macro>\n  <macro name=\"access\">\n    <choose>\n      <if variable=\"volume\" type=\"article dataset software\" match=\"any\"/>\n      <else-if variable=\"DOI\">\n        <text variable=\"DOI\" prefix=\"doi:\"/>\n      </else-if>\n    </choose>\n  </macro>\n  <macro name=\"access-data\">\n    <choose>\n      <if type=\"dataset software\" match=\"any\">\n        <text variable=\"DOI\" prefix=\"https://doi.org/\"/>\n      </if>\n    </choose>\n  </macro>\n  <macro name=\"issuance\">\n    <choose>\n      <if type=\"bill book graphic legal_case legislation motion_picture song thesis chapter paper-conference\" match=\"any\">\n        <group delimiter=\"; \" suffix=\".\">\n          <group delimiter=\", \" prefix=\"(\" suffix=\")\">\n            <text variable=\"publisher\" form=\"long\"/>\n            <text variable=\"publisher-place\"/>\n            <date variable=\"issued\">\n              <date-part name=\"year\"/>\n            </date>\n          </group>\n        </group>\n      </if>\n      <else-if type=\"article\">\n        <group delimiter=\" \">\n          <choose>\n            <if variable=\"genre\" match=\"any\">\n              <text variable=\"genre\" text-case=\"capitalize-first\"/>\n            </if>\n            <else>\n              <text term=\"preprint\" text-case=\"capitalize-first\"/>\n            </else>\n          </choose>\n          <text term=\"at\"/>\n          <choose>\n            <if variable=\"DOI\" match=\"any\">\n              <text variable=\"DOI\" prefix=\"https://doi.org/\"/>\n            </if>\n            <else>\n              <text variable=\"URL\"/>\n            </else>\n          </choose>\n          <date date-parts=\"year\" form=\"text\" variable=\"issued\" prefix=\"(\" suffix=\")\"/>\n        </group>\n      </else-if>\n      <else-if type=\"dataset software\" match=\"any\">\n        <group delimiter=\" \">\n          <text variable=\"publisher\"/>\n          <text macro=\"access-data\"/>\n          <date date-parts=\"year\" form=\"text\" variable=\"issued\" prefix=\"(\" suffix=\")\"/>\n        </group>\n      </else-if>\n      <else-if type=\"report webpage post post-weblog\" match=\"any\">\n        <group delimiter=\" \">\n          <text variable=\"URL\"/>\n          <date date-parts=\"year\" form=\"text\" variable=\"issued\" prefix=\"(\" suffix=\")\"/>\n        </group>\n      </else-if>\n      <else-if type=\"article-journal\" match=\"any\">\n        <group delimiter=\" \">\n          <choose>\n            <if match=\"none\" variable=\"volume page\">\n              <choose>\n                <if match=\"any\" variable=\"DOI\">\n                  <text variable=\"DOI\" prefix=\"https://doi.org/\"/>\n                </if>\n                <else>\n                  <text variable=\"URL\"/>\n                </else>\n              </choose>\n            </if>\n          </choose>\n          <date date-parts=\"year\" form=\"text\" variable=\"issued\" prefix=\"(\" suffix=\")\"/>\n        </group>\n      </else-if>\n      <else>\n        <date variable=\"issued\" prefix=\"(\" suffix=\")\">\n          <date-part name=\"year\"/>\n        </date>\n      </else>\n    </choose>\n  </macro>\n  <macro name=\"container-title\">\n    <choose>\n      <if type=\"article-journal\">\n        <text variable=\"container-title\" font-style=\"italic\" form=\"short\"/>\n      </if>\n      <else>\n        <text variable=\"container-title\" font-style=\"italic\"/>\n      </else>\n    </choose>\n  </macro>\n  <macro name=\"editor\">\n    <choose>\n      <if type=\"chapter paper-conference\" match=\"any\">\n        <names variable=\"editor\" prefix=\"(\" suffix=\")\">\n          <label form=\"short\" suffix=\" \"/>\n          <name and=\"symbol\" delimiter-precedes-last=\"never\" initialize-with=\". \" name-as-sort-order=\"all\"/>\n        </names>\n      </if>\n    </choose>\n  </macro>\n  <macro name=\"volume\">\n    <choose>\n      <if type=\"article-journal\" match=\"any\">\n        <text variable=\"volume\" font-weight=\"bold\" suffix=\",\"/>\n      </if>\n      <else>\n        <group delimiter=\" \">\n          <label variable=\"volume\" form=\"short\"/>\n          <text variable=\"volume\"/>\n        </group>\n      </else>\n    </choose>\n  </macro>\n  <citation collapse=\"citation-number\">\n    <sort>\n      <key variable=\"citation-number\"/>\n    </sort>\n    <layout vertical-align=\"sup\" delimiter=\",\">\n      <text variable=\"citation-number\"/>\n    </layout>\n  </citation>\n  <bibliography et-al-min=\"6\" et-al-use-first=\"1\" second-field-align=\"flush\" entry-spacing=\"0\" line-spacing=\"2\">\n    <layout suffix=\".\">\n      <text variable=\"citation-number\" suffix=\".\"/>\n      <group delimiter=\" \">\n        <text macro=\"author\" suffix=\".\"/>\n        <text macro=\"title\" suffix=\".\"/>\n        <choose>\n          <if type=\"chapter paper-conference\" match=\"any\">\n            <text term=\"in\"/>\n          </if>\n        </choose>\n        <text macro=\"container-title\"/>\n        <text macro=\"editor\"/>\n        <text macro=\"volume\"/>\n        <text variable=\"page\"/>\n        <text macro=\"issuance\"/>\n        <text macro=\"access\"/>\n      </group>\n    </layout>\n  </bibliography>\n</style>\n",
  "science": "<?xml version=\"1.0\" encoding=\"utf-8\"?>\n<style xmlns=\"http://purl.org/net/xbiblio/csl\" class=\"in-text\" version=\"1.0\" demote-non-dropping-particle=\"sort-only\" default-locale=\"en-US\">\n  <info>\n    <title>Science</title>\n    <id>http://www.zotero.org/styles/science</id>\n    <link href=\"http://www.zotero.org/styles/science\" rel=\"self\"/>\n    <link href=\"https://www.science.org/content/page/instructions-preparing-initial-manuscript#science-citation-style\" rel=\"documentation\"/>\n    <author>\n      <name>Julian Onions</name>\n      <email>julian.onions@gmail.com</email>\n    </author>\n    <contributor>\n      <name>Sebastian Karcher</name>\n    </contributor>\n    <contributor>\n      <name>Greg Barendt</name>\n    </contributor>\n    <category citation-format=\"numeric\"/>\n    <category field=\"science\"/>\n    <issn>0036-8075</issn>\n    <eissn>1095-9203</eissn>\n    <summary>The Science journal style.</summary>\n    <updated>2019-07-02T08:06:38+00:00</updated>\n    <rights license=\"http://creativecommons.org/licenses/by-sa/3.0/\">This work is licensed under a Creative Commons Attribution-ShareAlike 3.0 License</rights>\n  </info>\n  <macro name=\"editor\">\n    <names variable=\"editor\" delimiter=\", \">\n      <name initialize-with=\". \" delimiter=\", \" delimiter-precedes-last=\"always\"/>\n      <label form=\"short\" prefix=\", \" text-case=\"capitalize-first\"/>\n    </names>\n  </macro>\n  <macro name=\"author\">\n    <names variable=\"author\">\n      <name sort-separator=\", \" initialize-with=\". \" delimiter=\", \" delimiter-precedes-last=\"always\"/>\n      <label form=\"short\" prefix=\", \" text-case=\"capitalize-first\"/>\n      <et-al font-style=\"italic\"/>\n      <substitute>\n        <names variable=\"editor\"/>\n      </substitute>\n    </names>\n  </macro>\n  <macro name=\"access\">\n    <choose>\n      <if variable=\"page\" match=\"none\">\n        <text macro=\"access-value\"/>\n      </if>\n    </choose>\n  </macro>\n  <macro name=\"access-value\">\n    <choose>\n      <if variable=\"DOI\">\n        <text variable=\"DOI\" prefix=\"https://doi.org/\"/>\n      </if>\n      <else>\n        <text variable=\"URL\"/>\n      </else>\n    </choose>\n  </macro>\n  <macro name=\"title\">\n    <choose>\n      <if type=\"bill book graphic legal_case legislation motion_picture song\" match=\"any\">\n        <text variable=\"title\" font-style=\"italic\" text-case=\"title\"/>\n      </if>\n      <else-if type=\"chapter report thesis paper-conference\" match=\"any\">\n        <text variable=\"title\" quotes=\"true\"/>\n      </else-if>\n      <else>\n        <text variable=\"title\"/>\n      </else>\n    </choose>\n  </macro>\n  <macro name=\"article-details\">\n    <group delimiter=\", \">\n      <group delimiter=\" \">\n        <text form=\"short\" variable=\"container-title\" font-style=\"italic\"/>\n        <text variable=\"volume\" font-weight=\"bold\"/>\n      </group>\n      <choose>\n        <if variable=\"page volume\" match=\"none\">\n          <text variable=\"DOI\" prefix=\"doi: \"/>\n        </if>\n      </choose>\n      <text variable=\"page\"/>\n    </group>\n    <text macro=\"issued\" prefix=\" (\" suffix=\")\"/>\n  </macro>\n  <macro name=\"publisher\">\n    <group delimiter=\", \">\n      <text variable=\"publisher\"/>\n      <text variable=\"publisher-place\"/>\n    </group>\n  </macro>\n  <macro name=\"pages\">\n    <label variable=\"page\" form=\"short\" suffix=\" \"/>\n    <text variable=\"page\" form=\"short\"/>\n  </macro>\n  <macro name=\"issued\">\n    <date variable=\"issued\" delimiter=\" \">\n      <date-part name=\"year\"/>\n    </date>\n  </macro>\n  <macro name=\"edition\">\n    <choose>\n      <if is-numeric=\"edition\">\n        <group delimiter=\" \">\n          <text term=\"edition\" form=\"short\"/>\n          <number variable=\"edition\" form=\"numeric\"/>\n        </group>\n      </if>\n      <else>\n        <text variable=\"edition\" suffix=\".\"/>\n      </else>\n    </choose>\n  </macro>\n  <citation collapse=\"citation-number\">\n    <sort>\n      <key variable=\"citation-number\"/>\n    </sort>\n    <layout prefix=\"(\" suffix=\")\" delimiter=\", \">\n      <text variable=\"citation-number\" font-style=\"italic\"/>\n    </layout>\n  </citation>\n  <bibliography second-field-align=\"flush\">\n    <layout suffix=\".\">\n      <text variable=\"citation-number\" suffix=\". \"/>\n      <group delimiter=\", \">\n        <text macro=\"author\"/>\n        <text macro=\"title\"/>\n      </group>\n      <choose>\n        <if type=\"thesis\">\n          <group delimiter=\" \" prefix=\", \">\n            <group delimiter=\", \">\n              <text term=\"thesis\"/>\n              <text macro=\"publisher\"/>\n            </group>\n            <text macro=\"issued\" prefix=\"(\" suffix=\")\"/>\n          </group>\n        </if>\n        <else-if type=\"bill book graphic legal_case legislation motion_picture song chapter paper-conference\" match=\"any\">\n          <group delimiter=\" \" prefix=\" \">\n            <choose>\n              <if type=\"chapter paper-conference\" match=\"any\">\n                <group delimiter=\", \">\n                  <group delimiter=\" \">\n                    <text term=\"in\"/>\n                    <text variable=\"container-title\" font-style=\"italic\" text-case=\"title\"/>\n                  </group>\n                  <text macro=\"editor\"/>\n                </group>\n              </if>\n            </choose>\n            <group prefix=\"(\" suffix=\")\" delimiter=\"; \">\n              <group delimiter=\", \">\n                <text macro=\"publisher\"/>\n                <text macro=\"edition\"/>\n                <text macro=\"issued\"/>\n              </group>\n              <text variable=\"URL\"/>\n            </group>\n          </group>\n          <group delimiter=\" of \">\n            <group>\n              <label variable=\"volume\" form=\"short\" suffix=\" \"/>\n              <number variable=\"volume\"/>\n            </group>\n            <text variable=\"collection-title\" font-style=\"italic\"/>\n          </group>\n          <choose>\n            <if type=\"chapter paper-conference\" match=\"any\">\n              <text macro=\"pages\" prefix=\", \"/>\n            </if>\n          </choose>\n        </else-if>\n        <else-if type=\"article-journal\">\n          <text macro=\"article-details\" prefix=\". \"/>\n        </else-if>\n        <else-if type=\"report\">\n          <group prefix=\" (\" suffix=\")\" delimiter=\", \">\n            <group delimiter=\" \">\n              <text variable=\"genre\" form=\"short\"/>\n              <number variable=\"number\"/>\n            </group>\n            <text variable=\"publisher\"/>\n            <text variable=\"publisher-place\"/>\n            <text macro=\"issued\"/>\n          </group>\n          <text macro=\"access-value\" prefix=\"; \"/>\n        </else-if>\n        <else-if type=\"article\">\n          <group delimiter=\". \" prefix=\". \">\n            <group delimiter=\" \">\n              <text variable=\"publisher\"/>\n              <text variable=\"number\"/>\n              <text term=\"article\" text-case=\"capitalize-first\" prefix=\"[\" suffix=\"]\"/>\n              <text macro=\"issued\" prefix=\"(\" suffix=\")\"/>\n            </group>\n            <text macro=\"access-value\"/>\n          </group>\n        </else-if>\n        <else-if type=\"dataset software\" match=\"any\">\n          <group delimiter=\" \" prefix=\", \">\n            <group delimiter=\", \">\n              <group delimiter=\" \">\n                <text term=\"version\"/>\n                <text variable=\"version\"/>\n              </group>\n              <text variable=\"publisher\"/>\n            </group>\n            <text macro=\"issued\" prefix=\"(\" suffix=\")\"/>\n          </group>\n          <text macro=\"access-value\" prefix=\"; \"/>\n        </else-if>\n        <else>\n          <group>\n            <group delimiter=\", \" prefix=\", \">\n              <text macro=\"editor\"/>\n              <group delimiter=\". \">\n                <text variable=\"container-title\" font-style=\"italic\"/>\n                <text variable=\"volume\" font-weight=\"bold\"/>\n              </group>\n            </group>\n            <text macro=\"issued\" prefix=\" (\" suffix=\")\"/>\n          </group>\n          <text macro=\"pages\"/>\n          <text macro=\"access\" prefix=\". \"/>\n        </else>\n      </choose>\n    </layout>\n  </bibliography>\n</style>\n",
  "ama": "<?xml version=\"1.0\" encoding=\"utf-8\"?>\n<style xmlns=\"http://purl.org/net/xbiblio/csl\" class=\"in-text\" delimiter-precedes-last=\"always\" demote-non-dropping-particle=\"sort-only\" initialize-with=\"\" initialize-with-hyphen=\"false\" name-as-sort-order=\"all\" name-delimiter=\", \" page-range-format=\"expanded\" sort-separator=\" \" version=\"1.0\" default-locale=\"en-US\">\n  <!-- This file was generated by the Style Variant Builder <https://github.com/citation-style-language/style-variant-builder>. To contribute changes, modify the template and regenerate variants. -->\n  <info>\n    <title>AMA Manual of Style 11th edition</title>\n    <title-short>American Medical Association (numeric/Vancouver/citation-sequence)</title-short>\n    <id>http://www.zotero.org/styles/american-medical-association</id>\n    <link href=\"http://www.zotero.org/styles/american-medical-association\" rel=\"self\"/>\n    <link href=\"http://www.zotero.org/styles/american-medical-association-10th-edition\" rel=\"template\"/>\n    <link href=\"https://doi.org/10.1093/jama/9780190246556.003.0003\" rel=\"documentation\"/>\n    <link href=\"https://zotero.org/groups/2205533/collections/QW4JGG9G\" rel=\"documentation\"/>\n    <author>\n      <name>Julian Onions</name>\n      <uri>https://orcid.org/0000-0001-5192-6856</uri>\n    </author>\n    <contributor>\n      <name>Christian Pietsch</name>\n      <uri>https://orcid.org/0000-0001-8778-1273</uri>\n    </contributor>\n    <contributor>\n      <name>Daniel W. Chan</name>\n      <uri>https://orcid.org/0000-0002-8082-2316</uri>\n    </contributor>\n    <contributor>\n      <name>Patrick O'Brien</name>\n      <email>obrienpat86@gmail.com</email>\n    </contributor>\n    <contributor>\n      <name>Andrew Dunning</name>\n      <uri>https://orcid.org/0000-0003-0464-5036</uri>\n    </contributor>\n    <category citation-format=\"numeric\"/>\n    <category field=\"medicine\"/>\n    <summary>AMA Manual of Style: A Guide for Authors and Editors (11th ed.)</summary>\n    <updated>2026-02-06T00:00:00+00:00</updated>\n    <rights license=\"http://creativecommons.org/licenses/by-sa/3.0/\">This work is licensed under a Creative Commons Attribution-ShareAlike 3.0 License</rights>\n  </info>\n  <locale xml:lang=\"en\">\n    <terms>\n      <term name=\"advance-online-publication\">published online</term>\n      <term name=\"page-range-delimiter\">-</term>\n      <term name=\"presented at\">presented at</term>\n      <term name=\"preprint\">preprint posted online</term>\n      <term form=\"short\" name=\"supplement\">\n        <single>suppl.</single>\n        <multiple>suppls.</multiple>\n      </term>\n    </terms>\n  </locale>\n  <macro name=\"label-chapter-number\">\n    <group delimiter=\" \">\n      <choose>\n        <if is-numeric=\"chapter-number\">\n          <label form=\"short\" strip-periods=\"true\" variable=\"chapter-number\"/>\n        </if>\n      </choose>\n      <text variable=\"chapter-number\"/>\n    </group>\n  </macro>\n  <macro name=\"label-edition\">\n    <group delimiter=\" \">\n      <choose>\n        <if is-numeric=\"edition\">\n          <number form=\"ordinal\" variable=\"edition\"/>\n          <label form=\"short\" variable=\"edition\"/>\n        </if>\n        <else>\n          <text variable=\"edition\"/>\n        </else>\n      </choose>\n    </group>\n  </macro>\n  <macro name=\"label-supplement-number\">\n    <group delimiter=\" \">\n      <choose>\n        <if is-numeric=\"supplement-number\">\n          <!-- TODO: Replace with `supplement-number` label when CSL provides one -->\n          <text form=\"short\" strip-periods=\"true\" term=\"supplement\"/>\n        </if>\n      </choose>\n      <text variable=\"supplement-number\"/>\n    </group>\n  </macro>\n  <macro name=\"label-volume\">\n    <group delimiter=\" \">\n      <choose>\n        <if is-numeric=\"volume\">\n          <label form=\"short\" strip-periods=\"true\" text-case=\"capitalize-first\" variable=\"volume\"/>\n        </if>\n      </choose>\n      <text variable=\"volume\"/>\n    </group>\n  </macro>\n  <macro name=\"editor\">\n    <names variable=\"editor\">\n      <label form=\"short\" prefix=\", \"/>\n    </names>\n  </macro>\n  <macro name=\"author\">\n    <names variable=\"author\">\n      <label form=\"short\" prefix=\", \"/>\n      <substitute>\n        <names variable=\"editor\"/>\n        <text macro=\"title\"/>\n      </substitute>\n    </names>\n  </macro>\n  <macro name=\"access\">\n    <choose>\n      <if variable=\"DOI\">\n        <text prefix=\"doi:\" variable=\"DOI\"/>\n      </if>\n      <else-if variable=\"URL\">\n        <group delimiter=\". \">\n          <group delimiter=\" \">\n            <text term=\"accessed\" text-case=\"capitalize-first\"/>\n            <date form=\"text\" variable=\"accessed\"/>\n          </group>\n          <text variable=\"URL\"/>\n        </group>\n      </else-if>\n    </choose>\n  </macro>\n  <macro name=\"title\">\n    <choose>\n      <if match=\"any\" type=\"bill book graphic legal_case legislation motion_picture report song thesis\">\n        <text font-style=\"italic\" text-case=\"title\" variable=\"title\"/>\n      </if>\n      <else>\n        <text variable=\"title\"/>\n      </else>\n    </choose>\n  </macro>\n  <citation collapse=\"citation-number\">\n    <sort>\n      <key variable=\"citation-number\"/>\n    </sort>\n    <layout delimiter=\",\" vertical-align=\"sup\">\n      <text variable=\"citation-number\"/>\n      <group prefix=\"(\" suffix=\")\">\n        <label form=\"short\" strip-periods=\"true\" variable=\"locator\"/>\n        <text variable=\"locator\"/>\n      </group>\n    </layout>\n  </citation>\n  <bibliography et-al-min=\"7\" et-al-use-first=\"3\" second-field-align=\"flush\">\n    <layout>\n      <text suffix=\".\" variable=\"citation-number\"/>\n      <group delimiter=\". \">\n        <group delimiter=\". \" suffix=\".\">\n          <text macro=\"author\"/>\n          <text macro=\"title\"/>\n          <choose>\n            <if match=\"any\" type=\"bill book graphic legislation motion_picture report song\">\n              <group delimiter=\":\">\n                <group delimiter=\". \">\n                  <text macro=\"label-volume\"/>\n                  <text macro=\"label-edition\"/>\n                  <text macro=\"editor\" prefix=\"(\" suffix=\")\"/>\n                  <group delimiter=\"; \">\n                    <text variable=\"publisher\"/>\n                    <date date-parts=\"year\" form=\"text\" variable=\"issued\"/>\n                  </group>\n                </group>\n                <text variable=\"page\"/>\n              </group>\n            </if>\n            <else-if match=\"any\" type=\"chapter paper-conference entry-dictionary entry-encyclopedia\">\n              <group delimiter=\":\">\n                <group delimiter=\": \">\n                  <text term=\"in\" text-case=\"capitalize-first\"/>\n                  <group delimiter=\". \">\n                    <text macro=\"editor\"/>\n                    <text font-style=\"italic\" text-case=\"title\" variable=\"container-title\"/>\n                    <text macro=\"label-volume\"/>\n                    <text macro=\"label-edition\"/>\n                    <text variable=\"collection-title\"/>\n                    <group delimiter=\"; \">\n                      <text variable=\"publisher\"/>\n                      <date date-parts=\"year\" form=\"text\" variable=\"issued\"/>\n                    </group>\n                  </group>\n                </group>\n                <choose>\n                  <if variable=\"page\">\n                    <text variable=\"page\"/>\n                  </if>\n                  <else>\n                    <text macro=\"label-chapter-number\"/>\n                  </else>\n                </choose>\n              </group>\n            </else-if>\n            <else-if type=\"legal_case\">\n              <group delimiter=\" \">\n                <group delimiter=\", \">\n                  <group delimiter=\". \">\n                    <text macro=\"editor\" prefix=\"(\" suffix=\")\"/>\n                    <group delimiter=\" \">\n                      <text variable=\"container-title\"/>\n                      <text variable=\"volume\"/>\n                    </group>\n                  </group>\n                  <text variable=\"page\"/>\n                </group>\n                <group delimiter=\" \" prefix=\"(\" suffix=\")\">\n                  <text variable=\"authority\"/>\n                  <date date-parts=\"year\" form=\"numeric\" variable=\"issued\"/>\n                </group>\n              </group>\n            </else-if>\n            <else-if match=\"any\" type=\"post post-weblog webpage\">\n              <text variable=\"container-title\"/>\n              <date form=\"text\" variable=\"issued\"/>\n            </else-if>\n            <else-if type=\"speech\">\n              <group delimiter=\": \">\n                <choose>\n                  <if variable=\"genre\">\n                    <group delimiter=\" \">\n                      <text text-case=\"capitalize-first\" variable=\"genre\"/>\n                      <text term=\"presented at\"/>\n                    </group>\n                  </if>\n                  <else-if match=\"any\" variable=\"event-title event-place\">\n                    <text term=\"presented at\" text-case=\"capitalize-first\"/>\n                  </else-if>\n                </choose>\n                <group delimiter=\"; \">\n                  <text variable=\"event-title\"/>\n                  <date form=\"text\" variable=\"issued\"/>\n                  <text variable=\"event-place\"/>\n                </group>\n              </group>\n            </else-if>\n            <else-if type=\"thesis\">\n              <text variable=\"genre\"/>\n              <group delimiter=\"; \">\n                <text variable=\"publisher\"/>\n                <date date-parts=\"year\" form=\"text\" variable=\"issued\"/>\n              </group>\n            </else-if>\n            <else>\n              <text macro=\"editor\"/>\n              <text font-style=\"italic\" form=\"short\" strip-periods=\"true\" variable=\"container-title\"/>\n              <choose>\n                <if type=\"article\">\n                  <text font-style=\"italic\" variable=\"publisher\"/>\n                </if>\n              </choose>\n              <group delimiter=\":\">\n                <group delimiter=\";\">\n                  <choose>\n                    <if match=\"any\" variable=\"issue volume\">\n                      <date date-parts=\"year\" form=\"numeric\" variable=\"issued\"/>\n                    </if>\n                    <else>\n                      <group delimiter=\" \">\n                        <choose>\n                          <if type=\"article\">\n                            <text term=\"preprint\" text-case=\"capitalize-first\"/>\n                          </if>\n                          <else-if type=\"article-newspaper\"/>\n                          <else>\n                            <text term=\"advance-online-publication\" text-case=\"capitalize-first\"/>\n                          </else>\n                        </choose>\n                        <date form=\"text\" variable=\"issued\"/>\n                      </group>\n                    </else>\n                  </choose>\n                  <choose>\n                    <if match=\"none\" type=\"article-newspaper\">\n                      <group>\n                        <text variable=\"volume\"/>\n                        <text prefix=\"(\" suffix=\")\" variable=\"issue\"/>\n                        <text macro=\"label-supplement-number\" prefix=\"(\" suffix=\")\"/>\n                      </group>\n                    </if>\n                  </choose>\n                </group>\n                <choose>\n                  <if variable=\"number\">\n                    <text variable=\"number\"/>\n                  </if>\n                  <else>\n                    <text variable=\"page\"/>\n                  </else>\n                </choose>\n              </group>\n            </else>\n          </choose>\n        </group>\n        <text macro=\"access\"/>\n      </group>\n    </layout>\n  </bibliography>\n</style>\n",
  "cell": "<?xml version=\"1.0\" encoding=\"utf-8\"?>\n<style xmlns=\"http://purl.org/net/xbiblio/csl\" version=\"1.0\" class=\"in-text\" demote-non-dropping-particle=\"sort-only\" page-range-format=\"expanded\" default-locale=\"en-US\">\n  <info>\n    <title>Cell</title>\n    <id>http://www.zotero.org/styles/cell</id>\n    <link href=\"http://www.zotero.org/styles/cell\" rel=\"self\"/>\n    <link href=\"https://www.cell.com/cell/authors\" rel=\"documentation\"/>\n    <author>\n      <name>Adam Mark</name>\n      <email>a.mark@uoguelph.ca</email>\n    </author>\n    <contributor>\n      <name>Julian Onions</name>\n      <email>julian.onions@gmail.com</email>\n    </contributor>\n    <contributor>\n      <name>Aurimas Vinckevicius</name>\n      <email>aurimas.dev@gmail.com</email>\n    </contributor>\n    <contributor>\n      <name>Patrick O'Brien</name>\n    </contributor>\n    <category citation-format=\"numeric\"/>\n    <category field=\"biology\"/>\n    <issn>0092-8674</issn>\n    <eissn>1097-4172</eissn>\n    <summary>The Cell journal style, switched to numeric superscript as per the Cell editorial office in Sept. 2022</summary>\n    <updated>2024-03-28T09:46:58+00:00</updated>\n    <rights license=\"http://creativecommons.org/licenses/by-sa/3.0/\">This work is licensed under a Creative Commons Attribution-ShareAlike 3.0 License</rights>\n  </info>\n  <macro name=\"editor\">\n    <names variable=\"editor\" delimiter=\", \">\n      <name and=\"text\" initialize-with=\". \" delimiter=\", \"/>\n      <label form=\"short\" prefix=\", \"/>\n    </names>\n  </macro>\n  <macro name=\"author\">\n    <names variable=\"author\">\n      <name name-as-sort-order=\"all\" and=\"text\" sort-separator=\", \" initialize-with=\".\" delimiter=\", \" delimiter-precedes-last=\"always\"/>\n      <label form=\"short\" prefix=\" \"/>\n      <substitute>\n        <names variable=\"editor\"/>\n        <text variable=\"title\"/>\n      </substitute>\n    </names>\n  </macro>\n  <macro name=\"access\">\n    <choose>\n      <if match=\"any\" variable=\"DOI\">\n        <text variable=\"DOI\" prefix=\"https://doi.org/\"/>\n      </if>\n      <else-if match=\"any\" type=\"webpage dataset entry-dictionary entry-encyclopedia post post-weblog\">\n        <text variable=\"URL\"/>\n      </else-if>\n    </choose>\n  </macro>\n  <macro name=\"title\">\n    <text variable=\"title\"/>\n  </macro>\n  <macro name=\"publisher\">\n    <text variable=\"publisher\" prefix=\"(\" suffix=\")\"/>\n  </macro>\n  <macro name=\"edition\">\n    <choose>\n      <if is-numeric=\"edition\">\n        <group delimiter=\" \">\n          <number variable=\"edition\" form=\"ordinal\"/>\n          <text term=\"edition\" form=\"short\"/>\n        </group>\n      </if>\n      <else>\n        <text variable=\"edition\" suffix=\".\"/>\n      </else>\n    </choose>\n  </macro>\n  <citation collapse=\"citation-number\">\n    <sort>\n      <key variable=\"citation-number\"/>\n    </sort>\n    <layout vertical-align=\"sup\" delimiter=\",\">\n      <text variable=\"citation-number\"/>\n    </layout>\n  </citation>\n  <bibliography et-al-min=\"11\" et-al-use-first=\"10\" second-field-align=\"flush\">\n    <sort>\n      <key variable=\"citation-number\"/>\n    </sort>\n    <layout suffix=\".\">\n      <text variable=\"citation-number\" suffix=\".\"/>\n      <text macro=\"author\"/>\n      <date variable=\"issued\" prefix=\" (\" suffix=\").\">\n        <date-part name=\"year\"/>\n      </date>\n      <choose>\n        <if type=\"bill book graphic legal_case legislation motion_picture report song\" match=\"any\">\n          <group delimiter=\" \" prefix=\" \">\n            <text macro=\"title\"/>\n            <text macro=\"edition\"/>\n            <text macro=\"editor\"/>\n            <text macro=\"publisher\"/>\n          </group>\n        </if>\n        <else-if type=\"chapter paper-conference\" match=\"any\">\n          <group delimiter=\" \" prefix=\" \">\n            <text macro=\"title\" suffix=\".\"/>\n            <text term=\"in\" text-case=\"capitalize-first\"/>\n            <text variable=\"container-title\"/>\n            <text variable=\"collection-title\" suffix=\".\"/>\n          </group>\n          <text macro=\"editor\" prefix=\", \"/>\n          <group suffix=\".\">\n            <text macro=\"publisher\" prefix=\" \"/>\n            <group prefix=\", \">\n              <label variable=\"page\" suffix=\" \" form=\"short\"/>\n              <text variable=\"page\"/>\n            </group>\n          </group>\n        </else-if>\n        <else-if type=\"article\">\n          <text macro=\"title\" prefix=\" \"/>\n          <text term=\"article\" text-case=\"capitalize-first\" prefix=\". \"/>\n          <text variable=\"publisher\" prefix=\" at \"/>\n          <text macro=\"access\" prefix=\", \"/>\n        </else-if>\n        <else-if type=\"dataset software\" match=\"any\">\n          <group delimiter=\". \" prefix=\" \">\n            <text macro=\"title\"/>\n            <group delimiter=\" \">\n              <group delimiter=\" \">\n                <text term=\"version\" text-case=\"capitalize-first\"/>\n                <text variable=\"version\"/>\n              </group>\n              <text variable=\"publisher\" prefix=\"(\" suffix=\")\"/>\n            </group>\n            <text macro=\"access\"/>\n          </group>\n        </else-if>\n        <else>\n          <text macro=\"title\" prefix=\" \" suffix=\".\"/>\n          <group delimiter=\", \" prefix=\" \" suffix=\".\">\n            <group delimiter=\" \">\n              <text variable=\"container-title\" form=\"short\"/>\n              <text variable=\"volume\" font-style=\"italic\"/>\n            </group>\n            <text variable=\"page\"/>\n          </group>\n        </else>\n      </choose>\n      <text prefix=\" \" macro=\"access\"/>\n    </layout>\n  </bibliography>\n</style>\n",
  "plos": "<?xml version=\"1.0\" encoding=\"utf-8\"?>\n<style xmlns=\"http://purl.org/net/xbiblio/csl\" class=\"in-text\" version=\"1.0\" demote-non-dropping-particle=\"sort-only\" default-locale=\"en-US\">\n  <info>\n    <title>Public Library of Science</title>\n    <title-short>PLOS</title-short>\n    <id>http://www.zotero.org/styles/plos</id>\n    <link href=\"http://www.zotero.org/styles/plos\" rel=\"self\"/>\n    <link href=\"http://www.zotero.org/styles/nlm-citation-sequence\" rel=\"template\"/>\n    <link href=\"http://www.plosone.org/static/guidelines#references\" rel=\"documentation\"/>\n    <author>\n      <name>Sebastian Karcher</name>\n    </author>\n    <contributor>\n      <name>Patrick O'Brien</name>\n    </contributor>\n    <category citation-format=\"numeric\"/>\n    <category field=\"science\"/>\n    <summary>Vancouver for PLoS Journals as of January 2015</summary>\n    <updated>2019-09-29T19:19:07+00:00</updated>\n    <rights license=\"http://creativecommons.org/licenses/by-sa/3.0/\">This work is licensed under a Creative Commons Attribution-ShareAlike 3.0 License</rights>\n  </info>\n  <locale xml:lang=\"en\">\n    <date form=\"text\" delimiter=\" \">\n      <date-part name=\"day\"/>\n      <date-part name=\"month\" form=\"short\" strip-periods=\"true\"/>\n      <date-part name=\"year\"/>\n    </date>\n    <terms>\n      <term name=\"presented at\">presented at</term>\n      <term name=\"retrieved\">available</term>\n      <term name=\"section\" form=\"short\">sect.</term>\n    </terms>\n  </locale>\n  <macro name=\"author\">\n    <names variable=\"author\">\n      <name sort-separator=\" \" initialize-with=\"\" name-as-sort-order=\"all\" delimiter=\", \" delimiter-precedes-last=\"always\"/>\n      <label form=\"long\" prefix=\", \"/>\n      <substitute>\n        <names variable=\"editor\"/>\n      </substitute>\n    </names>\n  </macro>\n  <macro name=\"editor\">\n    <group delimiter=\": \">\n      <choose>\n        <if type=\"chapter paper-conference\" match=\"any\">\n          <text term=\"in\" text-case=\"capitalize-first\"/>\n        </if>\n      </choose>\n      <names variable=\"editor\" suffix=\".\">\n        <name sort-separator=\" \" initialize-with=\"\" name-as-sort-order=\"all\" delimiter=\", \" delimiter-precedes-last=\"always\"/>\n        <label form=\"long\" prefix=\", \"/>\n      </names>\n    </group>\n  </macro>\n  <macro name=\"publisher\">\n    <choose>\n      <if type=\"thesis\">\n        <group delimiter=\", \" suffix=\".\">\n          <text variable=\"genre\"/>\n          <text variable=\"publisher\"/>\n        </group>\n      </if>\n      <else>\n        <choose>\n          <if type=\"article-newspaper article-journal article-magazine\" match=\"none\">\n            <group delimiter=\": \" suffix=\";\">\n              <choose>\n                <if type=\"speech\" match=\"any\"/>\n                <else>\n                  <text variable=\"publisher-place\"/>\n                </else>\n              </choose>\n              <text variable=\"publisher\"/>\n            </group>\n          </if>\n        </choose>\n      </else>\n    </choose>\n  </macro>\n  <macro name=\"access\">\n    <choose>\n      <if variable=\"DOI\">\n        <text variable=\"DOI\" prefix=\"doi:\"/>\n      </if>\n      <else-if variable=\"URL\">\n        <group delimiter=\". \">\n          <group delimiter=\": \">\n            <text term=\"retrieved\" text-case=\"capitalize-first\"/>\n            <text variable=\"URL\"/>\n          </group>\n          <choose>\n            <if type=\"article-newspaper article-magazine\" match=\"any\">\n              <group delimiter=\" \" suffix=\".\">\n                <text term=\"accessed\" text-case=\"capitalize-first\"/>\n                <date variable=\"accessed\" form=\"text\"/>\n              </group>\n            </if>\n          </choose>\n        </group>\n      </else-if>\n    </choose>\n  </macro>\n  <macro name=\"accessed-date\">\n    <choose>\n      <if variable=\"URL\">\n        <group prefix=\"[\" suffix=\"]\" delimiter=\" \">\n          <text term=\"cited\" text-case=\"lowercase\"/>\n          <date variable=\"accessed\" form=\"text\"/>\n        </group>\n      </if>\n    </choose>\n  </macro>\n  <macro name=\"container-title\">\n    <choose>\n      <if type=\"article-journal article-magazine chapter paper-conference article-newspaper post-weblog webpage post report\" match=\"any\">\n        <group suffix=\".\" delimiter=\" \">\n          <choose>\n            <if type=\"article-journal report\" match=\"any\">\n              <text variable=\"container-title\" form=\"short\" strip-periods=\"true\"/>\n            </if>\n            <else-if type=\"post-weblog webpage post\" match=\"any\">\n              <group delimiter=\" \">\n                <text term=\"in\" text-case=\"capitalize-first\" suffix=\":\"/>\n                <text variable=\"container-title\"/>\n                <choose>\n                  <if variable=\"URL\">\n                    <text term=\"internet\" prefix=\"[\" suffix=\"]\" text-case=\"capitalize-first\"/>\n                  </if>\n                </choose>\n              </group>\n            </else-if>\n            <else>\n              <text variable=\"container-title\" strip-periods=\"true\"/>\n            </else>\n          </choose>\n        </group>\n        <text macro=\"edition\" prefix=\" \"/>\n      </if>\n      <else-if type=\"bill legislation\" match=\"any\">\n        <group delimiter=\", \">\n          <group delimiter=\". \">\n            <text variable=\"container-title\"/>\n            <group delimiter=\" \">\n              <text term=\"section\" form=\"short\" text-case=\"capitalize-first\"/>\n              <text variable=\"section\"/>\n            </group>\n          </group>\n          <text variable=\"number\"/>\n        </group>\n      </else-if>\n      <else-if type=\"speech\">\n        <group delimiter=\": \" suffix=\";\">\n          <group delimiter=\" \">\n            <text variable=\"genre\" text-case=\"capitalize-first\"/>\n            <text term=\"presented at\"/>\n          </group>\n          <text variable=\"event\"/>\n        </group>\n      </else-if>\n      <else>\n        <text variable=\"container-title\" suffix=\".\"/>\n      </else>\n    </choose>\n  </macro>\n  <macro name=\"title\">\n    <text variable=\"title\"/>\n    <choose>\n      <if type=\"book chapter\" match=\"any\">\n        <text macro=\"edition\" prefix=\". \"/>\n      </if>\n    </choose>\n    <choose>\n      <if type=\"song motion_picture\" match=\"any\">\n        <text variable=\"medium\" prefix=\" [\" suffix=\"]\"/>\n      </if>\n    </choose>\n  </macro>\n  <macro name=\"edition\">\n    <choose>\n      <if is-numeric=\"edition\">\n        <group delimiter=\" \">\n          <number variable=\"edition\" form=\"ordinal\"/>\n          <text term=\"edition\" form=\"short\"/>\n        </group>\n      </if>\n      <else>\n        <text variable=\"edition\" suffix=\".\"/>\n      </else>\n    </choose>\n  </macro>\n  <macro name=\"date\">\n    <choose>\n      <if type=\"article-journal\" match=\"any\">\n        <choose>\n          <if match=\"none\" variable=\"volume page\">\n            <group delimiter=\" \">\n              <date date-parts=\"year\" form=\"text\" variable=\"issued\"/>\n              <text macro=\"accessed-date\"/>\n            </group>\n          </if>\n          <else>\n            <date date-parts=\"year\" form=\"text\" variable=\"issued\" suffix=\";\"/>\n          </else>\n        </choose>\n      </if>\n      <else-if type=\"article-magazine article-newspaper\" match=\"any\">\n        <date variable=\"issued\" form=\"text\"/>\n      </else-if>\n      <else-if type=\"bill legislation\" match=\"any\">\n        <group delimiter=\", \">\n          <date variable=\"issued\" delimiter=\" \">\n            <date-part name=\"month\" form=\"short\" strip-periods=\"true\"/>\n            <date-part name=\"day\"/>\n          </date>\n          <date variable=\"issued\">\n            <date-part name=\"year\"/>\n          </date>\n        </group>\n      </else-if>\n      <else-if type=\"report\">\n        <date variable=\"issued\" delimiter=\" \">\n          <date-part name=\"year\"/>\n          <date-part name=\"month\" form=\"short\" strip-periods=\"true\"/>\n        </date>\n      </else-if>\n      <else-if type=\"patent\">\n        <group suffix=\".\">\n          <group delimiter=\", \">\n            <text variable=\"number\"/>\n            <date variable=\"issued\">\n              <date-part name=\"year\"/>\n            </date>\n          </group>\n        </group>\n      </else-if>\n      <else-if type=\"speech\">\n        <group delimiter=\"; \">\n          <group delimiter=\" \">\n            <date variable=\"issued\" delimiter=\" \">\n              <date-part name=\"year\"/>\n              <date-part name=\"month\" form=\"short\" strip-periods=\"true\"/>\n              <date-part name=\"day\"/>\n            </date>\n          </group>\n          <text variable=\"event-place\"/>\n        </group>\n      </else-if>\n      <else-if type=\"post-weblog webpage\" match=\"any\">\n        <date variable=\"issued\" form=\"text\"/>\n        <text macro=\"accessed-date\" prefix=\" \"/>\n      </else-if>\n      <else>\n        <group suffix=\".\">\n          <date variable=\"issued\">\n            <date-part name=\"year\"/>\n          </date>\n        </group>\n      </else>\n    </choose>\n  </macro>\n  <macro name=\"pages\">\n    <choose>\n      <if type=\"article-journal article-magazine article-newspaper\" match=\"any\">\n        <text variable=\"page\" prefix=\": \"/>\n      </if>\n      <else>\n        <group prefix=\" \" delimiter=\" \">\n          <label variable=\"page\" form=\"short\"/>\n          <text variable=\"page\"/>\n        </group>\n      </else>\n    </choose>\n  </macro>\n  <macro name=\"journal-location\">\n    <choose>\n      <if type=\"article-journal article-magazine\" match=\"any\">\n        <text variable=\"volume\"/>\n      </if>\n    </choose>\n  </macro>\n  <macro name=\"report-details\">\n    <choose>\n      <if type=\"report\">\n        <text variable=\"number\" prefix=\"Report No.: \"/>\n      </if>\n    </choose>\n  </macro>\n  <citation collapse=\"citation-number\">\n    <sort>\n      <key variable=\"citation-number\"/>\n    </sort>\n    <layout prefix=\"[\" suffix=\"]\" delimiter=\",\">\n      <text variable=\"citation-number\"/>\n    </layout>\n  </citation>\n  <bibliography et-al-min=\"7\" et-al-use-first=\"6\" second-field-align=\"flush\">\n    <layout>\n      <text variable=\"citation-number\" suffix=\". \"/>\n      <group delimiter=\". \" suffix=\". \">\n        <text macro=\"author\"/>\n        <text macro=\"title\"/>\n      </group>\n      <group delimiter=\" \" suffix=\". \">\n        <text macro=\"editor\"/>\n        <text macro=\"container-title\"/>\n        <text macro=\"publisher\"/>\n        <group>\n          <text macro=\"date\"/>\n          <text macro=\"journal-location\"/>\n          <text macro=\"pages\"/>\n        </group>\n      </group>\n      <text macro=\"report-details\" suffix=\". \"/>\n      <text macro=\"access\"/>\n    </layout>\n  </bibliography>\n</style>\n",
  "bmj": "<?xml version=\"1.0\" encoding=\"utf-8\"?>\n<style xmlns=\"http://purl.org/net/xbiblio/csl\" class=\"in-text\" version=\"1.0\" demote-non-dropping-particle=\"sort-only\" page-range-format=\"minimal\" default-locale=\"en-GB\">\n  <info>\n    <title>BMJ</title>\n    <id>http://www.zotero.org/styles/bmj</id>\n    <link href=\"http://www.zotero.org/styles/bmj\" rel=\"self\"/>\n    <link href=\"http://group.bmj.com/products/journals/instructions-for-authors/formatting#references\" rel=\"documentation\"/>\n    <link href=\"https://authors.bmj.com/writing-and-formatting/formatting-your-paper/\" rel=\"documentation\"/>\n    <author>\n      <name>Sebastian Karcher</name>\n    </author>\n    <contributor>\n      <name>Sean Takats</name>\n      <email>stakats@gmu.edu</email>\n    </contributor>\n    <contributor>\n      <name>Michael Berkowitz</name>\n      <email>mberkowi@gmu.edu</email>\n    </contributor>\n    <contributor>\n      <name>Patrick O'Brien</name>\n    </contributor>\n    <category citation-format=\"numeric\"/>\n    <category field=\"medicine\"/>\n    <issn>0959-8138</issn>\n    <eissn>1756-1833</eissn>\n    <summary>Vancouver style adapted for BMJ journals</summary>\n    <updated>2024-06-06T09:34:02+00:00</updated>\n    <rights license=\"http://creativecommons.org/licenses/by-sa/3.0/\">This work is licensed under a Creative Commons Attribution-ShareAlike 3.0 License</rights>\n  </info>\n  <macro name=\"author\">\n    <names variable=\"author\">\n      <name sort-separator=\" \" initialize-with=\"\" name-as-sort-order=\"all\" delimiter=\", \" delimiter-precedes-last=\"always\"/>\n      <label form=\"long\" prefix=\", \"/>\n      <et-al term=\"et-al\" font-style=\"italic\"/>\n      <substitute>\n        <names variable=\"editor\"/>\n      </substitute>\n    </names>\n  </macro>\n  <macro name=\"editor\">\n    <names variable=\"editor\">\n      <name sort-separator=\" \" initialize-with=\"\" name-as-sort-order=\"all\" delimiter=\", \" delimiter-precedes-last=\"always\"/>\n      <label form=\"short\" prefix=\", \"/>\n      <et-al term=\"et-al\" font-style=\"italic\"/>\n    </names>\n  </macro>\n  <macro name=\"publisher\">\n    <group delimiter=\" \">\n      <group delimiter=\": \" suffix=\" \">\n        <text variable=\"publisher-place\"/>\n        <text variable=\"publisher\"/>\n      </group>\n      <text macro=\"date\"/>\n    </group>\n  </macro>\n  <macro name=\"access\">\n    <choose>\n      <if type=\"article-journal\">\n        <text variable=\"DOI\" prefix=\"doi: \"/>\n      </if>\n      <else-if type=\"webpage post post-weblog\" match=\"any\">\n        <group delimiter=\" \">\n          <text variable=\"URL\"/>\n          <group delimiter=\" \" prefix=\"(\" suffix=\")\">\n            <text term=\"accessed\"/>\n            <date variable=\"accessed\">\n              <date-part name=\"day\" suffix=\" \"/>\n              <date-part name=\"month\" strip-periods=\"false\" suffix=\" \"/>\n              <date-part name=\"year\"/>\n            </date>\n          </group>\n        </group>\n      </else-if>\n    </choose>\n  </macro>\n  <macro name=\"journal-title\">\n    <choose>\n      <if type=\"article-journal article-magazine\" match=\"any\">\n        <text variable=\"container-title\" form=\"short\" font-style=\"italic\" strip-periods=\"true\"/>\n      </if>\n      <else>\n        <text variable=\"container-title\" form=\"short\"/>\n      </else>\n    </choose>\n  </macro>\n  <macro name=\"date\">\n    <choose>\n      <if type=\"article-journal\">\n        <choose>\n          <if variable=\"volume page\" match=\"none\">\n            <choose>\n              <if variable=\"DOI URL\" match=\"any\">\n                <group prefix=\"Published Online First: \">\n                  <date variable=\"issued\" delimiter=\" \">\n                    <date-part name=\"day\"/>\n                    <date-part name=\"month\" form=\"long\" text-case=\"capitalize-first\"/>\n                    <date-part name=\"year\"/>\n                  </date>\n                </group>\n              </if>\n              <else>\n                <date variable=\"issued\">\n                  <date-part name=\"year\"/>\n                </date>\n              </else>\n            </choose>\n          </if>\n          <else>\n            <date variable=\"issued\">\n              <date-part name=\"year\"/>\n            </date>\n          </else>\n        </choose>\n      </if>\n      <else>\n        <date variable=\"issued\">\n          <date-part name=\"year\"/>\n        </date>\n      </else>\n    </choose>\n  </macro>\n  <macro name=\"title\">\n    <choose>\n      <if type=\"book thesis\" match=\"any\">\n        <text variable=\"title\" font-style=\"italic\"/>\n      </if>\n      <else>\n        <text variable=\"title\"/>\n      </else>\n    </choose>\n  </macro>\n  <macro name=\"edition\">\n    <choose>\n      <if is-numeric=\"edition\">\n        <group delimiter=\" \">\n          <number variable=\"edition\" form=\"ordinal\"/>\n          <text term=\"edition\" form=\"short\"/>\n        </group>\n      </if>\n      <else>\n        <text variable=\"edition\"/>\n      </else>\n    </choose>\n  </macro>\n  <citation collapse=\"citation-number\">\n    <sort>\n      <key variable=\"citation-number\"/>\n    </sort>\n    <layout prefix=\"[\" suffix=\"]\" delimiter=\",\">\n      <text variable=\"citation-number\"/>\n    </layout>\n  </citation>\n  <bibliography et-al-min=\"4\" et-al-use-first=\"3\" second-field-align=\"flush\">\n    <layout>\n      <text variable=\"citation-number\" suffix=\" \"/>\n      <group delimiter=\". \" suffix=\".\">\n        <text macro=\"author\"/>\n        <text macro=\"title\"/>\n        <choose>\n          <if type=\"bill book graphic legal_case legislation motion_picture report song\" match=\"any\">\n            <group delimiter=\". \">\n              <text macro=\"edition\"/>\n              <text macro=\"publisher\"/>\n            </group>\n          </if>\n          <else-if type=\"chapter paper-conference\" match=\"any\">\n            <group delimiter=\". \">\n              <group delimiter=\": \">\n                <text term=\"in\" text-case=\"capitalize-first\"/>\n                <text macro=\"editor\"/>\n              </group>\n              <text variable=\"container-title\" font-style=\"italic\"/>\n              <group delimiter=\":\">\n                <text macro=\"publisher\"/>\n                <text variable=\"page\" suffix=\".\"/>\n              </group>\n            </group>\n          </else-if>\n          <else>\n            <text macro=\"journal-title\"/>\n            <group>\n              <text macro=\"date\"/>\n              <group prefix=\";\" delimiter=\":\">\n                <text variable=\"volume\"/>\n                <text variable=\"page\"/>\n              </group>\n            </group>\n          </else>\n        </choose>\n      </group>\n      <text macro=\"access\" prefix=\" \"/>\n    </layout>\n  </bibliography>\n</style>\n",
  "elsevier-vancouver": "<?xml version=\"1.0\" encoding=\"utf-8\"?>\n<style xmlns=\"http://purl.org/net/xbiblio/csl\" page-range-format=\"minimal\" class=\"in-text\" version=\"1.0\" demote-non-dropping-particle=\"sort-only\" default-locale=\"en-US\">\n  <info>\n    <title>Elsevier - NLM/Vancouver (citation-sequence)</title>\n    <title-short>Elsevier - Vancouver</title-short>\n    <id>http://www.zotero.org/styles/elsevier-vancouver</id>\n    <link href=\"http://www.zotero.org/styles/elsevier-vancouver\" rel=\"self\"/>\n    <link href=\"http://www.elsevier.com/journals/energy/0360-5442/guide-for-authors#68000\" rel=\"documentation\"/>\n    <author>\n      <name>Richard Karnesky</name>\n      <email>karnesky+zotero@gmail.com</email>\n      <uri>http://arc.nucapt.northwestern.edu/Richard_Karnesky</uri>\n    </author>\n    <category citation-format=\"numeric\"/>\n    <summary>A style for some Elsevier journals, resembles Vancouver style</summary>\n    <updated>2019-10-15T22:06:38+00:00</updated>\n    <rights license=\"http://creativecommons.org/licenses/by-sa/3.0/\">This work is licensed under a Creative Commons Attribution-ShareAlike 3.0 License</rights>\n  </info>\n  <macro name=\"author\">\n    <names variable=\"author\">\n      <name initialize-with=\"\" delimiter=\", \" delimiter-precedes-last=\"always\" name-as-sort-order=\"all\" sort-separator=\" \"/>\n      <label form=\"long\" prefix=\", \"/>\n      <substitute>\n        <names variable=\"editor\"/>\n        <names variable=\"translator\"/>\n      </substitute>\n    </names>\n  </macro>\n  <macro name=\"editor\">\n    <names variable=\"editor\">\n      <name initialize-with=\"\" delimiter=\", \" delimiter-precedes-last=\"always\" name-as-sort-order=\"all\" sort-separator=\" \"/>\n      <label form=\"long\" prefix=\", \" suffix=\".\"/>\n    </names>\n  </macro>\n  <macro name=\"year-date\">\n    <choose>\n      <if variable=\"issued\">\n        <date variable=\"issued\">\n          <date-part name=\"year\"/>\n        </date>\n      </if>\n      <else>\n        <text term=\"no date\" form=\"short\"/>\n      </else>\n    </choose>\n  </macro>\n  <macro name=\"publisher\">\n    <text variable=\"publisher-place\" suffix=\": \" text-case=\"title\"/>\n    <text variable=\"publisher\" suffix=\"; \"/>\n    <text macro=\"year-date\"/>\n  </macro>\n  <macro name=\"edition\">\n    <choose>\n      <if is-numeric=\"edition\">\n        <group delimiter=\" \">\n          <number variable=\"edition\" form=\"ordinal\"/>\n          <text term=\"edition\" form=\"short\"/>\n        </group>\n      </if>\n      <else>\n        <text variable=\"edition\"/>\n      </else>\n    </choose>\n  </macro>\n  <macro name=\"access\">\n    <choose>\n      <if variable=\"DOI\">\n        <text variable=\"DOI\" prefix=\"https://doi.org/\"/>\n      </if>\n      <else-if type=\"webpage post-weblog\" match=\"any\">\n        <choose>\n          <if variable=\"URL\">\n            <text variable=\"URL\"/>\n            <group prefix=\" (\" suffix=\")\" delimiter=\" \">\n              <text term=\"accessed\"/>\n              <date variable=\"accessed\" form=\"text\"/>\n            </group>\n          </if>\n        </choose>\n      </else-if>\n    </choose>\n  </macro>\n  <citation collapse=\"citation-number\">\n    <sort>\n      <key variable=\"citation-number\"/>\n    </sort>\n    <layout prefix=\"[\" suffix=\"]\" delimiter=\",\">\n      <text variable=\"citation-number\"/>\n    </layout>\n  </citation>\n  <bibliography entry-spacing=\"0\" second-field-align=\"flush\" et-al-min=\"7\" et-al-use-first=\"6\">\n    <layout suffix=\".\">\n      <text variable=\"citation-number\" prefix=\"[\" suffix=\"]\"/>\n      <text macro=\"author\" suffix=\". \"/>\n      <choose>\n        <if type=\"bill book graphic legal_case legislation motion_picture report song\" match=\"any\">\n          <group delimiter=\". \">\n            <text variable=\"title\"/>\n            <text variable=\"volume\" prefix=\"vol. \"/>\n            <text macro=\"edition\"/>\n            <text macro=\"publisher\"/>\n          </group>\n        </if>\n        <else-if type=\"chapter paper-conference\" match=\"any\">\n          <group delimiter=\", \">\n            <group delimiter=\". \">\n              <text variable=\"title\"/>\n              <group>\n                <text term=\"in\" text-case=\"sentence\" suffix=\": \"/>\n                <text macro=\"editor\"/>\n              </group>\n              <group delimiter=\", \">\n                <text variable=\"container-title\" form=\"short\"/>\n                <text variable=\"volume\" prefix=\"vol. \"/>\n              </group>\n              <text macro=\"edition\"/>\n            </group>\n            <text macro=\"publisher\"/>\n            <group delimiter=\" \">\n              <label variable=\"page\" form=\"short\" plural=\"never\"/>\n              <text variable=\"page\"/>\n            </group>\n          </group>\n        </else-if>\n        <else-if type=\"patent\">\n          <group delimiter=\", \">\n            <group delimiter=\". \">\n              <text variable=\"title\"/>\n              <text variable=\"number\"/>\n            </group>\n            <text macro=\"year-date\"/>\n          </group>\n        </else-if>\n        <else-if type=\"thesis\">\n          <group delimiter=\". \">\n            <text variable=\"title\"/>\n            <text variable=\"genre\"/>\n            <group delimiter=\", \">\n              <text variable=\"publisher\"/>\n              <text macro=\"year-date\"/>\n            </group>\n          </group>\n        </else-if>\n        <else>\n          <group delimiter=\":\">\n            <group delimiter=\" \">\n              <group delimiter=\". \">\n                <text variable=\"title\"/>\n                <text variable=\"container-title\" form=\"short\" text-case=\"title\" strip-periods=\"true\"/>\n              </group>\n              <group delimiter=\";\">\n                <text macro=\"year-date\"/>\n                <text variable=\"volume\"/>\n              </group>\n            </group>\n            <text variable=\"page\" form=\"short\"/>\n          </group>\n        </else>\n      </choose>\n      <text macro=\"access\" prefix=\". \"/>\n    </layout>\n  </bibliography>\n</style>\n",
  "elsevier-harvard": "<?xml version=\"1.0\" encoding=\"utf-8\"?>\n<style xmlns=\"http://purl.org/net/xbiblio/csl\" class=\"in-text\" version=\"1.0\" demote-non-dropping-particle=\"never\" default-locale=\"en-US\">\n  <info>\n    <title>Elsevier (author-date/Harvard, with titles)</title>\n    <id>http://www.zotero.org/styles/elsevier-harvard</id>\n    <link href=\"http://www.zotero.org/styles/elsevier-harvard\" rel=\"self\"/>\n    <link href=\"http://www.zotero.org/styles/ecology-letters\" rel=\"template\"/>\n    <link href=\"http://www.elsevier.com/journals/biological-conservation/0006-3207/guide-for-authors#68000\" rel=\"documentation\"/>\n    <author>\n      <name>David Kaplan</name>\n      <email>david.kaplan@ird.fr</email>\n    </author>\n    <contributor>\n      <name>Simon Kornblith</name>\n      <email>simon@simonster.com</email>\n    </contributor>\n    <contributor>\n      <name>Bruce D'Arcus</name>\n    </contributor>\n    <contributor>\n      <name>Curtis M. Humphrey</name>\n    </contributor>\n    <contributor>\n      <name>Richard Karnesky</name>\n      <email>karnesky+zotero@gmail.com</email>\n      <uri>http://arc.nucapt.northwestern.edu/Richard_Karnesky</uri>\n    </contributor>\n    <contributor>\n      <name>Sebastian Karcher</name>\n    </contributor>\n    <category citation-format=\"author-date\"/>\n    <category field=\"biology\"/>\n    <updated>2014-03-04T00:09:00+00:00</updated>\n    <rights license=\"http://creativecommons.org/licenses/by-sa/3.0/\">This work is licensed under a Creative Commons Attribution-ShareAlike 3.0 License</rights>\n  </info>\n  <macro name=\"container\">\n    <choose>\n      <if type=\"chapter paper-conference\" match=\"any\">\n        <text term=\"in\" prefix=\", \" suffix=\": \"/>\n        <names variable=\"editor translator\" delimiter=\", \" suffix=\", \">\n          <name name-as-sort-order=\"all\" sort-separator=\", \" initialize-with=\".\" delimiter=\", \" delimiter-precedes-last=\"always\"/>\n          <label form=\"short\" text-case=\"capitalize-first\" prefix=\" (\" suffix=\")\"/>\n        </names>\n        <group delimiter=\", \">\n          <text variable=\"container-title\" text-case=\"title\"/>\n          <text variable=\"collection-title\" text-case=\"title\"/>\n        </group>\n      </if>\n      <else-if type=\"bill book graphic legal_case legislation motion_picture report song\" match=\"any\">\n        <group prefix=\", \" delimiter=\", \">\n          <text variable=\"container-title\"/>\n          <text variable=\"collection-title\"/>\n        </group>\n      </else-if>\n      <else>\n        <group prefix=\". \" delimiter=\", \">\n          <text variable=\"container-title\" form=\"short\"/>\n          <text variable=\"collection-title\"/>\n        </group>\n      </else>\n    </choose>\n  </macro>\n  <macro name=\"author\">\n    <names variable=\"author\">\n      <name name-as-sort-order=\"all\" sort-separator=\", \" initialize-with=\".\" delimiter=\", \" delimiter-precedes-last=\"always\"/>\n      <label form=\"short\" prefix=\" (\" suffix=\")\" text-case=\"capitalize-first\"/>\n      <substitute>\n        <names variable=\"editor\"/>\n        <names variable=\"translator\"/>\n        <text macro=\"title\"/>\n      </substitute>\n    </names>\n  </macro>\n  <macro name=\"author-short\">\n    <names variable=\"author\">\n      <name form=\"short\" and=\"text\" delimiter=\", \" initialize-with=\". \"/>\n      <substitute>\n        <names variable=\"editor\"/>\n        <names variable=\"translator\"/>\n        <choose>\n          <if type=\"bill book graphic legal_case legislation motion_picture report song\" match=\"any\">\n            <text variable=\"title\" form=\"short\" font-style=\"italic\"/>\n          </if>\n          <else>\n            <text variable=\"title\" form=\"short\" quotes=\"true\"/>\n          </else>\n        </choose>\n      </substitute>\n    </names>\n  </macro>\n  <macro name=\"access\">\n    <choose>\n      <if variable=\"DOI\">\n        <text variable=\"DOI\" prefix=\"https://doi.org/\"/>\n      </if>\n      <else-if type=\"webpage post-weblog\" match=\"any\">\n        <group delimiter=\" \">\n          <text value=\"URL\"/>\n          <text variable=\"URL\"/>\n          <group prefix=\"(\" suffix=\").\">\n            <text term=\"accessed\" suffix=\" \"/>\n            <date variable=\"accessed\">\n              <date-part name=\"month\" form=\"numeric\" suffix=\".\"/>\n              <date-part name=\"day\" suffix=\".\"/>\n              <date-part name=\"year\" form=\"short\"/>\n            </date>\n          </group>\n        </group>\n      </else-if>\n    </choose>\n  </macro>\n  <macro name=\"title\">\n    <choose>\n      <if type=\"report thesis\" match=\"any\">\n        <text variable=\"title\"/>\n        <group prefix=\" (\" suffix=\")\" delimiter=\" \">\n          <text variable=\"genre\"/>\n          <text variable=\"number\" prefix=\"No. \"/>\n        </group>\n      </if>\n      <else-if type=\"bill book graphic legal_case legislation motion_picture report song speech\" match=\"any\">\n        <text variable=\"title\"/>\n        <text macro=\"edition\" prefix=\", \"/>\n      </else-if>\n      <else-if type=\"webpage\">\n        <text variable=\"title\"/>\n        <text value=\"WWW Document\" prefix=\" [\" suffix=\"]\"/>\n      </else-if>\n      <else>\n        <text variable=\"title\"/>\n      </else>\n    </choose>\n  </macro>\n  <macro name=\"publisher\">\n    <group delimiter=\", \">\n      <text variable=\"publisher\"/>\n      <text variable=\"publisher-place\"/>\n    </group>\n  </macro>\n  <macro name=\"event\">\n    <choose>\n      <if variable=\"event\">\n        <text term=\"presented at\" text-case=\"capitalize-first\" suffix=\" \"/>\n        <text variable=\"event\"/>\n      </if>\n    </choose>\n  </macro>\n  <macro name=\"issued\">\n    <choose>\n      <if variable=\"issued\">\n        <date variable=\"issued\">\n          <date-part name=\"year\"/>\n        </date>\n      </if>\n      <else>\n        <text term=\"no date\" form=\"short\"/>\n      </else>\n    </choose>\n  </macro>\n  <macro name=\"edition\">\n    <group delimiter=\" \">\n      <choose>\n        <if is-numeric=\"edition\">\n          <number variable=\"edition\" form=\"ordinal\"/>\n        </if>\n        <else>\n          <text variable=\"edition\" suffix=\".\"/>\n        </else>\n      </choose>\n      <text value=\"ed\"/>\n    </group>\n  </macro>\n  <macro name=\"locators\">\n    <choose>\n      <if type=\"article-journal article-magazine article-newspaper\" match=\"any\">\n        <group prefix=\" \" delimiter=\", \">\n          <group>\n            <text variable=\"volume\"/>\n          </group>\n          <text variable=\"page\"/>\n        </group>\n      </if>\n      <else-if type=\"bill book graphic legal_case legislation motion_picture report song thesis\" match=\"any\">\n        <group delimiter=\", \" prefix=\". \">\n          <text macro=\"event\"/>\n          <text macro=\"publisher\"/>\n        </group>\n      </else-if>\n      <else-if type=\"chapter paper-conference\" match=\"any\">\n        <group delimiter=\", \" prefix=\". \">\n          <text macro=\"event\"/>\n          <text macro=\"publisher\"/>\n          <group>\n            <label variable=\"page\" form=\"short\" suffix=\" \"/>\n            <text variable=\"page\"/>\n          </group>\n        </group>\n      </else-if>\n      <else-if type=\"patent\">\n        <text variable=\"number\" prefix=\". \"/>\n      </else-if>\n    </choose>\n  </macro>\n  <citation et-al-min=\"3\" et-al-use-first=\"1\" disambiguate-add-givenname=\"true\" disambiguate-add-year-suffix=\"true\" collapse=\"year\" cite-group-delimiter=\", \">\n    <sort>\n      <key macro=\"author\"/>\n      <key macro=\"issued\" sort=\"descending\"/>\n    </sort>\n    <layout prefix=\"(\" suffix=\")\" delimiter=\"; \">\n      <group delimiter=\", \">\n        <text macro=\"author-short\"/>\n        <text macro=\"issued\"/>\n        <group delimiter=\" \">\n          <label variable=\"locator\" form=\"short\"/>\n          <text variable=\"locator\"/>\n        </group>\n      </group>\n    </layout>\n  </citation>\n  <bibliography hanging-indent=\"true\" entry-spacing=\"0\" line-spacing=\"1\">\n    <sort>\n      <key macro=\"author\"/>\n      <key macro=\"issued\" sort=\"descending\"/>\n    </sort>\n    <layout>\n      <group suffix=\".\">\n        <text macro=\"author\" suffix=\",\"/>\n        <text macro=\"issued\" prefix=\" \"/>\n        <group prefix=\". \">\n          <text macro=\"title\"/>\n          <text macro=\"container\"/>\n          <text macro=\"locators\"/>\n        </group>\n      </group>\n      <text macro=\"access\" prefix=\". \"/>\n    </layout>\n  </bibliography>\n</style>\n",
  "acs": "<?xml version=\"1.0\" encoding=\"utf-8\"?>\n<style xmlns=\"http://purl.org/net/xbiblio/csl\" class=\"in-text\" version=\"1.0\" demote-non-dropping-particle=\"sort-only\" page-range-format=\"expanded\" default-locale=\"en-US\">\n  <info>\n    <title>ACS Guide 2022 revision</title>\n    <title-short>American Chemical Society</title-short>\n    <id>http://www.zotero.org/styles/american-chemical-society</id>\n    <link href=\"http://www.zotero.org/styles/american-chemical-society\" rel=\"self\"/>\n    <link href=\"https://doi.org/10.1021/acsguide.40303\" rel=\"documentation\"/>\n    <link href=\"https://doi.org/10.1021/acsguide\" rel=\"documentation\"/>\n    <author>\n      <name>Julian Onions</name>\n      <email>julian.onions@gmail.com</email>\n    </author>\n    <contributor>\n      <name>Ivan Bushmarinov</name>\n      <email>ib@ineos.ac.ru</email>\n    </contributor>\n    <contributor>\n      <name>Sebastian Karcher</name>\n    </contributor>\n    <contributor>\n      <name>Patrick O'Brien</name>\n    </contributor>\n    <category citation-format=\"numeric\"/>\n    <category field=\"chemistry\"/>\n    <summary>The American Chemical Society style</summary>\n    <updated>2022-09-19T18:32:56+00:00</updated>\n    <rights license=\"http://creativecommons.org/licenses/by-sa/3.0/\">This work is licensed under a Creative Commons Attribution-ShareAlike 3.0 License</rights>\n  </info>\n  <locale xml:lang=\"en\">\n    <terms>\n      <term name=\"editortranslator\" form=\"short\">\n        <single>ed. and translator</single>\n        <multiple>eds. and translators</multiple>\n      </term>\n      <term name=\"translator\" form=\"short\">\n        <single>translator</single>\n        <multiple>translators</multiple>\n      </term>\n      <term name=\"collection-editor\" form=\"short\">\n        <single>series ed.</single>\n        <multiple>series eds.</multiple>\n      </term>\n    </terms>\n  </locale>\n  <macro name=\"editor\">\n    <group delimiter=\"; \">\n      <names variable=\"editor translator\" delimiter=\"; \">\n        <name sort-separator=\", \" initialize-with=\". \" name-as-sort-order=\"all\" delimiter=\", \" delimiter-precedes-last=\"always\"/>\n        <label form=\"short\" prefix=\", \" text-case=\"title\"/>\n      </names>\n      <names variable=\"collection-editor\">\n        <name sort-separator=\", \" initialize-with=\". \" name-as-sort-order=\"all\" delimiter=\", \" delimiter-precedes-last=\"always\"/>\n        <label form=\"short\" prefix=\", \" text-case=\"title\"/>\n      </names>\n    </group>\n  </macro>\n  <macro name=\"author\">\n    <names variable=\"author\" suffix=\".\">\n      <name sort-separator=\", \" initialize-with=\". \" name-as-sort-order=\"all\" delimiter=\"; \" delimiter-precedes-last=\"always\"/>\n      <label form=\"short\" prefix=\", \" text-case=\"capitalize-first\"/>\n    </names>\n  </macro>\n  <macro name=\"publisher\">\n    <choose>\n      <if type=\"thesis\" match=\"any\">\n        <group delimiter=\", \">\n          <text variable=\"publisher\"/>\n          <text variable=\"publisher-place\"/>\n        </group>\n      </if>\n      <else>\n        <group delimiter=\": \">\n          <text variable=\"publisher\"/>\n          <text variable=\"publisher-place\"/>\n        </group>\n      </else>\n    </choose>\n  </macro>\n  <macro name=\"title\">\n    <choose>\n      <if type=\"bill book graphic legal_case legislation motion_picture report song\" match=\"any\">\n        <text variable=\"title\" text-case=\"title\" font-style=\"italic\"/>\n      </if>\n      <else>\n        <text variable=\"title\" text-case=\"title\"/>\n      </else>\n    </choose>\n  </macro>\n  <macro name=\"volume\">\n    <group delimiter=\" \">\n      <text term=\"volume\" form=\"short\" text-case=\"capitalize-first\"/>\n      <text variable=\"volume\"/>\n    </group>\n  </macro>\n  <macro name=\"series\">\n    <text variable=\"collection-title\"/>\n  </macro>\n  <macro name=\"pages\">\n    <label variable=\"page\" form=\"short\" suffix=\" \" strip-periods=\"true\"/>\n    <text variable=\"page\"/>\n  </macro>\n  <macro name=\"book-container\">\n    <group delimiter=\". \">\n      <text macro=\"title\"/>\n      <choose>\n        <if type=\"entry-dictionary entry-encyclopedia\" match=\"none\">\n          <group delimiter=\" \">\n            <text term=\"in\" text-case=\"capitalize-first\"/>\n            <text variable=\"container-title\" font-style=\"italic\"/>\n          </group>\n        </if>\n        <else>\n          <text variable=\"container-title\" font-style=\"italic\"/>\n        </else>\n      </choose>\n    </group>\n  </macro>\n  <macro name=\"issued\">\n    <date variable=\"issued\" delimiter=\" \">\n      <date-part name=\"year\"/>\n    </date>\n  </macro>\n  <macro name=\"full-issued\">\n    <date variable=\"issued\" delimiter=\" \">\n      <date-part name=\"month\" form=\"long\" suffix=\" \"/>\n      <date-part name=\"day\" suffix=\", \"/>\n      <date-part name=\"year\"/>\n    </date>\n  </macro>\n  <macro name=\"edition\">\n    <choose>\n      <if is-numeric=\"edition\">\n        <group delimiter=\" \">\n          <number variable=\"edition\" form=\"ordinal\"/>\n          <text term=\"edition\" form=\"short\"/>\n        </group>\n      </if>\n      <else>\n        <text variable=\"edition\" suffix=\".\"/>\n      </else>\n    </choose>\n  </macro>\n  <macro name=\"access\">\n    <choose>\n      <if variable=\"DOI\" match=\"any\">\n        <text variable=\"DOI\" prefix=\"https://doi.org/\"/>\n      </if>\n      <else-if type=\"article-journal book chapter entry-encyclopedia entry-dictionary paper-conference\" match=\"none\">\n        <choose>\n          <if variable=\"URL\">\n            <group delimiter=\" \">\n              <text variable=\"URL\"/>\n              <group delimiter=\" \" prefix=\"(\" suffix=\")\">\n                <text term=\"accessed\"/>\n                <date variable=\"accessed\">\n                  <date-part name=\"year\"/>\n                  <date-part name=\"month\" prefix=\"-\" form=\"numeric-leading-zeros\"/>\n                  <date-part name=\"day\" prefix=\"-\" form=\"numeric-leading-zeros\"/>\n                </date>\n              </group>\n            </group>\n          </if>\n        </choose>\n      </else-if>\n    </choose>\n  </macro>\n  <citation collapse=\"citation-number\">\n    <sort>\n      <key variable=\"citation-number\"/>\n    </sort>\n    <layout delimiter=\",\" vertical-align=\"sup\">\n      <text variable=\"citation-number\"/>\n    </layout>\n  </citation>\n  <bibliography second-field-align=\"flush\" entry-spacing=\"0\">\n    <layout suffix=\".\">\n      <text variable=\"citation-number\" prefix=\"(\" suffix=\")\"/>\n      <text macro=\"author\" suffix=\" \"/>\n      <choose>\n        <if type=\"article-journal review\" match=\"any\">\n          <group delimiter=\" \">\n            <text macro=\"title\" suffix=\".\"/>\n            <text variable=\"container-title\" font-style=\"italic\" form=\"short\"/>\n            <group delimiter=\", \">\n              <text macro=\"issued\" font-weight=\"bold\"/>\n              <choose>\n                <if variable=\"volume\">\n                  <group delimiter=\" \">\n                    <text variable=\"volume\" font-style=\"italic\"/>\n                    <text variable=\"issue\" prefix=\"(\" suffix=\")\"/>\n                  </group>\n                </if>\n                <else>\n                  <group delimiter=\" \">\n                    <text term=\"issue\" form=\"short\" text-case=\"capitalize-first\"/>\n                    <text variable=\"issue\"/>\n                  </group>\n                </else>\n              </choose>\n              <text variable=\"page\"/>\n            </group>\n          </group>\n        </if>\n        <else-if type=\"article-magazine article-newspaper article\" match=\"any\">\n          <group delimiter=\" \">\n            <text macro=\"title\" suffix=\".\"/>\n            <text variable=\"container-title\" font-style=\"italic\" suffix=\".\"/>\n            <text macro=\"edition\"/>\n            <text macro=\"publisher\"/>\n            <group delimiter=\", \">\n              <text macro=\"full-issued\"/>\n              <text macro=\"pages\"/>\n            </group>\n          </group>\n        </else-if>\n        <else-if type=\"thesis\">\n          <group delimiter=\", \">\n            <group delimiter=\". \">\n              <text macro=\"title\"/>\n              <text variable=\"genre\"/>\n            </group>\n            <text macro=\"publisher\"/>\n            <text macro=\"issued\"/>\n            <text macro=\"volume\"/>\n            <text macro=\"pages\"/>\n          </group>\n        </else-if>\n        <else-if type=\"bill book graphic legal_case legislation motion_picture report song\" match=\"any\">\n          <group delimiter=\"; \">\n            <group delimiter=\", \">\n              <text macro=\"title\"/>\n              <text macro=\"edition\"/>\n            </group>\n            <text macro=\"editor\" prefix=\" \"/>\n            <text macro=\"series\"/>\n            <choose>\n              <if type=\"report\">\n                <group delimiter=\" \">\n                  <text variable=\"genre\"/>\n                  <text variable=\"number\"/>\n                </group>\n              </if>\n            </choose>\n            <group delimiter=\", \">\n              <text macro=\"publisher\"/>\n              <text macro=\"issued\"/>\n            </group>\n            <group delimiter=\", \">\n              <text macro=\"volume\"/>\n              <text macro=\"pages\"/>\n            </group>\n          </group>\n        </else-if>\n        <else-if type=\"patent\">\n          <group delimiter=\", \">\n            <group delimiter=\". \">\n              <text macro=\"title\"/>\n              <text variable=\"number\"/>\n            </group>\n            <date variable=\"issued\" form=\"text\"/>\n          </group>\n        </else-if>\n        <else-if type=\"chapter paper-conference entry-dictionary entry-encyclopedia\" match=\"any\">\n          <group delimiter=\"; \">\n            <text macro=\"book-container\"/>\n            <text macro=\"editor\"/>\n            <text macro=\"series\"/>\n            <group delimiter=\", \">\n              <text macro=\"publisher\"/>\n              <text macro=\"issued\"/>\n            </group>\n            <group delimiter=\", \">\n              <text macro=\"volume\"/>\n              <text macro=\"pages\"/>\n            </group>\n          </group>\n        </else-if>\n        <else-if type=\"webpage post post-weblog\" match=\"any\">\n          <group delimiter=\". \">\n            <text variable=\"title\" font-style=\"italic\"/>\n            <text variable=\"container-title\"/>\n          </group>\n        </else-if>\n        <else>\n          <group delimiter=\", \">\n            <group delimiter=\". \">\n              <text macro=\"title\"/>\n              <text variable=\"container-title\" font-style=\"italic\"/>\n            </group>\n            <group delimiter=\", \">\n              <text macro=\"issued\"/>\n              <text variable=\"volume\" font-style=\"italic\"/>\n              <text variable=\"page\"/>\n            </group>\n          </group>\n        </else>\n      </choose>\n      <text macro=\"access\" prefix=\". \"/>\n    </layout>\n  </bibliography>\n</style>\n"
};
